// Diagnóstico cirúrgico: pega TODAS as decisões e mostra exatamente o
// sistemaId de cada uma (tipo, length, charcode) pra entender por que o
// sumário acha N itens mas a query direta acha 0. Usado pelo botão de
// debug no BacklogPanel quando há discrepância.
function diagnosticarBacklogSistema(sistemaIdAlvo: string): ServerResult {
  try {
    const alvoBruto = sistemaIdAlvo;
    const alvoTrim = String(sistemaIdAlvo || '').trim();
    const todas = dbGetAll('Decisoes') as Array<Record<string, unknown>>;

    // Amostra dos primeiros 5 sistemaIds encontrados na planilha, com tipo
    const amostraTipos = todas.slice(0, 5).map((d) => ({
      sistemaId: d.sistemaId,
      tipo: typeof d.sistemaId,
      asString: String(d.sistemaId || ''),
      trimmed: String(d.sistemaId || '').trim(),
      length: String(d.sistemaId || '').length,
      lengthTrim: String(d.sistemaId || '').trim().length,
      titulo: d.titulo,
      status: d.status,
    }));

    // Quantos batem por cada estratégia
    const batemEstrito = todas.filter((d) => d.sistemaId === alvoBruto).length;
    const batemString = todas.filter((d) => String(d.sistemaId || '') === alvoBruto).length;
    const batemTrim = todas.filter((d) => String(d.sistemaId || '').trim() === alvoTrim).length;
    const batemTrimAmbos = todas.filter((d) => {
      const a = String(d.sistemaId || '').trim();
      const b = alvoTrim;
      return a === b;
    }).length;

    // Lista os IDs distintos presentes na planilha
    const idsDistintos = Array.from(new Set(todas.map((d) => String(d.sistemaId || '').trim()))).slice(0, 20);

    return {
      ok: true,
      data: {
        sistemaIdAlvo: alvoBruto,
        sistemaIdAlvoLength: String(alvoBruto || '').length,
        sistemaIdAlvoTrim: alvoTrim,
        totalDecisoesNaPlanilha: todas.length,
        batemEstrito,
        batemString,
        batemTrim,
        batemTrimAmbos,
        idsDistintos,
        amostraTipos,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Diagnóstico + recuperação: encontra decisões/riscos com sistemaId inválido
// (vazio, "<ID>", "undefined") e tenta amarrar a algum sistema. Se passado
// `sistemaIdDestino`, aplica direto; caso contrário, lista os órfãos pra UI
// decidir.
function diagnosticarDecisoesOrfas(payload: { sistemaIdDestino?: string } = {}): ServerResult {
  try {
    const ehInvalido = (s: unknown): boolean => {
      const v = String(s || '').trim();
      return !v || v === '<ID>' || v === 'undefined' || v === 'null';
    };

    const decisoes = (dbGetAll('Decisoes') as Array<Record<string, unknown>>).filter((d) => ehInvalido(d.sistemaId));
    const riscos = (dbGetAll('Riscos') as Array<Record<string, unknown>>).filter((r) => ehInvalido(r.sistemaId));

    if (!payload.sistemaIdDestino) {
      return {
        ok: true,
        data: {
          decisoesOrfas: decisoes.length,
          riscosOrfos: riscos.length,
          amostraDecisoes: decisoes.slice(0, 5).map((d) => ({ id: d.id, titulo: d.titulo, data: d.data })),
          amostraRiscos: riscos.slice(0, 5).map((r) => ({ id: r.id, area: r.area, descricao: r.descricao })),
        },
      };
    }

    // Sistema destino: confirma que existe
    const sistemas = dbGetAll('Sistemas') as Array<Record<string, unknown>>;
    if (!sistemas.find((s) => s.id === payload.sistemaIdDestino)) {
      return { ok: false, error: 'Sistema destino não encontrado' };
    }

    let decisoesCorrigidas = 0;
    for (const d of decisoes) {
      try {
        dbUpdate('Decisoes', String(d.id), { sistemaId: payload.sistemaIdDestino });
        decisoesCorrigidas++;
      } catch { /* segue */ }
    }
    let riscosCorrigidos = 0;
    for (const r of riscos) {
      try {
        dbUpdate('Riscos', String(r.id), { sistemaId: payload.sistemaIdDestino });
        riscosCorrigidos++;
      } catch { /* segue */ }
    }

    return { ok: true, data: { decisoesCorrigidas, riscosCorrigidos } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Seed do backlog "Forja v2.0": registra a lista de melhorias que a gente
// guardou pra próxima versão como itens no Kanban do próprio sistema Forja.
// Idempotente — só insere se ainda não tem nenhum item com a tag "forja-v2".
// O usuário roda essa função uma vez via UI ou via Apps Script editor.
function seedForjaV2Backlog(sistemaId: string): ServerResult {
  try {
    if (!sistemaId) return { ok: false, error: 'sistemaId é obrigatório' };

    const existentes = (dbGetAll('Decisoes') as Array<Record<string, unknown>>)
      .filter((d) => String(d.sistemaId || '') === sistemaId)
      .filter((d) => String(d.tags || '').toLowerCase().indexOf('forja-v2') >= 0);
    if (existentes.length > 0) {
      return { ok: true, data: { criados: 0, ja_existiam: existentes.length, mensagem: 'Backlog v2.0 já estava semeado' } };
    }

    interface ItemBacklog {
      titulo: string;
      decisao: string;
      justificativa: string;
      prioridade: string;
      estimativa: string;
      status: string;
    }

    const itens: ItemBacklog[] = [
      {
        titulo: 'Multi-usuário com perfis (admin/cliente/operador)',
        decisao: 'Implementar autenticação por perfil. Admin vê tudo; Cliente vê só os sistemas dele; Operador vê portfólio mas sem editar configurações sensíveis.',
        justificativa: 'Forja hoje é single-user (vinculada ao dono do Sheet). Pra vender como SaaS ou compartilhar com clientes precisa multi-tenancy.',
        prioridade: 'alta',
        estimativa: '2 semanas',
        status: 'backlog',
      },
      {
        titulo: 'Webhooks de entrada (receber eventos de sistemas externos)',
        decisao: 'Endpoint público doPost autenticado que recebe pulsos / erros / receitas de fora e popula a timeline e alertas automaticamente.',
        justificativa: 'Hoje só consumimos APIs (Uptime, GitHub, LLM). Faltam webhooks de entrada pra automação real: Stripe → Receita, Sentry → Alerta, GitHub Actions → Pulso de deploy.',
        prioridade: 'alta',
        estimativa: '1 semana',
        status: 'backlog',
      },
      {
        titulo: 'IA proativa (notifica achados sem o usuário pedir)',
        decisao: 'A auditoria agendada já roda. Adicionar: relatório diário no email com top 3 achados críticos, e push no Drawer de Alertas quando novo finding ALTA aparecer.',
        justificativa: 'Auditoria agendada hoje só registra. A IA poderia ser mais proativa em chamar atenção pra problemas urgentes — virar mais um "co-piloto" do que uma "ferramenta".',
        prioridade: 'media',
        estimativa: '4 dias',
        status: 'backlog',
      },
    ];

    let criados = 0;
    for (const item of itens) {
      dbCreate('Decisoes', {
        sistemaId,
        data: new Date().toISOString().slice(0, 10),
        titulo: item.titulo,
        decisao: item.decisao,
        justificativa: item.justificativa,
        status: item.status,
        prioridade: item.prioridade,
        tags: 'forja-v2,roadmap',
        estimativa: item.estimativa,
      });
      criados++;
    }

    return { ok: true, data: { criados, ja_existiam: 0, mensagem: `${criados} itens v2.0 adicionados ao backlog` } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao semear backlog' };
  }
}

// Gera um prompt em markdown com todo o backlog "a fazer" + "fazendo" do
// sistema, pronto pra colar no Cursor/Claude. Inclui contexto do projeto
// (nome, propósito, stack, repo) pra que a IA externa entenda o ambiente.
function gerarPromptBacklog(sistemaId: string): ServerResult {
  try {
    const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId);
    if (!sistema) return { ok: false, error: 'Sistema não encontrado' };

    const decisoes = (dbGetAll('Decisoes') as Array<Record<string, unknown>>)
      .filter((d) => String(d.sistemaId || '') === sistemaId)
      .filter((d) => {
        const s = String(d.status || '').toLowerCase();
        return s === 'backlog' || s === 'fazendo' || s === 'ativa' || s === '';
      });

    const linhas: string[] = [];
    linhas.push('# Backlog — ' + String(sistema.nome || sistemaId));
    linhas.push('');
    linhas.push('_Exportado da Forja em ' + new Date().toLocaleString('pt-BR') + '_');
    linhas.push('');
    linhas.push('## Contexto do projeto');
    if (sistema.proposito) linhas.push('- **Propósito:** ' + String(sistema.proposito));
    if (sistema.stack) linhas.push('- **Stack:** ' + String(sistema.stack));
    if (sistema.urlProd || sistema.dominioCustomizado) linhas.push('- **URL:** ' + String(sistema.dominioCustomizado || sistema.urlProd));
    if (sistema.repoUrl) linhas.push('- **Repo:** ' + String(sistema.repoUrl));
    linhas.push('');

    if (decisoes.length === 0) {
      linhas.push('## Backlog vazio');
      linhas.push('');
      linhas.push('Nenhum item em "backlog" ou "fazendo" pra este sistema.');
      return { ok: true, data: { markdown: linhas.join('\n'), total: 0 } };
    }

    const ordemPrioridade: Record<string, number> = { alta: 0, media: 1, baixa: 2 };
    decisoes.sort((a, b) => {
      const pa = ordemPrioridade[String(a.prioridade || 'media').toLowerCase()] ?? 1;
      const pb = ordemPrioridade[String(b.prioridade || 'media').toLowerCase()] ?? 1;
      return pa - pb;
    });

    linhas.push('## Itens a executar (' + decisoes.length + ')');
    linhas.push('');
    decisoes.forEach((d, i) => {
      const prio = String(d.prioridade || 'media').toUpperCase();
      const status = String(d.status || 'backlog').toUpperCase();
      linhas.push('### ' + (i + 1) + '. [' + prio + '] ' + String(d.titulo));
      linhas.push('');
      linhas.push('- **Status:** ' + status);
      if (d.estimativa) linhas.push('- **Estimativa:** ' + String(d.estimativa));
      if (d.tags) linhas.push('- **Tags:** ' + String(d.tags));
      linhas.push('');
      linhas.push('**O que fazer:** ' + String(d.decisao || ''));
      linhas.push('');
      if (d.justificativa) {
        linhas.push('**Por quê:** ' + String(d.justificativa));
        linhas.push('');
      }
    });

    linhas.push('---');
    linhas.push('');
    linhas.push('## Instruções pra IA');
    linhas.push('');
    linhas.push('Você está recebendo o backlog atual deste projeto. Faça o seguinte:');
    linhas.push('');
    linhas.push('1. Comece pelos itens marcados como **[ALTA]**.');
    linhas.push('2. Pra cada item, antes de codar, **resuma o que entendeu** em 2 linhas e pergunte se está correto.');
    linhas.push('3. Depois implemente, escrevendo código direto no projeto.');
    linhas.push('4. Ao concluir cada item, **diga explicitamente "concluído"** pra eu marcar no kanban da Forja.');
    linhas.push('5. Se faltar contexto, peça antes de assumir.');

    return { ok: true, data: { markdown: linhas.join('\n'), total: decisoes.length } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar prompt' };
  }
}

// ─── Riscos (Mapa de Quebra) ─────────────────────────────────────────────────

// Um risco está "ativo" enquanto não for mitigado. Riscos mitigados (resolvidos
// por um diff, via auditoria incremental) somem do mapa e param de pesar na saúde.
function _riscoAtivo(r: Record<string, unknown>): boolean {
  return String(r.status || '').toLowerCase().trim() !== 'mitigado';
}

function getRiscosBySistema(sistemaId: string): ServerResult {
  try {
    const alvo = String(sistemaId || '').trim();
    const riscos = (dbGetAll('Riscos') as Array<Record<string, unknown>>)
      .filter((r) => String(r.sistemaId || '').trim() === alvo && _riscoAtivo(r));
    return { ok: true, data: riscos };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar riscos' };
  }
}

function createRisco(data: Record<string, unknown>): ServerResult {
  try {
    const created = dbCreate('Riscos', data);
    return { ok: true, data: created };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao criar risco' };
  }
}

function updateRisco(id: string, data: Record<string, unknown>): ServerResult {
  try {
    const updated = dbUpdate('Riscos', id, data);
    if (!updated) return { ok: false, error: 'Risco não encontrado' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao atualizar risco' };
  }
}

function deleteRisco(id: string): ServerResult {
  try {
    return dbDelete('Riscos', id) ? { ok: true } : { ok: false, error: 'Risco não encontrado' };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao deletar risco' };
  }
}

// ─── Passaporte do Sistema ───────────────────────────────────────────────────

function gerarPassaporte(sistemaId: string): ServerResult {
  try {
    const sistema = dbGetById('Sistemas', sistemaId);
    if (!sistema) return { ok: false, error: 'Sistema não encontrado' };

    const recursos = dbQuery('Recursos', { sistemaId });
    const decisoes = dbQuery('Decisoes', { sistemaId });
    const riscos = dbQuery('Riscos', { sistemaId });
    const timeline = dbQuery('Timeline', { sistemaId });
    const custos = dbQuery('Custos', { sistemaId });

    let md = `# ${sistema['nome']} (${sistema['codinome']})\n\n`;
    md += `> ${sistema['proposito']}\n\n`;
    md += `**Estágio:** ${sistema['estagio']} | **Saúde:** ${sistema['scoreSaude']}%\n`;
    md += `**Stack:** ${sistema['stack']}\n`;
    if (sistema['urlProd']) md += `**URL:** ${sistema['urlProd']}\n`;
    md += `\n---\n\n`;

    // Recursos
    md += `## Recursos\n\n`;
    if (recursos.length === 0) {
      md += `_Nenhum recurso registrado._\n\n`;
    } else {
      for (const r of recursos) {
        md += `### [${r['tipo']}] ${r['chave']}\n`;
        if (r['descricao']) md += `${r['descricao']}\n`;
        if (r['link']) md += `Link: ${r['link']}\n`;
        md += `\n`;
      }
    }

    // Decisões
    md += `## Decisões Técnicas\n\n`;
    if (decisoes.length === 0) {
      md += `_Nenhuma decisão registrada._\n\n`;
    } else {
      for (const d of decisoes) {
        md += `### ${d['titulo']} (${d['data']})\n`;
        md += `**Decisão:** ${d['decisao']}\n`;
        md += `**Justificativa:** ${d['justificativa']}\n`;
        md += `**Status:** ${d['status']}\n\n`;
      }
    }

    // Riscos (Mapa de Quebra)
    md += `## ⚠️ Mapa de Quebra (Riscos)\n\n`;
    if (riscos.length === 0) {
      md += `_Nenhum risco mapeado._\n\n`;
    } else {
      for (const r of riscos) {
        const gravidade = Number(r['gravidade'] || 0);
        const emoji = gravidade >= 8 ? '🔴' : gravidade >= 5 ? '🟡' : '🟢';
        md += `### ${emoji} ${r['area']} (gravidade: ${gravidade}/10)\n`;
        md += `${r['descricao']}\n`;
        if (r['historicoIncidentes']) md += `_Histórico: ${r['historicoIncidentes']}_\n`;
        md += `\n`;
      }
    }

    // Custos
    md += `## Custos\n\n`;
    if (custos.length === 0) {
      md += `_Nenhum custo registrado._\n\n`;
    } else {
      md += `| Fornecedor | Valor | Recorrência |\n|---|---|---|\n`;
      for (const c of custos) {
        md += `| ${c['fornecedor']} | R$ ${Number(c['valor'] || 0).toFixed(2)} | ${c['recorrencia']} |\n`;
      }
      md += `\n`;
    }

    // Timeline
    md += `## Timeline\n\n`;
    if (timeline.length === 0) {
      md += `_Nenhum evento registrado._\n\n`;
    } else {
      for (const t of timeline) {
        const emoji = t['tipo'] === 'ship' ? '🚀' : '🚨';
        md += `- ${emoji} **${t['data']}** — ${t['texto']}\n`;
      }
      md += `\n`;
    }

    md += `---\n_Gerado pela FORJA em ${new Date().toISOString().split('T')[0]}_\n`;

    return { ok: true, data: md };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar passaporte' };
  }
}

// ─── Ideias (Faísca) ─────────────────────────────────────────────────────────

function getIdeias(): ServerResult {
  try {
    // Normaliza os campos novos de trilha (v1.145.0):
    // - `reaberturas` vem como string do sheet → convertemos pra number.
    // - `concluidaEmHist` vem como string JSON → parseamos pra array.
    // Ideias legadas (sem esses campos) ficam com defaults seguros.
    const todas = (dbGetAll('Ideias') as Array<Record<string, unknown>>).map((i) => ({
      ...i,
      reaberturas: Number(i.reaberturas || 0) || 0,
      concluidaEmHist: _historicoConclusao(i),
    }));
    return { ok: true, data: todas };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar ideias' };
  }
}

function createIdeia(data: Record<string, unknown>): ServerResult {
  try {
    // v1.143.0 (fusão Centelha): zero-fricção — só `titulo` é obrigatório.
    // Tudo mais pode entrar depois via triagem (drawer ou modo batch).
    const titulo = String((data && data.titulo) || '').trim();
    if (!titulo) return { ok: false, error: 'Título é obrigatório' };
    const created = dbCreate('Ideias', {
      titulo,
      descricao: String(data.descricao || ''),
      notaImpacto: Number(data.notaImpacto || 0),
      notaEsforco: Number(data.notaEsforco || 0),
      estado: String(data.estado || 'nova'),
      tipo: String(data.tipo || ''),
      sistemaId: String(data.sistemaId || ''),
      prioridade: String(data.prioridade || ''),
      criadoEm: String(data.criadoEm || new Date().toISOString()),
      atualizadoEm: '',
      concluidaEm: '',
      categoria: String(data.categoria || ''),
      arquivadaEm: '',
      reabertaEm: '',
      reaberturas: '0',
      concluidaEmHist: '[]',
    });
    return { ok: true, data: created };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao criar ideia' };
  }
}

// Conta as ideias no inbox (zero-fricção): estado=nova SEM categoria E SEM
// sistemaId — ou seja, capturada bruta esperando triagem. Usado pelo Dashboard
// pra badge "tem X esperando ser triada" e pelo CTA "Modo Triagem" na IdeiasView.
function getIdeiasInboxCount(): ServerResult {
  try {
    const todas = dbGetAll('Ideias') as Array<Record<string, unknown>>;
    const pendentes = todas.filter((i) => {
      const estado = String(i.estado || 'nova').toLowerCase();
      if (estado !== 'nova') return false;
      const cat = String(i.categoria || '').trim();
      const sis = String(i.sistemaId || '').trim();
      return !cat && !sis; // bruta = sem categoria E sem sistema
    }).length;
    return { ok: true, data: { pendentes } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao contar inbox de ideias' };
  }
}

function updateIdeia(id: string, data: Record<string, unknown>): ServerResult {
  try {
    const updated = dbUpdate('Ideias', id, { ...data, atualizadoEm: new Date().toISOString() });
    if (!updated) return { ok: false, error: 'Ideia não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao atualizar ideia' };
  }
}

// Lifecycle actions (v1.142.0): ações dedicadas pro fluxo Nova → Validando →
// Em andamento → Concluída → (Arquivada / Descartada). Concluir e reabrir
// gerenciam o campo `concluidaEm` pra histórico.

function deleteIdeia(id: string): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    const ok = dbDelete('Ideias', id);
    if (!ok) return { ok: false, error: 'Ideia não encontrada' };
    return { ok: true, data: { id } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao remover ideia' };
  }
}

// Helper: lê o histórico de conclusões anteriores. Tolera valores ausentes,
// não-JSON e tipos errados — sempre devolve um array de ISO strings.
function _historicoConclusao(ideia: Record<string, unknown>): string[] {
  const raw = ideia.concluidaEmHist;
  if (!raw) return [];
  if (Array.isArray(raw)) return raw.map(String).filter(Boolean);
  try {
    const parsed = JSON.parse(String(raw));
    return Array.isArray(parsed) ? parsed.map(String).filter(Boolean) : [];
  } catch { return []; }
}

function concluirIdeia(id: string): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    const agora = new Date().toISOString();
    // Se concluindo após uma reabertura, limpamos `reabertaEm` (sinaliza que a
    // ideia está fechada de novo). Mantemos `reaberturas` como histórico —
    // mostra "concluída após 2 reaberturas" no card.
    const updated = dbUpdate('Ideias', id, {
      estado: 'concluida',
      concluidaEm: agora,
      reabertaEm: '',
      atualizadoEm: agora,
    });
    if (!updated) return { ok: false, error: 'Ideia não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao concluir ideia' };
  }
}

function reabrirIdeia(id: string): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    const ideia = dbGetById('Ideias', id) as Record<string, unknown> | null;
    if (!ideia) return { ok: false, error: 'Ideia não encontrada' };
    const agora = new Date().toISOString();
    // Trilha de vida: NÃO apagamos `concluidaEm` (perdia histórico). Em vez
    // disso, empilhamos a conclusão anterior em `concluidaEmHist` e gravamos
    // a reabertura em `reabertaEm` + incrementamos o contador. Permite ver:
    //   "Concluída há 4d → Reaberta há 1d (já foi reaberta 2x)"
    const historico = _historicoConclusao(ideia);
    const concluidaAnterior = String(ideia.concluidaEm || '').trim();
    if (concluidaAnterior) historico.push(concluidaAnterior);
    const reaberturasAnt = Number(ideia.reaberturas || 0) || 0;
    const updated = dbUpdate('Ideias', id, {
      estado: 'em andamento',
      concluidaEm: '', // a próxima conclusão sobrescreve este campo
      reabertaEm: agora,
      reaberturas: String(reaberturasAnt + 1),
      concluidaEmHist: JSON.stringify(historico),
      atualizadoEm: agora,
    });
    if (!updated) return { ok: false, error: 'Ideia não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao reabrir ideia' };
  }
}

function arquivarIdeia(id: string): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    const agora = new Date().toISOString();
    const updated = dbUpdate('Ideias', id, {
      estado: 'arquivada',
      arquivadaEm: agora,
      atualizadoEm: agora,
    });
    if (!updated) return { ok: false, error: 'Ideia não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao arquivar ideia' };
  }
}

function descartarIdeia(id: string): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    const agora = new Date().toISOString();
    const updated = dbUpdate('Ideias', id, {
      estado: 'descartada',
      arquivadaEm: agora, // descartar também marca arquivadaEm pra agrupar como "fora do fluxo"
      atualizadoEm: agora,
    });
    if (!updated) return { ok: false, error: 'Ideia não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao descartar ideia' };
  }
}

// Refina uma Ideia genérica com IA: sugere categoria, prioridade, sistema
// vinculado, título limpo, contexto enriquecido e detecta duplicata cruzando com
// Ideias ativas + Decisões abertas. NÃO grava nada; a UI mostra a proposta
// dentro do IdeiaTriagemDrawer e o usuário decide o que aplicar.
// (v1.143.0: substitui refinarCentelhaComIA — Centelha foi fundida em Ideias.)
function refinarIdeiaComIA(payload: { ideiaId: string }): ServerResult {
  try {
    if (!payload || !payload.ideiaId) return { ok: false, error: 'ideiaId é obrigatório' };
    const ideia = dbGetById('Ideias', payload.ideiaId) as Record<string, unknown> | null;
    if (!ideia) return { ok: false, error: 'Ideia não encontrada' };

    const sistemas = (dbGetAll('Sistemas') as Array<Record<string, unknown>>)
      .map((s) => ({ id: String(s.id), nome: String(s.nome || ''), proposito: String(s.proposito || '').slice(0, 100) }));
    // Universo de duplicatas: outras ideias ativas (não esta) + decisões abertas.
    const ideiasExist = (dbGetAll('Ideias') as Array<Record<string, unknown>>)
      .filter((i) => String(i.id) !== String(ideia.id))
      .filter((i) => {
        const e = String(i.estado || '').toLowerCase();
        return e !== 'descartada' && e !== 'arquivada' && e !== 'concluida';
      })
      .map((i) => ({ id: 'ideia:' + String(i.id), titulo: String(i.titulo || ''), resumo: String(i.descricao || '').slice(0, 120) }));
    const decisoesExist = (dbGetAll('Decisoes') as Array<Record<string, unknown>>)
      .filter((d) => {
        const s = String(d.status || '').toLowerCase();
        return s !== 'cancelado' && s !== 'feito';
      })
      .map((d) => ({ id: 'decisao:' + String(d.id), titulo: String(d.titulo || ''), resumo: String(d.decisao || '').slice(0, 120) }));

    const listaSistemas = sistemas.length
      ? sistemas.map((s) => `- ${s.id}: ${s.nome} (${s.proposito || 'sem propósito'})`).join('\n')
      : '(sem sistemas cadastrados)';
    const universoDup = [...ideiasExist, ...decisoesExist];
    const listaDup = universoDup.length
      ? universoDup.slice(0, 60).map((d, i) => `${i + 1}. [${d.id}] ${d.titulo} — ${d.resumo}`).join('\n')
      : '(sem itens ainda)';

    const sys = 'Você é um PM técnico ajudando a triar uma ideia capturada de forma bruta. '
      + 'Responda SOMENTE com JSON válido, sem markdown, no formato exato:\n'
      + '{"categoria": "feature"|"bug"|"melhoria"|"sistema_novo"|"processo"|"pessoal"|"", '
      + '"prioridade": "alta"|"media"|"baixa", '
      + '"sistemaIdSugerido": string, "tituloSugerido": string, "descricaoSugerida": string, '
      + '"notaImpactoSugerida": number, "notaEsforcoSugerida": number, '
      + '"destino": "ideia"|"backlog"|"arquivar"|"descartar", '
      + '"justificativa": string, '
      + '"duplicado": {"id": string|null, "titulo": string|null, "motivo": string|null}}\n'
      + '- categoria: classifica a natureza da ideia.\n'
      + '- prioridade: alta/media/baixa baseado em urgência e impacto declarado.\n'
      + '- sistemaIdSugerido: id de um sistema da lista (vazio se for ideia nova ou pessoal).\n'
      + '- tituloSugerido: título mais claro e acionável (em formato verbo+objeto se possível).\n'
      + '- descricaoSugerida: contexto expandido com o que faz sentido inferir.\n'
      + '- notaImpactoSugerida / notaEsforcoSugerida: chute de 1 a 10 (1=baixo, 10=alto).\n'
      + '- destino: pra qual fluxo levar (ideia=banco de ideias global; backlog=item acionável de um sistema; arquivar=relevante mas sem ação agora; descartar=ruído).\n'
      + '- duplicado: se já existir item igual no universo (ideia: ou decisao:), preencha id/titulo/motivo; senão null em todos.';

    const userMsg = `Ideia capturada:\nTítulo: ${String(ideia.titulo || '')}\n`
      + `Descrição: ${String(ideia.descricao || '(vazio)')}\n`
      + `Sistema vinculado atual: ${String(ideia.sistemaId || '(nenhum)')}\n\n`
      + `Sistemas existentes:\n${listaSistemas}\n\n`
      + `Universo de duplicatas (ideias ativas + backlog aberto):\n${listaDup}`;

    const resposta = forjaCallLLM(
      [{ role: 'system', content: sys }, { role: 'user', content: userMsg }],
      900, undefined, 'acoes',
    );
    const parsed = extrairJson(resposta) as Record<string, unknown>;
    const dupRaw = (parsed.duplicado || {}) as Record<string, unknown>;
    const duplicado = dupRaw && dupRaw.id
      ? { id: String(dupRaw.id), titulo: String(dupRaw.titulo || ''), motivo: String(dupRaw.motivo || '') }
      : null;

    const proposta = {
      categoria: String(parsed.categoria || ''),
      prioridade: ['alta', 'media', 'baixa'].includes(String(parsed.prioridade)) ? String(parsed.prioridade) : 'media',
      sistemaIdSugerido: String(parsed.sistemaIdSugerido || ''),
      tituloSugerido: String(parsed.tituloSugerido || ideia.titulo || ''),
      descricaoSugerida: String(parsed.descricaoSugerida || ideia.descricao || ''),
      notaImpactoSugerida: Number(parsed.notaImpactoSugerida || 5),
      notaEsforcoSugerida: Number(parsed.notaEsforcoSugerida || 5),
      destino: ['ideia', 'backlog', 'arquivar', 'descartar'].includes(String(parsed.destino)) ? String(parsed.destino) : 'ideia',
      justificativa: String(parsed.justificativa || ''),
    };

    return { ok: true, data: { proposta, duplicado } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao refinar ideia' };
  }
}

// ─── Ideias do tipo "melhoria" (incremento num sistema existente) ─────────────
//
// Fluxo: capturei uma faísca de melhoria amarrada a um sistema → ela vive na
// "faixa Ideias" do Backlog daquele sistema (sem poluir o acionável) → quando
// refino, a IA estrutura num item de backlog e checa duplicado contra o que já
// existe → confirmo e vira um item "A fazer".

// Lista melhorias pendentes (não promovidas/descartadas) de um sistema.
// Aplica o mesmo trim defensivo do Backlog (sistemaId pode ter espaço no Sheets).
function getMelhoriasBySistema(sistemaId: string): ServerResult {
  try {
    const alvo = String(sistemaId || '').trim();
    const todas = dbGetAll('Ideias') as Array<Record<string, unknown>>;
    const itens = todas.filter((i) => {
      if (String(i.tipo || '') !== 'melhoria') return false;
      if (String(i.sistemaId || '').trim() !== alvo) return false;
      const estado = String(i.estado || 'nova').toLowerCase();
      return estado !== 'promovida' && estado !== 'descartada';
    });
    // Mais recentes primeiro (criadoEm desc; legado sem data vai pro fim).
    itens.sort((a, b) => String(b.criadoEm || '').localeCompare(String(a.criadoEm || '')));
    return { ok: true, data: itens };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar melhorias' };
  }
}

// Refina uma ideia/melhoria em um item de backlog estruturado E checa duplicado
// contra as decisões existentes do sistema. NÃO grava nada — só devolve a
// proposta + alerta de duplicado pra UI confirmar (passo anti-redundância).
function refinarIdeiaMelhoria(payload: { ideiaId: string }): ServerResult {
  try {
    if (!payload || !payload.ideiaId) return { ok: false, error: 'ideiaId é obrigatório' };
    const ideia = dbGetById('Ideias', payload.ideiaId) as Record<string, unknown> | null;
    if (!ideia) return { ok: false, error: 'Ideia não encontrada' };

    const sistemaId = String(ideia.sistemaId || '').trim();
    const sistema = sistemaId ? dbGetById('Sistemas', sistemaId) as Record<string, unknown> | null : null;
    const nomeSistema = sistema ? String(sistema.nome || '') : '';

    // Backlog/decisões existentes do sistema pra dedup.
    const existentes = (dbGetAll('Decisoes') as Array<Record<string, unknown>>)
      .filter((d) => String(d.sistemaId || '').trim() === sistemaId)
      .map((d) => ({ id: String(d.id), titulo: String(d.titulo || ''), resumo: String(d.decisao || '').slice(0, 160) }));

    const listaExistentes = existentes.length
      ? existentes.map((d, i) => `${i + 1}. [${d.id}] ${d.titulo} — ${d.resumo}`).join('\n')
      : '(nenhum item de backlog ainda)';

    const sys = 'Você é um PM técnico. Transforme uma ideia crua de melhoria em UM item de backlog acionável '
      + 'e verifique se ela já não existe no backlog atual. Responda SOMENTE com JSON válido, sem markdown, no formato exato:\n'
      + '{"titulo": string, "decisao": string, "justificativa": string, "prioridade": "alta"|"media"|"baixa", '
      + '"tags": string, "estimativa": string, "duplicado": {"id": string|null, "titulo": string|null, "motivo": string|null}}\n'
      + '- "decisao": o que precisa ser feito, objetivo e direto.\n'
      + '- "justificativa": por que importa.\n'
      + '- "tags": 1-3 palavras separadas por vírgula.\n'
      + '- "estimativa": chute curto tipo "2h", "1d" (ou "" se não der pra estimar).\n'
      + '- "duplicado": se a ideia for essencialmente igual a um item existente, preencha id/titulo/motivo; senão use null em todos.';

    const userMsg = `Sistema: ${nomeSistema || '(sem nome)'}\n\n`
      + `Ideia de melhoria:\nTítulo: ${String(ideia.titulo || '')}\nDescrição: ${String(ideia.descricao || '')}\n\n`
      + `Backlog/decisões já existentes neste sistema:\n${listaExistentes}`;

    const resposta = forjaCallLLM(
      [{ role: 'system', content: sys }, { role: 'user', content: userMsg }],
      900, undefined, 'acoes',
    );
    const parsed = extrairJson(resposta) as Record<string, unknown>;
    const dupRaw = (parsed.duplicado || {}) as Record<string, unknown>;
    const duplicado = dupRaw && dupRaw.id
      ? { id: String(dupRaw.id), titulo: String(dupRaw.titulo || ''), motivo: String(dupRaw.motivo || '') }
      : null;

    const proposta = {
      titulo: String(parsed.titulo || ideia.titulo || ''),
      decisao: String(parsed.decisao || ideia.descricao || ''),
      justificativa: String(parsed.justificativa || ''),
      prioridade: ['alta', 'media', 'baixa'].includes(String(parsed.prioridade)) ? String(parsed.prioridade) : 'media',
      tags: String(parsed.tags || ''),
      estimativa: String(parsed.estimativa || ''),
    };

    return { ok: true, data: { proposta, duplicado, sistemaId, nomeSistema } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao refinar ideia' };
  }
}

// Confirma a promoção: cria o item de backlog (Decisoes, status 'backlog') a
// partir da proposta (possivelmente editada na UI) e marca a ideia como
// 'promovida' (preserva o histórico, some das listas ativas).
function confirmarPromocaoIdeia(payload: {
  ideiaId: string;
  sistemaId: string;
  item: { titulo: string; decisao: string; justificativa?: string; prioridade?: string; tags?: string; estimativa?: string };
}): ServerResult {
  try {
    if (!payload || !payload.ideiaId) return { ok: false, error: 'ideiaId é obrigatório' };
    const sistemaId = String(payload.sistemaId || '').trim();
    if (!sistemaId) return { ok: false, error: 'Destine a ideia a um sistema antes de promover' };
    const item = payload.item || ({} as Record<string, unknown>);
    if (!item.titulo) return { ok: false, error: 'Título é obrigatório' };

    const created = dbCreate('Decisoes', {
      sistemaId,
      data: new Date().toISOString().slice(0, 10),
      titulo: String(item.titulo),
      decisao: String(item.decisao || ''),
      justificativa: String(item.justificativa || ''),
      status: 'backlog',
      prioridade: String(item.prioridade || 'media'),
      tags: String(item.tags || ''),
      estimativa: String(item.estimativa || ''),
    });

    dbUpdate('Ideias', payload.ideiaId, { estado: 'promovida', atualizadoEm: new Date().toISOString() });

    return { ok: true, data: { decisao: created } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao promover ideia' };
  }
}

// ─── Centelha (v1.141.0) ─────────────────────────────────────────────────────
//
// Caixa global de captura zero-fricção. Filosofia: tudo que aparece na cabeça
// durante o dia entra aqui sem amarra — depois você processa em lotes (princípio
// GTD: capture first, organize later). Cada Centelha pode virar Ideia (sistema
// novo), virar Decisão (item de backlog de um sistema existente), ser arquivada
// pra histórico ou descartada como ruído.

function getCentelhas(): ServerResult {
  try {
    const todas = dbGetAll('Centelhas') as Array<Record<string, unknown>>;
    todas.sort((a, b) => String(b.criadoEm || '').localeCompare(String(a.criadoEm || '')));
    return { ok: true, data: todas };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar centelhas' };
  }
}

// Conta só as não-triadas — usado pelo Dashboard pra badge "tem X esperando triagem".
function getCentelhasNaoTriadasCount(): ServerResult {
  try {
    const todas = dbGetAll('Centelhas') as Array<Record<string, unknown>>;
    const pendentes = todas.filter((c) => String(c.estado || 'capturada') === 'capturada').length;
    return { ok: true, data: { pendentes } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao contar centelhas' };
  }
}

function createCentelha(data: Record<string, unknown>): ServerResult {
  try {
    const titulo = String((data && data.titulo) || '').trim();
    if (!titulo) return { ok: false, error: 'Título é obrigatório' };
    // MVP: zero-fricção. Só `titulo` é obrigatório. O resto entra na triagem.
    const created = dbCreate('Centelhas', {
      titulo,
      contexto: String(data.contexto || ''),
      estado: 'capturada',
      categoria: String(data.categoria || ''),
      sistemaId: String(data.sistemaId || ''),
      clienteId: String(data.clienteId || ''),
      promovidaPara: '',
      tags: String(data.tags || ''),
      prioridade: String(data.prioridade || ''),
      criadoEm: new Date().toISOString(),
      triadoEm: '',
      decididoEm: '',
    });
    return { ok: true, data: created };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao criar centelha' };
  }
}

function updateCentelha(id: string, data: Record<string, unknown>): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    // Triagem: se vier campo de categoria/sistemaId/clienteId/prioridade e ainda
    // está no estado 'capturada', auto-promove pra 'triada' e marca `triadoEm`.
    const atual = dbGetById('Centelhas', id) as Record<string, unknown> | null;
    if (!atual) return { ok: false, error: 'Centelha não encontrada' };
    const merged = { ...data } as Record<string, unknown>;
    if (String(atual.estado || 'capturada') === 'capturada') {
      const triou = data.categoria || data.sistemaId || data.clienteId || data.prioridade;
      if (triou && !data.estado) {
        merged.estado = 'triada';
        merged.triadoEm = new Date().toISOString();
      }
    }
    const updated = dbUpdate('Centelhas', id, merged);
    if (!updated) return { ok: false, error: 'Centelha não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao atualizar centelha' };
  }
}

function deleteCentelha(id: string): ServerResult {
  try {
    if (!id) return { ok: false, error: 'id é obrigatório' };
    const ok = dbDelete('Centelhas', id);
    if (!ok) return { ok: false, error: 'Centelha não encontrada' };
    return { ok: true, data: { id } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao remover centelha' };
  }
}

function arquivarCentelha(id: string): ServerResult {
  try {
    const updated = dbUpdate('Centelhas', id, { estado: 'arquivada', decididoEm: new Date().toISOString() });
    if (!updated) return { ok: false, error: 'Centelha não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao arquivar centelha' };
  }
}

function descartarCentelha(id: string): ServerResult {
  try {
    const updated = dbUpdate('Centelhas', id, { estado: 'descartada', decididoEm: new Date().toISOString() });
    if (!updated) return { ok: false, error: 'Centelha não encontrada' };
    return { ok: true, data: updated };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao descartar centelha' };
  }
}

// Promove uma Centelha pra Ideia (banco de ideias global). Aceita override dos
// campos editados pela UI na hora da promoção. Marca a Centelha como
// 'promovida' com `promovidaPara='ideia:<id>'` pra rastreabilidade.
function promoverCentelhaParaIdeia(payload: {
  centelhaId: string;
  ideia: { titulo: string; descricao?: string; notaImpacto?: number; notaEsforco?: number; tipo?: string; sistemaId?: string; prioridade?: string };
}): ServerResult {
  try {
    if (!payload || !payload.centelhaId) return { ok: false, error: 'centelhaId é obrigatório' };
    const centelha = dbGetById('Centelhas', payload.centelhaId) as Record<string, unknown> | null;
    if (!centelha) return { ok: false, error: 'Centelha não encontrada' };
    const ideia = payload.ideia || ({} as Record<string, unknown>);
    if (!ideia.titulo) return { ok: false, error: 'Título da ideia é obrigatório' };
    const novaIdeia = dbCreate('Ideias', {
      titulo: String(ideia.titulo),
      descricao: String(ideia.descricao || centelha.contexto || ''),
      notaImpacto: Number(ideia.notaImpacto || 5),
      notaEsforco: Number(ideia.notaEsforco || 5),
      estado: 'nova',
      tipo: String(ideia.tipo || 'sistema'),
      sistemaId: String(ideia.sistemaId || ''),
      prioridade: String(ideia.prioridade || 'media'),
      criadoEm: new Date().toISOString(),
    }) as Record<string, unknown>;
    dbUpdate('Centelhas', payload.centelhaId, {
      estado: 'promovida',
      promovidaPara: 'ideia:' + String(novaIdeia.id || ''),
      decididoEm: new Date().toISOString(),
    });
    return { ok: true, data: { ideia: novaIdeia } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao promover centelha pra ideia' };
  }
}

// Promove uma Centelha direto pra item de Backlog (Decisões) de um sistema.
function promoverCentelhaParaBacklog(payload: {
  centelhaId: string;
  decisao: { sistemaId: string; titulo: string; decisao?: string; justificativa?: string; prioridade?: string; tags?: string; estimativa?: string };
}): ServerResult {
  try {
    if (!payload || !payload.centelhaId) return { ok: false, error: 'centelhaId é obrigatório' };
    const centelha = dbGetById('Centelhas', payload.centelhaId) as Record<string, unknown> | null;
    if (!centelha) return { ok: false, error: 'Centelha não encontrada' };
    const d = payload.decisao || ({} as Record<string, unknown>);
    if (!d.sistemaId) return { ok: false, error: 'Sistema é obrigatório pra promover ao backlog' };
    if (!d.titulo) return { ok: false, error: 'Título é obrigatório' };
    const novaDecisao = dbCreate('Decisoes', {
      sistemaId: String(d.sistemaId),
      data: new Date().toISOString().slice(0, 10),
      titulo: String(d.titulo),
      decisao: String(d.decisao || centelha.contexto || ''),
      justificativa: String(d.justificativa || ''),
      status: 'backlog',
      prioridade: String(d.prioridade || 'media'),
      tags: String(d.tags || ''),
      estimativa: String(d.estimativa || ''),
    }) as Record<string, unknown>;
    dbUpdate('Centelhas', payload.centelhaId, {
      estado: 'promovida',
      promovidaPara: 'decisao:' + String(novaDecisao.id || ''),
      decididoEm: new Date().toISOString(),
    });
    return { ok: true, data: { decisao: novaDecisao } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao promover centelha pro backlog' };
  }
}

// Refina uma Centelha com IA: sugere categoria, prioridade, sistema vinculado e
// detecta duplicata cruzando com Ideias + Decisões existentes. NÃO grava nada;
// a UI mostra a proposta e o usuário decide.
function refinarCentelhaComIA(payload: { centelhaId: string }): ServerResult {
  try {
    if (!payload || !payload.centelhaId) return { ok: false, error: 'centelhaId é obrigatório' };
    const centelha = dbGetById('Centelhas', payload.centelhaId) as Record<string, unknown> | null;
    if (!centelha) return { ok: false, error: 'Centelha não encontrada' };

    const sistemas = (dbGetAll('Sistemas') as Array<Record<string, unknown>>)
      .map((s) => ({ id: String(s.id), nome: String(s.nome || ''), proposito: String(s.proposito || '').slice(0, 100) }));
    const ideiasExist = (dbGetAll('Ideias') as Array<Record<string, unknown>>)
      .filter((i) => String(i.estado || '') !== 'descartada')
      .map((i) => ({ id: 'ideia:' + String(i.id), titulo: String(i.titulo || ''), resumo: String(i.descricao || '').slice(0, 120) }));
    const decisoesExist = (dbGetAll('Decisoes') as Array<Record<string, unknown>>)
      .filter((d) => String(d.status || '') !== 'cancelado' && String(d.status || '') !== 'feito')
      .map((d) => ({ id: 'decisao:' + String(d.id), titulo: String(d.titulo || ''), resumo: String(d.decisao || '').slice(0, 120) }));

    const listaSistemas = sistemas.length
      ? sistemas.map((s) => `- ${s.id}: ${s.nome} (${s.proposito || 'sem propósito'})`).join('\n')
      : '(sem sistemas cadastrados)';
    const universoDup = [...ideiasExist, ...decisoesExist];
    const listaDup = universoDup.length
      ? universoDup.slice(0, 60).map((d, i) => `${i + 1}. [${d.id}] ${d.titulo} — ${d.resumo}`).join('\n')
      : '(sem itens ainda)';

    const sys = 'Você é um PM técnico ajudando a triar uma anotação rápida. '
      + 'Responda SOMENTE com JSON válido, sem markdown, no formato exato:\n'
      + '{"categoria": "feature"|"bug"|"melhoria"|"sistema_novo"|"processo"|"pessoal"|"", '
      + '"prioridade": "alta"|"media"|"baixa", '
      + '"sistemaIdSugerido": string, "tituloSugerido": string, "contextoSugerido": string, '
      + '"destino": "ideia"|"backlog"|"arquivar"|"descartar", '
      + '"justificativa": string, '
      + '"duplicado": {"id": string|null, "titulo": string|null, "motivo": string|null}}\n'
      + '- categoria: classifica a natureza.\n'
      + '- prioridade: chute pragmático.\n'
      + '- sistemaIdSugerido: id de um sistema da lista (vazio se for ideia nova ou pessoal).\n'
      + '- destino: pra qual fluxo levar (ideia=banco de ideias global; backlog=item acionável de um sistema; arquivar=relevante mas sem ação agora; descartar=ruído).\n'
      + '- duplicado: se já existir item igual no universo (ideia: ou decisao:), preencha id/titulo/motivo; senão null em todos.';

    const userMsg = `Centelha capturada:\nTítulo: ${String(centelha.titulo || '')}\n`
      + `Contexto: ${String(centelha.contexto || '(vazio)')}\n\n`
      + `Sistemas existentes:\n${listaSistemas}\n\n`
      + `Universo de duplicatas (ideias + backlog ativo):\n${listaDup}`;

    const resposta = forjaCallLLM(
      [{ role: 'system', content: sys }, { role: 'user', content: userMsg }],
      900, undefined, 'acoes',
    );
    const parsed = extrairJson(resposta) as Record<string, unknown>;
    const dupRaw = (parsed.duplicado || {}) as Record<string, unknown>;
    const duplicado = dupRaw && dupRaw.id
      ? { id: String(dupRaw.id), titulo: String(dupRaw.titulo || ''), motivo: String(dupRaw.motivo || '') }
      : null;

    const proposta = {
      categoria: String(parsed.categoria || ''),
      prioridade: ['alta', 'media', 'baixa'].includes(String(parsed.prioridade)) ? String(parsed.prioridade) : 'media',
      sistemaIdSugerido: String(parsed.sistemaIdSugerido || ''),
      tituloSugerido: String(parsed.tituloSugerido || centelha.titulo || ''),
      contextoSugerido: String(parsed.contextoSugerido || centelha.contexto || ''),
      destino: ['ideia', 'backlog', 'arquivar', 'descartar'].includes(String(parsed.destino)) ? String(parsed.destino) : 'ideia',
      justificativa: String(parsed.justificativa || ''),
    };

    return { ok: true, data: { proposta, duplicado } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao refinar centelha' };
  }
}

// ─── Pessoas (Mini-CRM) ─────────────────────────────────────────────────────

function getPessoas(): ServerResult {
  try {
    const pessoas = dbGetAll('Pessoas') as Array<Record<string, unknown>>;
    const todasReceitas = dbGetAll('Receitas') as Array<Record<string, unknown>>;

    // Indexar receitas por pessoaId pra um pass O(N)
    const porPessoa = new Map<string, Array<Record<string, unknown>>>();
    for (const r of todasReceitas) {
      const pid = String(r.pessoaId || '');
      if (!pid) continue;
      const arr = porPessoa.get(pid) || [];
      arr.push(r);
      porPessoa.set(pid, arr);
    }

    // Enriquece cada pessoa com `saude` + `pendenciasQtd` derivados.
    // O cálculo é o mesmo de snapshotCliente, só mais enxuto (não monta
    // o histórico, só conta atrasadas).
    const enriquecidas = pessoas.map((p) => {
      const pid = String(p.id || '');
      const recs = porPessoa.get(pid) || [];
      const { saude, pendenciasQtd, pendenciasValor } = _calcularSaudePessoa(recs);
      return { ...p, saude, pendenciasQtd, pendenciasValor };
    });

    return { ok: true, data: enriquecidas };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar pessoas' };
  }
}

// Calcula a saúde financeira de uma pessoa a partir das suas receitas.
// "Atrasada" = a próximaCobranca é uma data no passado E a assinatura está
// ativa (foi pra cobrar e não foi). Critérios:
//   • em_dia       — nenhuma receita atrasada
//   • atencao      — 1+ atrasada com no máx 15 dias de atraso
//   • inadimplente — atraso > 15d OU 3+ receitas atrasadas
//   • sem_historico— sem nenhuma receita cadastrada pra essa pessoa
function _calcularSaudePessoa(
  receitas: Array<Record<string, unknown>>,
): { saude: 'em_dia' | 'atencao' | 'inadimplente' | 'sem_historico'; pendenciasQtd: number; pendenciasValor: number } {
  if (receitas.length === 0) return { saude: 'sem_historico', pendenciasQtd: 0, pendenciasValor: 0 };
  const hoje = Date.now();
  let qtd = 0;
  let valor = 0;
  let pior = 0; // dias do atraso mais antigo
  for (const r of receitas) {
    const statusR = String(r.status || '').toLowerCase();
    if (statusR !== 'ativa') continue;
    const proximaStr = String(r.proximaCobranca || '');
    if (!proximaStr) continue;
    const t = new Date(proximaStr).getTime();
    if (Number.isNaN(t) || t >= hoje) continue;
    const dias = Math.floor((hoje - t) / 86400000);
    qtd++;
    valor += Number(r.valor || 0);
    if (dias > pior) pior = dias;
  }
  let saude: 'em_dia' | 'atencao' | 'inadimplente' | 'sem_historico';
  if (qtd === 0) saude = 'em_dia';
  else if (pior > 15 || qtd >= 3) saude = 'inadimplente';
  else saude = 'atencao';
  return { saude, pendenciasQtd: qtd, pendenciasValor: Math.round(valor * 100) / 100 };
}

