function deletePulso(id: string): ServerResult {
  try {
    const schema = SCHEMA.find(s => s.name === 'Pulsos');
    if (!schema) return { ok: false, error: 'Schema não encontrado' };
    const sheet = getSpreadsheet().getSheetByName('Pulsos');
    if (!sheet) return { ok: false, error: 'Aba não encontrada' };
    const lastRow = sheet.getLastRow();
    if (lastRow <= 1) return { ok: false, error: 'Pulso não encontrado' };
    const data = sheet.getRange(2, 1, lastRow - 1, schema.columns.length).getValues();
    const rowIndex = data.findIndex(row => row[0] === id);
    if (rowIndex === -1) return { ok: false, error: 'Pulso não encontrado' };
    sheet.deleteRow(rowIndex + 2);
    return { ok: true };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao deletar pulso' };
  }
}

// Trigger function — roda automaticamente via time-driven trigger
// Verifica todas as URLs monitoradas e atualiza status + latência
function executarPulsos(): void {
  initDatabase();
  const pulsos = dbGetAll('Pulsos');
  for (const pulso of pulsos) {
    const url = String(pulso['urlCheck'] || '');
    if (!url) continue;
    try {
      const start = Date.now();
      const response = UrlFetchApp.fetch(url, { muteHttpExceptions: true, followRedirects: true });
      const latencia = Date.now() - start;
      const status = response.getResponseCode();
      dbUpdate('Pulsos', String(pulso['id']), { ultimoStatus: status, latenciaMs: latencia, verificadoEm: new Date().toISOString() });

      // Se status >= 500, atualiza scoreSaude do sistema
      if (status >= 500) {
        const sistemaId = String(pulso['sistemaId'] || '');
        if (sistemaId) {
          const sistema = dbGetById('Sistemas', sistemaId);
          if (sistema) {
            const currentScore = Number(sistema['scoreSaude'] || 0);
            const newScore = Math.max(0, currentScore - 10);
            dbUpdate('Sistemas', sistemaId, { scoreSaude: newScore });
          }
          // Registrar incidente na Timeline
          dbCreate('Timeline', {
            sistemaId,
            data: new Date().toISOString().split('T')[0],
            tipo: 'incidente',
            texto: `URL ${url} retornou status ${status}`,
          });
        }
      }
    } catch {
      // URL inacessível
      dbUpdate('Pulsos', String(pulso['id']), { ultimoStatus: 0, latenciaMs: 0, verificadoEm: new Date().toISOString() });
      const sistemaId = String(pulso['sistemaId'] || '');
      if (sistemaId) {
        dbCreate('Timeline', {
          sistemaId,
          data: new Date().toISOString().split('T')[0],
          tipo: 'incidente',
          texto: `URL ${url} inacessível (timeout/erro de rede)`,
        });
      }
    }
  }
}

// Checa AGORA as URLs monitoradas de um sistema (sem esperar o trigger de 15min)
// e devolve a lista atualizada. Usado pelo botão "Verificar agora" no painel.
function verificarPulsosSistema(sistemaId: string): ServerResult {
  try {
    initDatabase();
    const pulsos = (dbGetAll('Pulsos') as Array<Record<string, unknown>>).filter((p) => String(p.sistemaId || '') === sistemaId);
    for (const pulso of pulsos) {
      const url = String(pulso.urlCheck || '');
      if (!url) continue;
      try {
        const start = Date.now();
        const response = UrlFetchApp.fetch(url, { muteHttpExceptions: true, followRedirects: true });
        const latencia = Date.now() - start;
        const status = response.getResponseCode();
        dbUpdate('Pulsos', String(pulso.id), { ultimoStatus: status, latenciaMs: latencia, verificadoEm: new Date().toISOString() });
      } catch (_e) {
        dbUpdate('Pulsos', String(pulso.id), { ultimoStatus: 0, latenciaMs: 0, verificadoEm: new Date().toISOString() });
      }
    }
    const atualizados = (dbGetAll('Pulsos') as Array<Record<string, unknown>>).filter((p) => String(p.sistemaId || '') === sistemaId);
    return { ok: true, data: atualizados };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao verificar pulsos' };
  }
}

// ─── Alertas de Renovação Financeira ─────────────────────────────────────────

// Trigger function — verifica custos com proximaCobranca nos próximos 7 dias
function verificarRenovacoes(): void {
  initDatabase();
  const custos = dbGetAll('Custos');
  const hoje = new Date();
  const em7Dias = new Date(hoje.getTime() + 7 * 24 * 60 * 60 * 1000);
  const alertas: string[] = [];

  for (const custo of custos) {
    const proxCobranca = String(custo['proximaCobranca'] || '');
    if (!proxCobranca) continue;
    const dataCob = new Date(proxCobranca);
    if (dataCob >= hoje && dataCob <= em7Dias) {
      const sistema = custo['sistemaId'] ? dbGetById('Sistemas', String(custo['sistemaId'])) : null;
      const nomeSistema = sistema ? String(sistema['nome']) : 'Sem sistema';
      alertas.push(`• ${custo['fornecedor']} — R$ ${Number(custo['valor'] || 0).toFixed(2)} (${nomeSistema}) vence em ${proxCobranca}`);
    }
  }

  if (alertas.length > 0) {
    const email = Session.getActiveUser().getEmail();
    const corpo = `🔔 FORJA — Renovações nos próximos 7 dias:\n\n${alertas.join('\n')}\n\n---\nEnviado automaticamente pela FORJA.`;
    MailApp.sendEmail(email, '🔔 FORJA: Renovações próximas', corpo);
  }
}

// Configura os triggers automaticamente
function configurarTriggers(): ServerResult {
  try {
    // Remove triggers existentes da Forja para evitar duplicação
    const triggers = ScriptApp.getProjectTriggers();
    for (const trigger of triggers) {
      const handlerName = trigger.getHandlerFunction();
      if (handlerName === 'executarPulsos' || handlerName === 'verificarRenovacoes') {
        ScriptApp.deleteTrigger(trigger);
      }
    }

    // Pulsos: a cada 15 minutos
    ScriptApp.newTrigger('executarPulsos')
      .timeBased()
      .everyMinutes(15)
      .create();

    // Renovações: diariamente às 9h
    ScriptApp.newTrigger('verificarRenovacoes')
      .timeBased()
      .atHour(9)
      .everyDays(1)
      .create();

    return { ok: true, data: 'Triggers configurados: Pulsos a cada 15min, Renovações diárias às 9h' };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao configurar triggers' };
  }
}

// ─── Busca Global ────────────────────────────────────────────────────────────

interface SearchResult {
  tipo: string;
  id: string;
  titulo: string;
  subtitulo: string;
}

function buscaGlobal(query: string): ServerResult {
  try {
    if (!query || query.length < 2) return { ok: true, data: [] };
    const q = query.toLowerCase();
    const resultados: SearchResult[] = [];

    // Buscar em Sistemas
    const sistemas = dbGetAll('Sistemas');
    for (const s of sistemas) {
      const match = String(s['nome'] || '').toLowerCase().includes(q)
        || String(s['codinome'] || '').toLowerCase().includes(q)
        || String(s['proposito'] || '').toLowerCase().includes(q)
        || String(s['stack'] || '').toLowerCase().includes(q);
      if (match) {
        resultados.push({ tipo: 'sistema', id: String(s['id']), titulo: String(s['nome']), subtitulo: String(s['codinome']) });
      }
    }

    // Buscar em Ideias
    const ideias = dbGetAll('Ideias');
    for (const i of ideias) {
      const match = String(i['titulo'] || '').toLowerCase().includes(q)
        || String(i['descricao'] || '').toLowerCase().includes(q);
      if (match) {
        resultados.push({ tipo: 'ideia', id: String(i['id']), titulo: String(i['titulo']), subtitulo: String(i['estado'] || '') });
      }
    }

    // Buscar em Pessoas
    const pessoas = dbGetAll('Pessoas');
    for (const p of pessoas) {
      const match = String(p['nome'] || '').toLowerCase().includes(q)
        || String(p['contato'] || '').toLowerCase().includes(q);
      if (match) {
        resultados.push({ tipo: 'pessoa', id: String(p['id']), titulo: String(p['nome']), subtitulo: String(p['papel'] || '') });
      }
    }

    // Buscar em Oportunidades
    const oportunidades = dbGetAll('Oportunidades');
    for (const o of oportunidades) {
      const match = String(o['titulo'] || '').toLowerCase().includes(q);
      if (match) {
        resultados.push({ tipo: 'oportunidade', id: String(o['id']), titulo: String(o['titulo']), subtitulo: `R$ ${Number(o['valorEstimado'] || 0).toLocaleString()}` });
      }
    }

    return { ok: true, data: resultados.slice(0, 10) };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro na busca' };
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// DASHBOARD — dados consolidados (KPIs, série de MRR, apps, contas a vencer)
// ═══════════════════════════════════════════════════════════════════════════════

function getDashboardData(): ServerResult {
  try {
    initDatabase();
    seedStacks();
    const sistemas = dbGetAll('Sistemas');
    const custos = dbGetAll('Custos');
    const receitas = dbGetAll('Receitas');

    const custoMensal = custos.reduce((sum, c) => sum + toMonthly(Number(c['valor'] || 0), String(c['recorrencia'] || 'mensal')), 0);
    const receitasAtivas = receitas.filter(r => String(r['status'] || 'ativa').toLowerCase() !== 'cancelada');
    const mrr = receitasAtivas.reduce((sum, r) => sum + toMonthly(Number(r['valor'] || 0), String(r['recorrencia'] || 'mensal')), 0);
    const lucro = mrr - custoMensal;

    const ativos = sistemas.filter(s => s['estagio'] === 'forja' || s['estagio'] === 'tempera');
    const saudeMedia = ativos.length > 0
      ? Math.round(ativos.reduce((sum, s) => sum + Number(s['scoreSaude'] || 0), 0) / ativos.length)
      : 0;

    // Série de MRR dos últimos 6 meses (a partir da data de início das assinaturas)
    const mrrSeries: Array<{ label: string; valor: number }> = [];
    const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const agora = new Date();
    for (let i = 5; i >= 0; i--) {
      const ref = new Date(agora.getFullYear(), agora.getMonth() - i, 1);
      const fimMes = new Date(ref.getFullYear(), ref.getMonth() + 1, 0);
      const valorMes = receitasAtivas.reduce((sum, r) => {
        const inicioStr = String(r['inicio'] || '');
        const inicio = inicioStr ? new Date(inicioStr) : new Date(0);
        if (inicio <= fimMes) return sum + toMonthly(Number(r['valor'] || 0), String(r['recorrencia'] || 'mensal'));
        return sum;
      }, 0);
      mrrSeries.push({ label: `${meses[ref.getMonth()]}/${String(ref.getFullYear()).slice(2)}`, valor: Math.round(valorMes) });
    }
    // Custos não têm histórico mensal no schema → mantemos o custo atual constante (linha plana, honesto).
    // Lucro por mês = MRR do mês − custo mensal atual.
    const custoSerie = mrrSeries.map(() => Math.round(custoMensal));
    const lucroSerie = mrrSeries.map((m) => Math.round(m.valor - custoMensal));

    // Apps com MRR e status
    const apps = sistemas.map(s => {
      const mrrApp = receitasAtivas
        .filter(r => r['sistemaId'] === s['id'])
        .reduce((sum, r) => sum + toMonthly(Number(r['valor'] || 0), String(r['recorrencia'] || 'mensal')), 0);
      const saude = Number(s['scoreSaude'] || 0);
      const status = s['estagio'] === 'prateleira' ? 'arquivado' : (saude >= 70 ? 'ativo' : saude > 0 ? 'atencao' : 'rascunho');
      const removidoNoGas = !!s['removidoNoGas'] && String(s['removidoNoGas']).toLowerCase() !== 'false';
      return { id: s['id'], nome: s['nome'], estagio: s['estagio'], cliente: '', mrr: Math.round(mrrApp), saude, status, removidoNoGas };
    });

    // Contas a vencer (próximos 30 dias) — custos a pagar + receitas a receber
    const hoje = new Date();
    const limite = new Date(hoje.getTime() + 30 * 24 * 60 * 60 * 1000);
    const contas: Array<{ tipo: string; nome: string; descricao: string; valor: number; data: string; dias: number }> = [];
    for (const c of custos) {
      const d = String(c['proximaCobranca'] || '');
      if (!d) continue;
      const data = new Date(d);
      if (data >= hoje && data <= limite) {
        contas.push({ tipo: 'pagar', nome: String(c['fornecedor'] || ''), descricao: String(c['categoria'] || 'Custo'), valor: Number(c['valor'] || 0), data: d, dias: Math.ceil((data.getTime() - hoje.getTime()) / 86400000) });
      }
    }
    for (const r of receitasAtivas) {
      const d = String(r['proximaCobranca'] || '');
      if (!d) continue;
      const data = new Date(d);
      if (data >= hoje && data <= limite) {
        const sistema = r['sistemaId'] ? dbGetById('Sistemas', String(r['sistemaId'])) : null;
        contas.push({ tipo: 'receber', nome: sistema ? String(sistema['nome']) : String(r['plano'] || 'Assinatura'), descricao: `Plano ${r['plano'] || ''}`, valor: Number(r['valor'] || 0), data: d, dias: Math.ceil((data.getTime() - hoje.getTime()) / 86400000) });
      }
    }
    contas.sort((a, b) => a.dias - b.dias);

    return {
      ok: true,
      data: {
        kpis: { mrr: Math.round(mrr), custoMensal: Math.round(custoMensal), lucro: Math.round(lucro), saudeMedia },
        mrrSeries,
        custoSerie,
        lucroSerie,
        apps,
        contas: contas.slice(0, 8),
        totais: { sistemas: sistemas.length, ativos: ativos.length, assinaturas: receitasAtivas.length },
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao carregar dashboard' };
  }
}

