// ═══════════════════════════════════════════════════════════════════════════════
// FORJA IA — Conselho de especialistas, Blueprint e Diagramas (Fase 3)
// ═══════════════════════════════════════════════════════════════════════════════

// Extrai JSON de uma resposta do LLM (tolera ```json e texto ao redor).
function extrairJson(texto: string): unknown {
  let s = String(texto || '').trim();
  s = s.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  try { return JSON.parse(s); } catch { /* tenta recortar */ }
  const ini = Math.min(...[s.indexOf('{'), s.indexOf('[')].filter(i => i >= 0).concat([Infinity]));
  const fim = Math.max(s.lastIndexOf('}'), s.lastIndexOf(']'));
  if (ini !== Infinity && fim > ini) {
    try { return JSON.parse(s.slice(ini, fim + 1)); } catch { /* falhou */ }
  }
  throw new Error('A IA não retornou um JSON válido.');
}

// A IA às vezes escreve valores no formato BR (ex.: 1.285,90) dentro dos campos
// numéricos da fatura — o que quebra o JSON.parse (vírgula no meio do número).
// Normaliza SÓ os campos conhecidos (valor/total) pra ponto decimal e remove
// separador de milhar; também converte de string ("1285,90") pra número.
function _repararNumerosFaturaJson(s: string): string {
  return String(s || '').replace(
    /("(?:valor|total)"\s*:\s*)"?(-?\d[\d.]*(?:,\d+)?)"?/g,
    (_m, pre: string, num: string) => {
      let n = num;
      if (n.indexOf(',') >= 0) n = n.replace(/\./g, '').replace(',', '.');
      return `${pre}${n}`;
    },
  );
}

// Parser de JSON de fatura tolerante: tenta o normal e, se falhar, repara os
// números BR e tenta de novo. Centraliza o tratamento usado pelos extratores.
function extrairJsonFatura(texto: string): unknown {
  try { return extrairJson(texto); }
  catch {
    return extrairJson(_repararNumerosFaturaJson(String(texto || '')));
  }
}

// Tenta extrair um bloco Mermaid válido de uma resposta crua da IA.
// A IA frequentemente devolve uma de:
//   1) JSON limpo:  {"mermaid":"flowchart TD\n A-->B"}
//   2) Markdown:    ```mermaid\nflowchart TD\n A-->B\n```
//   3) Texto solto: flowchart TD\n A-->B
//   4) JSON quebrado (aspas mal escapadas) com Mermaid lá dentro
// Esta função tenta as 4 ordens — retorna string vazia se não achar nada plausível.
function _extrairMermaidBruto(texto: string): string {
  const raw = String(texto || '');
  if (!raw.trim()) return '';

  // 1) Procura bloco ```mermaid ... ``` explícito (mais confiável)
  const blocoMermaid = raw.match(/```\s*mermaid\s*\n([\s\S]+?)```/i);
  if (blocoMermaid && blocoMermaid[1].trim()) return blocoMermaid[1].trim();

  // 2) Procura qualquer ``` ... ``` que comece com palavra-chave Mermaid
  const blocosCode = raw.match(/```\s*\n?([\s\S]+?)```/g) || [];
  for (const b of blocosCode) {
    const conteudo = b.replace(/^```[^\n]*\n?/, '').replace(/```$/, '').trim();
    if (_pareceMermaid(conteudo)) return conteudo;
  }

  // 3) Procura campo "mermaid":"..." dentro de JSON quebrado, com regex tolerante.
  //    Pega entre as primeiras aspas e o último } anterior ao fim do bloco.
  const matchCampo = raw.match(/"mermaid"\s*:\s*"([\s\S]*?)"\s*[,}]/);
  if (matchCampo && matchCampo[1]) {
    // Desescapa \n e \" mais comuns
    const decoded = matchCampo[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\t/g, '  ');
    if (_pareceMermaid(decoded)) return decoded.trim();
  }

  // 4) Procura a primeira linha que tem palavra-chave Mermaid e pega dali até o fim
  const linhas = raw.split('\n');
  let inicio = -1;
  for (let i = 0; i < linhas.length; i++) {
    if (_pareceMermaid(linhas[i])) { inicio = i; break; }
  }
  if (inicio >= 0) {
    // Tira lixo de fechamento que sobra
    let bloco = linhas.slice(inicio).join('\n').trim();
    bloco = bloco.replace(/```[\s\S]*$/, '').trim();
    // Cortar JSON closing "}" no fim
    bloco = bloco.replace(/"\s*}\s*$/, '').replace(/\\n/g, '\n').replace(/\\"/g, '"');
    if (_pareceMermaid(bloco)) return bloco;
  }

  return '';
}

// Detecta se uma string parece código Mermaid pela palavra-chave inicial.
function _pareceMermaid(s: string): boolean {
  if (!s) return false;
  return /^\s*(flowchart|graph|sequenceDiagram|classDiagram|erDiagram|stateDiagram(?:-v2)?|mindmap|gantt|pie|journey|gitGraph|timeline|quadrantChart|requirementDiagram|c4Context)\b/i
    .test(s);
}

// Resolve o texto de contexto a partir de um id de ideia/sistema ou texto livre.
function resolverContexto(input: { ideiaId?: string; sistemaId?: string; texto?: string }): string {
  const partes: string[] = [];
  if (input.texto) partes.push(input.texto);
  if (input.ideiaId) {
    const ideia = dbGetById('Ideias', input.ideiaId);
    if (ideia) partes.push(`Ideia: ${ideia['titulo']}\nDescrição: ${ideia['descricao']}`);
  }
  if (input.sistemaId) {
    const pass = gerarPassaporte(input.sistemaId);
    if (pass.ok && typeof pass.data === 'string') partes.push(pass.data);
  }
  return partes.join('\n\n');
}

const PERSONAS_PADRAO = ['Product/BA', 'UX', 'UI', 'Arquitetura', 'Engenharia'];

// Conselho de especialistas: cada persona dá um parecer + síntese com recomendação.
function conselhoEspecialistas(input: { ideiaId?: string; sistemaId?: string; texto?: string; personas?: string[]; usarCodex?: boolean }): ServerResult {
  try {
    const contexto = resolverContexto(input);
    if (!contexto.trim()) return { ok: false, error: 'Descreva a ideia ou selecione um contexto.' };
    const personas = (input.personas && input.personas.length) ? input.personas : PERSONAS_PADRAO;

    const codexTxt = input.usarCodex !== false ? _buildCodexContext() : '';
    const system = getPromptEfetivo('conselho').replace(/\{\{personas\}\}/g, personas.join(', ')) + codexTxt;

    const resposta = forjaCallLLM([
      { role: 'system', content: system },
      { role: 'user', content: contexto },
    ], 2500, undefined, 'conselho');
    const json = extrairJson(resposta);

    dbCreate('Conselho', { contexto: contexto.slice(0, 4000), persona: personas.join(','), parecer: JSON.stringify(json), sintese: '', data: new Date().toISOString() });
    return { ok: true, data: json };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro no conselho' };
  }
}

// Gera um Blueprint (Markdown) + prompts prontos para Cursor, Claude e ChatGPT.
//
// GRACEFUL DEGRADATION (v1.4.3): se a IA não retornar JSON válido, NÃO joga
// fora o trabalho — salva o conteúdo bruto com `parseAviso='sim'` pra UI
// indicar. Antes desse fix, qualquer resposta sem JSON era perdida.
function gerarBlueprint(input: { ideiaId?: string; sistemaId?: string; texto?: string; stack?: string; usarCodex?: boolean }): ServerResult {
  try {
    const contexto = resolverContexto(input);
    if (!contexto.trim()) return { ok: false, error: 'Descreva a ideia ou selecione um contexto.' };
    const stackTxt = input.stack ? `\nStack preferida pelo usuário: ${input.stack}.` : '';
    const codexTxt = input.usarCodex !== false ? _buildCodexContext() : '';
    const system = getPromptEfetivo('blueprint').replace(/\{\{stack\}\}/g, stackTxt) + codexTxt;

    // maxTokens 3000 (era 3500) pra caber melhor no timeout de UrlFetchApp.
    // Pode subir de novo se trocar pra modelo rápido (haiku/mini).
    const llm = forjaCallLLMDetalhado([
      { role: 'system', content: system },
      { role: 'user', content: contexto },
    ], 3000, undefined, 'blueprint');

    // Parse com fallback: se falhar, preserva resposta bruta.
    let json: { titulo?: string; conteudoMd?: string; prompts?: unknown } = {};
    let parseAviso = 'nao';
    try {
      json = extrairJson(llm.texto) as { titulo?: string; conteudoMd?: string; prompts?: unknown };
    } catch {
      parseAviso = 'sim';
      json = { titulo: 'Blueprint (sem formatação)', conteudoMd: llm.texto };
    }

    const saved = dbCreate('Blueprints', {
      ideiaId: input.ideiaId || '',
      sistemaId: input.sistemaId || '',
      titulo: json.titulo || 'Blueprint',
      conteudoMd: json.conteudoMd || '',
      promptsJson: JSON.stringify(json.prompts || {}),
      data: new Date().toISOString(),
      origem: 'normal',
      referencia: 'nao',
      modeloUsado: llm.modelo,
      parseAviso,
    });
    return { ok: true, data: { ...json, id: saved['id'], modeloUsado: llm.modelo, parseAviso } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar blueprint' };
  }
}

function getBlueprints(): ServerResult {
  try {
    const all = dbGetAll('Blueprints').map((b) => ({
      ...b,
      prompts: (() => { try { return JSON.parse(String(b['promptsJson'] || '{}')); } catch { return {}; } })(),
    }));
    return { ok: true, data: all.reverse() };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar blueprints' };
  }
}

function deleteBlueprint(id: string): ServerResult {
  try {
    return dbDelete('Blueprints', id) ? { ok: true } : { ok: false, error: 'Blueprint não encontrado' };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao deletar blueprint' };
  }
}

// Gera código Mermaid a partir de uma descrição (estúdio de diagramas híbrido).
// Não persiste — o save é feito separado pelo frontend via `saveDiagrama`.
function gerarDiagrama(input: { texto?: string; ideiaId?: string; sistemaId?: string; tipo?: string; usarCodex?: boolean }): ServerResult {
  try {
    const contexto = resolverContexto({ texto: input.texto, ideiaId: input.ideiaId, sistemaId: input.sistemaId });
    if (!contexto.trim()) return { ok: false, error: 'Descreva o que deseja diagramar.' };
    const tipo = input.tipo || 'flowchart';
    const codexTxt = input.usarCodex !== false ? _buildCodexContext() : '';
    const system = getPromptEfetivo('diagrama').replace(/\{\{tipo\}\}/g, tipo) + codexTxt;

    const llm = forjaCallLLMDetalhado([
      { role: 'system', content: system },
      { role: 'user', content: contexto },
    ], 1500, undefined, 'diagrama');

    // Parse com fallback em camadas:
    //   1) JSON limpo → ideal
    //   2) extrair Mermaid bruto do texto (lida com ```mermaid, JSON quebrado, etc)
    //   3) último recurso: devolve texto cru com aviso
    let titulo = 'Diagrama';
    let mermaid = '';
    let parseAviso: 'nao' | 'sim' | 'recuperado' = 'nao';
    try {
      const json = extrairJson(llm.texto) as { titulo?: string; mermaid?: string };
      titulo = json.titulo || titulo;
      mermaid = String(json.mermaid || '').replace(/^```(?:mermaid)?\s*/i, '').replace(/\s*```$/i, '').trim();
      if (!mermaid || !_pareceMermaid(mermaid)) {
        // JSON parseou mas o conteúdo não é Mermaid — tenta extrair do texto cru
        const recuperado = _extrairMermaidBruto(llm.texto);
        if (recuperado) { mermaid = recuperado; parseAviso = 'recuperado'; }
        else { parseAviso = 'sim'; mermaid = String(json.mermaid || llm.texto); }
      }
    } catch {
      // JSON inválido — tenta extrair Mermaid direto do texto
      const recuperado = _extrairMermaidBruto(llm.texto);
      if (recuperado) { mermaid = recuperado; parseAviso = 'recuperado'; }
      else { parseAviso = 'sim'; titulo = 'Diagrama (sem formatação)'; mermaid = llm.texto; }
    }
    return { ok: true, data: { titulo, mermaid, tipo, modeloUsado: llm.modelo, parseAviso } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar diagrama' };
  }
}

function saveDiagrama(data: Record<string, unknown>): ServerResult {
  try {
    if (data['id']) {
      const upd = dbUpdate('Diagramas', String(data['id']), data);
      return upd ? { ok: true, data: upd } : { ok: false, error: 'Diagrama não encontrado' };
    }
    const saved = dbCreate('Diagramas', {
      sistemaId: data['sistemaId'] || '',
      ideiaId: data['ideiaId'] || '',
      tipo: data['tipo'] || 'flowchart',
      titulo: data['titulo'] || 'Diagrama',
      mermaid: data['mermaid'] || '',
      data: new Date().toISOString(),
      origem: data['origem'] || 'normal',
      referencia: 'nao',
      // Passa modeloUsado se o gerador devolveu (já vem no result do gerarDiagrama)
      modeloUsado: data['modeloUsado'] || '',
      parseAviso: data['parseAviso'] || 'nao',
    });
    return { ok: true, data: saved };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar diagrama' };
  }
}

function getDiagramas(): ServerResult {
  try {
    return { ok: true, data: dbGetAll('Diagramas').reverse() };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar diagramas' };
  }
}

function deleteDiagrama(id: string): ServerResult {
  try {
    return dbDelete('Diagramas', id) ? { ok: true } : { ok: false, error: 'Diagrama não encontrado' };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao deletar diagrama' };
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// FORJA SOBRE FORJA (v1.4.1) — dogfooding com nome bonito
// ═══════════════════════════════════════════════════════════════════════════════
// Permite que o usuário gere blueprints/diagramas usando o PRÓPRIO Forja como
// entrada — assim ele valida o pipeline com algo que conhece de cor antes de
// aplicar a outros sistemas. Reusa Blueprint/Diagrama storage, só adiciona a
// flag `origem='forja-self'` pra discriminar no histórico.

// Snapshot estruturado do app atual. Mantém atualizado quando uma feature nova
// for adicionada (ou refatorar pra ler de package.json + version automatic).
// Cuidadosamente curtido pra caber bem no prompt sem inflar tokens.
function _buildForjaSelfContext(): string {
  const v = '1.4.1';
  return `## SISTEMA: Forja (v${v})

Headquarters pessoal pra gestão de projetos de desenvolvimento assistido por IA.
Filosofia: vibe code minimalista — premium, leve, intuitivo, fácil de usar.

### Módulos
- **Dashboard**: visão consolidada de saúde, custos e alertas dos sistemas
- **Clientes**: CRM leve (pessoas + empresas)
- **Ideias**: captura de oportunidades + roteiros de discovery
- **Sistemas**: catálogo de projetos com auditoria de saúde (Forja IA + estrutural)
- **Operações**: integração GitHub + status monitor multi-app
- **Financeiro**: contas a receber/pagar + módulo pessoal completo (cartões, pix, contas, parcelas automáticas, recorrências, orçamentos por categoria, gestão de categorias)
- **Forja IA**: chat com tools, blueprints, diagramas Mermaid, conselho de especialistas, perguntas de discovery
- **Atelier**: skills, snippets, templates, bookmarks, **Códex** (DNA de dev), hospedagem, cofre criptografado
- **Relatórios**: dashboards mensais + export PDF/JSON

### Stack real
- Frontend: React 18 + TypeScript + Ant Design + lucide-react
- Build: esbuild (chunking obrigatório <=195KB/fatia por limite do GAS)
- Backend: Google Apps Script V8 (zero infra, gratuito)
- Banco: Google Sheets via SheetDB caseiro com schema append-only
- IA: Anthropic Claude via proxy configurável em ScriptProperties
- Deploy: clasp deploy -i <STABLE_ID> pra URL pública preservada

### Integrações
- GitHub API (operações)
- Google Apps Script (importação de scripts existentes do user)
- Anthropic API via proxy customizável (modelo configurável: claude-3.5-sonnet, etc.)

### Pontos fortes
- 100% serverless, gratuito (rodando em GAS sob conta Google)
- Mobile-friendly via web app
- Tema claro/noturno persistente
- Cold start sub-segundo (após primeira)
- Vault zero-knowledge no client (chaves nunca saem do browser)
- Códex injeta padrões pessoais como contexto vivo em qualquer geração de IA

### Limitações conhecidas
- GAS tem timeout de 6min por execução (impede operações longas)
- SheetDB não suporta queries complexas (full scan) — degrada com >5k linhas/sheet
- Sem realtime — UI re-fetch on action
- Sem multi-usuário nativo (cada user tem sua planilha)

### Entidades (Sheets)
Pessoas, Sistemas, Custos, Ideias, Diagramas, Blueprints, Entrevistas, Skills, Snippets, Templates, Bookmarks, Hospedagem, Vault, Decisoes, Riscos, Oportunidades, Apis, AuditFindings, FinPessoal* (5 sheets), Codex* (2 sheets), Config.

### Estágios do ciclo de uma Ideia
Faísca (captura) → Forja (em desenvolvimento) → Têmpera (no ar / produção) → Prateleira (pausado/aposentado)`;
}

// Atalho que gera um blueprint usando Forja como input. Marca origem=forja-self
// pra discriminar no histórico. usarCodex default true.
//
// SEMPRE SALVA (v1.4.3): se a IA não devolver JSON, salva o texto bruto com
// parseAviso='sim'. Antes desse fix, blueprint sem JSON era jogado fora —
// causava o bug "gerei e não tem registro".
function gerarBlueprintDoForja(input?: { usarCodex?: boolean }): ServerResult {
  try {
    const usarCodex = input?.usarCodex !== false;
    const contexto = _buildForjaSelfContext();
    const codexTxt = usarCodex ? _buildCodexContext() : '';
    const system = getPromptEfetivo('blueprint').replace(/\{\{stack\}\}/g, '') + codexTxt;

    // maxTokens 3000 (era 4000): com Sonnet a 50-80 tok/s, 4000 tokens = 60-90s,
    // que estoura o timeout default do UrlFetchApp (~60s). 3000 cabe em ~40-60s.
    const llm = forjaCallLLMDetalhado([
      { role: 'system', content: system },
      { role: 'user', content: contexto + '\n\nGere um BLUEPRINT completo desta aplicação ("Forja"). Estruture como se fosse documentar pra outro dev assumir o projeto. Inclua: arquitetura, decisões-chave, próximos passos sugeridos, e prompts úteis pra evoluir o produto.' },
    ], 3000);

    let json: { titulo?: string; conteudoMd?: string; prompts?: unknown } = {};
    let parseAviso = 'nao';
    try {
      json = extrairJson(llm.texto) as { titulo?: string; conteudoMd?: string; prompts?: unknown };
    } catch {
      parseAviso = 'sim';
      json = { titulo: 'Forja sobre Forja (sem formatação)', conteudoMd: llm.texto };
    }

    const saved = dbCreate('Blueprints', {
      ideiaId: '',
      sistemaId: '',
      titulo: json.titulo || 'Blueprint: Forja sobre Forja',
      conteudoMd: json.conteudoMd || '',
      promptsJson: JSON.stringify(json.prompts || {}),
      data: new Date().toISOString(),
      origem: 'forja-self',
      referencia: 'nao',
      modeloUsado: llm.modelo,
      parseAviso,
    });
    return { ok: true, data: { ...json, id: saved['id'], origem: 'forja-self', modeloUsado: llm.modelo, parseAviso } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar blueprint do Forja' };
  }
}

// Atalho que gera um diagrama usando Forja como input. Por padrão sugere
// flowchart, mas user pode passar outro tipo (sequence/er/class/mindmap).
function gerarDiagramaDoForja(input?: { tipo?: string; usarCodex?: boolean }): ServerResult {
  try {
    const tipo = input?.tipo || 'flowchart';
    const usarCodex = input?.usarCodex !== false;
    const contexto = _buildForjaSelfContext();
    const codexTxt = usarCodex ? _buildCodexContext() : '';
    const system = getPromptEfetivo('diagrama').replace(/\{\{tipo\}\}/g, tipo) + codexTxt;

    // Instrução adicional por tipo pra direcionar melhor a IA
    const instrucao = tipo === 'flowchart'
      ? 'Crie um fluxograma mostrando a jornada principal do usuário no Forja: do cadastro de uma ideia até o sistema em produção monitorado, passando por blueprint, deploy, auditoria e códex.'
      : tipo === 'erDiagram'
      ? 'Crie um diagrama ER mostrando as entidades principais e relacionamentos: Sistema, Cliente, Ideia, Custo, Decisão, Risco, Oportunidade, Diagrama, Blueprint, CodexSecao, CodexCard.'
      : tipo === 'sequenceDiagram'
      ? 'Crie um diagrama de sequência mostrando: User → Frontend → google.script.run → SheetDB → Resposta. Para uma ação típica como salvar um lançamento financeiro pessoal.'
      : tipo === 'classDiagram'
      ? 'Modele as principais entidades do Forja como classes com atributos chave (Sistema, Codex, Lancamento, etc.)'
      : 'Mapa mental dos módulos do Forja: Dashboard, Clientes, Ideias, Sistemas, Operações, Financeiro, Forja IA, Atelier, Relatórios. Para cada módulo, sub-itens das features.';

    const llm = forjaCallLLMDetalhado([
      { role: 'system', content: system },
      { role: 'user', content: contexto + '\n\n' + instrucao },
    ], 2000);

    // Mesmo pipeline em camadas do gerarDiagrama (ver comentário lá)
    let titulo = `Forja sobre Forja — ${tipo}`;
    let mermaid = '';
    let parseAviso: 'nao' | 'sim' | 'recuperado' = 'nao';
    try {
      const json = extrairJson(llm.texto) as { titulo?: string; mermaid?: string };
      if (json.titulo) titulo = json.titulo;
      mermaid = String(json.mermaid || '').replace(/^```(?:mermaid)?\s*/i, '').replace(/\s*```$/i, '').trim();
      if (!mermaid || !_pareceMermaid(mermaid)) {
        const recuperado = _extrairMermaidBruto(llm.texto);
        if (recuperado) { mermaid = recuperado; parseAviso = 'recuperado'; }
        else { parseAviso = 'sim'; mermaid = String(json.mermaid || llm.texto); }
      }
    } catch {
      const recuperado = _extrairMermaidBruto(llm.texto);
      if (recuperado) { mermaid = recuperado; parseAviso = 'recuperado'; }
      else { parseAviso = 'sim'; titulo = `Forja sobre Forja — ${tipo} (sem formatação)`; mermaid = llm.texto; }
    }

    const saved = dbCreate('Diagramas', {
      sistemaId: '',
      ideiaId: '',
      tipo,
      titulo,
      mermaid,
      data: new Date().toISOString(),
      origem: 'forja-self',
      referencia: 'nao',
      modeloUsado: llm.modelo,
      parseAviso,
    });
    return { ok: true, data: { id: saved['id'], titulo: saved['titulo'], mermaid, tipo, origem: 'forja-self', modeloUsado: llm.modelo, parseAviso } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar diagrama do Forja' };
  }
}

// ─── Galeria completa do Forja (multi-gen dogfooding) ───────────────────────
// Gera as 5 visões do Forja em sequência (flowchart, sequence, ER, class,
// mindmap). Pra cada uma:
//   - chama gerarDiagramaDoForja({ tipo, usarCodex: true })
//   - se ok, marca referencia='sim' (vai pro topo da lista como biblioteca)
//   - se falha, segue em frente acumulando o erro — não aborta o lote
//
// Custo: 5 chamadas IA × ~15-30s cada = 75-150s total. Cabe no limite de 6min
// do GAS com folga. Sem paralelização porque (a) UrlFetchApp.fetchAll não
// funciona pra POSTs com bodies diferentes em todas as APIs LLM, e (b) o user
// já espera ~1-2min sem regenerar — paralelizar dispararia rate limit.
//
// Retorno: { gerados: Diagrama[], erros: Array<{tipo, error}> }
//
// O frontend pode usar isso pra:
//   - mostrar progresso (quantos deram certo / quantos faltam)
//   - listar os tipos que falharam pra o user clicar e re-tentar individual
function gerarTodasAsVisoesDoForja(): ServerResult {
  const TIPOS = ['flowchart', 'sequenceDiagram', 'erDiagram', 'classDiagram', 'mindmap'];
  const gerados: Array<Record<string, unknown>> = [];
  const erros: Array<{ tipo: string; error: string }> = [];

  for (const tipo of TIPOS) {
    try {
      const r = gerarDiagramaDoForja({ tipo, usarCodex: true });
      if (r.ok && r.data) {
        const d = r.data as { id: string };
        // Marca como referência (pinned) — toda visão da galeria entra como
        // material de referência. User pode desfixar individualmente depois.
        try { dbUpdate('Diagramas', d.id, { referencia: 'sim' }); } catch { /* não bloqueia */ }
        gerados.push(r.data as Record<string, unknown>);
      } else {
        erros.push({ tipo, error: r.error || 'Erro desconhecido' });
      }
    } catch (e: unknown) {
      erros.push({ tipo, error: e instanceof Error ? e.message : String(e) });
    }
  }

  return {
    ok: gerados.length > 0,
    data: { gerados, erros, total: TIPOS.length },
    error: gerados.length === 0 ? `Nenhuma visão gerada — ${erros.length} falhas` : undefined,
  };
}

// Alterna o flag `referencia` de um item. Pinned items aparecem no topo.
// Suporta as duas tabelas — passa qual no parâmetro.
function alternarReferencia(tipo: 'blueprint' | 'diagrama', id: string): ServerResult {
  try {
    const sheetName = tipo === 'blueprint' ? 'Blueprints' : 'Diagramas';
    const reg = dbGetById(sheetName, id);
    if (!reg) return { ok: false, error: 'Item não encontrado' };
    const novoValor = String(reg['referencia'] || 'nao') === 'sim' ? 'nao' : 'sim';
    const updated = dbUpdate(sheetName, id, { referencia: novoValor });
    return { ok: true, data: { referencia: novoValor, item: updated } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao alternar referência' };
  }
}

// ─── Discovery & Entrevistas (Fase 6) ────────────────────────────────────────

function getEntrevistas(): ServerResult {
  try {
    const pessoas = dbGetAll('Pessoas');
    const nomePorId: Record<string, string> = {};
    pessoas.forEach((p) => { nomePorId[String(p['id'])] = String(p['nome'] || ''); });
    const data = dbGetAll('Entrevistas').map((e) => {
      let analise: unknown = null;
      try { if (e['requisitos']) analise = JSON.parse(String(e['requisitos'])); } catch { analise = null; }
      return { ...e, pessoaNome: nomePorId[String(e['pessoaId'])] || '', analise };
    }).reverse();
    return { ok: true, data };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar entrevistas' };
  }
}

function createEntrevista(data: Record<string, unknown>): ServerResult {
  try {
    const saved = dbCreate('Entrevistas', {
      pessoaId: data['pessoaId'] || '',
      data: data['data'] || new Date().toISOString().slice(0, 10),
      tipo: data['tipo'] || 'Discovery',
      transcricao: data['transcricao'] || '',
      resumoIA: data['resumoIA'] || '',
      requisitos: data['requisitos'] || '',
    });
    return { ok: true, data: saved };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar entrevista' };
  }
}

function updateEntrevista(id: string, data: Record<string, unknown>): ServerResult {
  try {
    const upd = dbUpdate('Entrevistas', id, data);
    return upd ? { ok: true, data: upd } : { ok: false, error: 'Entrevista não encontrada' };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao atualizar entrevista' };
  }
}

function deleteEntrevista(id: string): ServerResult {
  try {
    return dbDelete('Entrevistas', id) ? { ok: true } : { ok: false, error: 'Entrevista não encontrada' };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao deletar entrevista' };
  }
}

function analisarEntrevista(input: { id?: string; transcricao?: string }): ServerResult {
  try {
    let texto = input.transcricao || '';
    if (!texto && input.id) {
      const e = dbGetAll('Entrevistas').find((r) => String(r['id']) === String(input.id));
      if (e) texto = String(e['transcricao'] || '');
    }
    if (!texto.trim()) return { ok: false, error: 'Sem transcrição para analisar.' };

    const resposta = forjaCallLLM([
      { role: 'system', content: getPromptEfetivo('entrevista') },
      { role: 'user', content: texto },
    ], 1500, undefined, 'entrevista');
    const json = extrairJson(resposta) as {
      resumo?: string; dores?: string[]; objetivos?: string[];
      requisitos?: string[]; perguntasAbertas?: string[]; oportunidade?: string;
    };
    const analise = {
      resumo: json.resumo || '',
      dores: json.dores || [],
      objetivos: json.objetivos || [],
      requisitos: json.requisitos || [],
      perguntasAbertas: json.perguntasAbertas || [],
      oportunidade: json.oportunidade || '',
    };

    if (input.id) {
      dbUpdate('Entrevistas', String(input.id), {
        resumoIA: analise.resumo,
        requisitos: JSON.stringify(analise),
      });
    }
    return { ok: true, data: analise };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao analisar entrevista' };
  }
}

function gerarPerguntasDiscovery(input: { segmento?: string; contexto?: string }): ServerResult {
  try {
    const segmento = (input.segmento || '').trim() || 'não informado';
    const system = getPromptEfetivo('perguntas').replace(/\{\{segmento\}\}/g, segmento);
    const userMsg = input.contexto && input.contexto.trim()
      ? input.contexto
      : `Segmento/contexto do cliente: ${segmento}. Gere o roteiro de discovery.`;
    const resposta = forjaCallLLM([
      { role: 'system', content: system },
      { role: 'user', content: userMsg },
    ], 1400, undefined, 'entrevista');
    const json = extrairJson(resposta) as { blocos?: Array<{ tema?: string; perguntas?: string[] }> };
    return { ok: true, data: { blocos: json.blocos || [] } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar perguntas' };
  }
}

function criarIdeiaDeEntrevista(input: { id?: string; titulo?: string }): ServerResult {
  try {
    const e = dbGetAll('Entrevistas').find((r) => String(r['id']) === String(input.id));
    if (!e) return { ok: false, error: 'Entrevista não encontrada' };
    let analise: { resumo?: string; dores?: string[]; objetivos?: string[]; requisitos?: string[] } = {};
    try { if (e['requisitos']) analise = JSON.parse(String(e['requisitos'])); } catch { /* ignora */ }

    const partes: string[] = [];
    if (analise.resumo) partes.push(analise.resumo);
    if (analise.dores && analise.dores.length) partes.push('Dores: ' + analise.dores.join('; '));
    if (analise.objetivos && analise.objetivos.length) partes.push('Objetivos: ' + analise.objetivos.join('; '));
    if (analise.requisitos && analise.requisitos.length) partes.push('Requisitos: ' + analise.requisitos.join('; '));
    const descricao = partes.join('\n\n') || String(e['transcricao'] || '').slice(0, 500);

    const saved = dbCreate('Ideias', {
      titulo: input.titulo || ('Ideia de entrevista ' + (e['data'] || '')),
      descricao,
      notaImpacto: 5,
      notaEsforco: 5,
      estado: 'nova',
    });
    return { ok: true, data: saved };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao criar ideia' };
  }
}

// ─── Discovery: roteiros estruturados + formulário público ─────────────────────
// Leva 1 (este projeto, privado): persiste o roteiro gerado pela IA por cliente,
// publica (gera token) e lê as respostas que o app público (Leva 2) grava na
// mesma planilha. A base da URL pública fica em Script Property DISCOVERY_PUBLIC_URL.

function _parseBlocosDiscovery(raw: unknown): unknown[] {
  try { const v = JSON.parse(String(raw || '[]')); return Array.isArray(v) ? v : []; } catch { return []; }
}

function _discoveryPublicBaseUrl(): string {
  try { return String(PropertiesService.getScriptProperties().getProperty('DISCOVERY_PUBLIC_URL') || '').trim(); }
  catch { return ''; }
}

function _discoveryUrlComToken(token: string): string {
  const base = _discoveryPublicBaseUrl();
  if (!base || !token) return '';
  return base + (base.indexOf('?') >= 0 ? '&' : '?') + 'f=' + encodeURIComponent(token);
}

// Score determinístico de oportunidade (0-100): o quanto a resposta sinaliza que
// vale virar um app. Componentes auditáveis em breakdown. A Leva 2 pode somar IA.
function _scoreOportunidadeDiscovery(input: {
  respostas?: Record<string, unknown>; ferramentas?: unknown[];
  querAmostra?: boolean; agendaPref?: string; nome?: string; email?: string; totalPerguntas?: number;
}): { score: number; breakdown: Record<string, number> } {
  const respostas = input.respostas || {};
  const total = Math.max(1, Number(input.totalPerguntas || Object.keys(respostas).length) || 1);
  const respondidas = Object.keys(respostas).filter((k) => {
    const v = respostas[k];
    return v !== null && v !== undefined && String(v).trim() !== '' && !(Array.isArray(v) && v.length === 0);
  }).length;
  const completude = Math.round((respondidas / total) * 40); // até 40
  const ferramentas = Array.isArray(input.ferramentas) ? input.ferramentas.filter((x) => String(x || '').trim()) : [];
  const ferramentasPts = ferramentas.length ? Math.min(12, 4 + ferramentas.length * 2) : 0; // até 12
  // riqueza de texto livre — sinaliza clareza/engajamento
  let chars = 0;
  Object.keys(respostas).forEach((k) => { const v = respostas[k]; if (typeof v === 'string') chars += v.trim().length; });
  const textoPts = Math.min(18, Math.round(chars / 40)); // até 18
  const amostraPts = input.querAmostra ? 15 : 0;
  const agendaPts = String(input.agendaPref || '').trim() ? 8 : 0;
  const contatoPts = (String(input.nome || '').trim() && String(input.email || '').trim()) ? 7 : 0;
  const breakdown = {
    completude, ferramentas: ferramentasPts, riquezaTexto: textoPts,
    pediuAmostra: amostraPts, agenda: agendaPts, contato: contatoPts,
  };
  let score = completude + ferramentasPts + textoPts + amostraPts + agendaPts + contatoPts;
  if (score > 100) score = 100;
  return { score, breakdown };
}

function salvarRoteiroDiscovery(input: { id?: string; pessoaId?: string; titulo?: string; segmento?: string; blocos?: unknown }): ServerResult {
  try {
    const pessoaId = String(input.pessoaId || '').trim();
    if (!pessoaId) return { ok: false, error: 'Selecione o cliente para salvar o roteiro' };
    const blocos = Array.isArray(input.blocos) ? input.blocos : [];
    if (!blocos.length) return { ok: false, error: 'Roteiro vazio — gere as perguntas primeiro' };
    const perguntasJson = JSON.stringify(blocos);
    const titulo = String(input.titulo || '').trim() || ('Roteiro ' + new Date().toISOString().slice(0, 10));
    const segmento = String(input.segmento || '').trim();
    if (input.id) {
      const upd = dbUpdate('DiscoveryForms', String(input.id), { pessoaId, titulo, segmento, perguntasJson });
      if (!upd) return { ok: false, error: 'Roteiro não encontrado' };
      return { ok: true, data: upd };
    }
    const created = dbCreate('DiscoveryForms', {
      pessoaId, titulo, segmento, perguntasJson,
      token: '', status: 'rascunho', criadoEm: new Date().toISOString(), publicadoEm: '',
    });
    return { ok: true, data: created };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar roteiro' }; }
}

function getDiscoveryForms(): ServerResult {
  try {
    const pessoas = dbGetAll('Pessoas');
    const findPessoa = (id: string) => pessoas.find((p) => String(p['id']) === String(id)) || null;
    const nome = (id: string) => {
      const p = findPessoa(id);
      if (!p) return '';
      return String(p['empresa'] || p['nome'] || '');
    };
    const respostas = dbGetAll('DiscoveryRespostas');
    const rows = dbGetAll('DiscoveryForms').map((r) => {
      const id = String(r['id']);
      const token = String(r['token'] || '');
      const respDoForm = respostas.filter((x) => String(x['formId']) === id).length;
      return {
        id,
        pessoaId: String(r['pessoaId'] || ''),
        pessoaNome: nome(String(r['pessoaId'] || '')),
        titulo: String(r['titulo'] || ''),
        segmento: String(r['segmento'] || ''),
        blocos: _parseBlocosDiscovery(r['perguntasJson']),
        token,
        status: String(r['status'] || 'rascunho'),
        url: _discoveryUrlComToken(token),
        publicoConfigurado: !!_discoveryPublicBaseUrl(),
        respostasCount: respDoForm,
        criadoEm: String(r['criadoEm'] || ''),
        publicadoEm: String(r['publicadoEm'] || ''),
      };
    });
    rows.sort((a, b) => (b.criadoEm || '').localeCompare(a.criadoEm || ''));
    return { ok: true, data: rows };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar roteiros' }; }
}

// Converte perguntas (texto puro) em campos de formulário leves e clicáveis.
// Idempotente: se já estiver estruturado, devolve como está. Falha → mantém texto.
function _estruturarPerguntasDiscovery(blocos: Array<{ tema?: string; perguntas?: unknown[] }>): unknown[] {
  const jaEstrut = blocos.some((b) => Array.isArray(b.perguntas) && b.perguntas.some((p) => p && typeof p === 'object'));
  if (jaEstrut) return blocos;
  try {
    const system = [
      'Você transforma perguntas de discovery num formulário leve e progressivo para um cliente leigo.',
      'Para CADA pergunta escolha o tipo de campo ideal:',
      "'sim_nao' (Sim/Não/Mais ou menos), 'escala' (1 a 5), 'unica' (uma opção), 'multipla' (várias), 'texto' (curto) ou 'texto_longo'.",
      'EQUILÍBRIO: use clicáveis (sim_nao/escala/unica/multipla) para qualificar e dar ritmo leve;',
      "MAS quando a pergunta pede detalhe sobre o SISTEMA/ferramentas/telas/rotina/jornada do cliente, use 'texto_longo' — é onde queremos respostas ricas.",
      "Para perguntas sobre QUAIS ferramentas/sistemas/marcas/produtos a pessoa usa, prefira 'multipla' (ou 'unica' quando só uma resposta faz sentido) com opções plausíveis do segmento.",
      "REGRA IMPORTANTE: sempre que a lista NÃO for exaustiva (sistemas, ferramentas, fornecedores, marcas, métodos, etc.), INCLUA SEMPRE 'Outro' como ÚLTIMA opção — exatamente com essa palavra; o frontend já trata isso como campo aberto pro cliente digitar.",
      "Para 'unica'/'multipla' gere 3 a 6 opções curtas e claras (mais a 'Outro' quando se aplicar).",
      'Marque obrigatorio:true nas perguntas-chave sobre o sistema atual. Reescreva o texto pra ficar amigável e específico, pedindo exemplos quando fizer sentido. Mantenha os mesmos temas.',
      'Responda SOMENTE JSON: {"blocos":[{"tema":"...","perguntas":[{"texto":"...","tipo":"...","opcoes":["..."],"obrigatorio":true}]}]}.',
    ].join(' ');
    const resp = forjaCallLLM([
      { role: 'system', content: system },
      { role: 'user', content: JSON.stringify({ blocos }).slice(0, 6000) },
    ], 1800, undefined, 'entrevista');
    const json = extrairJson(resp) as { blocos?: Array<{ tema?: string; perguntas?: unknown[] }> };
    const out = (json.blocos || []).map((b, bi) => ({
      tema: String(b.tema || `Bloco ${bi + 1}`),
      perguntas: (b.perguntas || []).map((p, pi) => {
        const po = (p && typeof p === 'object') ? p as Record<string, unknown> : { texto: String(p || '') };
        const tipo = String(po['tipo'] || 'texto');
        const opcoes = Array.isArray(po['opcoes']) ? (po['opcoes'] as unknown[]).map((o) => String(o)).filter(Boolean).slice(0, 5) : undefined;
        return { id: `b${bi}q${pi}`, texto: String(po['texto'] || ''), tipo, opcoes, obrigatorio: !!po['obrigatorio'] };
      }).filter((p) => p.texto),
    })).filter((b) => b.perguntas.length);
    return out.length ? out : blocos;
  } catch { return blocos; }
}

function publicarFormDiscovery(input: { id?: string }): ServerResult {
  try {
    const id = String(input.id || '').trim();
    if (!id) return { ok: false, error: 'Roteiro inválido' };
    const row = dbGetAll('DiscoveryForms').find((r) => String(r['id']) === id);
    if (!row) return { ok: false, error: 'Roteiro não encontrado' };
    let token = String(row['token'] || '').trim();
    if (!token) token = Utilities.getUuid().replace(/-/g, '');
    // Estrutura as perguntas (texto → campos clicáveis) na 1ª publicação.
    const blocosAtuais = _parseBlocosDiscovery(row['perguntasJson']) as Array<{ tema?: string; perguntas?: unknown[] }>;
    const estruturado = _estruturarPerguntasDiscovery(blocosAtuais);
    const upd = dbUpdate('DiscoveryForms', id, {
      token, status: 'publicado',
      perguntasJson: JSON.stringify(estruturado),
      publicadoEm: String(row['publicadoEm'] || '') || new Date().toISOString(),
    });
    const url = _discoveryUrlComToken(token);
    return { ok: true, data: { token, url, configurado: !!_discoveryPublicBaseUrl(), form: upd } };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao publicar' }; }
}

function excluirFormDiscovery(id: string): ServerResult {
  try {
    const ok = dbDelete('DiscoveryForms', String(id));
    return ok ? { ok: true, data: true } : { ok: false, error: 'Roteiro não encontrado' };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao excluir' }; }
}

function getDiscoveryPublicUrl(): ServerResult {
  try { return { ok: true, data: { url: _discoveryPublicBaseUrl() } }; }
  catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro' }; }
}

function setDiscoveryPublicUrl(input: { url?: string }): ServerResult {
  try {
    const url = String(input.url || '').trim();
    if (url && !/^https:\/\/script\.google\.com\/.+\/exec(\?.*)?$/.test(url)) {
      return { ok: false, error: 'Cole a URL do app público (deve terminar em /exec).' };
    }
    PropertiesService.getScriptProperties().setProperty('DISCOVERY_PUBLIC_URL', url);
    return { ok: true, data: { url } };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar URL' }; }
}

function getRespostasDiscovery(): ServerResult {
  try {
    const pessoas = dbGetAll('Pessoas');
    const nome = (id: string) => String(pessoas.find((p) => String(p['id']) === String(id))?.['nome'] || '');
    const rows = dbGetAll('DiscoveryRespostas').map((r) => {
      let respostas: Record<string, unknown> = {};
      let ferramentas: unknown[] = [];
      let breakdown: Record<string, number> = {};
      try { respostas = JSON.parse(String(r['respostasJson'] || '{}')) || {}; } catch { /* ignora */ }
      try { ferramentas = JSON.parse(String(r['ferramentasJson'] || '[]')) || []; } catch { /* ignora */ }
      try { breakdown = JSON.parse(String(r['scoreBreakdownJson'] || '{}')) || {}; } catch { /* ignora */ }
      return {
        id: String(r['id']),
        formId: String(r['formId'] || ''),
        pessoaId: String(r['pessoaId'] || ''),
        pessoaNome: nome(String(r['pessoaId'] || '')),
        emailRespondente: String(r['emailRespondente'] || ''),
        nome: String(r['nome'] || ''),
        respostas,
        ferramentas,
        querAmostra: String(r['querAmostra'] || '') === 'true' || r['querAmostra'] === true,
        agendaPref: String(r['agendaPref'] || ''),
        score: Number(r['score'] || 0),
        breakdown,
        criadoEm: String(r['criadoEm'] || ''),
      };
    });
    rows.sort((a, b) => (b.criadoEm || '').localeCompare(a.criadoEm || ''));
    return { ok: true, data: rows };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar respostas' }; }
}

// Transforma uma resposta de discovery numa Ideia no banco (fecha o ciclo:
// oportunidade clara → ideia priorizável). Impacto sugerido a partir do score.
function promoverRespostaDiscoveryParaIdeia(input: { id?: string }): ServerResult {
  try {
    const id = String(input.id || '').trim();
    const r = dbGetAll('DiscoveryRespostas').find((x) => String(x['id']) === id);
    if (!r) return { ok: false, error: 'Resposta não encontrada' };
    const pessoas = dbGetAll('Pessoas');
    const pessoaNome = String(pessoas.find((p) => String(p['id']) === String(r['pessoaId']))?.['nome'] || '');
    let respostas: Record<string, unknown> = {};
    let ferramentas: unknown[] = [];
    try { respostas = JSON.parse(String(r['respostasJson'] || '{}')) || {}; } catch { /* ignora */ }
    try { ferramentas = JSON.parse(String(r['ferramentasJson'] || '[]')) || []; } catch { /* ignora */ }
    const score = Number(r['score'] || 0);
    const nome = String(r['nome'] || '') || pessoaNome || String(r['emailRespondente'] || '');

    const partes: string[] = [];
    partes.push(`Origem: Discovery (formulário público) — score ${score}/100.`);
    if (r['emailRespondente']) partes.push(`Contato: ${nome} <${r['emailRespondente']}>`);
    if (ferramentas.length) partes.push(`Ferramentas que usa hoje: ${ferramentas.join(', ')}`);
    if (String(r['querAmostra']) === 'true' || r['querAmostra'] === true) partes.push(`Pediu amostra${r['agendaPref'] ? ` — agenda: ${r['agendaPref']}` : ''}.`);
    const respLinhas = Object.keys(respostas).map((k) => {
      const v = respostas[k];
      return `- ${Array.isArray(v) ? v.join(', ') : String(v)}`;
    }).filter((l) => l !== '- ');
    if (respLinhas.length) partes.push('Respostas:\n' + respLinhas.join('\n'));

    const saved = dbCreate('Ideias', {
      titulo: `Discovery — ${nome || 'oportunidade'}`,
      descricao: partes.join('\n\n'),
      notaImpacto: Math.max(1, Math.min(10, Math.round(score / 10))),
      notaEsforco: 5,
      estado: 'nova',
      tipo: 'novo',
      criadoEm: new Date().toISOString(),
      atualizadoEm: new Date().toISOString(),
    });
    return { ok: true, data: saved };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao promover' }; }
}

// ─── Automações & Alertas (Fase 10) ───────────────────────────────────────────

const AUTOM_KEY = 'FORJA_AUTOMATIONS_CONFIG';

interface WhatsappConfigInternal {
  provider: 'meta' | 'twilio';
  destinos: string[];
  metaToken: string;
  metaPhoneNumberId: string;
  metaTemplate: string;
  metaTemplateLang: string;
  twilioSid: string;
  twilioToken: string;
  twilioFrom: string;
}

interface AutomationConfigInternal {
  ativo: boolean;
  intervaloMin: number;
  canais: { email: boolean; webhook: boolean; whatsapp: boolean };
  webhookUrl: string;
  whatsapp: WhatsappConfigInternal;
  regras: {
    appOffline: { ativo: boolean };
    apiOffline: { ativo: boolean };
    contaVence: { ativo: boolean; diasAntes: number };
    saudeBaixa: { ativo: boolean; minimo: number };
    custoSubiu: { ativo: boolean; pctLimite: number };
    mrrCaiu: { ativo: boolean; pctLimite: number };
    // Auditoria agendada: roda a Forja AI em sistemas "envelhecidos" de tempos em
    // tempos, sem precisar do usuário clicar. Processa NO MÁXIMO maxPorCiclo
    // sistemas por execução pra não estourar o timeout de 6min do GAS.
    auditoriaAgendada: {
      ativo: boolean;
      frequenciaDias: number;  // re-auditar sistemas que tenham mais de N dias sem auditoria
      maxPorCiclo: number;     // máximo de sistemas auditados por execução (default 2)
      alertarSeAlta: boolean;  // criar alerta se achar finding de severidade alta
      pularAposentados: boolean;
    };
  };
  ultimaExec?: string;
}

const WHATSAPP_DEFAULT: WhatsappConfigInternal = {
  provider: 'meta',
  destinos: [],
  metaToken: '',
  metaPhoneNumberId: '',
  metaTemplate: '',
  metaTemplateLang: 'pt_BR',
  twilioSid: '',
  twilioToken: '',
  twilioFrom: '',
};

const AUTOM_DEFAULT: AutomationConfigInternal = {
  ativo: false,
  intervaloMin: 30,
  canais: { email: true, webhook: false, whatsapp: false },
  webhookUrl: '',
  whatsapp: WHATSAPP_DEFAULT,
  regras: {
    appOffline: { ativo: true },
    apiOffline: { ativo: true },
    contaVence: { ativo: true, diasAntes: 7 },
    saudeBaixa: { ativo: true, minimo: 50 },
    custoSubiu: { ativo: false, pctLimite: 20 },
    mrrCaiu: { ativo: false, pctLimite: 15 },
    auditoriaAgendada: {
      ativo: false,
      frequenciaDias: 7,
      maxPorCiclo: 2,
      alertarSeAlta: true,
      pularAposentados: true,
    },
  },
};

function getAutomationConfig(): AutomationConfigInternal {
  try {
    const raw = PropertiesService.getScriptProperties().getProperty(AUTOM_KEY);
    if (!raw) return AUTOM_DEFAULT;
    const parsed = JSON.parse(raw) as Partial<AutomationConfigInternal>;
    return {
      ...AUTOM_DEFAULT,
      ...parsed,
      canais: { ...AUTOM_DEFAULT.canais, ...(parsed.canais || {}) },
      whatsapp: { ...WHATSAPP_DEFAULT, ...(parsed.whatsapp || {}) },
      regras: {
        ...AUTOM_DEFAULT.regras,
        ...(parsed.regras || {}),
      },
    };
  } catch { return AUTOM_DEFAULT; }
}

function setAutomationConfig(cfg: AutomationConfigInternal): void {
  PropertiesService.getScriptProperties().setProperty(AUTOM_KEY, JSON.stringify(cfg));
}

function getAutomationsSettings(): ServerResult {
  const cfg = getAutomationConfig();
  // Nunca devolve os tokens pro client — só flags indicando que estão salvos.
  const safe = {
    ...cfg,
    whatsapp: {
      ...cfg.whatsapp,
      metaToken: '',
      twilioToken: '',
      metaTokenSet: !!cfg.whatsapp.metaToken,
      twilioTokenSet: !!cfg.whatsapp.twilioToken,
    },
  };
  return { ok: true, data: safe };
}

function saveAutomationsSettings(cfg: Partial<AutomationConfigInternal>): ServerResult {
  try {
    const atual = getAutomationConfig();
    // WhatsApp: campos de segredo (tokens) só são sobrescritos quando vierem
    // preenchidos — string vazia mantém o que já está salvo (padrão "preencha
    // só pra substituir"). O resto sobrescreve normalmente.
    const waIn = (cfg.whatsapp || {}) as Partial<WhatsappConfigInternal>;
    const whatsapp: WhatsappConfigInternal = {
      ...atual.whatsapp,
      ...waIn,
      metaToken: (waIn.metaToken && String(waIn.metaToken).trim()) ? String(waIn.metaToken).trim() : atual.whatsapp.metaToken,
      twilioToken: (waIn.twilioToken && String(waIn.twilioToken).trim()) ? String(waIn.twilioToken).trim() : atual.whatsapp.twilioToken,
      destinos: Array.isArray(waIn.destinos) ? waIn.destinos.map((d) => String(d).trim()).filter(Boolean) : atual.whatsapp.destinos,
    };
    const novo: AutomationConfigInternal = {
      ...atual,
      ...cfg,
      canais: { ...atual.canais, ...(cfg.canais || {}) },
      whatsapp,
      regras: { ...atual.regras, ...(cfg.regras || {}) },
    };
    setAutomationConfig(novo);
    return getAutomationsSettings();
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar' };
  }
}

function ativarAutomacoes(intervaloMin: number): ServerResult {
  try {
    const intervalo = [10, 15, 30, 60].indexOf(Number(intervaloMin)) >= 0 ? Number(intervaloMin) : 30;
    ScriptApp.getProjectTriggers().forEach((tr) => { if (tr.getHandlerFunction() === 'runAutomacoes') ScriptApp.deleteTrigger(tr); });
    ScriptApp.newTrigger('runAutomacoes').timeBased().everyMinutes(intervalo).create();
    const cfg = getAutomationConfig();
    cfg.ativo = true;
    cfg.intervaloMin = intervalo;
    setAutomationConfig(cfg);
    return { ok: true, data: cfg };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao ativar automações' };
  }
}

function desativarAutomacoes(): ServerResult {
  try {
    ScriptApp.getProjectTriggers().forEach((tr) => { if (tr.getHandlerFunction() === 'runAutomacoes') ScriptApp.deleteTrigger(tr); });
    const cfg = getAutomationConfig();
    cfg.ativo = false;
    setAutomationConfig(cfg);
    return { ok: true, data: cfg };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao desativar automações' };
  }
}

interface AlertaInternal {
  id: string;
  tipo: string;
  severidade: 'info' | 'aviso' | 'critico';
  titulo: string;
  mensagem: string;
  sistemaId: string;
  criadoEm: string;
  lidoEm: string;
  dedupeKey: string;
  link: string;
}

function getAlertasRecentes(limit: number = 50): AlertaInternal[] {
  const todos = (dbGetAll('Alertas') as unknown as AlertaInternal[]).slice();
  todos.sort((a, b) => (b.criadoEm || '').localeCompare(a.criadoEm || ''));
  return todos.slice(0, limit);
}

function alertaJaExisteRecente(dedupeKey: string, janelaHoras: number): boolean {
  if (!dedupeKey) return false;
  const limite = Date.now() - janelaHoras * 3600 * 1000;
  const alertas = dbGetAll('Alertas') as Array<Record<string, unknown>>;
  for (const a of alertas) {
    if (String(a.dedupeKey || '') !== dedupeKey) continue;
    const criado = new Date(String(a.criadoEm || '')).getTime();
    if (!Number.isNaN(criado) && criado >= limite) return true;
  }
  return false;
}

function criarAlerta(input: { tipo: string; severidade: 'info' | 'aviso' | 'critico'; titulo: string; mensagem: string; sistemaId?: string; dedupeKey: string; link?: string; janelaDedupeHoras?: number }): AlertaInternal | null {
  const janela = input.janelaDedupeHoras ?? 24;
  if (alertaJaExisteRecente(input.dedupeKey, janela)) return null;
  const novo = dbCreate('Alertas', {
    tipo: input.tipo,
    severidade: input.severidade,
    titulo: input.titulo,
    mensagem: input.mensagem,
    sistemaId: input.sistemaId || '',
    criadoEm: new Date().toISOString(),
    lidoEm: '',
    dedupeKey: input.dedupeKey,
    link: input.link || '',
  }) as unknown as AlertaInternal;
  return novo;
}

// Normaliza um telefone pra E.164 só-dígitos (com código de país). Remove
// espaços, traços, parênteses e o '+'. Ex.: "+55 (71) 99999-9999" → "5571999999999".
function _normalizarTelefone(s: string): string {
  return String(s || '').replace(/\D/g, '');
}

// Envia uma mensagem WhatsApp via Meta Cloud API. Retorna code/body pra quem
// quiser inspecionar (teste). Em alertas, o erro é ignorado pra não derrubar
// os outros canais.
function _enviarWhatsappMeta(w: WhatsappConfigInternal, toDigits: string, titulo: string, mensagem: string, texto: string): { code: number; body: string } {
  const versao = 'v21.0';
  const url = `https://graph.facebook.com/${versao}/${encodeURIComponent(w.metaPhoneNumberId)}/messages`;
  let payload: Record<string, unknown>;
  if (w.metaTemplate) {
    // Mensagem proativa precisa de template aprovado. Manda título e mensagem
    // como os 2 primeiros parâmetros do corpo do template.
    payload = {
      messaging_product: 'whatsapp',
      to: toDigits,
      type: 'template',
      template: {
        name: w.metaTemplate,
        language: { code: w.metaTemplateLang || 'pt_BR' },
        components: [{ type: 'body', parameters: [{ type: 'text', text: titulo }, { type: 'text', text: mensagem }] }],
      },
    };
  } else {
    // Sem template: texto livre (funciona com número de teste e dentro da
    // janela de 24h após o destinatário ter falado com você).
    payload = { messaging_product: 'whatsapp', to: toDigits, type: 'text', text: { body: texto } };
  }
  const resp = UrlFetchApp.fetch(url, {
    method: 'post',
    contentType: 'application/json',
    headers: { Authorization: 'Bearer ' + w.metaToken },
    payload: JSON.stringify(payload),
    muteHttpExceptions: true,
  });
  return { code: resp.getResponseCode(), body: resp.getContentText() };
}

// Envia via Twilio WhatsApp (Sandbox ou número aprovado).
function _enviarWhatsappTwilio(w: WhatsappConfigInternal, toDigits: string, texto: string): { code: number; body: string } {
  const url = `https://api.twilio.com/2010-04-01/Accounts/${encodeURIComponent(w.twilioSid)}/Messages.json`;
  const from = w.twilioFrom.indexOf('whatsapp:') === 0 ? w.twilioFrom : 'whatsapp:+' + _normalizarTelefone(w.twilioFrom);
  const to = 'whatsapp:+' + toDigits;
  const auth = Utilities.base64Encode(w.twilioSid + ':' + w.twilioToken);
  const resp = UrlFetchApp.fetch(url, {
    method: 'post',
    headers: { Authorization: 'Basic ' + auth },
    payload: { From: from, To: to, Body: texto },
    muteHttpExceptions: true,
  });
  return { code: resp.getResponseCode(), body: resp.getContentText() };
}

// Dispara um alerta por WhatsApp pra todos os destinos configurados. Tolerante
// a falha por destino (um número inválido não impede os outros).
function _enviarWhatsapp(cfg: AutomationConfigInternal, titulo: string, mensagem: string): void {
  const w = cfg.whatsapp;
  if (!w || !Array.isArray(w.destinos) || w.destinos.length === 0) return;
  const texto = `*${titulo}*\n${mensagem}\n\n— FORJA`;
  for (const numRaw of w.destinos) {
    const num = _normalizarTelefone(numRaw);
    if (!num) continue;
    try {
      if (w.provider === 'twilio') _enviarWhatsappTwilio(w, num, texto);
      else _enviarWhatsappMeta(w, num, titulo, mensagem, texto);
    } catch { /* esse destino falhou; segue os outros */ }
  }
}

function despacharAlertaCanais(alerta: AlertaInternal, cfg: AutomationConfigInternal): void {
  const sev = alerta.severidade === 'critico' ? '🔴' : alerta.severidade === 'aviso' ? '🟡' : '🔵';
  const linha = `${sev} ${alerta.titulo}`;
  const corpo = `${linha}\n\n${alerta.mensagem}${alerta.link ? '\n\n' + alerta.link : ''}\n\n— FORJA, automaticamente.`;
  if (cfg.canais.email) {
    try {
      const email = Session.getActiveUser().getEmail();
      if (email) MailApp.sendEmail(email, `[FORJA] ${alerta.titulo}`, corpo);
    } catch { /* sem permissão */ }
  }
  if (cfg.canais.webhook && cfg.webhookUrl) {
    try {
      // Formato compatível Slack/Discord (campo "text"/"content")
      const payload = { text: linha + '\n' + alerta.mensagem, content: linha + '\n' + alerta.mensagem, username: 'FORJA' };
      UrlFetchApp.fetch(cfg.webhookUrl, {
        method: 'post',
        contentType: 'application/json',
        payload: JSON.stringify(payload),
        muteHttpExceptions: true,
      });
    } catch { /* webhook fora do ar */ }
  }
  if (cfg.canais.whatsapp) {
    try { _enviarWhatsapp(cfg, alerta.titulo, alerta.mensagem); } catch { /* whatsapp falhou */ }
  }
}

function runAutomacoes(): void {
  initDatabase();
  const cfg = getAutomationConfig();
  const hojeISO = new Date().toISOString().split('T')[0];
  const novosAlertas: AlertaInternal[] = [];

  const tryEmit = (input: Parameters<typeof criarAlerta>[0]) => {
    const a = criarAlerta(input);
    if (a) { novosAlertas.push(a); despacharAlertaCanais(a, cfg); }
  };

  // Regra 1 + 2: app/api offline (reusa o monitor existente, mas com dedup)
  const sistemas = dbGetAll('Sistemas');
  const apis = dbGetAll('Apis');
  const snapshot: Array<{ tipo: string; nome: string; conectado: boolean; status: number }> = [];

  if (cfg.regras.appOffline.ativo) {
    for (const s of sistemas) {
      const url = String(s['urlProd'] || '');
      if (!url) continue;
      const p = pingUrl(url);
      const ok = isConectado(p.status);
      snapshot.push({ tipo: 'app', nome: String(s['nome']), conectado: ok, status: p.status });
      if (!ok) {
        tryEmit({
          tipo: 'app_offline', severidade: 'critico',
          titulo: `App fora do ar: ${s['nome']}`,
          mensagem: `${url} respondeu ${p.status || 'sem resposta'}.`,
          sistemaId: String(s['id']),
          dedupeKey: `app_offline:${s['id']}`,
          link: url,
        });
      }
    }
  }
  if (cfg.regras.apiOffline.ativo) {
    for (const a of apis) {
      const url = String(a['healthUrl'] || a['baseUrl'] || '');
      if (!url) continue;
      const p = pingUrl(url);
      dbUpdate('Apis', String(a['id']), { ultimoStatus: p.status, latenciaMs: p.latenciaMs });
      const ok = isConectado(p.status);
      snapshot.push({ tipo: 'api', nome: String(a['nome']), conectado: ok, status: p.status });
      if (!ok) {
        tryEmit({
          tipo: 'api_offline', severidade: 'aviso',
          titulo: `API fora do ar: ${a['nome']}`,
          mensagem: `${url} respondeu ${p.status || 'sem resposta'}.`,
          sistemaId: String(a['sistemaId'] || ''),
          dedupeKey: `api_offline:${a['id']}`,
          link: url,
        });
      }
    }
  }

  // Regra 3: contas vencendo nos próximos N dias
  if (cfg.regras.contaVence.ativo) {
    const dias = Math.max(1, Math.min(60, cfg.regras.contaVence.diasAntes || 7));
    const limite = new Date(Date.now() + dias * 86400000);
    const custos = dbGetAll('Custos');
    for (const c of custos) {
      const prox = String(c['proximaCobranca'] || '');
      if (!prox) continue;
      const dataCob = new Date(prox);
      if (Number.isNaN(dataCob.getTime())) continue;
      if (dataCob >= new Date() && dataCob <= limite) {
        const valor = Number(c['valor'] || 0);
        tryEmit({
          tipo: 'conta_vence', severidade: 'aviso',
          titulo: `Conta a vencer: ${c['fornecedor']}`,
          mensagem: `R$ ${valor.toFixed(2)} vence em ${prox} (${c['recorrencia'] || 'única'}).`,
          sistemaId: String(c['sistemaId'] || ''),
          dedupeKey: `conta_vence:${c['id']}:${prox}`,
          janelaDedupeHoras: 24 * 7,
        });
      }
    }
  }

  // Regra 4: saúde baixa
  if (cfg.regras.saudeBaixa.ativo) {
    const minimo = Math.max(0, Math.min(100, cfg.regras.saudeBaixa.minimo || 50));
    for (const s of sistemas) {
      const score = Number(s['scoreSaude'] || 0);
      if (score > 0 && score < minimo) {
        tryEmit({
          tipo: 'saude_baixa', severidade: 'aviso',
          titulo: `Saúde baixa: ${s['nome']}`,
          mensagem: `Score atual: ${score} (limite ${minimo}).`,
          sistemaId: String(s['id']),
          dedupeKey: `saude_baixa:${s['id']}`,
          janelaDedupeHoras: 24 * 3,
        });
      }
    }
  }

  // Regra 5/6: variações MRR/custo (comparando snapshot do mês passado em Properties)
  try {
    const dash = getDashboardData();
    if (dash.ok && dash.data) {
      const d = dash.data as { kpis: { mrr: number; custoMensal: number }; mrrSeries?: Array<{ valor: number }> };
      const props = PropertiesService.getScriptProperties();
      const snapMes = String(new Date().getMonth());
      const snapAtual = JSON.stringify({ mes: snapMes, mrr: d.kpis.mrr, custo: d.kpis.custoMensal });
      const snapAnterior = props.getProperty('FORJA_AUTOM_KPI_SNAPSHOT') || '';
      if (snapAnterior && snapAnterior !== snapAtual) {
        try {
          const sa = JSON.parse(snapAnterior) as { mes: string; mrr: number; custo: number };
          if (sa.mes !== snapMes) {
            if (cfg.regras.mrrCaiu.ativo && sa.mrr > 0) {
              const pct = Math.round(((d.kpis.mrr - sa.mrr) / sa.mrr) * 100);
              if (pct < 0 && Math.abs(pct) >= cfg.regras.mrrCaiu.pctLimite) {
                tryEmit({
                  tipo: 'mrr_caiu', severidade: 'aviso',
                  titulo: `MRR caiu ${pct}% no mês`,
                  mensagem: `MRR anterior: R$ ${sa.mrr.toFixed(2)} → atual: R$ ${d.kpis.mrr.toFixed(2)}.`,
                  dedupeKey: `mrr_caiu:${snapMes}`,
                  janelaDedupeHoras: 24 * 30,
                });
              }
            }
            if (cfg.regras.custoSubiu.ativo && sa.custo > 0) {
              const pct = Math.round(((d.kpis.custoMensal - sa.custo) / sa.custo) * 100);
              if (pct > 0 && pct >= cfg.regras.custoSubiu.pctLimite) {
                tryEmit({
                  tipo: 'custo_subiu', severidade: 'info',
                  titulo: `Custos subiram ${pct}% no mês`,
                  mensagem: `Custos anteriores: R$ ${sa.custo.toFixed(2)} → atual: R$ ${d.kpis.custoMensal.toFixed(2)}.`,
                  dedupeKey: `custo_subiu:${snapMes}`,
                  janelaDedupeHoras: 24 * 30,
                });
              }
            }
          }
        } catch { /* snapshot malformado */ }
      }
      props.setProperty('FORJA_AUTOM_KPI_SNAPSHOT', snapAtual);
    }
  } catch { /* não derruba o engine por causa de KPI */ }

  // Snapshot operacional p/ a tela de Operações
  const propsOps = PropertiesService.getScriptProperties();
  propsOps.setProperty('FORJA_MONITOR_RUN', new Date().toISOString());
  propsOps.setProperty('FORJA_MONITOR_SNAPSHOT', JSON.stringify(snapshot));

  // Regra 7: auditoria agendada (Forja AI em background)
  // Rate-limit: ciclo dura no máximo 1x por dia. Cada ciclo processa até
  // maxPorCiclo sistemas. Ao longo da semana/mês, todos vão sendo auditados.
  if (cfg.regras.auditoriaAgendada?.ativo) {
    try {
      const auditRes = _executarAuditoriaAgendada(cfg, sistemas, tryEmit);
      if (auditRes.processados > 0) {
        Logger.log(`runAutomacoes: auditoria agendada processou ${auditRes.processados} sistema(s).`);
      }
    } catch (e) {
      Logger.log('runAutomacoes: erro na auditoria agendada → ' + (e instanceof Error ? e.message : e));
    }
  }

  cfg.ultimaExec = new Date().toISOString();
  setAutomationConfig(cfg);

  // Limpa alertas com mais de 60 dias pra não inchar a planilha
  try {
    const limite = Date.now() - 60 * 86400000;
    const todos = dbGetAll('Alertas') as Array<Record<string, unknown>>;
    for (const a of todos) {
      const criado = new Date(String(a.criadoEm || '')).getTime();
      if (!Number.isNaN(criado) && criado < limite) dbDelete('Alertas', String(a.id));
    }
  } catch { /* ignora limpeza */ }

  // Logging mínimo do trigger
  if (novosAlertas.length === 0) {
    Logger.log('runAutomacoes: nenhum novo alerta (' + hojeISO + ')');
  } else {
    Logger.log('runAutomacoes: ' + novosAlertas.length + ' novo(s) alerta(s) em ' + hojeISO);
  }
}

// ─── Auditoria agendada (background) ─────────────────────────────────────────
// Processa até `maxPorCiclo` sistemas por execução, escolhendo os mais "envelhecidos"
// (nunca auditados ou auditados há mais que frequenciaDias). Cria alertas se
// encontrar findings de severidade alta. Sem essa rate-limit, atropelaria o
// timeout de 6min do GAS.
function _executarAuditoriaAgendada(
  cfg: AutomationConfigInternal,
  sistemas: Array<Record<string, unknown>>,
  tryEmit: (input: Parameters<typeof criarAlerta>[0]) => void,
): { processados: number; ignorados: number; criticosNovos: number } {
  const regra = cfg.regras.auditoriaAgendada;
  const props = PropertiesService.getScriptProperties();
  const PROP_ULTIMO_CICLO = 'FORJA_AUDIT_AGENDADA_LAST_CYCLE';

  // Rate-limit: 1 ciclo por dia no máximo
  const ultimoCicloRaw = props.getProperty(PROP_ULTIMO_CICLO);
  if (ultimoCicloRaw) {
    const horasDesde = (Date.now() - new Date(ultimoCicloRaw).getTime()) / 3600000;
    if (horasDesde < 24) return { processados: 0, ignorados: sistemas.length, criticosNovos: 0 };
  }

  const auditorias = dbGetAll('Auditorias') as Array<Record<string, unknown>>;
  // Mapa sistemaId → ISO da última auditoria
  const ultimaPorSistema: Record<string, string> = {};
  for (const a of auditorias) {
    const sid = String(a.sistemaId || '');
    const dt = String(a.criadoEm || '');
    if (!ultimaPorSistema[sid] || dt > ultimaPorSistema[sid]) ultimaPorSistema[sid] = dt;
  }

  const limiteStale = Date.now() - (regra.frequenciaDias || 7) * 86400000;
  const candidatos: Array<Record<string, unknown>> = [];

  for (const s of sistemas) {
    const _est = String(s.estagio || '').toLowerCase();
    if (regra.pularAposentados && (_est === 'prateleira' || _est === 'aposentado')) continue;
    const sid = String(s.id || '');
    const ultISO = ultimaPorSistema[sid];
    if (!ultISO) {
      // Nunca auditado → prioridade máxima
      candidatos.unshift(s);
    } else if (new Date(ultISO).getTime() < limiteStale) {
      candidatos.push(s);
    }
  }

  if (candidatos.length === 0) {
    // Atualiza ciclo mesmo assim pra evitar checar de novo no mesmo dia
    props.setProperty(PROP_ULTIMO_CICLO, new Date().toISOString());
    return { processados: 0, ignorados: sistemas.length, criticosNovos: 0 };
  }

  const maxPorCiclo = Math.max(1, Math.min(5, regra.maxPorCiclo || 2));
  const lote = candidatos.slice(0, maxPorCiclo);
  let criticosNovos = 0;

  for (const s of lote) {
    const sid = String(s.id || '');
    try {
      // Auditoria agendada roda em modo governança (barata) — auditoria de
      // código fica sob demanda no drawer pra não estourar custo em background.
      const r = acaoIAAuditarSistema(sid, 'governanca');
      if (r.ok && r.data) {
        const d = r.data as { payload?: { findings?: Array<{ severidade?: string }> } };
        const findings = d.payload?.findings || [];
        const altos = findings.filter((f) => String(f.severidade || '').toLowerCase() === 'alta').length;
        criticosNovos += altos;

        if (regra.alertarSeAlta && altos > 0) {
          const hoje = new Date().toISOString().split('T')[0];
          tryEmit({
            tipo: 'auditoria_findings_alta',
            severidade: 'aviso',
            titulo: `Auditoria IA: ${altos} finding${altos > 1 ? 's' : ''} de severidade alta em "${s.nome}"`,
            mensagem: `A Forja AI re-auditou e encontrou ${altos} ponto${altos > 1 ? 's' : ''} de atenção. Veja em Sistemas → ${s.nome} → Forja AI.`,
            sistemaId: sid,
            dedupeKey: `auditoria_agendada:${sid}:${hoje}`,
            janelaDedupeHoras: 24 * 3,
          });
        }
      }
    } catch (e) {
      Logger.log(`auditoria agendada: falha em "${s.nome}" → ${e instanceof Error ? e.message : e}`);
    }
  }

  props.setProperty(PROP_ULTIMO_CICLO, new Date().toISOString());
  return { processados: lote.length, ignorados: candidatos.length - lote.length, criticosNovos };
}

// Permite ao usuário disparar o ciclo manualmente sem esperar o cron (e ignorando
// o rate-limit diário, pra teste).
function rodarAuditoriaAgendadaAgora(): ServerResult {
  try {
    initDatabase();
    const cfg = getAutomationConfig();
    if (!cfg.regras.auditoriaAgendada?.ativo) {
      return { ok: false, error: 'Auditoria agendada não está ativa. Ative em Configurações > Automações.' };
    }
    // Limpa rate-limit pra rodar agora
    PropertiesService.getScriptProperties().deleteProperty('FORJA_AUDIT_AGENDADA_LAST_CYCLE');

    const sistemas = dbGetAll('Sistemas') as Array<Record<string, unknown>>;
    const novosAlertas: AlertaInternal[] = [];
    const tryEmit = (input: Parameters<typeof criarAlerta>[0]) => {
      const a = criarAlerta(input);
      if (a) { novosAlertas.push(a); despacharAlertaCanais(a, cfg); }
    };
    const res = _executarAuditoriaAgendada(cfg, sistemas, tryEmit);
    return {
      ok: true,
      data: {
        ...res,
        novosAlertas: novosAlertas.length,
        totalSistemas: sistemas.length,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Retorna estatísticas do estado da auditoria agendada pra UI mostrar progresso.
function getAuditoriaAgendadaStatus(): ServerResult {
  try {
    const cfg = getAutomationConfig();
    const regra = cfg.regras.auditoriaAgendada;
    const props = PropertiesService.getScriptProperties();
    const ultimoCiclo = props.getProperty('FORJA_AUDIT_AGENDADA_LAST_CYCLE') || '';

    const sistemas = dbGetAll('Sistemas') as Array<Record<string, unknown>>;
    const auditorias = dbGetAll('Auditorias') as Array<Record<string, unknown>>;

    const ultimaPorSistema: Record<string, string> = {};
    for (const a of auditorias) {
      const sid = String(a.sistemaId || '');
      const dt = String(a.criadoEm || '');
      if (!ultimaPorSistema[sid] || dt > ultimaPorSistema[sid]) ultimaPorSistema[sid] = dt;
    }

    const limiteStale = Date.now() - ((regra?.frequenciaDias || 7) * 86400000);
    let nuncaAuditados = 0;
    let staleCount = 0;
    let recentes = 0;
    let aposentadosPulados = 0;

    for (const s of sistemas) {
      const _est = String(s.estagio || '').toLowerCase();
      if (regra?.pularAposentados && (_est === 'prateleira' || _est === 'aposentado')) {
        aposentadosPulados++;
        continue;
      }
      const sid = String(s.id || '');
      const ultISO = ultimaPorSistema[sid];
      if (!ultISO) nuncaAuditados++;
      else if (new Date(ultISO).getTime() < limiteStale) staleCount++;
      else recentes++;
    }

    return {
      ok: true,
      data: {
        ativo: !!regra?.ativo,
        frequenciaDias: regra?.frequenciaDias || 7,
        maxPorCiclo: regra?.maxPorCiclo || 2,
        ultimoCiclo,
        proximoCicloEm: ultimoCiclo ? new Date(new Date(ultimoCiclo).getTime() + 86400000).toISOString() : '',
        sistemas: {
          total: sistemas.length,
          nuncaAuditados,
          stale: staleCount,
          recentes,
          aposentadosPulados,
        },
        elegiveis: nuncaAuditados + staleCount,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

function rodarAutomacoesAgora(): ServerResult {
  try {
    const antes = (dbGetAll('Alertas') as Array<Record<string, unknown>>).length;
    runAutomacoes();
    const depois = (dbGetAll('Alertas') as Array<Record<string, unknown>>).length;
    const cfg = getAutomationConfig();
    const sistemas = dbGetAll('Sistemas');
    const apis = dbGetAll('Apis');
    const custos = dbGetAll('Custos');
    const comUrl = sistemas.filter((s) => !!s['urlProd']).length;
    const comProx = custos.filter((c) => !!c['proximaCobranca']).length;
    const regrasAtivas = Object.entries(cfg.regras).filter(([, v]) => v.ativo).length;
    return {
      ok: true,
      data: {
        criados: depois - antes,
        regrasAtivas,
        avaliados: {
          sistemasComUrl: comUrl,
          totalSistemas: sistemas.length,
          apis: apis.length,
          custosComProximaCobranca: comProx,
        },
      },
    };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro ao rodar' }; }
}

function gerarAlertaTeste(): ServerResult {
  try {
    const cfg = getAutomationConfig();
    const a = dbCreate('Alertas', {
      tipo: 'teste',
      severidade: 'info',
      titulo: 'Alerta de teste',
      mensagem: 'Tudo certo: seus canais e o engine de automações estão funcionando. Você pode descartar este alerta.',
      sistemaId: '',
      criadoEm: new Date().toISOString(),
      lidoEm: '',
      dedupeKey: 'teste:' + Date.now(),
      link: '',
    }) as unknown as AlertaInternal;
    despacharAlertaCanais(a, cfg);
    return { ok: true, data: a };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro' }; }
}

function gasGetEditorUrl(): ServerResult {
  try {
    return { ok: true, data: `https://script.google.com/home/projects/${ScriptApp.getScriptId()}/edit` };
  } catch (e: unknown) { return { ok: false, error: e instanceof Error ? e.message : 'Erro' }; }
}

// ─── Relatórios e exportação (Fase 13) ───────────────────────────────────────

function _monthBounds(mes: number, ano: number): { inicio: Date; fim: Date } {
  const inicio = new Date(ano, mes - 1, 1, 0, 0, 0);
  const fim = new Date(ano, mes, 0, 23, 59, 59);
  return { inicio, fim };
}

function _mesNome(mes: number): string {
  return ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'][Math.max(0, Math.min(11, mes - 1))];
}

// Retorna um objeto estruturado pronto pra renderizar no front (sem HTML).
// O front transforma em layout de relatório com CSS de impressão.
function gerarRelatorioMensal(mes?: number, ano?: number, incluirIA?: boolean): ServerResult {
  try {
    initDatabase();
    const hoje = new Date();
    const m = mes && mes >= 1 && mes <= 12 ? mes : (hoje.getMonth() + 1);
    const y = ano && ano > 2000 ? ano : hoje.getFullYear();
    const { inicio, fim } = _monthBounds(m, y);

    const sistemas = dbGetAll('Sistemas');
    const clientes = (dbGetAll('Pessoas') as Array<Record<string, unknown>>).filter((p) => String(p.papel) === 'cliente');
    const ideias = dbGetAll('Ideias');
    const custos = dbGetAll('Custos') as Array<Record<string, unknown>>;
    const alertas = (dbGetAll('Alertas') as Array<Record<string, unknown>>).filter((a) => {
      const t = new Date(String(a.criadoEm || '')).getTime();
      return !Number.isNaN(t) && t >= inicio.getTime() && t <= fim.getTime();
    });
    const timeline = (dbGetAll('Timeline') as Array<Record<string, unknown>>).filter((t) => {
      const d = new Date(String(t.data || '')).getTime();
      return !Number.isNaN(d) && d >= inicio.getTime() && d <= fim.getTime();
    });

    // KPIs
    const totalSistemas = sistemas.length;
    const saudeMedia = totalSistemas > 0 ? Math.round(sistemas.reduce((acc, s) => acc + Number(s.scoreSaude || 0), 0) / totalSistemas) : 0;
    const custoMensal = custos.reduce((acc, c) => {
      const rec = String(c.recorrencia || '').toLowerCase();
      const v = Number(c.valor || 0);
      if (rec.indexOf('mensal') >= 0 || rec.indexOf('mes') >= 0 || rec.indexOf('mês') >= 0) return acc + v;
      if (rec.indexOf('anual') >= 0) return acc + v / 12;
      return acc;
    }, 0);
    const mrr = (dbGetAll('Receitas') as Array<Record<string, unknown>>).reduce((acc, r) => {
      const rec = String(r.recorrencia || '').toLowerCase();
      const status = String(r.status || '').toLowerCase();
      if (status === 'cancelada' || status === 'cancelado') return acc;
      const v = Number(r.valor || 0);
      if (rec.indexOf('mensal') >= 0 || rec.indexOf('mes') >= 0 || rec.indexOf('mês') >= 0) return acc + v;
      if (rec.indexOf('anual') >= 0) return acc + v / 12;
      return acc;
    }, 0);

    // Sistemas com detalhe enxuto pro relatório
    const sistemasOut = sistemas.map((s) => {
      const sCustos = custos.filter((c) => String(c.sistemaId || '') === String(s.id || ''));
      const custoMensalS = sCustos.reduce((acc, c) => {
        const rec = String(c.recorrencia || '').toLowerCase();
        const v = Number(c.valor || 0);
        if (rec.indexOf('mensal') >= 0 || rec.indexOf('mes') >= 0) return acc + v;
        if (rec.indexOf('anual') >= 0) return acc + v / 12;
        return acc;
      }, 0);
      const incidentes = timeline.filter((t) => String(t.sistemaId || '') === String(s.id || '') && String(t.tipo) === 'incidente').length;
      return {
        id: s.id,
        nome: s.nome,
        codinome: s.codinome,
        estagio: s.estagio,
        stack: s.stack,
        scoreSaude: Number(s.scoreSaude || 0),
        urlProd: s.urlProd || '',
        custoMensal: Math.round(custoMensalS * 100) / 100,
        incidentes,
      };
    });

    // Próximas cobranças nos próximos 30 dias
    const limite30 = new Date(Date.now() + 30 * 86400000);
    const proximasContas = custos
      .filter((c) => !!c.proximaCobranca)
      .map((c) => ({ ...c, _data: new Date(String(c.proximaCobranca)) }))
      .filter((c) => !Number.isNaN(c._data.getTime()) && c._data >= new Date() && c._data <= limite30)
      .map((c) => {
        const r = c as Record<string, unknown>;
        return {
          fornecedor: r.fornecedor,
          valor: Number(r.valor || 0),
          proximaCobranca: r.proximaCobranca,
          sistemaId: r.sistemaId || '',
        };
      });

    // Resumo IA (opcional — caro, só se pedirem)
    let resumoIA = '';
    if (incluirIA) {
      const r = acaoIAResumoExecutivo();
      if (r.ok && typeof r.data === 'string') resumoIA = r.data;
    }

    return {
      ok: true,
      data: {
        periodo: { mes: m, ano: y, mesNome: _mesNome(m), inicio: inicio.toISOString(), fim: fim.toISOString() },
        kpis: {
          totalSistemas,
          totalClientes: clientes.length,
          totalIdeias: ideias.length,
          saudeMedia,
          custoMensal: Math.round(custoMensal * 100) / 100,
          mrr: Math.round(mrr * 100) / 100,
          lucro: Math.round((mrr - custoMensal) * 100) / 100,
        },
        sistemas: sistemasOut,
        clientes: clientes.map((c) => ({ id: c.id, nome: c.nome, contato: c.contato })),
        alertas: alertas.map((a) => ({
          tipo: a.tipo, severidade: a.severidade, titulo: a.titulo, mensagem: a.mensagem, criadoEm: a.criadoEm,
        })),
        proximasContas,
        timelineRecente: timeline.slice(-20).map((t) => ({
          data: t.data, tipo: t.tipo, texto: t.texto, sistemaId: t.sistemaId,
        })),
        resumoIA,
        geradoEm: new Date().toISOString(),
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar relatório' };
  }
}

function _toCSV(rows: Array<Record<string, unknown>>): string {
  if (rows.length === 0) return '';
  const headers = Object.keys(rows[0]);
  const escape = (v: unknown) => {
    if (v === null || v === undefined) return '';
    const s = String(v);
    if (s.indexOf(',') >= 0 || s.indexOf('"') >= 0 || s.indexOf('\n') >= 0) return '"' + s.replace(/"/g, '""') + '"';
    return s;
  };
  const linhas = [headers.join(',')];
  for (const r of rows) linhas.push(headers.map((h) => escape(r[h])).join(','));
  return linhas.join('\n');
}

const EXPORTAVEIS = ['Sistemas', 'Pessoas', 'Ideias', 'Custos', 'Receitas', 'Apis', 'Alertas', 'Stacks', 'Timeline', 'Decisoes', 'Riscos', 'Oportunidades'] as const;

function exportarCSV(entidade: string): ServerResult {
  try {
    if (!(EXPORTAVEIS as readonly string[]).includes(entidade)) return { ok: false, error: 'Entidade não exportável: ' + entidade };
    const rows = dbGetAll(entidade) as Array<Record<string, unknown>>;
    const csv = _toCSV(rows);
    return { ok: true, data: { entidade, rows: rows.length, csv } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao exportar' };
  }
}

function exportarBackupJSON(): ServerResult {
  try {
    const out: Record<string, unknown> = {
      _meta: {
        geradoEm: new Date().toISOString(),
        scriptId: ScriptApp.getScriptId(),
        usuario: Session.getActiveUser().getEmail(),
        versao: 'forja-13',
      },
    };
    for (const ent of EXPORTAVEIS) {
      try { out[ent] = dbGetAll(ent); } catch { out[ent] = []; }
    }
    return { ok: true, data: { json: JSON.stringify(out, null, 2), entidades: EXPORTAVEIS.length } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao exportar backup' };
  }
}

function listarEntidadesExportaveis(): ServerResult {
  return { ok: true, data: EXPORTAVEIS };
}

// ═══════════════════════════════════════════════════════════════════════════════
// Relatórios financeiros pessoais (Fase 1) — Extrato mensal, Por categoria e
// Fluxo de caixa. Cada relatório gera: (a) dataset estruturado pro preview na
// tela, (b) PDF (HTML→pdf), (c) planilha CSV e XLSX. O XLSX é montado direto
// como pacote OOXML via Utilities.zip — sem Drive, sem arquivo temporário.
// ═══════════════════════════════════════════════════════════════════════════════

const _MESES_BR_REL = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];

function _finMetodoLabel(m: string): string {
  const map: Record<string, string> = { cartao: 'Cartão', pix: 'Pix', debito: 'Débito', dinheiro: 'Dinheiro', boleto: 'Boleto', transferencia: 'Transferência' };
  const s = String(m || '');
  return map[s] || (s ? s.charAt(0).toUpperCase() + s.slice(1) : '—');
}

function _finCatLabelMap(): Record<string, string> {
  const map: Record<string, string> = {};
  for (const c of dbGetAll('FinPessoalCategorias') as Array<Record<string, unknown>>) {
    const nome = String(c['nome'] || '').toLowerCase();
    if (nome) map[nome] = String(c['label'] || '') || (nome.charAt(0).toUpperCase() + nome.slice(1));
  }
  return map;
}

function _finCatLabel(slug: string, map: Record<string, string>): string {
  const s = String(slug || 'outros').toLowerCase();
  return map[s] || (s.charAt(0).toUpperCase() + s.slice(1));
}

function _compLabelRel(comp: string): string {
  const m = /^(\d{4})-(\d{2})/.exec(String(comp || ''));
  if (!m) return String(comp || '');
  return `${_MESES_BR_REL[Number(m[2]) - 1] || m[2]}/${m[1]}`;
}

// Monta o dataset de um relatório financeiro. `mes` = 'YYYY-MM' (default: atual);
// `meses` = janela do fluxo de caixa (default 12). Usa a MESMA competência da
// tela (despesa de cartão cai no mês da fatura).
function _dadosRelatorioFinanceiro(tipo: string, mes?: string, meses?: number): Record<string, unknown> {
  const cartoesMap = _cartoesMap();
  const catMap = _finCatLabelMap();
  const todos = dbGetAll('FinPessoalLancamentos') as Array<Record<string, unknown>>;
  const mesRef = /^\d{4}-\d{2}$/.test(String(mes || '')) ? String(mes) : _toYYYYMM(new Date().toISOString());
  const compDe = (l: Record<string, unknown>) => String(l['tipo']) === 'despesa' ? _competenciaLancamento(l, cartoesMap) : _toYYYYMM(l['data']);

  if (tipo === 'extrato') {
    const itens = todos.filter((l) => compDe(l) === mesRef);
    itens.sort((a, b) => String(a['data'] || '').localeCompare(String(b['data'] || '')));
    const linhas = itens.map((l) => {
      const cMeta = l['cartaoId'] && cartoesMap[String(l['cartaoId'])] ? cartoesMap[String(l['cartaoId'])] : null;
      const cartao = cMeta ? (String(cMeta['apelido'] || '') || String(cMeta['nome'] || '')) : '';
      const parc = Number(l['parcelas'] || 0) > 1 ? `${l['parcelaAtual']}/${l['parcelas']}` : '';
      return {
        data: _valorJsonSafe(l['data']),
        descricao: String(l['descricao'] || ''),
        categoria: _finCatLabel(String(l['categoria'] || 'outros'), catMap),
        metodo: _finMetodoLabel(String(l['metodo'] || '')),
        cartao,
        parcela: parc,
        status: String(l['status'] || ''),
        tipo: String(l['tipo'] || 'despesa'),
        valor: Number(l['valor'] || 0),
      };
    });
    const despesas = linhas.filter((x) => x.tipo === 'despesa').reduce((s, x) => s + x.valor, 0);
    const entradas = linhas.filter((x) => x.tipo === 'entrada').reduce((s, x) => s + x.valor, 0);
    return { tipo, mes: mesRef, periodoLabel: _compLabelRel(mesRef), linhas, totais: { despesas, entradas, saldo: entradas - despesas, qtd: linhas.length } };
  }

  if (tipo === 'categorias') {
    const mesAnterior = _addMesesComp(mesRef, -1);
    const acc: Record<string, { valor: number; qtd: number }> = {};
    const accAnt: Record<string, number> = {};
    for (const l of todos) {
      if (String(l['tipo']) !== 'despesa') continue;
      const c = compDe(l);
      const cat = String(l['categoria'] || 'outros').toLowerCase();
      const v = Number(l['valor'] || 0);
      if (c === mesRef) { if (!acc[cat]) acc[cat] = { valor: 0, qtd: 0 }; acc[cat].valor += v; acc[cat].qtd += 1; }
      else if (c === mesAnterior) { accAnt[cat] = (accAnt[cat] || 0) + v; }
    }
    const total = Object.keys(acc).reduce((s, k) => s + acc[k].valor, 0);
    const linhas = Object.keys(acc).map((slug) => ({
      slug, categoria: _finCatLabel(slug, catMap), valor: acc[slug].valor, qtd: acc[slug].qtd,
      pct: total > 0 ? (acc[slug].valor / total) * 100 : 0,
      anterior: accAnt[slug] || 0, variacao: acc[slug].valor - (accAnt[slug] || 0),
    })).sort((a, b) => b.valor - a.valor);
    return { tipo, mes: mesRef, periodoLabel: _compLabelRel(mesRef), mesAnteriorLabel: _compLabelRel(mesAnterior), linhas, total };
  }

  if (tipo === 'cartoes') return _dadosCartoesRel(mesRef, cartoesMap, todos);
  if (tipo === 'parcelas') return _dadosParcelasRel(mesRef, cartoesMap, todos);
  if (tipo === 'anual') return _dadosAnualRel(mesRef, cartoesMap, catMap, todos);
  if (tipo === 'dre') return _dadosDreRel(mesRef);
  if (tipo === 'livro') return _dadosLivroRel(mesRef);
  if (tipo === 'mrr') return _dadosMrrRel();

  // fluxo de caixa: N meses terminando em mesRef
  const n = Math.max(2, Math.min(24, Number(meses || 12)));
  const comps: string[] = [];
  for (let i = n - 1; i >= 0; i--) comps.push(_addMesesComp(mesRef, -i));
  const porMes: Record<string, { entradas: number; despesas: number }> = {};
  for (const c of comps) porMes[c] = { entradas: 0, despesas: 0 };
  for (const l of todos) {
    const c = compDe(l);
    if (!porMes[c]) continue;
    const v = Number(l['valor'] || 0);
    if (String(l['tipo']) === 'entrada') porMes[c].entradas += v; else porMes[c].despesas += v;
  }
  let acumulado = 0;
  const linhasFluxo = comps.map((c) => {
    const e = porMes[c].entradas; const d = porMes[c].despesas; const saldo = e - d; acumulado += saldo;
    return { comp: c, label: _compLabelRel(c), entradas: e, despesas: d, saldo, acumulado };
  });
  const totE = linhasFluxo.reduce((s, x) => s + x.entradas, 0);
  const totD = linhasFluxo.reduce((s, x) => s + x.despesas, 0);
  return { tipo: 'fluxo', mes: mesRef, meses: linhasFluxo, periodoLabel: `${linhasFluxo[0].label} – ${linhasFluxo[linhasFluxo.length - 1].label}`, totais: { entradas: totE, despesas: totD, saldo: totE - totD } };
}

const _RELATORIOS_VALIDOS = ['extrato', 'categorias', 'fluxo', 'cartoes', 'parcelas', 'anual', 'dre', 'livro', 'mrr'];

function getRelatorioFinanceiro(tipo: string, mes?: string, meses?: number): ServerResult {
  try {
    const t = String(tipo || 'extrato');
    if (_RELATORIOS_VALIDOS.indexOf(t) < 0) return { ok: false, error: 'Relatório inválido' };
    return { ok: true, data: _dadosRelatorioFinanceiro(t, mes, meses) };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar relatório' };
  }
}

// ─── Fase 2: cartões, parcelas e fechamento anual ──────────────────────────────

function _dadosCartoesRel(mesRef: string, cartoesMap: Record<string, Record<string, unknown>>, todos: Array<Record<string, unknown>>): Record<string, unknown> {
  const cartoes = (dbGetAll('FinPessoalCartoes') as Array<Record<string, unknown>>).filter((c) => String(c['ativo'] || 'sim') !== 'nao');
  const N = 5;
  const futuros: Array<{ comp: string; label: string }> = [];
  for (let i = 1; i <= N; i++) { const c = _addMesesComp(mesRef, i); futuros.push({ comp: c, label: _compLabelRel(c) }); }
  const compDe = (l: Record<string, unknown>) => _competenciaLancamento(l, cartoesMap);
  const somaCartaoComp = (cid: string, comp: string) => todos
    .filter((l) => String(l['tipo']) === 'despesa' && String(l['cartaoId']) === cid && compDe(l) === comp)
    .reduce((s, l) => s + Number(l['valor'] || 0), 0);

  const linhas = cartoes.map((cartao) => {
    const cid = String(cartao['id']);
    const nome = String(cartao['apelido'] || '') || String(cartao['nome'] || '');
    const doMes = todos.filter((l) => String(l['tipo']) === 'despesa' && String(l['cartaoId']) === cid && compDe(l) === mesRef);
    const faturaMes = doMes.reduce((s, l) => s + Number(l['valor'] || 0), 0);
    const qtd = doMes.length;
    const paga = qtd > 0 && doMes.every((l) => String(l['status']) === 'pago');
    const status = qtd === 0 ? '—' : (paga ? 'Paga' : 'Aberta');
    const venc = _vencimentoNoMes(mesRef, Number(cartao['diaVencimento'] || 0));
    const futs = futuros.map((f) => somaCartaoComp(cid, f.comp));
    return { cartao: nome, vencimento: venc, faturaMes, qtd, status, futuros: futs };
  }).filter((x) => x.faturaMes !== 0 || x.qtd > 0 || x.futuros.some((v) => v !== 0));

  const totFaturaMes = linhas.reduce((s, l) => s + l.faturaMes, 0);
  const totFuturos = futuros.map((_, i) => linhas.reduce((s, l) => s + (l.futuros[i] || 0), 0));
  return {
    tipo: 'cartoes', mes: mesRef, periodoLabel: _compLabelRel(mesRef),
    futurosLabels: futuros.map((f) => f.label),
    linhas, totais: { faturaMes: totFaturaMes, futuros: totFuturos },
  };
}

function _dadosParcelasRel(mesRef: string, cartoesMap: Record<string, Record<string, unknown>>, todos: Array<Record<string, unknown>>): Record<string, unknown> {
  const compDe = (l: Record<string, unknown>) => _competenciaLancamento(l, cartoesMap);
  const parceladas = todos.filter((l) => String(l['tipo']) === 'despesa' && Number(l['parcelas'] || 0) > 1);
  const grupos: Record<string, { descricao: string; cartaoId: string; parcelas: number; items: Array<Record<string, unknown>> }> = {};
  for (const l of parceladas) {
    const key = String(l['parcelaGrupoId'] || '') || (String(l['descricao'] || '') + '|' + String(l['cartaoId'] || '') + '|' + String(l['parcelas']));
    if (!grupos[key]) grupos[key] = { descricao: _descSemParcela(String(l['descricao'] || '')) || String(l['descricao'] || ''), cartaoId: String(l['cartaoId'] || ''), parcelas: Number(l['parcelas'] || 0), items: [] };
    grupos[key].parcelas = Math.max(grupos[key].parcelas, Number(l['parcelas'] || 0));
    grupos[key].items.push(l);
  }
  const linhas = Object.keys(grupos).map((k) => {
    const g = grupos[k];
    // Em aberto = parcelas com competência >= mês de referência e ainda não pagas.
    const restantesItems = g.items.filter((l) => compDe(l) >= mesRef && String(l['status']) !== 'pago');
    const valorRestante = restantesItems.reduce((s, l) => s + Number(l['valor'] || 0), 0);
    const valorParcela = Number((restantesItems[0] || g.items[0])['valor'] || 0);
    const cMeta = cartoesMap[g.cartaoId];
    const cartao = cMeta ? (String(cMeta['apelido'] || '') || String(cMeta['nome'] || '')) : '';
    const comps = restantesItems.map((l) => compDe(l)).sort();
    const proxima = comps.length ? _compLabelRel(comps[0]) : '';
    const nums = g.items.map((l) => Number(l['parcelaAtual'] || 0)).filter((x) => x > 0);
    const atualMax = nums.length ? Math.max.apply(null, nums) : 0;
    return {
      descricao: g.descricao, cartao, parcelas: g.parcelas, atual: atualMax,
      restantes: restantesItems.length, valorParcela, valorRestante, proxima,
    };
  }).filter((x) => x.restantes > 0).sort((a, b) => b.valorRestante - a.valorRestante);

  const totalRestante = linhas.reduce((s, l) => s + l.valorRestante, 0);
  const proxMes = linhas.reduce((s, l) => s + (l.proxima === _compLabelRel(_addMesesComp(mesRef, 1)) ? l.valorParcela : 0), 0);
  return {
    tipo: 'parcelas', mes: mesRef, periodoLabel: _compLabelRel(mesRef),
    linhas, totais: { valorRestante: totalRestante, qtdGrupos: linhas.length, proxMes },
  };
}

function _dadosAnualRel(mesRef: string, cartoesMap: Record<string, Record<string, unknown>>, catMap: Record<string, string>, todos: Array<Record<string, unknown>>): Record<string, unknown> {
  const ano = mesRef.split('-')[0];
  const MES3 = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
  const compDe = (l: Record<string, unknown>) => String(l['tipo']) === 'despesa' ? _competenciaLancamento(l, cartoesMap) : _toYYYYMM(l['data']);
  const porMes: Record<string, { entradas: number; despesas: number }> = {};
  for (let m = 1; m <= 12; m++) porMes[`${ano}-${String(m).padStart(2, '0')}`] = { entradas: 0, despesas: 0 };
  const catAcc: Record<string, number> = {};
  for (const l of todos) {
    const c = compDe(l);
    if (!porMes[c]) continue;
    const v = Number(l['valor'] || 0);
    if (String(l['tipo']) === 'entrada') porMes[c].entradas += v;
    else { porMes[c].despesas += v; const cat = String(l['categoria'] || 'outros').toLowerCase(); catAcc[cat] = (catAcc[cat] || 0) + v; }
  }
  let acumulado = 0;
  const meses = [];
  for (let m = 1; m <= 12; m++) {
    const comp = `${ano}-${String(m).padStart(2, '0')}`;
    const e = porMes[comp].entradas; const d = porMes[comp].despesas; const saldo = e - d; acumulado += saldo;
    meses.push({ comp, label: MES3[m - 1], entradas: e, despesas: d, saldo, acumulado });
  }
  const totD = meses.reduce((s, x) => s + x.despesas, 0);
  const totE = meses.reduce((s, x) => s + x.entradas, 0);
  const categorias = Object.keys(catAcc).map((slug) => ({ categoria: _finCatLabel(slug, catMap), valor: catAcc[slug], pct: totD > 0 ? (catAcc[slug] / totD) * 100 : 0 }))
    .sort((a, b) => b.valor - a.valor).slice(0, 12);
  return { tipo: 'anual', mes: mesRef, ano, periodoLabel: String(ano), meses, categorias, totais: { entradas: totE, despesas: totD, saldo: totE - totD } };
}

// ─── Fase 3: empresa (DRE, livro-caixa, MRR) ───────────────────────────────────

function _sistemaNomeMap(): Record<string, string> {
  const map: Record<string, string> = {};
  for (const s of dbGetAll('Sistemas') as Array<Record<string, unknown>>) map[String(s['id'])] = String(s['nome'] || '');
  return map;
}

function _dadosDreRel(mesRef: string): Record<string, unknown> {
  const sis = _sistemaNomeMap();
  const custos = dbGetAll('Custos') as Array<Record<string, unknown>>;
  const receitas = dbGetAll('Receitas') as Array<Record<string, unknown>>;
  const despesas = dbGetAll('FinEmpresaDespesas') as Array<Record<string, unknown>>;
  const ativas = receitas.filter((r) => String(r['status'] || 'ativa').toLowerCase() !== 'cancelada');
  const receitaRec = ativas.reduce((s, r) => s + toMonthly(Number(r['valor'] || 0), String(r['recorrencia'] || 'mensal')), 0);
  const custoRec = custos.reduce((s, c) => s + toMonthly(Number(c['valor'] || 0), String(c['recorrencia'] || 'mensal')), 0);
  const despesasMes = despesas.filter((d) => String(d['competencia']) === mesRef);
  const despesaVar = despesasMes.reduce((s, d) => s + Number(d['valor'] || 0), 0);
  const lucro = receitaRec - custoRec - despesaVar;
  const margem = receitaRec > 0 ? (lucro / receitaRec) * 100 : 0;

  const linhas = [
    { label: 'Receita recorrente (MRR)', valor: receitaRec, tipo: 'receita' },
    { label: 'Custos recorrentes', valor: -custoRec, tipo: 'custo' },
    { label: 'Despesas variáveis (' + _compLabelRel(mesRef) + ')', valor: -despesaVar, tipo: 'despesa' },
    { label: 'Resultado do mês', valor: lucro, tipo: 'resultado' },
  ];

  const mapa: Record<string, { nome: string; mrr: number; custo: number; despesa: number }> = {};
  const g = (id: string) => { if (!mapa[id]) mapa[id] = { nome: id ? (sis[id] || 'Sem app') : 'Sem app', mrr: 0, custo: 0, despesa: 0 }; return mapa[id]; };
  ativas.forEach((r) => { g(String(r['sistemaId'] || '')).mrr += toMonthly(Number(r['valor'] || 0), String(r['recorrencia'] || 'mensal')); });
  custos.forEach((c) => { g(String(c['sistemaId'] || '')).custo += toMonthly(Number(c['valor'] || 0), String(c['recorrencia'] || 'mensal')); });
  despesasMes.forEach((d) => { g(String(d['sistemaId'] || '')).despesa += Number(d['valor'] || 0); });
  const porApp = Object.keys(mapa).map((id) => { const x = mapa[id]; return { nome: x.nome, mrr: x.mrr, custo: x.custo, despesa: x.despesa, lucro: x.mrr - x.custo - x.despesa }; })
    .filter((x) => x.mrr > 0 || x.custo > 0 || x.despesa > 0).sort((a, b) => b.lucro - a.lucro);

  return { tipo: 'dre', mes: mesRef, periodoLabel: _compLabelRel(mesRef), linhas, porApp, totais: { receita: receitaRec, custo: custoRec, despesa: despesaVar, lucro, margem } };
}

function _dadosLivroRel(mesRef: string): Record<string, unknown> {
  const sis = _sistemaNomeMap();
  const despesas = (dbGetAll('FinEmpresaDespesas') as Array<Record<string, unknown>>)
    .filter((d) => String(d['competencia']) === mesRef)
    .sort((a, b) => String(a['data'] || '').localeCompare(String(b['data'] || '')));
  const linhas = despesas.map((d) => ({
    data: _valorJsonSafe(d['data']),
    fornecedor: String(d['fornecedor'] || ''),
    descricao: String(d['descricao'] || ''),
    categoria: String(d['categoria'] || 'Outro'),
    sistema: d['sistemaId'] ? (sis[String(d['sistemaId'])] || '') : '',
    status: String(d['status'] || ''),
    valor: Number(d['valor'] || 0),
  }));
  const total = linhas.reduce((s, l) => s + l.valor, 0);
  const pago = linhas.filter((l) => l.status === 'pago').reduce((s, l) => s + l.valor, 0);
  return { tipo: 'livro', mes: mesRef, periodoLabel: _compLabelRel(mesRef), linhas, totais: { total, pago, pendente: total - pago, qtd: linhas.length } };
}

function _dadosMrrRel(): Record<string, unknown> {
  const sis = _sistemaNomeMap();
  const receitas = dbGetAll('Receitas') as Array<Record<string, unknown>>;
  const ativas = receitas.filter((r) => String(r['status'] || 'ativa').toLowerCase() !== 'cancelada');
  const linhas = ativas.map((r) => ({
    app: r['sistemaId'] ? (sis[String(r['sistemaId'])] || 'Sem app') : 'Sem app',
    plano: String(r['plano'] || ''),
    recorrencia: String(r['recorrencia'] || 'mensal'),
    proxima: _valorJsonSafe(r['proximaCobranca']),
    valorMensal: toMonthly(Number(r['valor'] || 0), String(r['recorrencia'] || 'mensal')),
  })).sort((a, b) => b.valorMensal - a.valorMensal);
  const mrr = linhas.reduce((s, l) => s + l.valorMensal, 0);
  const canceladas = receitas.length - ativas.length;
  return { tipo: 'mrr', mes: '', periodoLabel: 'Assinaturas ativas', linhas, totais: { mrr, assinaturas: ativas.length, canceladas } };
}

// ─── Tabela neutra (usada por CSV, XLSX e PDF) ─────────────────────────────────
// `num` = numérico (alinhado à direita); `money` = moeda (numérico + formato R$).
interface RelCelula { v: string | number; num?: boolean; money?: boolean }
interface RelTabela { nome: string; header: string[]; rows: RelCelula[][] }

function _relTabela(ds: Record<string, unknown>): RelTabela {
  const tipo = String(ds['tipo']);
  if (tipo === 'extrato') {
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: _fmtDataBR(String(l['data'])) },
      { v: String(l['descricao']) },
      { v: String(l['categoria']) },
      { v: String(l['metodo']) },
      { v: String(l['cartao'] || '') },
      { v: String(l['parcela'] || '') },
      { v: String(l['status'] || '') },
      { v: l['tipo'] === 'entrada' ? 'Entrada' : 'Despesa' },
      { v: Number(l['valor'] || 0), money: true },
    ]);
    return { nome: 'Extrato', header: ['Data', 'Descrição', 'Categoria', 'Método', 'Cartão', 'Parcela', 'Status', 'Tipo', 'Valor'], rows };
  }
  if (tipo === 'categorias') {
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: String(l['categoria']) },
      { v: Number(l['valor'] || 0), money: true },
      { v: Number(Number(l['pct'] || 0).toFixed(1)), num: true },
      { v: Number(l['qtd'] || 0), num: true },
      { v: Number(l['anterior'] || 0), money: true },
      { v: Number(l['variacao'] || 0), money: true },
    ]);
    return { nome: 'Por categoria', header: ['Categoria', 'Valor', '% do mês', 'Lançamentos', 'Mês anterior', 'Variação'], rows };
  }
  if (tipo === 'cartoes') {
    const futLabels = (ds['futurosLabels'] as string[]) || [];
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: String(l['cartao']) },
      { v: l['vencimento'] ? _fmtDataBR(String(l['vencimento'])) : '—' },
      { v: String(l['status']) },
      { v: Number(l['qtd'] || 0), num: true },
      { v: Number(l['faturaMes'] || 0), money: true },
      ...(l['futuros'] as number[]).map((v) => ({ v: Number(v || 0), money: true })),
    ]);
    return { nome: 'Faturas de cartão', header: ['Cartão', 'Vencimento', 'Status', 'Lançamentos', 'Fatura do mês', ...futLabels], rows };
  }
  if (tipo === 'parcelas') {
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: String(l['descricao']) },
      { v: String(l['cartao'] || '') },
      { v: `${l['atual']}/${l['parcelas']}` },
      { v: Number(l['restantes'] || 0), num: true },
      { v: Number(l['valorParcela'] || 0), money: true },
      { v: Number(l['valorRestante'] || 0), money: true },
      { v: String(l['proxima'] || '') },
    ]);
    return { nome: 'Parcelas em aberto', header: ['Compra', 'Cartão', 'Parcela', 'Restantes', 'Valor parcela', 'Falta pagar', 'Próxima'], rows };
  }
  if (tipo === 'anual') {
    const rows = (ds['meses'] as Array<Record<string, unknown>>).map((m) => [
      { v: String(m['label']) },
      { v: Number(m['entradas'] || 0), money: true },
      { v: Number(m['despesas'] || 0), money: true },
      { v: Number(m['saldo'] || 0), money: true },
      { v: Number(m['acumulado'] || 0), money: true },
    ]);
    return { nome: 'Fechamento anual', header: ['Mês', 'Entradas', 'Despesas', 'Saldo', 'Acumulado'], rows };
  }
  if (tipo === 'dre') {
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: String(l['label']) },
      { v: Number(l['valor'] || 0), money: true },
    ]);
    return { nome: 'DRE', header: ['Linha', 'Valor'], rows };
  }
  if (tipo === 'livro') {
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: _fmtDataBR(String(l['data'])) },
      { v: String(l['fornecedor'] || '') },
      { v: String(l['descricao'] || '') },
      { v: String(l['categoria'] || '') },
      { v: String(l['sistema'] || '') },
      { v: String(l['status'] || '') },
      { v: Number(l['valor'] || 0), money: true },
    ]);
    return { nome: 'Livro-caixa', header: ['Data', 'Fornecedor', 'Descrição', 'Categoria', 'App', 'Status', 'Valor'], rows };
  }
  if (tipo === 'mrr') {
    const rows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => [
      { v: String(l['app'] || '') },
      { v: String(l['plano'] || '') },
      { v: String(l['recorrencia'] || '') },
      { v: l['proxima'] ? _fmtDataBR(String(l['proxima'])) : '—' },
      { v: Number(l['valorMensal'] || 0), money: true },
    ]);
    return { nome: 'MRR', header: ['App', 'Plano', 'Recorrência', 'Próx. cobrança', 'Valor mensal'], rows };
  }
  const rows = (ds['meses'] as Array<Record<string, unknown>>).map((m) => [
    { v: String(m['label']) },
    { v: Number(m['entradas'] || 0), money: true },
    { v: Number(m['despesas'] || 0), money: true },
    { v: Number(m['saldo'] || 0), money: true },
    { v: Number(m['acumulado'] || 0), money: true },
  ]);
  return { nome: 'Fluxo de caixa', header: ['Mês', 'Entradas', 'Despesas', 'Saldo', 'Acumulado'], rows };
}

// Renderiza uma RelTabela como tabela HTML pro PDF (moeda em R$, demais à direita).
function _relTabelaHtml(tab: RelTabela): string {
  const th = tab.header.map((h, i) => {
    const algo = tab.rows.length > 0 && tab.rows[0][i] && (tab.rows[0][i].num || tab.rows[0][i].money);
    return '<th' + (algo ? ' class="right"' : '') + '>' + _escHtml(h) + '</th>';
  }).join('');
  const body = tab.rows.length === 0
    ? '<tr><td colspan="' + tab.header.length + '" class="muted">Sem dados.</td></tr>'
    : tab.rows.map((row) => '<tr>' + row.map((c) => {
      if (c.money) return '<td class="right mono">' + _fmtBRLpdf(Number(c.v)) + '</td>';
      if (c.num) return '<td class="right">' + _escHtml(c.v) + '</td>';
      return '<td>' + _escHtml(c.v) + '</td>';
    }).join('') + '</tr>').join('');
  return '<table><thead><tr>' + th + '</tr></thead><tbody>' + body + '</tbody></table>';
}

function _relNomeArquivo(ds: Record<string, unknown>): string {
  const nomes: Record<string, string> = {
    extrato: 'extrato', categorias: 'por-categoria', fluxo: 'fluxo-de-caixa',
    cartoes: 'faturas-cartao', parcelas: 'parcelas-em-aberto', anual: 'fechamento-anual',
    dre: 'dre-empresa', livro: 'livro-caixa-empresa', mrr: 'mrr-assinaturas',
  };
  const base = nomes[String(ds['tipo'])] || 'relatorio';
  const sufixo = String(ds['tipo']) === 'anual' ? String(ds['ano'] || '') : String(ds['mes'] || '').replace(/[^\d-]/g, '');
  return `forja-${base}${sufixo ? '-' + sufixo : ''}`;
}

// ─── CSV (pt-BR: separador ';', decimal ',', BOM pro Excel) ─────────────────────
function _numBR2(n: number): string { return Number(n || 0).toFixed(2).replace('.', ','); }

function _relCsv(tab: RelTabela): string {
  const esc = (s: string) => (/[;"\n\r]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s);
  const linhas = [tab.header.map(esc).join(';')];
  for (const row of tab.rows) linhas.push(row.map((c) => esc(c.money ? _numBR2(Number(c.v)) : String(c.v))).join(';'));
  return '\uFEFF' + linhas.join('\r\n');
}

// ─── XLSX mínimo (OOXML) montado via Utilities.zip — uma aba ───────────────────
function _xlsxColLetra(n: number): string {
  let s = '';
  while (n > 0) { const m = (n - 1) % 26; s = String.fromCharCode(65 + m) + s; n = Math.floor((n - 1) / 26); }
  return s;
}

function _xlsxEsc(s: unknown): string {
  return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function _xlsxSheetXml(tab: RelTabela): string {
  const todas: RelCelula[][] = [tab.header.map((h) => ({ v: h })), ...tab.rows];
  const rowsXml = todas.map((row, ri) => {
    const celulas = row.map((c, ci) => {
      const ref = _xlsxColLetra(ci + 1) + (ri + 1);
      if (ri > 0 && (c.num || c.money) && typeof c.v === 'number' && isFinite(c.v)) {
        return `<c r="${ref}"><v>${c.v}</v></c>`;
      }
      return `<c r="${ref}" t="inlineStr"><is><t xml:space="preserve">${_xlsxEsc(c.v)}</t></is></c>`;
    }).join('');
    return `<row r="${ri + 1}">${celulas}</row>`;
  }).join('');
  return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
    + '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">'
    + `<sheetData>${rowsXml}</sheetData></worksheet>`;
}

function _xlsxBase64(tab: RelTabela): string {
  const nomeAba = tab.nome.replace(/[\\/?*[\]:]/g, ' ').slice(0, 31) || 'Planilha';
  const contentTypes = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
    + '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'
    + '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'
    + '<Default Extension="xml" ContentType="application/xml"/>'
    + '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>'
    + '<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>'
    + '</Types>';
  const rels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
    + '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
    + '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>'
    + '</Relationships>';
  const workbook = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
    + '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
    + `<sheets><sheet name="${_xlsxEsc(nomeAba)}" sheetId="1" r:id="rId1"/></sheets></workbook>`;
  const workbookRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
    + '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
    + '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>'
    + '</Relationships>';
  const blobs = [
    Utilities.newBlob(contentTypes, 'application/xml', '[Content_Types].xml'),
    Utilities.newBlob(rels, 'application/xml', '_rels/.rels'),
    Utilities.newBlob(workbook, 'application/xml', 'xl/workbook.xml'),
    Utilities.newBlob(workbookRels, 'application/xml', 'xl/_rels/workbook.xml.rels'),
    Utilities.newBlob(_xlsxSheetXml(tab), 'application/xml', 'xl/worksheets/sheet1.xml'),
  ];
  const zip = Utilities.zip(blobs, 'planilha.xlsx');
  return Utilities.base64Encode(zip.getBytes());
}

// Exporta um relatório financeiro em CSV ou XLSX.
function exportarRelatorioFinanceiro(tipo: string, mes?: string, meses?: number, formato?: string): ServerResult {
  try {
    const t = String(tipo || 'extrato');
    if (_RELATORIOS_VALIDOS.indexOf(t) < 0) return { ok: false, error: 'Relatório inválido' };
    const ds = _dadosRelatorioFinanceiro(t, mes, meses);
    const tab = _relTabela(ds);
    const nomeBase = _relNomeArquivo(ds);
    if (String(formato || 'csv') === 'xlsx') {
      return { ok: true, data: { filename: `${nomeBase}.xlsx`, mime: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', base64: _xlsxBase64(tab) } };
    }
    return { ok: true, data: { filename: `${nomeBase}.csv`, mime: 'text/csv', csv: _relCsv(tab) } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao exportar relatório' };
  }
}

// ─── PDF dos relatórios financeiros ────────────────────────────────────────────
function _relKpiBox(label: string, valor: string, cor?: string): string {
  return '<div style="background:#F6F3EE;border:1px solid #E7E1D8;border-radius:10px;padding:12px 14px;">'
    + '<div class="muted" style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;">' + _escHtml(label) + '</div>'
    + '<div style="font-size:19px;font-weight:600;margin-top:4px;' + (cor ? 'color:' + cor + ';' : '') + '">' + _escHtml(valor) + '</div></div>';
}

function _relCabecalhoHtml(titulo: string, periodo: string): string {
  return '<div style="border-bottom:2px solid #D99B73;padding-bottom:16px;margin-bottom:22px;">'
    + '<div class="muted" style="font-size:10px;letter-spacing:0.16em;text-transform:uppercase;">FORJA — Relatório financeiro</div>'
    + '<h1 style="font-size:28px;margin-top:6px;">' + _escHtml(titulo) + ' <span class="muted" style="font-weight:400;">' + _escHtml(periodo) + '</span></h1>'
    + '<div class="muted" style="font-size:11px;margin-top:4px;">Gerado em ' + _escHtml(new Date().toLocaleString('pt-BR')) + '</div></div>';
}

function gerarRelatorioFinanceiroPdf(tipo: string, mes?: string, meses?: number): ServerResult {
  try {
    const t = String(tipo || 'extrato');
    if (_RELATORIOS_VALIDOS.indexOf(t) < 0) return { ok: false, error: 'Relatório inválido' };
    const ds = _dadosRelatorioFinanceiro(t, mes, meses);
    let corpo = '';
    let titulo = '';

    if (t === 'extrato') {
      const tot = ds['totais'] as Record<string, number>;
      const linhas = ds['linhas'] as Array<Record<string, unknown>>;
      titulo = 'Extrato mensal';
      const rows = linhas.length === 0
        ? '<tr><td colspan="7" class="muted">Nenhum lançamento neste mês.</td></tr>'
        : linhas.map((l) => {
          const ent = l['tipo'] === 'entrada';
          return '<tr><td>' + _escHtml(_fmtDataBR(String(l['data']))) + '</td>'
            + '<td>' + _escHtml(l['descricao']) + (l['parcela'] ? ' <span class="muted">(' + _escHtml(l['parcela']) + ')</span>' : '') + '</td>'
            + '<td>' + _escHtml(l['categoria']) + '</td>'
            + '<td>' + _escHtml(l['metodo']) + (l['cartao'] ? ' · ' + _escHtml(l['cartao']) : '') + '</td>'
            + '<td style="text-transform:capitalize;">' + _escHtml(l['status']) + '</td>'
            + '<td class="right mono" style="color:' + (ent ? '#5C8A5A' : '#2A2724') + ';">' + (ent ? '+' : '') + _fmtBRLpdf(Number(l['valor'] || 0)) + '</td></tr>';
        }).join('');
      corpo = _relCabecalhoHtml(titulo, String(ds['periodoLabel'] || ''))
        + '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Despesas', _fmtBRLpdf(tot.despesas), '#B5544E')
        + _relKpiBox('Entradas', _fmtBRLpdf(tot.entradas), '#5C8A5A')
        + _relKpiBox('Saldo', _fmtBRLpdf(tot.saldo), tot.saldo >= 0 ? '#5C8A5A' : '#B5544E')
        + _relKpiBox('Lançamentos', String(tot.qtd)) + '</div>'
        + '<table><thead><tr><th>Data</th><th>Descrição</th><th>Categoria</th><th>Pagamento</th><th>Status</th><th class="right">Valor</th></tr></thead><tbody>' + rows + '</tbody></table>';
    } else if (t === 'categorias') {
      const linhas = ds['linhas'] as Array<Record<string, unknown>>;
      const total = Number(ds['total'] || 0);
      titulo = 'Gastos por categoria · ' + String(ds['periodoLabel']);
      const rows = linhas.length === 0
        ? '<tr><td colspan="5" class="muted">Sem despesas neste mês.</td></tr>'
        : linhas.map((l) => {
          const varv = Number(l['variacao'] || 0);
          const corVar = varv > 0 ? '#B5544E' : varv < 0 ? '#5C8A5A' : '#8C8378';
          return '<tr><td><strong>' + _escHtml(l['categoria']) + '</strong></td>'
            + '<td class="right mono">' + _fmtBRLpdf(Number(l['valor'] || 0)) + '</td>'
            + '<td class="right">' + Number(l['pct'] || 0).toFixed(0) + '%</td>'
            + '<td class="right">' + _escHtml(l['qtd']) + '</td>'
            + '<td class="right mono">' + _fmtBRLpdf(Number(l['anterior'] || 0)) + '</td>'
            + '<td class="right mono" style="color:' + corVar + ';">' + (varv > 0 ? '+' : '') + _fmtBRLpdf(varv) + '</td></tr>';
        }).join('');
      corpo = _relCabecalhoHtml('Gastos por categoria', String(ds['periodoLabel']))
        + '<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Total do mês', _fmtBRLpdf(total))
        + _relKpiBox('Categorias', String(linhas.length)) + '</div>'
        + '<table><thead><tr><th>Categoria</th><th class="right">Valor</th><th class="right">%</th><th class="right">Lanç.</th><th class="right">' + _escHtml(ds['mesAnteriorLabel']) + '</th><th class="right">Variação</th></tr></thead><tbody>' + rows + '</tbody></table>';
    } else if (t === 'fluxo') {
      const linhas = ds['meses'] as Array<Record<string, unknown>>;
      const tot = ds['totais'] as Record<string, number>;
      titulo = 'Fluxo de caixa';
      const rows = linhas.map((m) => {
        const saldo = Number(m['saldo'] || 0);
        return '<tr><td><strong>' + _escHtml(m['label']) + '</strong></td>'
          + '<td class="right mono" style="color:#5C8A5A;">' + _fmtBRLpdf(Number(m['entradas'] || 0)) + '</td>'
          + '<td class="right mono" style="color:#B5544E;">' + _fmtBRLpdf(Number(m['despesas'] || 0)) + '</td>'
          + '<td class="right mono" style="color:' + (saldo >= 0 ? '#5C8A5A' : '#B5544E') + ';">' + _fmtBRLpdf(saldo) + '</td>'
          + '<td class="right mono">' + _fmtBRLpdf(Number(m['acumulado'] || 0)) + '</td></tr>';
      }).join('');
      corpo = _relCabecalhoHtml('Fluxo de caixa', String(ds['periodoLabel']))
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Entradas', _fmtBRLpdf(tot.entradas), '#5C8A5A')
        + _relKpiBox('Despesas', _fmtBRLpdf(tot.despesas), '#B5544E')
        + _relKpiBox('Saldo do período', _fmtBRLpdf(tot.saldo), tot.saldo >= 0 ? '#5C8A5A' : '#B5544E') + '</div>'
        + '<table><thead><tr><th>Mês</th><th class="right">Entradas</th><th class="right">Despesas</th><th class="right">Saldo</th><th class="right">Acumulado</th></tr></thead><tbody>' + rows + '</tbody></table>';
    } else if (t === 'cartoes') {
      const tot = ds['totais'] as { faturaMes: number; futuros: number[] };
      titulo = 'Faturas de cartão';
      corpo = _relCabecalhoHtml('Faturas de cartão', String(ds['periodoLabel']))
        + '<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Fatura do mês', _fmtBRLpdf(tot.faturaMes))
        + _relKpiBox('Próximas (provisão)', _fmtBRLpdf((tot.futuros || []).reduce((s, v) => s + v, 0))) + '</div>'
        + _relTabelaHtml(_relTabela(ds))
        + '<p class="muted" style="font-size:11px;margin-top:10px;">As colunas dos meses futuros são a provisão das parcelas já lançadas.</p>';
    } else if (t === 'parcelas') {
      const tot = ds['totais'] as { valorRestante: number; qtdGrupos: number; proxMes: number };
      titulo = 'Parcelas em aberto';
      corpo = _relCabecalhoHtml('Parcelas em aberto', String(ds['periodoLabel']))
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Falta pagar (total)', _fmtBRLpdf(tot.valorRestante))
        + _relKpiBox('Compras parceladas', String(tot.qtdGrupos))
        + _relKpiBox('Próximo mês', _fmtBRLpdf(tot.proxMes)) + '</div>'
        + _relTabelaHtml(_relTabela(ds));
    } else if (t === 'anual') {
      const tot = ds['totais'] as Record<string, number>;
      const cats = (ds['categorias'] as Array<Record<string, unknown>>) || [];
      titulo = 'Fechamento anual ' + String(ds['ano']);
      const catRows = cats.map((c) => '<tr><td>' + _escHtml(c['categoria']) + '</td><td class="right mono">' + _fmtBRLpdf(Number(c['valor'] || 0)) + '</td><td class="right">' + Number(c['pct'] || 0).toFixed(0) + '%</td></tr>').join('');
      corpo = _relCabecalhoHtml('Fechamento anual', String(ds['ano']))
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Entradas no ano', _fmtBRLpdf(tot.entradas), '#5C8A5A')
        + _relKpiBox('Despesas no ano', _fmtBRLpdf(tot.despesas), '#B5544E')
        + _relKpiBox('Saldo do ano', _fmtBRLpdf(tot.saldo), tot.saldo >= 0 ? '#5C8A5A' : '#B5544E') + '</div>'
        + _relTabelaHtml(_relTabela(ds))
        + (catRows ? '<h2 style="font-size:16px;margin:22px 0 10px;">Categorias do ano</h2><table><thead><tr><th>Categoria</th><th class="right">Valor</th><th class="right">%</th></tr></thead><tbody>' + catRows + '</tbody></table>' : '');
    } else if (t === 'dre') {
      const tot = ds['totais'] as Record<string, number>;
      const porApp = (ds['porApp'] as Array<Record<string, unknown>>) || [];
      titulo = 'DRE — ' + String(ds['periodoLabel']);
      const dreRows = (ds['linhas'] as Array<Record<string, unknown>>).map((l) => {
        const v = Number(l['valor'] || 0);
        const forte = l['tipo'] === 'resultado';
        return '<tr style="' + (forte ? 'border-top:2px solid #E7E1D8;font-weight:600;' : '') + '"><td>' + _escHtml(l['label']) + '</td>'
          + '<td class="right mono" style="color:' + (v >= 0 ? '#5C8A5A' : '#B5544E') + ';">' + _fmtBRLpdf(v) + '</td></tr>';
      }).join('');
      const appRows = porApp.map((a) => '<tr><td>' + _escHtml(a['nome']) + '</td>'
        + '<td class="right mono">' + _fmtBRLpdf(Number(a['mrr'] || 0)) + '</td>'
        + '<td class="right mono">' + _fmtBRLpdf(Number(a['custo'] || 0)) + '</td>'
        + '<td class="right mono">' + _fmtBRLpdf(Number(a['despesa'] || 0)) + '</td>'
        + '<td class="right mono" style="color:' + (Number(a['lucro'] || 0) >= 0 ? '#5C8A5A' : '#B5544E') + ';">' + _fmtBRLpdf(Number(a['lucro'] || 0)) + '</td></tr>').join('');
      corpo = _relCabecalhoHtml('DRE', String(ds['periodoLabel']))
        + '<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Resultado', _fmtBRLpdf(tot.lucro), tot.lucro >= 0 ? '#5C8A5A' : '#B5544E')
        + _relKpiBox('Margem', Math.round(tot.margem) + '%') + '</div>'
        + '<table style="margin-bottom:24px;"><thead><tr><th>Linha</th><th class="right">Valor</th></tr></thead><tbody>' + dreRows + '</tbody></table>'
        + (appRows ? '<h2 style="font-size:16px;margin:0 0 10px;">Por app</h2><table><thead><tr><th>App</th><th class="right">MRR</th><th class="right">Custo</th><th class="right">Despesa</th><th class="right">Lucro</th></tr></thead><tbody>' + appRows + '</tbody></table>' : '');
    } else if (t === 'livro') {
      const tot = ds['totais'] as Record<string, number>;
      titulo = 'Livro-caixa — ' + String(ds['periodoLabel']);
      corpo = _relCabecalhoHtml('Livro-caixa', String(ds['periodoLabel']))
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('Total', _fmtBRLpdf(tot.total))
        + _relKpiBox('Pago', _fmtBRLpdf(tot.pago), '#5C8A5A')
        + _relKpiBox('Pendente', _fmtBRLpdf(tot.pendente), '#B5544E') + '</div>'
        + _relTabelaHtml(_relTabela(ds));
    } else {
      const tot = ds['totais'] as Record<string, number>;
      titulo = 'MRR — assinaturas';
      corpo = _relCabecalhoHtml('MRR', 'Assinaturas ativas')
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:22px;">'
        + _relKpiBox('MRR', _fmtBRLpdf(tot.mrr), '#5C8A5A')
        + _relKpiBox('Assinaturas ativas', String(tot.assinaturas))
        + _relKpiBox('Canceladas', String(tot.canceladas)) + '</div>'
        + _relTabelaHtml(_relTabela(ds));
    }

    const html = _pdfDoc(titulo, corpo);
    return _htmlToPdfResult(html, _relNomeArquivo(ds));
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao gerar PDF do relatório' };
  }
}

// ─── Fase 14: IA com ações reais (tool calling) ──────────────────────────────
//
// A Forja IA pode propor ações estruturadas (criar ideia, registrar risco, gerar
// backlog .md etc.) que o usuário aprova/recusa antes da execução. Não usamos a
// função nativa de "tool use" das APIs de LLM porque queremos portabilidade
// entre proxies — em vez disso, ensinamos o LLM a emitir JSON num bloco
// <TOOL_CALLS>…</TOOL_CALLS> e parseamos no servidor.

interface ToolParamSpec {
  tipo: 'string' | 'number' | 'sistemaId' | 'pessoaId' | 'bool';
  obrigatorio?: boolean;
  descricao?: string;
}

interface ToolDef {
  name: string;
  descricao: string;
  exemplo: string;
  parametros: Record<string, ToolParamSpec>;
}

const TOOLS_CATALOG: ToolDef[] = [
  {
    name: 'criar_ideia',
    descricao: 'Registra uma nova faísca/ideia no banco de ideias.',
    exemplo: '{"titulo":"App de gestão de leads para óticas","descricao":"...","notaImpacto":4,"notaEsforco":3}',
    parametros: {
      titulo: { tipo: 'string', obrigatorio: true, descricao: 'Título curto da ideia.' },
      descricao: { tipo: 'string', descricao: 'Detalhamento opcional.' },
      notaImpacto: { tipo: 'number', descricao: '1 a 5 (impacto esperado).' },
      notaEsforco: { tipo: 'number', descricao: '1 a 5 (esforço pra construir).' },
    },
  },
  {
    name: 'criar_sistema',
    descricao: 'Adiciona um novo sistema/app na bancada (Forja).',
    exemplo: '{"nome":"Otica 360","codinome":"otica-360","estagio":"forja","proposito":"Gestão completa de óticas","stack":"Apps Script, Sheets"}',
    parametros: {
      nome: { tipo: 'string', obrigatorio: true },
      codinome: { tipo: 'string', descricao: 'Slug. Se omitido, é gerado a partir do nome.' },
      estagio: { tipo: 'string', descricao: 'faisca | forja | tempera | prateleira' },
      proposito: { tipo: 'string' },
      stack: { tipo: 'string', descricao: 'Tecnologias separadas por vírgula.' },
      urlProd: { tipo: 'string', descricao: 'URL de produção, se já existir.' },
    },
  },
  {
    name: 'registrar_decisao',
    descricao: 'Adiciona uma decisão arquitetural/de produto à timeline de um sistema.',
    exemplo: '{"sistemaId":"<ID>","titulo":"Adotar OAuth Google","decisao":"...","justificativa":"..."}',
    parametros: {
      sistemaId: { tipo: 'sistemaId', obrigatorio: true },
      titulo: { tipo: 'string', obrigatorio: true },
      decisao: { tipo: 'string', obrigatorio: true, descricao: 'O que foi decidido (1-3 frases).' },
      justificativa: { tipo: 'string', descricao: 'Por quê.' },
    },
  },
  {
    name: 'registrar_risco',
    descricao: 'Lança um risco identificado para um sistema (técnico, operacional, financeiro etc.).',
    exemplo: '{"sistemaId":"<ID>","area":"segurança","descricao":"Sem rate-limit em endpoints de login","gravidade":"alta"}',
    parametros: {
      sistemaId: { tipo: 'sistemaId', obrigatorio: true },
      area: { tipo: 'string', obrigatorio: true, descricao: 'Ex.: segurança, custo, dependência, UX.' },
      descricao: { tipo: 'string', obrigatorio: true },
      gravidade: { tipo: 'string', descricao: 'baixa | media | alta' },
    },
  },
  {
    name: 'registrar_oportunidade',
    descricao: 'Adiciona uma oportunidade comercial à pipeline.',
    exemplo: '{"titulo":"Vender Otica 360 para rede X","pessoaId":"<ID>","valorEstimado":1500,"proximoPasso":"Marcar demo"}',
    parametros: {
      titulo: { tipo: 'string', obrigatorio: true },
      pessoaId: { tipo: 'pessoaId' },
      valorEstimado: { tipo: 'number' },
      proximoPasso: { tipo: 'string' },
    },
  },
  {
    name: 'criar_cobranca',
    descricao: 'Registra um custo recorrente (hospedagem, API, domínio etc.).',
    exemplo: '{"sistemaId":"<ID>","fornecedor":"OpenAI","valor":35,"recorrencia":"mensal","categoria":"api"}',
    parametros: {
      sistemaId: { tipo: 'sistemaId' },
      fornecedor: { tipo: 'string', obrigatorio: true },
      valor: { tipo: 'number', obrigatorio: true },
      recorrencia: { tipo: 'string', descricao: 'mensal | anual | unico' },
      proximaCobranca: { tipo: 'string', descricao: 'Data ISO YYYY-MM-DD.' },
      categoria: { tipo: 'string' },
    },
  },
  {
    name: 'marcar_alertas_lidos',
    descricao: 'Marca todos os alertas pendentes como lidos.',
    exemplo: '{"todos":true}',
    parametros: {
      todos: { tipo: 'bool', descricao: 'Se true, marca todos como lidos.' },
    },
  },
  {
    name: 'gerar_arquivo_md',
    descricao: 'Cria um arquivo .md que o usuário pode baixar e colar no Cursor/Claude/ChatGPT. Use pra entregar backlogs, blueprints, ou instruções de implementação.',
    exemplo: '{"titulo":"backlog-otica360","conteudo":"# Backlog\\n\\n## Próximas tarefas\\n- ..."}',
    parametros: {
      titulo: { tipo: 'string', obrigatorio: true, descricao: 'Nome do arquivo (sem .md, em kebab-case).' },
      conteudo: { tipo: 'string', obrigatorio: true, descricao: 'Conteúdo Markdown completo.' },
    },
  },
];

function listarToolsIA(): ServerResult {
  return { ok: true, data: TOOLS_CATALOG };
}

function _toolsParaPromptLLM(): string {
  const linhas = TOOLS_CATALOG.map((t) => {
    const params = Object.entries(t.parametros).map(([k, v]) => `${k}${v.obrigatorio ? '*' : ''}: ${v.tipo}${v.descricao ? ' — ' + v.descricao : ''}`).join('; ');
    return `- ${t.name}: ${t.descricao}\n  parâmetros: ${params}\n  exemplo: ${t.exemplo}`;
  }).join('\n');
  return linhas;
}

interface ToolCall {
  tool: string;
  params: Record<string, unknown>;
}

function _parseToolCalls(resposta: string): { texto: string; toolCalls: ToolCall[] } {
  const matchOpen = resposta.indexOf('<TOOL_CALLS>');
  if (matchOpen < 0) return { texto: resposta, toolCalls: [] };
  const matchClose = resposta.indexOf('</TOOL_CALLS>', matchOpen);
  if (matchClose < 0) return { texto: resposta, toolCalls: [] };
  const texto = resposta.slice(0, matchOpen).trim();
  const jsonStr = resposta.slice(matchOpen + '<TOOL_CALLS>'.length, matchClose).trim();
  try {
    let parsed: unknown;
    try { parsed = JSON.parse(jsonStr); }
    catch {
      // tenta extrair primeiro [ ... ] do bloco caso o LLM tenha vindo com cercas markdown
      const m = jsonStr.match(/\[[\s\S]*\]/);
      if (!m) return { texto, toolCalls: [] };
      parsed = JSON.parse(m[0]);
    }
    if (!Array.isArray(parsed)) return { texto, toolCalls: [] };
    const calls: ToolCall[] = [];
    for (const item of parsed) {
      if (item && typeof item === 'object' && 'tool' in (item as Record<string, unknown>)) {
        const c = item as Record<string, unknown>;
        calls.push({ tool: String(c.tool), params: (c.params && typeof c.params === 'object') ? c.params as Record<string, unknown> : {} });
      }
    }
    return { texto, toolCalls: calls };
  } catch {
    return { texto, toolCalls: [] };
  }
}

function chatLLMComTools(history: LlmMessage[], sistemaId: string, opts?: { contexto?: 'portfolio' | 'sistema' | 'nenhum'; permitirTools?: boolean; skillIds?: string[]; usarCodex?: boolean }): ServerResult {
  try {
    const modo = opts && opts.contexto ? opts.contexto : (sistemaId ? 'sistema' : 'nenhum');
    let contexto = '';
    if (modo === 'sistema') contexto = buildContextoSistema(sistemaId);
    else if (modo === 'portfolio') contexto = buildContextoPortfolio();

    // Skills aplicadas: carrega o conteúdo de cada skill da biblioteca do user
    // e injeta como bloco "## SKILLS ATIVAS" no system prompt.
    let blocoSkills = '';
    if (opts && opts.skillIds && opts.skillIds.length > 0) {
      const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
      const aplicadas = opts.skillIds
        .map((sid) => linhas.find((l) => String(l.id || '') === sid))
        .filter((x): x is Record<string, unknown> => !!x);
      if (aplicadas.length > 0) {
        const partes = aplicadas.map((sk) => {
          const nome = String(sk.nome || 'Skill');
          const conteudo = String(sk.conteudo || '').trim();
          return `### Skill: ${nome}\n\n${conteudo}`;
        });
        blocoSkills =
          '\n\n## SKILLS ATIVAS\n'
          + 'Estas são instruções/playbooks que o usuário ativou pra esta conversa. '
          + 'Siga-as como diretrizes adicionais ao responder.\n\n'
          + partes.join('\n\n---\n\n');
      }
    }

    const permitirTools = opts ? opts.permitirTools !== false : true;
    const instrucoesTools = permitirTools ? (
      '\n\n## AÇÕES QUE VOCÊ PODE EXECUTAR\n'
      + 'Você pode propor ações reais no sistema. O usuário sempre aprova antes da execução. '
      + 'Use ações SOMENTE quando o pedido do usuário implicar criar/registrar algo concreto, '
      + 'ou quando você claramente identificou um item de backlog/risco que vale a pena salvar. '
      + 'Nunca proponha ações sem o usuário pedir explicitamente, OU sem que você tenha avisado no texto da resposta o que vai propor. '
      + '\n\nFerramentas disponíveis:\n' + _toolsParaPromptLLM()
      + '\n\nQuando quiser propor ações, escreva no FINAL da sua resposta um bloco assim (e somente assim):\n'
      + '<TOOL_CALLS>\n[{"tool":"nome_da_tool","params":{...}}, {"tool":"...","params":{...}}]\n</TOOL_CALLS>\n'
      + 'Regras: (1) o bloco vai SEMPRE no final, (2) JSON válido sem comentários, (3) só inclua tools que existem na lista acima, '
      + '(4) preencha sistemaId/pessoaId com IDs reais do contexto (se disponíveis), (5) NÃO inclua o bloco se não houver ações a propor. '
      + '(6) Use criar_ideia/registrar_risco/registrar_decisao várias vezes num único bloco quando fizer sentido.'
    ) : '';

    // Códex: injeta padrões pessoais como diretrizes adicionais. Default true.
    const codexTxt = opts?.usarCodex !== false ? _buildCodexContext() : '';

    const sistema = getPromptEfetivo('chat') + contexto + blocoSkills + instrucoesTools + codexTxt;
    const messages: LlmMessage[] = [{ role: 'system', content: sistema }];
    for (const m of (history || [])) {
      if (m && (m.role === 'user' || m.role === 'assistant') && m.content) {
        messages.push({ role: m.role, content: String(m.content) });
      }
    }
    const resposta = forjaCallLLM(messages, 3500, undefined, 'chat');
    const parsed = _parseToolCalls(resposta);
    return { ok: true, data: { texto: parsed.texto || resposta, toolCalls: parsed.toolCalls } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao falar com a IA' };
  }
}

// Validação básica de parâmetros contra o schema da tool
function _validarParams(tool: ToolDef, params: Record<string, unknown>): string | null {
  for (const [chave, spec] of Object.entries(tool.parametros)) {
    const v = params[chave];
    if (spec.obrigatorio && (v === undefined || v === null || v === '')) {
      return `Parâmetro obrigatório ausente: ${chave}`;
    }
    if (v !== undefined && v !== null && v !== '') {
      if ((spec.tipo === 'number') && typeof v !== 'number' && isNaN(Number(v))) return `${chave} deve ser número`;
      if ((spec.tipo === 'string' || spec.tipo === 'sistemaId' || spec.tipo === 'pessoaId') && typeof v !== 'string') return `${chave} deve ser texto`;
    }
  }
  return null;
}

function _executarUmaTool(call: ToolCall): { tool: string; ok: boolean; data?: unknown; error?: string; preview: string } {
  const tool = TOOLS_CATALOG.find((t) => t.name === call.tool);
  if (!tool) return { tool: call.tool, ok: false, error: 'Tool desconhecida', preview: '?' };
  const params = call.params || {};
  const erro = _validarParams(tool, params);
  if (erro) return { tool: tool.name, ok: false, error: erro, preview: tool.descricao };

  try {
    switch (tool.name) {
      case 'criar_ideia': {
        const r = dbCreate('Ideias', {
          titulo: String(params.titulo),
          descricao: String(params.descricao || ''),
          notaImpacto: Number(params.notaImpacto || 3),
          notaEsforco: Number(params.notaEsforco || 3),
          estado: 'faisca',
        });
        return { tool: tool.name, ok: true, data: r, preview: `Ideia "${params.titulo}" criada` };
      }
      case 'criar_sistema': {
        const nome = String(params.nome);
        const codinome = String(params.codinome || nome.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''));
        const r = dbCreate('Sistemas', {
          nome, codinome,
          estagio: String(params.estagio || 'forja'),
          proposito: String(params.proposito || ''),
          stack: String(params.stack || ''),
          urlProd: String(params.urlProd || ''),
          scoreSaude: 0,
        });
        return { tool: tool.name, ok: true, data: r, preview: `Sistema "${nome}" criado` };
      }
      case 'registrar_decisao': {
        // Defesa: rejeita sistemaId placeholder vazio/<ID>/undefined pra evitar
        // criar decisão órfã. O FindingCard injeta o sistemaId correto, mas
        // outros chamadores podem não fazer — falhamos loud.
        const sidRaw = String(params.sistemaId || '').trim();
        if (!sidRaw || sidRaw === '<ID>' || sidRaw === 'undefined' || sidRaw === 'null') {
          return { tool: tool.name, ok: false, error: 'sistemaId inválido — não consegui amarrar a decisão a um sistema', preview: '?' };
        }
        // Dedup: re-rodar a auditoria gera findings "zerados" (o vínculo de
        // "já registrado" é por rodada). Sem isso, registrar de novo duplicava
        // cartões. Aqui checamos se já existe item com mesmo sistema + título.
        const tituloNorm = _normDedup(String(params.titulo || ''));
        const decisaoExistente = (dbGetAll('Decisoes') as Array<Record<string, unknown>>).find((d) =>
          String(d.sistemaId || '') === sidRaw && _normDedup(String(d.titulo || '')) === tituloNorm,
        );
        if (decisaoExistente) {
          return { tool: tool.name, ok: true, data: decisaoExistente, preview: `Já existia "${params.titulo}" no backlog — não dupliquei` };
        }
        // Decisões registradas via IA entram como "backlog" — o usuário move
        // pra "fazendo" / "feito" no Kanban quando trabalhar nelas.
        const r = dbCreate('Decisoes', {
          sistemaId: sidRaw,
          data: new Date().toISOString().slice(0, 10),
          titulo: String(params.titulo),
          decisao: String(params.decisao),
          justificativa: String(params.justificativa || ''),
          status: 'backlog',
          prioridade: String(params.prioridade || 'media'),
          tags: String(params.tags || 'auditoria'),
          estimativa: String(params.estimativa || ''),
        });
        return { tool: tool.name, ok: true, data: r, preview: `Decisão "${params.titulo}" registrada no backlog` };
      }
      case 'registrar_risco': {
        const sidRaw = String(params.sistemaId || '').trim();
        if (!sidRaw || sidRaw === '<ID>' || sidRaw === 'undefined' || sidRaw === 'null') {
          return { tool: tool.name, ok: false, error: 'sistemaId inválido — não consegui amarrar o risco a um sistema', preview: '?' };
        }
        const riscoNorm = _normDedup(String(params.area || '') + ' ' + String(params.descricao || ''));
        const riscoExistente = (dbGetAll('Riscos') as Array<Record<string, unknown>>).find((rk) =>
          String(rk.sistemaId || '') === sidRaw && _normDedup(String(rk.area || '') + ' ' + String(rk.descricao || '')) === riscoNorm,
        );
        if (riscoExistente) {
          return { tool: tool.name, ok: true, data: riscoExistente, preview: `Já existia esse risco em "${params.area}" — não dupliquei` };
        }
        const r = dbCreate('Riscos', {
          sistemaId: sidRaw,
          area: String(params.area),
          descricao: String(params.descricao),
          gravidade: String(params.gravidade || 'media'),
          historicoIncidentes: 0,
        });
        return { tool: tool.name, ok: true, data: r, preview: `Risco em "${params.area}" registrado` };
      }
      case 'registrar_oportunidade': {
        const r = dbCreate('Oportunidades', {
          titulo: String(params.titulo),
          pessoaId: String(params.pessoaId || ''),
          valorEstimado: Number(params.valorEstimado || 0),
          estado: 'lead',
          proximoPasso: String(params.proximoPasso || ''),
        });
        return { tool: tool.name, ok: true, data: r, preview: `Oportunidade "${params.titulo}" criada` };
      }
      case 'criar_cobranca': {
        const r = dbCreate('Custos', {
          sistemaId: String(params.sistemaId || ''),
          fornecedor: String(params.fornecedor),
          valor: Number(params.valor),
          recorrencia: String(params.recorrencia || 'mensal'),
          proximaCobranca: String(params.proximaCobranca || ''),
          categoria: String(params.categoria || ''),
        });
        return { tool: tool.name, ok: true, data: r, preview: `Cobrança ${params.fornecedor} R$${params.valor} adicionada` };
      }
      case 'marcar_alertas_lidos': {
        if (params.todos) {
          const r = marcarTodosAlertasLidos();
          return { tool: tool.name, ok: !!r.ok, data: r.data, error: r.error, preview: 'Todos os alertas marcados como lidos' };
        }
        return { tool: tool.name, ok: false, error: 'Especifique todos=true ou uma lista de ids', preview: '?' };
      }
      case 'gerar_arquivo_md': {
        const titulo = String(params.titulo).replace(/[^a-zA-Z0-9-_]/g, '-').replace(/^-|-$/g, '').toLowerCase() || 'arquivo';
        const conteudo = String(params.conteudo);
        return { tool: tool.name, ok: true, data: { filename: titulo + '.md', mime: 'text/markdown', conteudo }, preview: `Arquivo ${titulo}.md gerado (${conteudo.length} caracteres)` };
      }
      default:
        return { tool: tool.name, ok: false, error: 'Execução não implementada', preview: '?' };
    }
  } catch (e: unknown) {
    return { tool: tool.name, ok: false, error: e instanceof Error ? e.message : 'Erro ao executar', preview: '!' };
  }
}

function executarToolsIA(calls: ToolCall[]): ServerResult {
  try {
    if (!Array.isArray(calls) || calls.length === 0) return { ok: false, error: 'Nenhuma ação informada' };
    const resultados = calls.map((c) => _executarUmaTool(c));
    const sucessos = resultados.filter((r) => r.ok).length;
    return { ok: true, data: { resultados, sucessos, falhas: resultados.length - sucessos } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao executar ações' };
  }
}

// ─── Fase 15: Score de Saúde determinístico ──────────────────────────────────
//
// Em vez de pedir pra IA chutar um número, o score é calculado a partir de
// sinais reais e auditáveis. Cada fator contribui um peso e retornamos o
// breakdown completo pra o usuário entender o "por quê" do número.
//
// Fatores (peso = max):
//   Completude:   20 pts (proposito 5 + stack 3 + url/dominio 7 + repo 5)
//   Visibilidade: 20 pts (custos cadastrados 10 + atividade recente 10)
//   Operacional:  30 pts (sem alerta crítico 20 + sem alerta de aviso 10)
//   Riscos:       30 pts (sem risco alta 20 + custo controlado 10)
// Total: 100. Se completude < 8 (sistema vazio), o score é definido como 0
// ("não avaliado") em vez de mostrar um número artificial.

interface FatorSaude {
  nome: string;
  pontos: number;
  max: number;
  ok: boolean;
  detalhe: string;
}

// payloadOverride: quando a auditoria que ACABOU de rodar ainda não foi
// persistida (ex: meio do _executarAuditoriaIncremental), permite passar o
// novo payload diretamente em vez de ler do banco — assim o score já reflete
// os achados recém-reconciliados em vez dos antigos.
function calcularSaudeReal(sistemaId: string, payloadOverride?: { findings?: Array<{ severidade?: string }> } | null): ServerResult {
  try {
    initDatabase();
    const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId);
    if (!sistema) return { ok: false, error: 'Sistema não encontrado' };

    const fatores: FatorSaude[] = [];

    // 1. Completude
    const temProposito = !!(sistema.proposito && String(sistema.proposito).trim().length > 8);
    fatores.push({ nome: 'Tem propósito definido', pontos: temProposito ? 5 : 0, max: 5, ok: temProposito, detalhe: temProposito ? 'Propósito preenchido' : 'Sem propósito — define o "porquê" do sistema' });

    const temStack = !!(sistema.stack && String(sistema.stack).trim());
    fatores.push({ nome: 'Stack catalogada', pontos: temStack ? 3 : 0, max: 3, ok: temStack, detalhe: temStack ? String(sistema.stack) : 'Stack vazia — útil pra filtros e snapshots' });

    const temUrl = !!(sistema.urlProd || sistema.dominioCustomizado || sistema.webAppUrl);
    fatores.push({ nome: 'Está acessível (URL ou domínio)', pontos: temUrl ? 7 : 0, max: 7, ok: temUrl, detalhe: temUrl ? String(sistema.dominioCustomizado || sistema.urlProd || sistema.webAppUrl) : 'Sem URL de produção nem domínio próprio' });

    const temRepo = !!sistema.repoUrl;
    fatores.push({ nome: 'Tem repositório versionado', pontos: temRepo ? 5 : 0, max: 5, ok: temRepo, detalhe: temRepo ? String(sistema.repoUrl) : 'Sem repositório — código não rastreável' });

    // 2. Visibilidade financeira/operacional
    const custos = (dbGetAll('Custos') as Array<Record<string, unknown>>).filter((c) => String(c.sistemaId || '') === sistemaId);
    const temCustos = custos.length > 0;
    fatores.push({ nome: 'Custos cadastrados', pontos: temCustos ? 10 : 0, max: 10, ok: temCustos, detalhe: temCustos ? `${custos.length} item(s)` : 'Sem custos — você não sabe quanto este sistema te dá de prejuízo' });

    const trintaDias = Date.now() - 30 * 86400000;
    const timeline = (dbGetAll('Timeline') as Array<Record<string, unknown>>).filter((t) => String(t.sistemaId || '') === sistemaId);
    const eventosRecentes = timeline.filter((t) => {
      const d = new Date(String(t.data || '')).getTime();
      return !Number.isNaN(d) && d >= trintaDias;
    }).length;
    // Um pulso verificado recentemente (mesmo respondendo OK) conta como sinal de
    // vida — não só os incidentes da timeline. Isso alinha o fator com o que o
    // usuário espera: "monitorei a URL e ela responde" = sistema ativo.
    const pulsosSistema = (dbGetAll('Pulsos') as Array<Record<string, unknown>>).filter((p) => String(p.sistemaId || '') === sistemaId);
    const pulsoRecente = pulsosSistema.some((p) => {
      const d = new Date(String(p.verificadoEm || '')).getTime();
      return !Number.isNaN(d) && d >= trintaDias;
    });
    const ativo = eventosRecentes > 0 || pulsoRecente;
    const detalheAtividade = eventosRecentes > 0
      ? `${eventosRecentes} evento(s) na timeline`
      : pulsoRecente
        ? 'Pulso monitorado respondendo (verificado recentemente)'
        : 'Nenhum pulso/decisão/incidente recente — o sistema pode estar parado';
    fatores.push({ nome: 'Atividade nos últimos 30 dias', pontos: ativo ? 10 : 0, max: 10, ok: ativo, detalhe: detalheAtividade });

    // 3. Alertas em aberto
    const alertas = (dbGetAll('Alertas') as Array<Record<string, unknown>>).filter((a) => {
      if (String(a.dismissed || '').toLowerCase() === 'true') return false;
      if (String(a.lido || '').toLowerCase() === 'true') return false;
      const meta = String(a.metadata || a.mensagem || '');
      return meta.indexOf(sistemaId) >= 0 || String(a.sistemaId || '') === sistemaId;
    });
    const criticos = alertas.filter((a) => String(a.severidade) === 'critico').length;
    const avisos = alertas.filter((a) => String(a.severidade) === 'aviso').length;

    const semCritico = criticos === 0;
    fatores.push({ nome: 'Sem alertas críticos abertos', pontos: semCritico ? 20 : Math.max(0, 20 - criticos * 10), max: 20, ok: semCritico, detalhe: semCritico ? 'Tudo certo' : `${criticos} alerta(s) crítico(s) pendente(s)` });

    const semAviso = avisos === 0;
    fatores.push({ nome: 'Sem alertas de aviso abertos', pontos: semAviso ? 10 : Math.max(0, 10 - avisos * 3), max: 10, ok: semAviso, detalhe: semAviso ? 'Sem avisos' : `${avisos} aviso(s) pendente(s)` });

    // 4. Riscos e financeiro
    const riscos = (dbGetAll('Riscos') as Array<Record<string, unknown>>).filter((r) => String(r.sistemaId || '') === sistemaId && _riscoAtivo(r));
    const riscosAlta = riscos.filter((r) => String(r.gravidade).toLowerCase() === 'alta').length;
    const semRiscoAlta = riscosAlta === 0;
    fatores.push({ nome: 'Sem riscos de gravidade alta', pontos: semRiscoAlta ? 20 : Math.max(0, 20 - riscosAlta * 7), max: 20, ok: semRiscoAlta, detalhe: semRiscoAlta ? `${riscos.length} risco(s) total, nenhum alta` : `${riscosAlta} risco(s) de gravidade alta` });

    const custoMensal = custos.reduce((acc, c) => {
      const rec = String(c.recorrencia || '').toLowerCase();
      const v = Number(c.valor || 0);
      if (rec.indexOf('mensal') >= 0 || rec.indexOf('mes') >= 0) return acc + v;
      if (rec.indexOf('anual') >= 0) return acc + v / 12;
      return acc;
    }, 0);
    const receitas = (dbGetAll('Receitas') as Array<Record<string, unknown>>).filter((r) => String(r.sistemaId || '') === sistemaId);
    const mrr = receitas.reduce((acc, r) => {
      const rec = String(r.recorrencia || '').toLowerCase();
      const status = String(r.status || '').toLowerCase();
      if (status === 'cancelada' || status === 'cancelado') return acc;
      const v = Number(r.valor || 0);
      if (rec.indexOf('mensal') >= 0 || rec.indexOf('mes') >= 0) return acc + v;
      if (rec.indexOf('anual') >= 0) return acc + v / 12;
      return acc;
    }, 0);

    let detalheCusto: string;
    let pontosCusto: number;
    let okCusto: boolean;
    if (custoMensal === 0 && mrr === 0) {
      detalheCusto = 'Sem custos nem receitas — neutro';
      pontosCusto = 10; // não penaliza quem não cadastrou nada
      okCusto = true;
    } else if (custoMensal === 0) {
      detalheCusto = `Custo zero · MRR ${_fmtBRL(mrr)}`;
      pontosCusto = 10;
      okCusto = true;
    } else if (mrr >= custoMensal) {
      detalheCusto = `MRR ${_fmtBRL(mrr)} cobre custo ${_fmtBRL(custoMensal)}`;
      pontosCusto = 10;
      okCusto = true;
    } else if (mrr > 0) {
      detalheCusto = `MRR ${_fmtBRL(mrr)} insuficiente pro custo ${_fmtBRL(custoMensal)}`;
      pontosCusto = 5;
      okCusto = false;
    } else {
      detalheCusto = `Custo ${_fmtBRL(custoMensal)}/mês sem receita`;
      pontosCusto = 0;
      okCusto = false;
    }
    fatores.push({ nome: 'Equilíbrio custo × receita', pontos: pontosCusto, max: 10, ok: okCusto, detalhe: detalheCusto });

    // 5. Achados de auditoria em aberto — fechar achados sobe o score, MAS
    // de forma proporcional. Premissas do balanceamento (v2):
    // - Todo sistema saudável tem 1-2 TODOs naturais → SOFT CAP: os 2 primeiros
    //   achados de baixa/média SÃO PERDOADOS (não penalizam).
    // - Achados altos sempre pesam (são vulnerabilidades/quebras reais).
    // - Penalizações suaves: 1 alta = -3, 1 média = -1, 1 baixa = -0.5.
    // - Peso total reduzido de 15 → 10 pts (achados influenciam, não dominam).
    // Resultado: sistema com 0-2 achados leves continua "saudável" (80+).
    // Sistema com 1 alta + 4 médias + 1 baixa fica na faixa de "atenção" (~70).
    const MAX_ACHADOS = 10;
    const SOFT_CAP_LEVES = 2;
    let pontosAchados = MAX_ACHADOS;
    let detalheAchados = 'Sem auditoria anterior';
    let okAchados = true;
    let payloadParaScore: { findings?: Array<{ severidade?: string }> } | null = payloadOverride || null;
    if (!payloadParaScore) {
      const auditorias = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
        .filter((a) => String(a.sistemaId || '') === sistemaId)
        .sort((a, b) => String(b.criadoEm).localeCompare(String(a.criadoEm)));
      if (auditorias.length > 0) {
        try {
          payloadParaScore = JSON.parse(String(auditorias[0].payloadJson || '{}')) as { findings?: Array<{ severidade?: string }> };
        } catch {
          payloadParaScore = null;
          detalheAchados = 'Última auditoria sem payload legível';
        }
      }
    }
    if (payloadParaScore) {
      try {
        const findings = Array.isArray(payloadParaScore.findings) ? payloadParaScore.findings : [];
        const altas = findings.filter((f) => String(f.severidade || '').toLowerCase() === 'alta').length;
        const medias = findings.filter((f) => String(f.severidade || '').toLowerCase() === 'media').length;
        const baixas = findings.filter((f) => String(f.severidade || '').toLowerCase() === 'baixa').length;

        // Soft cap: perdoa os 2 primeiros achados leves (baixa primeiro, depois média).
        let baixasPunidas = baixas;
        let mediasPunidas = medias;
        let perdoadosRestantes = SOFT_CAP_LEVES;
        const perdoarBaixas = Math.min(baixasPunidas, perdoadosRestantes);
        baixasPunidas -= perdoarBaixas;
        perdoadosRestantes -= perdoarBaixas;
        if (perdoadosRestantes > 0) {
          const perdoarMedias = Math.min(mediasPunidas, perdoadosRestantes);
          mediasPunidas -= perdoarMedias;
        }

        // Penalizações suaves (cap por severidade pra não estourar a escala).
        const penalAlta = Math.min(altas, 3) * 3;          // até -9
        const penalMedia = Math.min(mediasPunidas, 4) * 1; // até -4
        const penalBaixa = Math.min(baixasPunidas, 3) * 1; // até -3 (raro: precisa 5+ baixas após o soft cap)
        pontosAchados = Math.max(0, MAX_ACHADOS - penalAlta - penalMedia - penalBaixa);

        const totalReais = altas + medias + baixas;
        const totalPunidos = altas + mediasPunidas + baixasPunidas;
        okAchados = totalReais === 0;
        const partes: string[] = [];
        if (altas > 0) partes.push(`${altas} alta${altas === 1 ? '' : 's'}`);
        if (medias > 0) partes.push(`${medias} média${medias === 1 ? '' : 's'}`);
        if (baixas > 0) partes.push(`${baixas} baixa${baixas === 1 ? '' : 's'}`);
        const perdoadosQtd = totalReais - totalPunidos;
        const sufixo = perdoadosQtd > 0 ? ` · ${perdoadosQtd} perdoado${perdoadosQtd === 1 ? '' : 's'} (soft cap)` : '';
        detalheAchados = okAchados
          ? 'Sem achados em aberto na última auditoria'
          : `${partes.join(', ')} em aberto${sufixo}`;
      } catch {
        detalheAchados = 'Última auditoria sem payload legível';
      }
    }
    fatores.push({ nome: 'Achados de auditoria em aberto', pontos: pontosAchados, max: MAX_ACHADOS, ok: okAchados, detalhe: detalheAchados });

    const completude = fatores.slice(0, 4).reduce((acc, f) => acc + f.pontos, 0);
    const totalPontos = fatores.reduce((acc, f) => acc + f.pontos, 0);
    const maxPossivel = fatores.reduce((acc, f) => acc + f.max, 0);

    // Normaliza 0-100 (max agora é 115 com o fator novo de achados).
    // Sistemas muito vazios continuam marcados como "não avaliados" (score=0).
    const score = completude < 8 ? 0 : Math.round((totalPontos / maxPossivel) * 100);

    return {
      ok: true,
      data: {
        score,
        fatores,
        calculadoEm: new Date().toISOString(),
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao calcular saúde' };
  }
}

function atualizarSaudeReal(sistemaId: string): ServerResult {
  try {
    const r = calcularSaudeReal(sistemaId);
    if (!r.ok || !r.data) return r;
    const breakdown = r.data as { score: number; fatores: FatorSaude[]; calculadoEm: string };
    dbUpdate('Sistemas', sistemaId, {
      scoreSaude: breakdown.score,
      saudeBreakdown: JSON.stringify(breakdown.fatores),
      saudeCalculadaEm: breakdown.calculadoEm,
    });
    return { ok: true, data: breakdown };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao atualizar saúde' };
  }
}

function recalcularSaudeTodosSistemas(): ServerResult {
  try {
    const sistemas = dbGetAll('Sistemas');
    let avaliados = 0;
    let naoAvaliados = 0;
    for (const s of sistemas) {
      const r = atualizarSaudeReal(String(s.id));
      if (r.ok && r.data) {
        const d = r.data as { score: number };
        if (d.score > 0) avaliados++; else naoAvaliados++;
      }
    }
    return { ok: true, data: { total: sistemas.length, avaliados, naoAvaliados } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// ─── Fase 15: Auditoria Forja IA ─────────────────────────────────────────────
//
// Reaproveita toda a infra de tool-calling da Fase 14. Monta um contexto
// profundo do sistema (descrição, stack, custos, decisões prévias, riscos
// abertos, alertas, atividade) e instrui a IA a propor concretamente:
// vulnerabilidades (registrar_risco), correções (registrar_decisao),
// oportunidades de features (registrar_oportunidade) e um arquivo .md de
// backlog pra colar na IA de desenvolvimento.

function _contextoSistemaProfundo(sistemaId: string): string {
  const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId);
  if (!sistema) return '(sistema não encontrado)';
  const custos = (dbGetAll('Custos') as Array<Record<string, unknown>>).filter((c) => String(c.sistemaId || '') === sistemaId);
  const decisoes = (dbGetAll('Decisoes') as Array<Record<string, unknown>>).filter((d) => String(d.sistemaId || '') === sistemaId);
  const riscos = (dbGetAll('Riscos') as Array<Record<string, unknown>>).filter((r) => String(r.sistemaId || '') === sistemaId);
  const oportunidades = dbGetAll('Oportunidades') as Array<Record<string, unknown>>;
  const timeline = (dbGetAll('Timeline') as Array<Record<string, unknown>>).filter((t) => String(t.sistemaId || '') === sistemaId).slice(-15);
  const alertas = (dbGetAll('Alertas') as Array<Record<string, unknown>>).filter((a) => String(a.sistemaId || '') === sistemaId || String(a.metadata || '').indexOf(sistemaId) >= 0);

  const linhas: string[] = [];
  linhas.push('## SISTEMA');
  linhas.push(`- id: ${sistema.id}`);
  linhas.push(`- nome: ${sistema.nome}`);
  linhas.push(`- codinome: ${sistema.codinome}`);
  linhas.push(`- estagio: ${sistema.estagio}`);
  linhas.push(`- proposito: ${sistema.proposito || '(vazio)'}`);
  linhas.push(`- stack: ${sistema.stack || '(vazio)'}`);
  linhas.push(`- urlProd: ${sistema.urlProd || '(vazio)'}`);
  linhas.push(`- dominioCustomizado: ${sistema.dominioCustomizado || '(vazio)'}`);
  linhas.push(`- repoUrl: ${sistema.repoUrl || '(vazio)'}`);
  linhas.push(`- scriptId: ${sistema.scriptId || '(vazio)'}`);
  linhas.push(`- scoreSaude atual: ${sistema.scoreSaude || 0}`);

  linhas.push('\n## CUSTOS (' + custos.length + ')');
  for (const c of custos.slice(0, 15)) linhas.push(`- ${c.fornecedor}: R$${c.valor} ${c.recorrencia || ''}`);

  linhas.push('\n## DECISÕES PRÉVIAS (' + decisoes.length + ')');
  for (const d of decisoes.slice(-10)) linhas.push(`- [${d.data}] ${d.titulo}: ${d.decisao}`);

  linhas.push('\n## RISCOS ABERTOS (' + riscos.length + ')');
  for (const r of riscos) linhas.push(`- (${r.gravidade}) ${r.area}: ${r.descricao}`);

  linhas.push('\n## ALERTAS RECENTES (' + alertas.length + ')');
  for (const a of alertas.slice(-10)) linhas.push(`- [${a.severidade}] ${a.titulo}: ${a.mensagem}`);

  linhas.push('\n## TIMELINE (últimos eventos)');
  for (const t of timeline) linhas.push(`- [${t.data}] (${t.tipo}) ${t.texto}`);

  linhas.push('\n## OPORTUNIDADES EXISTENTES NO PORTFÓLIO (' + oportunidades.length + ')');
  for (const o of oportunidades.slice(-8)) linhas.push(`- ${o.titulo}`);

  return linhas.join('\n');
}

// ─── Auditoria refinada (Fase 15.1) ──────────────────────────────────────────
//
// A IA agora retorna achados ESTRUTURADOS em JSON, cada um com:
// - problema (sintoma)
// - evidência (referência exata ao dado do contexto, pra rastreabilidade)
// - solução (passos práticos)
// - prompt (texto pronto pra colar no Cursor/Claude)
// - tool sugerida (registrar_risco/decisao/oportunidade) que o usuário aprova
// individualmente
//
// Também retornamos as "fontes consultadas" — contagem real de cada tabela
// que foi enviada à IA, pra o usuário saber sobre o que ela tem visibilidade.

/*! DEBT(arquitetura,media): AuditFontes está duplicada entre types.ts e server.ts — toda extensão precisa ser feita em 2 lugares (já mordeu na v1.147 com batchesUsados). Extrair pra source-of-truth única quando reorganizarmos o backend em módulos. */
interface AuditFontes {
  custos: number;
  decisoes: number;
  riscos: number;
  alertas: number;
  timeline: number;
  oportunidades: number;
  temProposito: boolean;
  temStack: boolean;
  temUrl: boolean;
  temRepo: boolean;
  modo?: 'governanca' | 'codigo' | 'completa';
  fonteCodigo?: 'github' | 'gas' | '';
  arquivosLidos?: number;
  bytesCodigo?: number;
  commitSha?: string;
  codigoTruncado?: boolean;
  codigoErro?: string;
  // Auditoria incremental (Fase 2.5): rodou só sobre o diff desde a última auditoria.
  incremental?: boolean;
  baseCommit?: string;
  // Chunking de diff (v1.147): batches usados, arquivos ignorados pelo cap global,
  // arquivos que foram splitted em janelas. Espelho de AuditFontes em types.ts.
  batchesUsados?: number;
  arquivosIgnorados?: string[];
  arquivosSplitted?: string[];
  // Auditoria de onboarding: sistema sem dados — devolvemos checklist (sem IA).
  onboarding?: boolean;
}

function _coletarFontesAuditoria(sistemaId: string): AuditFontes {
  const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId) || {};
  const custos = (dbGetAll('Custos') as Array<Record<string, unknown>>).filter((c) => String(c.sistemaId || '') === sistemaId);
  const decisoes = (dbGetAll('Decisoes') as Array<Record<string, unknown>>).filter((d) => String(d.sistemaId || '') === sistemaId);
  const riscos = (dbGetAll('Riscos') as Array<Record<string, unknown>>).filter((r) => String(r.sistemaId || '') === sistemaId && _riscoAtivo(r));
  const alertas = (dbGetAll('Alertas') as Array<Record<string, unknown>>).filter((a) => String(a.sistemaId || '') === sistemaId || String(a.metadata || '').indexOf(sistemaId) >= 0);
  const timeline = (dbGetAll('Timeline') as Array<Record<string, unknown>>).filter((t) => String(t.sistemaId || '') === sistemaId);
  const oportunidades = dbGetAll('Oportunidades') as Array<Record<string, unknown>>;
  return {
    custos: custos.length,
    decisoes: decisoes.length,
    riscos: riscos.length,
    alertas: alertas.length,
    timeline: timeline.length,
    oportunidades: oportunidades.length,
    temProposito: !!(sistema.proposito && String(sistema.proposito).trim().length > 8),
    temStack: !!(sistema.stack && String(sistema.stack).trim()),
    temUrl: !!(sistema.urlProd || sistema.dominioCustomizado || sistema.webAppUrl),
    temRepo: !!sistema.repoUrl,
  };
}

// ─── Leitura de CÓDIGO pra auditoria (Fase 1) ────────────────────────────────
//
// A auditoria de governança lê só os metadados da Forja. Aqui a gente abre o
// repositório de verdade (GitHub via repoUrl, ou projeto GAS via scriptId) e
// monta um contexto de código CURADO dentro de um orçamento — porque um repo
// inteiro não cabe num prompt nem nos 6 min do Apps Script.

interface CodigoContexto {
  contexto: string;
  fonte: 'github' | 'gas' | '';
  arquivos: number;
  bytes: number;
  commitSha: string;
  truncado: boolean;
  erro?: string;
}

// Orçamento conservador: o suficiente pra dar visão real sem estourar tokens/tempo.
const _CODE_MAX_ARQUIVOS = 28;
const _CODE_MAX_BYTES_TOTAL = 110000;
const _CODE_MAX_BYTES_ARQUIVO = 15000;

const _CODE_IGNORE_DIR = /(^|\/)(node_modules|dist|build|out|coverage|vendor|\.git|\.next|\.cache|tmp|__pycache__|target|bin|obj|Pods|\.venv|venv|\.idea|\.vscode)(\/|$)/i;
const _CODE_IGNORE_FILE = /(\.lock$|package-lock\.json$|yarn\.lock$|pnpm-lock\.yaml$|\.min\.(js|css)$|\.map$|\.(png|jpe?g|gif|svg|ico|webp|pdf|zip|gz|tar|woff2?|ttf|eot|mp4|mp3|mov|bmp|icns)$)/i;
const _CODE_ALLOW_EXT = /\.(ts|tsx|js|jsx|mjs|cjs|py|go|rb|java|kt|kts|rs|php|cs|swift|c|cc|cpp|h|hpp|sql|sh|bash|vue|svelte|yml|yaml|toml|gradle|md|json)$/i;

// Só inclui JSON/MD que sejam "úteis" pra auditoria (manifestos/configs/README),
// pra não despejar fixtures e dumps gigantes no contexto.
function _codeArquivoRelevante(path: string, size: number): boolean {
  if (_CODE_IGNORE_DIR.test(path)) return false;
  if (_CODE_IGNORE_FILE.test(path)) return false;
  if (size > 400000) return false; // arquivo gigante: ignora (provável gerado)
  const base = path.split('/').pop() || path;
  if (/\.json$/i.test(base)) {
    return /^(package\.json|tsconfig.*\.json|.*\.config\.json|appsscript\.json|composer\.json|.*\.csproj)$/i.test(base);
  }
  if (/\.md$/i.test(base)) return /readme|contributing|architecture|security/i.test(base);
  return _CODE_ALLOW_EXT.test(base);
}

// Prioriza âncoras (manifestos, configs, entrypoints, src) pra caber o que mais
// informa primeiro. Menor = melhor desempate (cabe mais arquivo no orçamento).
function _codePrioridade(path: string): number {
  const base = (path.split('/').pop() || path).toLowerCase();
  if (/readme/i.test(base)) return 100;
  if (/^(package\.json|requirements\.txt|go\.mod|cargo\.toml|pom\.xml|build\.gradle|gemfile|composer\.json|pyproject\.toml)$/i.test(base) || /\.csproj$/i.test(base)) return 95;
  if (/^(tsconfig|.*\.config\.|\.eslintrc|vite\.|webpack\.|next\.|rollup\.|babel\.|dockerfile|docker-compose)/i.test(base)) return 90;
  if (/^appsscript\.json$/i.test(base)) return 88;
  if (/(^|\/)\.github\/workflows\//i.test(path)) return 86;
  if (/^(index|main|app|server)\.(t|j)sx?$/i.test(base)) return 80;
  if (/^src\//i.test(path)) return 60;
  if (path.indexOf('/') < 0) return 50; // arquivo na raiz
  return 30;
}

interface _CodeFileRef { path: string; size: number; sha?: string }

function _codeSelecionar(files: _CodeFileRef[]): _CodeFileRef[] {
  const ordenado = files
    .filter((f) => _codeArquivoRelevante(f.path, f.size))
    .sort((a, b) => (_codePrioridade(b.path) - _codePrioridade(a.path)) || (a.size - b.size));
  const out: _CodeFileRef[] = [];
  let bytes = 0;
  for (const f of ordenado) {
    if (out.length >= _CODE_MAX_ARQUIVOS) break;
    if (bytes >= _CODE_MAX_BYTES_TOTAL) break;
    out.push(f);
    bytes += Math.min(f.size || 0, _CODE_MAX_BYTES_ARQUIVO);
  }
  return out;
}

function _codeBloco(path: string, conteudo: string): { texto: string; bytes: number; truncado: boolean } {
  let c = String(conteudo || '');
  let truncado = false;
  if (c.length > _CODE_MAX_BYTES_ARQUIVO) {
    c = c.slice(0, _CODE_MAX_BYTES_ARQUIVO) + '\n… [arquivo truncado para a auditoria]';
    truncado = true;
  }
  const ext = (path.split('.').pop() || '').toLowerCase();
  return { texto: `\n### ${path}\n\`\`\`${ext}\n${c}\n\`\`\`\n`, bytes: c.length, truncado };
}

// Resolve "owner/repo" a partir de uma URL ou nome completo.
function _ghFullName(repoUrl: string): string {
  let full = String(repoUrl || '').trim();
  const m = full.match(/github\.com\/([^/]+\/[^/?#]+)/);
  if (m) full = m[1];
  return full.replace(/\.git$/, '').replace(/^\/+|\/+$/g, '');
}

function _lerCodigoGitHub(repoUrl: string): CodigoContexto {
  const vazio: CodigoContexto = { contexto: '', fonte: 'github', arquivos: 0, bytes: 0, commitSha: '', truncado: false };
  const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
  if (!token) return { ...vazio, erro: 'GitHub não conectado (sem token em Configurações).' };
  const full = _ghFullName(repoUrl);
  if (!/^[^/]+\/[^/]+$/.test(full)) return { ...vazio, erro: 'repoUrl inválida (use https://github.com/owner/repo).' };

  const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };
  try {
    const repoRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}`, { headers, muteHttpExceptions: true });
    if (repoRes.getResponseCode() !== 200) return { ...vazio, erro: `GitHub respondeu ${repoRes.getResponseCode()} ao abrir o repo.` };
    const branch = String((JSON.parse(repoRes.getContentText()) as { default_branch?: string }).default_branch || 'main');

    // Commit sha do HEAD do branch (de verdade — não a tree sha). É o que o
    // diff/compare da Fase 2 usa pra saber se o repo mudou desde a última auditoria.
    let commitSha = '';
    try {
      const commitRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/commits/${encodeURIComponent(branch)}`, { headers, muteHttpExceptions: true });
      if (commitRes.getResponseCode() === 200) commitSha = String((JSON.parse(commitRes.getContentText()) as { sha?: string }).sha || '');
    } catch { /* segue com tree sha como fallback */ }

    const treeRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/git/trees/${encodeURIComponent(branch)}?recursive=1`, { headers, muteHttpExceptions: true });
    if (treeRes.getResponseCode() !== 200) return { ...vazio, erro: `Não consegui ler a árvore do repo (${treeRes.getResponseCode()}).` };
    const treeJson = JSON.parse(treeRes.getContentText()) as { sha?: string; tree?: Array<{ path: string; type: string; size?: number; sha: string }> };
    const headSha = String(commitSha || treeJson.sha || '');
    const blobs = (treeJson.tree || []).filter((n) => n.type === 'blob');
    const refs: _CodeFileRef[] = blobs.map((n) => ({ path: n.path, size: n.size || 0, sha: n.sha }));
    const selecionados = _codeSelecionar(refs);
    if (selecionados.length === 0) return { ...vazio, commitSha: headSha.slice(0, 7), erro: 'Nenhum arquivo de código auditável encontrado.' };

    // Cache por SHA de blob (content-addressed: muda o arquivo → muda o SHA →
    // invalida sozinho). Re-runs dentro de 6h não rebaixam blobs já vistos.
    const cache = CacheService.getScriptCache();
    const conteudos: Record<string, string> = {};
    const cacheKeys = selecionados.map((f) => 'fcode:' + f.sha);
    let cacheados: Record<string, string | null> = {};
    try { cacheados = cache.getAll(cacheKeys) as Record<string, string | null>; } catch { cacheados = {}; }

    const aBuscar = selecionados.filter((f) => {
      const hit = cacheados['fcode:' + f.sha];
      if (typeof hit === 'string') { conteudos[String(f.sha)] = hit; return false; }
      return true;
    });

    // fetchAll: baixa em paralelo só os blobs que faltam no cache.
    if (aBuscar.length > 0) {
      const requests = aBuscar.map((f) => ({ url: `https://api.github.com/repos/${full}/git/blobs/${f.sha}`, headers, muteHttpExceptions: true }));
      const respostas = UrlFetchApp.fetchAll(requests);
      const novos: Record<string, string> = {};
      for (let i = 0; i < respostas.length; i++) {
        const r = respostas[i];
        if (r.getResponseCode() !== 200) continue;
        const j = JSON.parse(r.getContentText()) as { content?: string; encoding?: string };
        if (j.encoding !== 'base64' || !j.content) continue;
        let conteudo = '';
        try { conteudo = Utilities.newBlob(Utilities.base64Decode(j.content.replace(/\n/g, ''))).getDataAsString(); } catch { continue; }
        const sha = String(aBuscar[i].sha);
        conteudos[sha] = conteudo;
        // CacheService limita 100KB/valor; só cacheia o que cabe (nosso teto por
        // arquivo já é 15KB, então na prática sempre cabe).
        if (conteudo.length <= 100000) novos['fcode:' + sha] = conteudo;
      }
      try { if (Object.keys(novos).length > 0) cache.putAll(novos, 21600); } catch { /* cache best-effort */ }
    }

    const partes: string[] = [];
    let bytes = 0; let truncadoGeral = false; let lidos = 0;
    for (const f of selecionados) {
      const conteudo = conteudos[String(f.sha)];
      if (typeof conteudo !== 'string') continue;
      const bloco = _codeBloco(f.path, conteudo);
      partes.push(bloco.texto);
      bytes += bloco.bytes; lidos++;
      if (bloco.truncado) truncadoGeral = true;
      if (bytes >= _CODE_MAX_BYTES_TOTAL) { truncadoGeral = true; break; }
    }

    const cabecalho = `Repositório GitHub: ${full} (branch ${branch}, commit ${headSha.slice(0, 7)})\nArquivos lidos: ${lidos} (de ${blobs.length} no repo) · ~${Math.round(bytes / 1024)}KB${truncadoGeral ? ' · amostra truncada pelo orçamento' : ''}\n`;
    return { contexto: cabecalho + partes.join(''), fonte: 'github', arquivos: lidos, bytes, commitSha: headSha.slice(0, 7), truncado: truncadoGeral };
  } catch (e: unknown) {
    return { ...vazio, erro: e instanceof Error ? e.message : 'Erro ao ler GitHub' };
  }
}

function _lerCodigoGAS(scriptId: string): CodigoContexto {
  const vazio: CodigoContexto = { contexto: '', fonte: 'gas', arquivos: 0, bytes: 0, commitSha: '', truncado: false };
  const sid = String(scriptId || '').trim();
  if (!sid) return { ...vazio, erro: 'Sistema sem scriptId.' };
  try {
    const token = ScriptApp.getOAuthToken();
    const res = UrlFetchApp.fetch(`https://script.googleapis.com/v1/projects/${encodeURIComponent(sid)}/content`, {
      headers: { Authorization: 'Bearer ' + token },
      muteHttpExceptions: true,
    });
    const code = res.getResponseCode();
    if (code === 403) return { ...vazio, erro: 'Apps Script API desativada. Ative em script.google.com/home/usersettings.' };
    if (code !== 200) return { ...vazio, erro: `Apps Script API respondeu ${code}.` };
    const json = JSON.parse(res.getContentText()) as { files?: Array<{ name: string; type: string; source?: string }> };
    const arquivos = json.files || [];
    if (arquivos.length === 0) return { ...vazio, erro: 'Projeto GAS sem arquivos legíveis.' };

    // Mapeia pra "path" com extensão (SERVER_JS→.gs, HTML→.html, JSON→.json).
    const refs: _CodeFileRef[] = arquivos.map((f) => {
      const ext = f.type === 'HTML' ? 'html' : f.type === 'JSON' ? 'json' : 'gs';
      return { path: `${f.name}.${ext}`, size: (f.source || '').length };
    });
    const ordenado = refs.sort((a, b) => (_codePrioridade(b.path) - _codePrioridade(a.path)) || (a.size - b.size)).slice(0, _CODE_MAX_ARQUIVOS);

    const partes: string[] = [];
    let bytes = 0; let truncadoGeral = false; let lidos = 0;
    for (const ref of ordenado) {
      const nomeBase = ref.path.replace(/\.(gs|html|json)$/i, '');
      const orig = arquivos.find((f) => f.name === nomeBase);
      const bloco = _codeBloco(ref.path, orig?.source || '');
      partes.push(bloco.texto);
      bytes += bloco.bytes; lidos++;
      if (bloco.truncado) truncadoGeral = true;
      if (bytes >= _CODE_MAX_BYTES_TOTAL) { truncadoGeral = true; break; }
    }
    const cabecalho = `Projeto Google Apps Script (scriptId ${sid.slice(0, 10)}…)\nArquivos lidos: ${lidos} de ${arquivos.length} · ~${Math.round(bytes / 1024)}KB${truncadoGeral ? ' · amostra truncada pelo orçamento' : ''}\n`;
    return { contexto: cabecalho + partes.join(''), fonte: 'gas', arquivos: lidos, bytes, commitSha: '', truncado: truncadoGeral };
  } catch (e: unknown) {
    return { ...vazio, erro: e instanceof Error ? e.message : 'Erro ao ler projeto GAS' };
  }
}

// Escolhe a melhor fonte de código disponível pro sistema. GitHub tem prioridade
// (mais rico: histórico, configs); GAS entra quando não há repoUrl.
function _lerCodigoSistema(sistema: Record<string, unknown>): CodigoContexto | null {
  const repoUrl = String(sistema.repoUrl || '').trim();
  const scriptId = String(sistema.scriptId || '').trim();
  if (repoUrl) return _lerCodigoGitHub(repoUrl);
  if (scriptId) return _lerCodigoGAS(scriptId);
  return null;
}

// Última auditoria de um sistema (linha mais recente) + o commit que foi auditado
// (lido do fontesJson). Base do incremental: se o HEAD do repo == este commit,
// nada mudou e não vale gastar LLM.
function _ultimaAuditoriaCommit(sistemaId: string): { auditoria: Record<string, unknown> | null; commit: string } {
  const auditorias = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
    .filter((a) => String(a.sistemaId || '') === sistemaId)
    .sort((a, b) => String(b.criadoEm || '').localeCompare(String(a.criadoEm || '')));
  if (auditorias.length === 0) return { auditoria: null, commit: '' };
  let commit = '';
  try { commit = String((JSON.parse(String(auditorias[0].fontesJson || '{}')) as { commitSha?: string }).commitSha || ''); } catch { commit = ''; }
  return { auditoria: auditorias[0], commit };
}

// HEAD commit sha (curto, 7) do branch padrão de um repo GitHub. 1 call barata.
function _ghHeadCommitCurto(full: string, headers: Record<string, string>): string {
  try {
    const res = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/commits?per_page=1`, { headers, muteHttpExceptions: true });
    if (res.getResponseCode() !== 200) return '';
    const arr = JSON.parse(res.getContentText()) as Array<{ sha?: string }>;
    return arr && arr[0] && arr[0].sha ? String(arr[0].sha).slice(0, 7) : '';
  } catch { return ''; }
}

interface DiffContexto {
  contexto: string;
  arquivos: number;
  bytes: number;
  baseCommit: string;
  headCommit: string;
  truncado: boolean;
  lista: string[];
  erro?: string;
}

// ─── Chunking de diff (v1.147 — resolve DIFF TRUNCADO) ────────────────────────
//
// Antes: 1 chamada LLM com diff inteiro → estoura limites → trunca silenciosamente.
// Agora: diff fatiado em batches que cabem na janela do modelo, LLM por batch,
// achados fundidos com dedup, narrativa final consolidada em chamada extra.
//
// Princípios:
// - Arquivo é a unidade primária. Arquivos individualmente > BATCH_MAX_BYTES
//   viram múltiplas janelas (com 5 linhas de overlap pra preservar contexto de
//   função/bloco — sem isso, a AI vê só metade de um diff e tira conclusão errada).
// - Cap global (BATCH_MAX_TOTAL): controla custo. Arquivos que sobrarem ficam
//   listados em `arquivosIgnorados` — com nome — pro user saber EXATAMENTE o
//   que não foi auditado (acaba a "traição silenciosa" do truncamento mudo).
// - Arquivos de prioridade alta entram primeiro (já existia em `_codePrioridade`).

const _BATCH_MAX_BYTES = 75_000;       // Capacidade efetiva por chamada LLM (folga pro prompt fixo + achados anteriores)
const _BATCH_MAX_TOTAL = 5;            // Máx de batches (cap global = ~375KB de diff por auditoria)
const _BATCH_OVERLAP_LINHAS = 5;       // Sobreposição entre janelas do mesmo arquivo

interface DiffArquivoBruto {
  filename: string;
  status: string;
  additions: number;
  deletions: number;
  patch: string;
  bytes: number;
}

interface DiffArquivoBlocado {
  filename: string;
  status: string;
  additions: number;
  deletions: number;
  patch: string;          // patch já formatado (já com header, ja com janela#X se splitted)
  bytes: number;
  janela?: { ix: number; total: number }; // presente se arquivo foi splitted
}

interface DiffBatch {
  arquivos: DiffArquivoBlocado[];
  contexto: string;       // texto completo do batch, pronto pra colar no prompt LLM
  bytes: number;
}

interface DiffPaginado {
  arquivos: DiffArquivoBruto[];   // todos os arquivos do compare (filtrados, sem truncar nada)
  batches: DiffBatch[];           // até _BATCH_MAX_TOTAL batches
  arquivosIgnorados: string[];    // nomes dos que ficaram fora pelo cap global
  arquivosSplitted: string[];     // nomes dos que foram divididos em múltiplas janelas
  baseCommit: string;
  headCommit: string;
  bytes: number;
  erro?: string;
}

// Busca o compare GitHub e retorna a lista CRUA de arquivos (sem caps), pronta
// pra ser fatiada em batches. Separar essa etapa permite que tanto o caminho
// "1 batch único" (diff pequeno) quanto o "N batches" (diff grande) compartilhem
// a mesma origem dos dados.
function _ghLerCompareBruto(repoUrl: string, baseSha: string): { arquivos: DiffArquivoBruto[]; baseCommit: string; headCommit: string; erro?: string } {
  const base7 = String(baseSha || '').slice(0, 7);
  const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
  if (!token) return { arquivos: [], baseCommit: base7, headCommit: '', erro: 'GitHub não conectado (sem token).' };
  const full = _ghFullName(repoUrl);
  if (!/^[^/]+\/[^/]+$/.test(full)) return { arquivos: [], baseCommit: base7, headCommit: '', erro: 'repoUrl inválida.' };
  const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };
  try {
    const head = _ghHeadCommitCurto(full, headers);
    if (!head) return { arquivos: [], baseCommit: base7, headCommit: '', erro: 'Não consegui ler o HEAD do repositório.' };
    if (head === base7) return { arquivos: [], baseCommit: base7, headCommit: head };

    const cmp = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/compare/${base7}...${head}`, { headers, muteHttpExceptions: true });
    if (cmp.getResponseCode() !== 200) return { arquivos: [], baseCommit: base7, headCommit: head, erro: `Não consegui comparar os commits (${cmp.getResponseCode()}).` };
    const j = JSON.parse(cmp.getContentText()) as { files?: Array<{ filename: string; status: string; additions?: number; deletions?: number; patch?: string }> };

    const arquivos = (j.files || [])
      .filter((f) => _codeArquivoRelevante(f.filename, 0))
      .sort((a, b) => _codePrioridade(b.filename) - _codePrioridade(a.filename))
      .map((f): DiffArquivoBruto => {
        let patch = String(f.patch || '');
        if (!patch) patch = f.status === 'removed' ? '(arquivo removido)' : '(sem patch textual — binário, renomeação ou diff muito grande)';
        return {
          filename: f.filename,
          status: f.status,
          additions: f.additions || 0,
          deletions: f.deletions || 0,
          patch,
          bytes: patch.length,
        };
      });

    return { arquivos, baseCommit: base7, headCommit: head };
  } catch (e: unknown) {
    return { arquivos: [], baseCommit: base7, headCommit: '', erro: e instanceof Error ? e.message : 'Erro ao ler o diff' };
  }
}

// Splita um patch grande em janelas linha-a-linha com `overlap` linhas de
// sobreposição entre janelas adjacentes. Preserva o cabeçalho `@@` mínimo pra
// que cada janela ainda faça sentido como diff isolado pra AI.
function _splitarPatchEmJanelas(patch: string, capBytes: number, overlap: number): string[] {
  if (patch.length <= capBytes) return [patch];
  const linhas = patch.split('\n');
  const janelas: string[] = [];
  let i = 0;
  while (i < linhas.length) {
    let acumulado = '';
    let j = i;
    while (j < linhas.length) {
      const next = linhas[j] + '\n';
      if (acumulado.length + next.length > capBytes && acumulado.length > 0) break;
      acumulado += next;
      j++;
    }
    janelas.push(acumulado.trimEnd());
    if (j >= linhas.length) break;
    // Próxima janela começa `overlap` linhas atrás pra manter contexto.
    i = Math.max(j - overlap, i + 1);
  }
  return janelas;
}

// Monta os batches a partir dos arquivos brutos. Aplica:
// 1. Split de arquivo grande em janelas
// 2. Empilhamento em batches até _BATCH_MAX_BYTES
// 3. Cap global _BATCH_MAX_TOTAL — sobras vão pra `arquivosIgnorados`
function _montarBatchesDoDiff(
  arquivos: DiffArquivoBruto[],
  repoFull: string,
  baseCommit: string,
  headCommit: string,
): { batches: DiffBatch[]; arquivosIgnorados: string[]; arquivosSplitted: string[]; bytesTotal: number } {
  // Expande arquivos grandes em janelas, mantendo ordem de prioridade.
  const unidades: DiffArquivoBlocado[] = [];
  const splittedNomes: string[] = [];
  for (const a of arquivos) {
    if (a.bytes <= _BATCH_MAX_BYTES) {
      unidades.push({ filename: a.filename, status: a.status, additions: a.additions, deletions: a.deletions, patch: a.patch, bytes: a.bytes });
    } else {
      const janelas = _splitarPatchEmJanelas(a.patch, _BATCH_MAX_BYTES, _BATCH_OVERLAP_LINHAS);
      splittedNomes.push(a.filename);
      janelas.forEach((p, ix) => {
        unidades.push({ filename: a.filename, status: a.status, additions: a.additions, deletions: a.deletions, patch: p, bytes: p.length, janela: { ix: ix + 1, total: janelas.length } });
      });
    }
  }

  // Empilha em batches respeitando o cap de bytes.
  const batches: DiffBatch[] = [];
  let atual: DiffArquivoBlocado[] = [];
  let atualBytes = 0;
  const ignorados: string[] = [];

  for (const u of unidades) {
    // Se já bateu o cap global, marca como ignorado.
    if (batches.length >= _BATCH_MAX_TOTAL) {
      // dedup: arquivo grande splitted pode aparecer várias vezes; conta uma só.
      if (ignorados.indexOf(u.filename) < 0) ignorados.push(u.filename);
      continue;
    }
    // Estouraria o cap por batch? Fecha o batch atual e abre outro.
    if (atualBytes + u.bytes > _BATCH_MAX_BYTES && atual.length > 0) {
      batches.push(_finalizarBatch(atual, repoFull, baseCommit, headCommit, batches.length + 1));
      atual = [];
      atualBytes = 0;
      // Verifica cap global de novo antes de iniciar nova unidade no novo batch.
      if (batches.length >= _BATCH_MAX_TOTAL) {
        if (ignorados.indexOf(u.filename) < 0) ignorados.push(u.filename);
        continue;
      }
    }
    atual.push(u);
    atualBytes += u.bytes;
  }
  if (atual.length > 0 && batches.length < _BATCH_MAX_TOTAL) {
    batches.push(_finalizarBatch(atual, repoFull, baseCommit, headCommit, batches.length + 1));
  }

  let bytesTotal = 0;
  batches.forEach((b) => { bytesTotal += b.bytes; });

  return { batches, arquivosIgnorados: ignorados, arquivosSplitted: splittedNomes, bytesTotal };
}

function _finalizarBatch(
  unidades: DiffArquivoBlocado[],
  repoFull: string,
  baseCommit: string,
  headCommit: string,
  numBatch: number,
): DiffBatch {
  const partes: string[] = [];
  for (const u of unidades) {
    const janelaTxt = u.janela ? ` · janela ${u.janela.ix}/${u.janela.total}` : '';
    partes.push(`\n### ${u.filename} (${u.status}, +${u.additions} −${u.deletions}${janelaTxt})\n\`\`\`diff\n${u.patch}\n\`\`\`\n`);
  }
  const cabecalho = `Diff do repositório ${repoFull}: ${baseCommit} → ${headCommit} · batch ${numBatch}\nArquivos neste batch: ${unidades.length}\n`;
  return { arquivos: unidades, contexto: cabecalho + partes.join(''), bytes: unidades.reduce((s, u) => s + u.bytes, 0) };
}

// Pagina o diff completo: agrega batches + métricas. Retorna `arquivosIgnorados`
// pra UI mostrar EXATAMENTE o que ficou de fora (sem silêncio).
function _lerDiffGitHubPaginado(repoUrl: string, baseSha: string): DiffPaginado {
  const bruto = _ghLerCompareBruto(repoUrl, baseSha);
  const full = _ghFullName(repoUrl);
  if (bruto.erro) {
    return { arquivos: [], batches: [], arquivosIgnorados: [], arquivosSplitted: [], baseCommit: bruto.baseCommit, headCommit: bruto.headCommit, bytes: 0, erro: bruto.erro };
  }
  if (bruto.arquivos.length === 0) {
    return { arquivos: [], batches: [], arquivosIgnorados: [], arquivosSplitted: [], baseCommit: bruto.baseCommit, headCommit: bruto.headCommit, bytes: 0 };
  }
  const { batches, arquivosIgnorados, arquivosSplitted, bytesTotal } = _montarBatchesDoDiff(bruto.arquivos, full, bruto.baseCommit, bruto.headCommit);
  return {
    arquivos: bruto.arquivos,
    batches,
    arquivosIgnorados,
    arquivosSplitted,
    baseCommit: bruto.baseCommit,
    headCommit: bruto.headCommit,
    bytes: bytesTotal,
  };
}

// Wrapper retro-compatível: monta UM DiffContexto único a partir do paginado
// (usa só batch 1). Mantido pra rotas que ainda chamam o nome antigo — e como
// caminho rápido quando o diff todo cabe em 1 batch (caso comum: 90% das vezes).
function _lerDiffGitHub(repoUrl: string, baseSha: string): DiffContexto {
  const pag = _lerDiffGitHubPaginado(repoUrl, baseSha);
  const base7 = pag.baseCommit;
  if (pag.erro) {
    return { contexto: '', arquivos: 0, bytes: 0, baseCommit: base7, headCommit: pag.headCommit, truncado: false, lista: [], erro: pag.erro };
  }
  if (pag.batches.length === 0) {
    return { contexto: '', arquivos: 0, bytes: 0, baseCommit: base7, headCommit: pag.headCommit, truncado: false, lista: [] };
  }
  const arquivosTotal = pag.arquivos.length;
  const arquivosNoBatch1 = pag.batches[0].arquivos.length;
  const truncado = pag.batches.length > 1 || pag.arquivosIgnorados.length > 0;
  const lista = pag.batches[0].arquivos.map((u) => u.filename);
  return {
    contexto: pag.batches[0].contexto,
    arquivos: arquivosNoBatch1,
    bytes: pag.batches[0].bytes,
    baseCommit: base7,
    headCommit: pag.headCommit,
    truncado: arquivosTotal > arquivosNoBatch1,
    lista,
  };
}

// Status de frescor da auditoria de código: diz se o repositório mudou desde a
// última auditoria, e quantos/quais arquivos relevantes mudaram. Chamado quando
// o drawer abre, pra mostrar o banner e decidir se vale re-rodar.
function getStatusAuditoriaCodigo(sistemaId: string): ServerResult {
  try {
    const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId);
    if (!sistema) return { ok: false, error: 'Sistema não encontrado' };

    const repoUrl = String(sistema.repoUrl || '').trim();
    const scriptId = String(sistema.scriptId || '').trim();
    const temFonte = !!(repoUrl || scriptId);

    const { auditoria, commit: ultimoCommitAuditado } = _ultimaAuditoriaCommit(sistemaId);
    const nuncaAuditado = !auditoria;

    const data: {
      temFonte: boolean; fonte: 'github' | 'gas' | '';
      nuncaAuditado: boolean; ultimoCommitAuditado: string; headCommit: string;
      mudou: boolean; semDiff: boolean; arquivosMudados: number; listaMudados: string[]; erro?: string;
      // Detector de "rodada só de docs": quando o repo mudou mas nenhum
      // arquivo de código (filtro `_codeArquivoRelevante`) foi alterado.
      // Sinaliza que a IA externa provavelmente só escreveu .md em vez de
      // implementar correções — a Forja mostra alerta acima do hero.
      arquivosMudadosTotal: number; mudancasSaoDocsOnly: boolean; listaDocsMudados: string[];
    } = {
      temFonte, fonte: repoUrl ? 'github' : (scriptId ? 'gas' : ''),
      nuncaAuditado, ultimoCommitAuditado, headCommit: '',
      mudou: true, semDiff: false, arquivosMudados: 0, listaMudados: [],
      arquivosMudadosTotal: 0, mudancasSaoDocsOnly: false, listaDocsMudados: [],
    };

    // Sem fonte de código: nada de incremental de código pra reportar.
    if (!temFonte) { data.mudou = false; return { ok: true, data }; }

    // GAS não tem commit/diff confiável: sempre "pode re-rodar", sem diff.
    if (!repoUrl && scriptId) { data.semDiff = true; return { ok: true, data }; }

    const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
    if (!token) { data.erro = 'GitHub não conectado (sem token em Configurações).'; data.semDiff = true; return { ok: true, data }; }
    const full = _ghFullName(repoUrl);
    if (!/^[^/]+\/[^/]+$/.test(full)) { data.erro = 'repoUrl inválida.'; data.semDiff = true; return { ok: true, data }; }
    const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };

    const head = _ghHeadCommitCurto(full, headers);
    data.headCommit = head;
    if (!head) { data.erro = 'Não consegui ler o HEAD do repositório.'; data.semDiff = true; return { ok: true, data }; }

    // Nunca auditado ou sem commit registrado (auditorias antigas): há o que auditar,
    // mas não dá pra fazer diff confiável.
    if (nuncaAuditado || !ultimoCommitAuditado) { data.mudou = true; data.semDiff = true; return { ok: true, data }; }

    if (ultimoCommitAuditado === head) { data.mudou = false; data.arquivosMudados = 0; return { ok: true, data }; }

    // Repo mudou: conta/lista os arquivos relevantes alterados via compare API.
    try {
      const cmp = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/compare/${ultimoCommitAuditado}...${head}`, { headers, muteHttpExceptions: true });
      if (cmp.getResponseCode() === 200) {
        const j = JSON.parse(cmp.getContentText()) as { files?: Array<{ filename: string; status: string }> };
        const todos = j.files || [];
        const relevantes = todos.filter((f) => _codeArquivoRelevante(f.filename, 0));
        const naoRelevantes = todos.filter((f) => !_codeArquivoRelevante(f.filename, 0));
        data.mudou = true;
        data.arquivosMudados = relevantes.length;
        data.listaMudados = relevantes.slice(0, 8).map((f) => f.filename);
        data.arquivosMudadosTotal = todos.length;
        // Docs-only: o repo teve mudanças (algum arquivo) mas NENHUM arquivo
        // de código foi alterado. Padrão clássico de "IA externa só escreveu
        // .md em vez de implementar". Coleta amostra dos arquivos não-relevantes
        // pra mostrar exemplos no alerta.
        if (todos.length > 0 && relevantes.length === 0) {
          data.mudancasSaoDocsOnly = true;
          data.listaDocsMudados = naoRelevantes.slice(0, 8).map((f) => f.filename);
        }
      } else {
        // base sumiu (rebase/force-push) ou diff grande demais: muda, mas sem diff.
        data.mudou = true; data.semDiff = true;
      }
    } catch {
      data.mudou = true; data.semDiff = true;
    }
    return { ok: true, data };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao checar status' };
  }
}

// Tenta extrair um bloco <AUDIT>...</AUDIT> com JSON estruturado.
// Se falhar, devolve apenas o texto bruto da IA pra o front renderizar como fallback.
interface AuditFinding {
  id: string;
  titulo: string;
  severidade: 'alta' | 'media' | 'baixa';
  area: string;
  problema: string;
  evidencia: string;
  solucao: string;
  prompt: string;
  toolSugerida?: string;
  toolParams?: Record<string, unknown>;
  // Auditoria incremental (Fase 2.5): de onde veio este achado nesta rodada.
  origem?: 'novo' | 'persiste';
}

interface AuditPayload {
  estadoGeral: string;
  oQueEmpolga: string[];
  proximosPassos: string;
  findings: AuditFinding[];
  // Títulos de achados anteriores que o diff resolveu (só em auditoria incremental).
  resolvidos?: string[];
}

function _parseAuditPayload(resposta: string): { texto: string; payload: AuditPayload | null } {
  const openTag = resposta.indexOf('<AUDIT>');
  const closeTag = resposta.indexOf('</AUDIT>');
  if (openTag < 0 || closeTag < 0) return { texto: resposta, payload: null };
  const textoAntes = resposta.slice(0, openTag).trim();
  const jsonStr = resposta.slice(openTag + '<AUDIT>'.length, closeTag).trim();
  try {
    let parsed: unknown;
    try { parsed = JSON.parse(jsonStr); }
    catch {
      const m = jsonStr.match(/\{[\s\S]*\}/);
      if (!m) return { texto: textoAntes || resposta, payload: null };
      parsed = JSON.parse(m[0]);
    }
    if (!parsed || typeof parsed !== 'object') return { texto: textoAntes || resposta, payload: null };
    const p = parsed as Record<string, unknown>;
    const findingsRaw = Array.isArray(p.findings) ? p.findings : [];
    const findings: AuditFinding[] = findingsRaw.map((f: unknown, i: number) => {
      const item = (f || {}) as Record<string, unknown>;
      const sev = String(item.severidade || 'media').toLowerCase();
      const sevTipada: AuditFinding['severidade'] = (sev === 'alta' || sev === 'baixa') ? sev : 'media';
      const orig = String(item.origem || '').toLowerCase();
      return {
        id: 'finding-' + (i + 1),
        titulo: String(item.titulo || `Achado #${i + 1}`),
        severidade: sevTipada,
        area: String(item.area || 'geral'),
        problema: String(item.problema || ''),
        evidencia: String(item.evidencia || ''),
        solucao: String(item.solucao || ''),
        prompt: String(item.prompt || ''),
        toolSugerida: item.toolSugerida ? String(item.toolSugerida) : undefined,
        toolParams: (item.toolParams && typeof item.toolParams === 'object') ? item.toolParams as Record<string, unknown> : undefined,
        origem: (orig === 'novo' || orig === 'persiste') ? (orig as 'novo' | 'persiste') : undefined,
      };
    });
    const payload: AuditPayload = {
      estadoGeral: String(p.estadoGeral || ''),
      oQueEmpolga: Array.isArray(p.oQueEmpolga) ? p.oQueEmpolga.map((x: unknown) => String(x)) : [],
      proximosPassos: String(p.proximosPassos || ''),
      findings,
      resolvidos: Array.isArray(p.resolvidos) ? p.resolvidos.map((x: unknown) => String(x)).filter((s) => s.trim()) : undefined,
    };
    return { texto: textoAntes, payload };
  } catch {
    return { texto: resposta, payload: null };
  }
}

// Estado por finding: { tipo: 'risco'|'decisao'|'oportunidade', idCriado: string, registradoEm: string }
interface RegistroFinding {
  tipo: string;
  idCriado: string;
  registradoEm: string;
}

interface BacklogFechadoAuto {
  tipo: string;
  idCriado: string;
  titulo: string;
}

interface AuditResultPayloadServer {
  id: string;
  texto: string;
  payload: AuditPayload | null;
  fontes: AuditFontes;
  saudeAtual: unknown;
  modeloUsado: string;
  duracaoMs: number;
  criadoEm: string;
  registros: Record<string, RegistroFinding>;
  fechadosAuto?: BacklogFechadoAuto[];
}

// Fecha automaticamente os itens de backlog (decisão/risco/oportunidade) que
// foram criados a partir de achados que o diff resolveu. O vínculo achado→item
// vem do `registrosJson` da auditoria anterior (chaveado por finding.id, que é
// posicional: "finding-N"). Casamos o título resolvido com o achado anterior,
// achamos o item criado e mudamos o status pra "fechado".
function _fecharBacklogResolvidos(
  prevPayload: AuditPayload,
  prevRegistros: Record<string, RegistroFinding>,
  resolvidos: string[],
): BacklogFechadoAuto[] {
  const fechados: BacklogFechadoAuto[] = [];
  if (!resolvidos || resolvidos.length === 0) return fechados;
  const norm = (s: string) => String(s || '').toLowerCase().replace(/\s+/g, ' ').trim();
  const resolvidosNorm = resolvidos.map(norm);

  for (let i = 0; i < prevPayload.findings.length; i++) {
    const f = prevPayload.findings[i];
    if (resolvidosNorm.indexOf(norm(f.titulo)) < 0) continue;
    const reg = prevRegistros[f.id || ('finding-' + (i + 1))];
    if (!reg || !reg.idCriado) continue;
    const tipo = String(reg.tipo || '').toLowerCase();
    try {
      if (tipo === 'decisao') {
        dbUpdate('Decisoes', reg.idCriado, { status: 'feito' });
      } else if (tipo === 'risco') {
        dbUpdate('Riscos', reg.idCriado, { status: 'mitigado' });
      } else if (tipo === 'oportunidade') {
        dbUpdate('Oportunidades', reg.idCriado, { estado: 'ganho' });
      } else {
        continue;
      }
      fechados.push({ tipo, idCriado: reg.idCriado, titulo: f.titulo });
    } catch { /* best-effort: um item que falha não derruba a auditoria */ }
  }
  return fechados;
}

// Auditoria de onboarding: quando o sistema não tem NENHUM dado (sem código
// legível, sem repo, sem custos/decisões/riscos/alertas/timeline), uma auditoria
// com IA só produziria achados genéricos. Em vez disso devolvemos um checklist
// determinístico (sem gastar LLM) que diz exatamente o que preencher pra destravar
// auditorias de verdade. Mesmo formato AuditPayload → render/persistência iguais.
function _auditoriaOnboarding(
  sistemaId: string,
  sistema: Record<string, unknown>,
  fontes: AuditFontes,
  codigoErro: string,
): ServerResult {
  fontes.onboarding = true;

  const findings: AuditFinding[] = [];
  const add = (f: Partial<AuditFinding> & { titulo: string; problema: string; solucao: string }) => {
    findings.push({
      id: 'finding-' + (findings.length + 1),
      titulo: f.titulo,
      severidade: f.severidade || 'media',
      area: f.area || 'governanca',
      problema: f.problema,
      evidencia: f.evidencia || 'Dado ausente na ficha do sistema.',
      solucao: f.solucao,
      prompt: f.prompt || '',
      toolSugerida: f.toolSugerida,
      toolParams: f.toolParams,
    });
  };

  const ehGas = !!String(sistema.scriptId || '').trim() && !String(sistema.repoUrl || '').trim();

  // 1. Código ilegível (o bloqueio mais comum em projetos GAS).
  if (codigoErro && /apps script api/i.test(codigoErro)) {
    add({
      titulo: 'Ative a Apps Script API pra IA ler o código',
      severidade: 'alta',
      area: 'operacional',
      problema: 'A IA não conseguiu abrir o código deste projeto Apps Script — a Apps Script API está desativada na sua conta Google.',
      evidencia: codigoErro,
      solucao: '1) Abra script.google.com/home/usersettings\n2) Ative "Google Apps Script API"\n3) Volte aqui e rode a auditoria de novo.',
    });
  }

  // 2. Repositório — destrava auditoria de código + incremental.
  if (!fontes.temRepo) {
    add({
      titulo: 'Conecte o repositório (GitHub) do sistema',
      severidade: 'alta',
      area: 'arquitetura',
      problema: 'Sem um repoUrl, a IA não lê o código real e a auditoria fica limitada à governança.' + (ehGas ? ' Mesmo sendo um projeto Apps Script, se ele é versionado via clasp no GitHub, conectar o repo desbloqueia leitura de código mais rica + auditoria incremental.' : ''),
      solucao: '1) Abra a ficha do sistema\n2) Preencha o campo repoUrl com https://github.com/owner/repo\n3) Rode a auditoria no modo "Completa".',
    });
  }

  // 3. Propósito.
  if (!fontes.temProposito) {
    add({
      titulo: 'Defina o propósito do sistema',
      area: 'produto',
      problema: 'O sistema não tem um propósito documentado — sem isso é difícil priorizar e a auditoria não tem âncora de negócio.',
      solucao: '1) Abra a ficha do sistema\n2) Escreva 1-2 frases: o que resolve e pra quem.',
    });
  }

  // 4. Stack.
  if (!fontes.temStack) {
    add({
      titulo: 'Documente a stack técnica',
      area: 'arquitetura',
      problema: 'A stack não está registrada — a IA não sabe quais riscos técnicos (deps, runtime, infra) avaliar.',
      solucao: '1) Liste linguagem(ns), frameworks e serviços principais na ficha do sistema.',
    });
  }

  // 5. URL/domínio de produção.
  if (!fontes.temUrl) {
    add({
      titulo: 'Registre a URL/domínio de produção',
      area: 'operacional',
      problema: 'Não há URL de produção nem domínio customizado — não dá pra saber se/onde o sistema está no ar.',
      solucao: '1) Preencha urlProd (e domínio, se houver) na ficha do sistema.',
    });
  }

  // 6. Primeira decisão registrada (com tool pronta).
  if (fontes.decisoes === 0) {
    add({
      titulo: 'Registre a primeira decisão técnica',
      area: 'governanca',
      problema: 'O backlog/histórico de decisões está vazio. Registrar decisões cria a memória do sistema.',
      solucao: '1) Pense numa decisão já tomada (ex.: "usar Sheets como banco")\n2) Registre com justificativa.',
      toolSugerida: 'registrar_decisao',
      toolParams: { sistemaId, titulo: '', decisao: '', justificativa: '' },
    });
  }

  // 7. Primeiro risco conhecido (com tool pronta).
  if (fontes.riscos === 0) {
    add({
      titulo: 'Registre o primeiro risco conhecido',
      area: 'governanca',
      problema: 'Nenhum risco mapeado. Todo sistema tem pelo menos um (custo, dependência, single point of failure).',
      solucao: '1) Aponte o maior risco atual\n2) Registre com gravidade.',
      toolSugerida: 'registrar_risco',
      toolParams: { sistemaId, area: 'operacional', descricao: '', gravidade: 'media' },
    });
  }

  const nome = String(sistema.nome || 'Este sistema');
  const payload: AuditPayload = {
    estadoGeral: `${nome} está praticamente sem dados na Forja — sem código legível e sem registros de governança. Antes de uma auditoria crítica fazer sentido, vale preencher o básico abaixo. Esta é uma checklist de setup (gerada sem IA), não uma análise crítica.`,
    oQueEmpolga: [],
    proximosPassos: 'Comece pelo achado #1. Cada item preenchido destrava uma camada da próxima auditoria — com código conectado, a IA passa a citar arquivo + trecho real.',
    findings,
  };

  const saudeAtual = calcularSaudeReal(sistemaId);
  const saudeScore = (saudeAtual.ok && saudeAtual.data) ? Number((saudeAtual.data as { score: number }).score) : 0;

  const resultadoFinal: AuditResultPayloadServer = {
    id: '',
    texto: '',
    payload,
    fontes,
    saudeAtual: saudeAtual.ok ? saudeAtual.data : null,
    modeloUsado: 'Checklist Forja (sem IA)',
    duracaoMs: 0,
    criadoEm: new Date().toISOString(),
    registros: {},
  };

  try {
    const novaLinha = dbCreate('Auditorias', {
      sistemaId,
      criadoEm: resultadoFinal.criadoEm,
      modeloUsado: resultadoFinal.modeloUsado,
      duracaoMs: 0,
      scoreNoMomento: saudeScore,
      numFindings: payload.findings.length,
      payloadJson: JSON.stringify(payload),
      fontesJson: JSON.stringify(fontes),
      registrosJson: '{}',
    }) as Record<string, unknown>;
    resultadoFinal.id = String(novaLinha.id || '');
  } catch { /* persistência é best-effort */ }

  return { ok: true, data: resultadoFinal };
}

// Similaridade Jaccard entre palavras-chave de 2 títulos, ignorando palavras
// curtas (<4 chars), acentos e pontuação. >= 0.4 = "mesmo achado" pra fins de
// reconciliação. Threshold testado contra casos reais: "URL de produção não
// registrada" vs "URL de produção não registrada na Forja" → 0.66 (mesmo);
// "Cobertura de testes baixa" vs "Cobertura de testes baixa fora do Authz" →
// 0.5 (mesmo); "Webapp acessível por ANYONE" vs "Webapp restritivo" → 0.2
// (diferentes).
function _similaridadeTitulos(a: string, b: string): number {
  const norm = (s: string): string[] => {
    return String(s || '')
      .toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-z0-9\s]/g, ' ')
      .split(/\s+/)
      .filter((w) => w.length > 3);
  };
  const wa = norm(a);
  const wb = norm(b);
  if (wa.length === 0 || wb.length === 0) return 0;
  const setA: Record<string, boolean> = {};
  const setB: Record<string, boolean> = {};
  wa.forEach((w) => { setA[w] = true; });
  wb.forEach((w) => { setB[w] = true; });
  let intersection = 0;
  const seen: Record<string, boolean> = {};
  Object.keys(setA).forEach((w) => {
    if (setB[w]) intersection++;
    seen[w] = true;
  });
  Object.keys(setB).forEach((w) => { seen[w] = true; });
  const union = Object.keys(seen).length;
  return union === 0 ? 0 : intersection / union;
}

// Palavras-chave técnicas que indicam "tema". Quando 2 achados têm a MESMA
// ÁREA + ≥1 keyword técnica em comum, são considerados mesmo achado mesmo
// que o Jaccard de palavras seja baixo. Resolve falso negativo real visto na
// v1.140.0 ("Zero monitoramento/alerting em produção" vs "Sem monitoramento/
// alertas de erros em produção" — Jaccard 0.09, mas é o mesmo achado).
const _KEYWORDS_RECONCILIACAO = [
  'monitoramento', 'alerting', 'alertas', 'observability', 'observabilidade',
  'backup', 'restore', 'recuperacao',
  'testes', 'cobertura', 'coverage',
  'deploy', 'pipeline', 'rollback',
  'spreadsheet', 'database', 'sheet', 'planilha',
  'vendor', 'lockin', 'contingencia', 'fallback',
  'seguranca', 'security', 'autenticacao', 'authz', 'permissao',
  'dependencia', 'dependencias', 'deps',
  'lint', 'eslint', 'tipagem', 'typescript',
  'documentacao', 'readme',
  'performance', 'latencia', 'escalabilidade',
  'segredo', 'segredos', 'secret', 'secrets', 'token', 'credencial',
  'rate', 'limit', 'throttle',
  'logs', 'logging', 'auditoria',
  'cron', 'agendamento', 'scheduler',
  'cors', 'csrf', 'xss', 'sql', 'injection',
];

function _extrairKeywordsTema(titulo: string): string[] {
  const norm = String(titulo || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const presentes: string[] = [];
  _KEYWORDS_RECONCILIACAO.forEach((kw) => {
    if (norm.indexOf(kw) >= 0) presentes.push(kw);
  });
  return presentes;
}

// Reconciliação semântica em 2 camadas:
//   1. Jaccard de palavras-chave >= 0.4 (variações textuais óbvias)
//   2. MESMA ÁREA + ≥1 keyword técnica em comum (reformulações pela IA)
// Qualquer camada positiva = mesmo achado.
function _mesmoAchado(prev: AuditFinding, atual: AuditFinding): boolean {
  const tituloPrev = String(prev.titulo || '');
  const tituloAtual = String(atual.titulo || '');

  if (_similaridadeTitulos(tituloPrev, tituloAtual) >= 0.4) return true;

  const areaPrev = String(prev.area || '').toLowerCase().trim();
  const areaAtual = String(atual.area || '').toLowerCase().trim();
  if (areaPrev && areaPrev === areaAtual) {
    const keysPrev = _extrairKeywordsTema(tituloPrev);
    const keysAtual = _extrairKeywordsTema(tituloAtual);
    if (keysPrev.length > 0 && keysAtual.length > 0) {
      const comum = keysPrev.filter((k) => keysAtual.indexOf(k) >= 0);
      if (comum.length >= 1) return true;
    }
  }

  return false;
}

// Reconciliação determinística pós-IA (Fase 2.6): a auditoria completa NÃO passa
// achados anteriores pra IA (caminho forçado, sem diff de código), então a IA
// retorna findings do zero — sem origem nem resolvidos. Aqui cruzamos os títulos
// novos contra os da última auditoria salva pra reconstruir o Antes vs Depois.
// Resultado: o ComparativoAntesDepois funciona em QUALQUER caminho (incremental
// ou completo), e o usuário sempre vê "saíram N · entraram M · persistem K".
function _reconciliarComAnterior(payload: AuditPayload, sistemaId: string): AuditPayload {
  if (!payload || !Array.isArray(payload.findings)) return payload;
  // Se a IA já marcou origem nos findings (caminho incremental), respeita.
  const jaTemOrigem = payload.findings.some((f) => f.origem === 'novo' || f.origem === 'persiste');
  if (jaTemOrigem && Array.isArray(payload.resolvidos)) return payload;

  const auditorias = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
    .filter((a) => String(a.sistemaId || '') === sistemaId)
    .sort((a, b) => String(b.criadoEm).localeCompare(String(a.criadoEm)));
  if (auditorias.length === 0) return payload; // primeira auditoria — nada a reconciliar

  let prev: AuditPayload | null = null;
  try { prev = JSON.parse(String(auditorias[0].payloadJson || 'null')) as AuditPayload; } catch { prev = null; }
  if (!prev || !Array.isArray(prev.findings) || prev.findings.length === 0) return payload;

  // Reconciliação semântica em 2 camadas (Jaccard + área+keywords). Cobre tanto
  // variações textuais óbvias quanto reformulações da IA com palavras diferentes.
  const findingsComOrigem = payload.findings.map((f) => {
    const temSimilarAnterior = prev!.findings.some((p) => _mesmoAchado(p, f));
    return Object.assign({}, f, { origem: temSimilarAnterior ? 'persiste' : 'novo' }) as AuditFinding;
  });

  const resolvidos = prev.findings
    .filter((p) => !payload.findings.some((a) => _mesmoAchado(p, a)))
    .map((p) => String(p.titulo || ''))
    .filter((t) => t.length > 0);

  return Object.assign({}, payload, { findings: findingsComOrigem, resolvidos });
}

// Auditoria incremental (Fase 2.5): em vez de reler o repo inteiro, manda pro LLM
// (1) os achados anteriores e (2) só o DIFF desde a última auditoria, pedindo pra
// RECONCILIAR — o que o diff resolveu, o que persiste e quais problemas novos ele
// introduziu. Sai no MESMO formato AuditPayload, então persistência/render não mudam.
// ─── Merge de findings entre batches (v1.147) ─────────────────────────────────
//
// Usado quando a auditoria roda em N batches: cada batch devolve seus achados
// e seus "resolvidos". Aqui:
// - Findings dedupados via `_mesmoAchado` (Jaccard + área+keywords). Mantemos
//   a primeira ocorrência (já vem do batch de maior prioridade, pois ordenamos
//   por `_codePrioridade`).
// - Resolvidos unidos por título (case-insensitive, espaços normalizados).
// - "estadoGeral" / "proximosPassos" / "oQueEmpolga" ficam VAZIOS aqui — quem
//   preenche é a síntese final em chamada LLM extra (vê narrativa coerente).
function _mergeAuditPayloads(payloads: AuditPayload[]): AuditPayload {
  const findings: AuditFinding[] = [];
  const resolvidosSet = new Map<string, string>(); // chave normalizada → título original
  for (const p of payloads) {
    if (!p || !Array.isArray(p.findings)) continue;
    for (const f of p.findings) {
      const jaExiste = findings.some((e) => _mesmoAchado(e, f));
      if (!jaExiste) findings.push(f);
    }
    if (Array.isArray(p.resolvidos)) {
      for (const r of p.resolvidos) {
        const k = String(r || '').trim().toLowerCase().replace(/\s+/g, ' ');
        if (k && !resolvidosSet.has(k)) resolvidosSet.set(k, String(r));
      }
    }
  }
  // Re-ID posicional pros findings (importante: registrosJson é chaveado por id).
  const findingsId = findings.map((f, i) => Object.assign({}, f, { id: 'finding-' + (i + 1) }));
  return {
    estadoGeral: '',
    oQueEmpolga: [],
    proximosPassos: '',
    findings: findingsId,
    resolvidos: Array.from(resolvidosSet.values()),
  };
}

// Síntese final: depois dos batches devolverem findings, fazemos UMA chamada
// extra pedindo só a narrativa (Estado geral / O que mudou / Próximos passos)
// baseada nos achados consolidados — sem mandar o diff de novo, só os títulos.
// Custo: 1 chamada curta (~800 tokens out).
function _sintetizarNarrativaPosBatch(
  sistemaNome: string,
  payload: AuditPayload,
  numBatches: number,
  totalArquivos: number,
): { estadoGeral: string; oQueEmpolga: string[]; proximosPassos: string } {
  const fallback = {
    estadoGeral: `Auditei ${totalArquivos} arquivo(s) modificado(s) em ${numBatches} batch(es). ${payload.findings.length} achado(s) ativo(s), ${(payload.resolvidos || []).length} resolvido(s).`,
    oQueEmpolga: [],
    proximosPassos: payload.findings.length > 0
      ? `Comece pelos achados de severidade ALTA (${payload.findings.filter(f => f.severidade === 'alta').length}).`
      : 'Sem achados ativos — bom momento pra avançar com features novas.',
  };
  try {
    const findingsTxt = payload.findings.slice(0, 12)
      .map((f, i) => `#${i + 1} [${f.severidade}|${f.area}|${f.origem || '?'}] ${f.titulo}`)
      .join('\n');
    const resolvidosTxt = (payload.resolvidos || []).slice(0, 8).map((r, i) => `- ${r}`).join('\n');

    const prompt = (
      `Você sintetizou achados de uma auditoria incremental de "${sistemaNome}". O diff foi grande e veio em ${numBatches} batches (cobrindo ${totalArquivos} arquivos). Os achados foram consolidados:\n\n`
      + `## Achados ativos (${payload.findings.length})\n${findingsTxt || '(nenhum)'}\n\n`
      + `## Resolvidos pelo diff (${(payload.resolvidos || []).length})\n${resolvidosTxt || '(nenhum)'}\n\n`
      + `Sua tarefa: gerar a NARRATIVA executiva em JSON puro (sem cercas):\n`
      + `{\n`
      + `  "estadoGeral": "<2-3 frases sobre o impacto do diff: o que melhorou, o que ainda falta. Cite números (X resolvidos, Y persistem).>",\n`
      + `  "oQueEmpolga": ["bullet 1", "bullet 2"],\n`
      + `  "proximosPassos": "<1 parágrafo. Aponte o achado #N mais importante por nome e diga POR ONDE COMEÇAR.>"\n`
      + `}\n\n`
      + `Seja CONCRETO. Sem genérico. JSON válido, aspas escapadas.`
    );
    const messages: LlmMessage[] = [
      { role: 'system', content: 'Você é um auditor técnico sênior fazendo a síntese final de uma auditoria já reconciliada.' },
      { role: 'user', content: prompt },
    ];
    const resp = forjaCallLLM(messages, 800, undefined, 'auditoria');
    // Parse tolerante: extrai primeiro {...}
    const m = resp.match(/\{[\s\S]*\}/);
    if (!m) return fallback;
    const j = JSON.parse(m[0]) as { estadoGeral?: string; oQueEmpolga?: unknown[]; proximosPassos?: string };
    return {
      estadoGeral: String(j.estadoGeral || fallback.estadoGeral),
      oQueEmpolga: Array.isArray(j.oQueEmpolga) ? j.oQueEmpolga.map((x) => String(x)) : [],
      proximosPassos: String(j.proximosPassos || fallback.proximosPassos),
    };
  } catch {
    return fallback;
  }
}

// Roda 1 chamada LLM pra UM batch do diff. Retorna o AuditPayload já parseado
// (com findings + resolvidos do batch). Sem narrativa aqui — vai pra síntese.
function _auditarUmBatch(
  sistemaId: string,
  sistema: Record<string, unknown>,
  diffContexto: string,
  prevPayload: AuditPayload,
  numBatch: number,
  totalBatches: number,
  modeloAuditoria: string,
): AuditPayload | null {
  const areasPermitidas = 'governanca|arquitetura|seguranca|dependencias|testes|operacional|financeiro|produto|ux|codigo|performance';
  const prevList = prevPayload.findings
    .map((f, i) => `#${i + 1} [${f.severidade}|${f.area}] ${f.titulo}`)
    .join('\n');

  const promptUser = (
    `Auditoria INCREMENTAL do sistema "${sistema.nome}" — BATCH ${numBatch}/${totalBatches}.\n\n`
    + 'O diff é grande e está sendo auditado em pedaços. Você recebe AGORA UM PEDAÇO dos arquivos alterados. '
    + 'Sua tarefa: analisar SÓ os arquivos deste batch, reconciliando contra os achados anteriores listados abaixo.\n\n'
    + 'Responda APENAS com o JSON dentro de <AUDIT>...</AUDIT> (sem texto fora):\n\n'
    + '<AUDIT>\n'
    + '{\n'
    + '  "resolvidos": ["<título de achado anterior que ESTE batch claramente resolve>"],\n'
    + '  "findings": [\n'
    + '    {\n'
    + '      "titulo": "<curto, máx 70 chars>",\n'
    + '      "severidade": "alta|media|baixa",\n'
    + '      "area": "' + areasPermitidas + '",\n'
    + '      "origem": "novo|persiste",\n'
    + '      "problema": "<1-2 frases>",\n'
    + '      "evidencia": "<arquivo:trecho do diff>",\n'
    + '      "solucao": "<2-4 passos numerados>",\n'
    + '      "prompt": "<colável no Cursor/Claude>",\n'
    + '      "toolSugerida": "registrar_risco|registrar_decisao|registrar_oportunidade",\n'
    + '      "toolParams": { "sistemaId": "' + sistemaId + '" }\n'
    + '    }\n'
    + '  ]\n'
    + '}\n'
    + '</AUDIT>\n\n'
    + 'REGRAS DURAS:\n'
    + '- SÓ analise os arquivos DESTE batch. NÃO especule sobre arquivos que não estão aqui.\n'
    + '- "resolvidos" = títulos LITERAIS dos achados anteriores que ESTE batch resolve. Na dúvida, NÃO inclua (outro batch pode resolver).\n'
    + '- Persistem ≠ todos os anteriores: só marque "persiste" se o batch atual mostra que o problema CONTINUA (ex.: arquivo do problema NÃO mudou ou mudou em outra dimensão).\n'
    + '- Achados NOVOS: só os introduzidos pelo diff DESTE batch. Sem inferências sobre outros batches.\n'
    + '- Máx 6 findings por batch. Qualidade > quantidade.\n'
    + '- JSON VÁLIDO. Aspas escapadas. Sem comentários.\n\n'
    + 'IDs reais: sistemaId="' + sistemaId + '"\n\n'
    + '--- ACHADOS ANTERIORES (referência para reconciliação) ---\n' + prevList + '\n\n'
    + '--- DIFF DESTE BATCH ---\n' + diffContexto
  );

  const messages: LlmMessage[] = [
    { role: 'system', content: 'Você audita UM batch de um diff grande. Não generaliza pra arquivos fora do batch.' },
    { role: 'user', content: promptUser },
  ];
  try {
    const resp = forjaCallLLM(messages, 4000, modeloAuditoria, 'auditoria');
    const parsed = _parseAuditPayload(resp);
    return parsed.payload;
  } catch {
    return null;
  }
}

// Versão CHUNKED da auditoria incremental: usada quando o diff bate em > 1 batch.
function _executarAuditoriaIncrementalChunked(
  sistemaId: string,
  sistema: Record<string, unknown>,
  modo: 'codigo' | 'completa',
  paginado: DiffPaginado,
  prevPayload: AuditPayload,
  prevRegistros: Record<string, RegistroFinding>,
): ServerResult {
  const fontes = _coletarFontesAuditoria(sistemaId);
  fontes.modo = modo;
  fontes.fonteCodigo = 'github';
  fontes.incremental = true;
  fontes.arquivosLidos = paginado.arquivos.length - paginado.arquivosIgnorados.length;
  fontes.bytesCodigo = paginado.bytes;
  fontes.commitSha = paginado.headCommit;
  fontes.baseCommit = paginado.baseCommit;
  // Em chunked, "truncado" só é verdade se o cap GLOBAL bateu (não pela
  // existência de múltiplos batches em si — múltiplos batches = sucesso!).
  fontes.codigoTruncado = paginado.arquivosIgnorados.length > 0;
  fontes.batchesUsados = paginado.batches.length;
  fontes.arquivosIgnorados = paginado.arquivosIgnorados;
  fontes.arquivosSplitted = paginado.arquivosSplitted;

  const props = PropertiesService.getScriptProperties();
  const modeloAuditoria = props.getProperty('LLM_MODEL_AUDITORIA') || '';
  const modeloEfetivo = modeloAuditoria || props.getProperty('LLM_MODEL') || 'desconhecido';

  const inicio = Date.now();

  // Roda os batches sequencialmente. Falhas em 1 batch não derrubam os outros.
  const payloadsParciais: AuditPayload[] = [];
  for (let i = 0; i < paginado.batches.length; i++) {
    const b = paginado.batches[i];
    const p = _auditarUmBatch(sistemaId, sistema, b.contexto, prevPayload, i + 1, paginado.batches.length, modeloAuditoria);
    if (p) payloadsParciais.push(p);
  }

  if (payloadsParciais.length === 0) {
    return { ok: false, error: 'Todos os batches da auditoria falharam. Tente de novo em 1 min ou troque o modelo em Configurações.' };
  }

  // Merge: dedup findings + união de resolvidos.
  const merged = _mergeAuditPayloads(payloadsParciais);

  // Síntese final: 1 chamada extra pra narrativa.
  const narrativa = _sintetizarNarrativaPosBatch(String(sistema.nome || 'sistema'), merged, paginado.batches.length, paginado.arquivos.length);
  merged.estadoGeral = narrativa.estadoGeral;
  merged.oQueEmpolga = narrativa.oQueEmpolga;
  merged.proximosPassos = narrativa.proximosPassos;

  const duracaoMs = Date.now() - inicio;

  // Auto-fecha backlog dos resolvidos antes de calcular saúde.
  let fechadosAuto: BacklogFechadoAuto[] = [];
  if (merged.resolvidos && merged.resolvidos.length > 0) {
    fechadosAuto = _fecharBacklogResolvidos(prevPayload, prevRegistros, merged.resolvidos);
  }

  const saudeAtual = calcularSaudeReal(sistemaId, merged);
  const saudeScore = (saudeAtual.ok && saudeAtual.data) ? Number((saudeAtual.data as { score: number }).score) : 0;

  const resultadoFinal: AuditResultPayloadServer = {
    id: '',
    texto: `## Estado geral\n${merged.estadoGeral}\n\n## Próximos passos estratégicos\n${merged.proximosPassos}`,
    payload: merged,
    fontes,
    saudeAtual: saudeAtual.ok ? saudeAtual.data : null,
    modeloUsado: modeloEfetivo,
    duracaoMs,
    criadoEm: new Date().toISOString(),
    registros: {},
    fechadosAuto,
  };

  try {
    const novaLinha = dbCreate('Auditorias', {
      sistemaId,
      criadoEm: resultadoFinal.criadoEm,
      modeloUsado: modeloEfetivo,
      duracaoMs,
      scoreNoMomento: saudeScore,
      numFindings: merged.findings.length,
      payloadJson: JSON.stringify(merged),
      fontesJson: JSON.stringify(fontes),
      registrosJson: '{}',
    }) as Record<string, unknown>;
    resultadoFinal.id = String(novaLinha.id || '');
  } catch { /* persistência é best-effort */ }

  return { ok: true, data: resultadoFinal };
}

function _executarAuditoriaIncremental(
  sistemaId: string,
  sistema: Record<string, unknown>,
  modo: 'codigo' | 'completa',
  diff: DiffContexto,
  prevPayload: AuditPayload,
  prevRegistros: Record<string, RegistroFinding>,
): ServerResult {
  const fontes = _coletarFontesAuditoria(sistemaId);
  fontes.modo = modo;
  fontes.fonteCodigo = 'github';
  fontes.incremental = true;
  fontes.arquivosLidos = diff.arquivos;
  fontes.bytesCodigo = diff.bytes;
  fontes.commitSha = diff.headCommit;
  fontes.baseCommit = diff.baseCommit;
  fontes.codigoTruncado = diff.truncado;
  fontes.batchesUsados = 1;

  const areasPermitidas = 'governanca|arquitetura|seguranca|dependencias|testes|operacional|financeiro|produto|ux|codigo|performance';

  const prevList = prevPayload.findings
    .map((f, i) => `#${i + 1} [${f.severidade}|${f.area}] ${f.titulo}\n   problema: ${f.problema}\n   evidência: ${f.evidencia}`)
    .join('\n');

  const promptUser = (
    `Auditoria INCREMENTAL do sistema "${sistema.nome}" (id=${sistemaId}).\n\n`
    + 'Já houve uma auditoria anterior. Abaixo estão (1) os ACHADOS ANTERIORES e (2) o DIFF de código (o que mudou no repositório desde então). '
    + 'Sua tarefa é RECONCILIAR: dizer o que o diff resolveu, o que ainda persiste, e quais problemas NOVOS o diff introduziu.\n\n'
    + 'Você é um diretor técnico/produto experiente. A saída vira cards individuais, então seja CONCRETO e ACIONÁVEL.\n\n'
    + 'Responda ESTRITAMENTE neste formato Markdown + bloco JSON ao final:\n\n'
    + '## Estado geral\n(2-3 frases sobre o impacto do diff: o que melhorou, o que ainda falta.)\n\n'
    + '## O que mudou\n(1 parágrafo curto resumindo o diff e o que ele resolve/quebra.)\n\n'
    + '## Próximos passos estratégicos\n(1 parágrafo sobre o que priorizar AGORA. Aponta o achado #N mais importante.)\n\n'
    + '<AUDIT>\n'
    + '{\n'
    + '  "estadoGeral": "<repita Estado geral>",\n'
    + '  "oQueEmpolga": ["bullet 1", "bullet 2"],\n'
    + '  "proximosPassos": "<repita Próximos passos>",\n'
    + '  "resolvidos": ["<título de um achado anterior que o diff resolveu>"],\n'
    + '  "findings": [\n'
    + '    {\n'
    + '      "titulo": "<curto, máx 70 chars>",\n'
    + '      "severidade": "alta|media|baixa",\n'
    + '      "area": "' + areasPermitidas + '",\n'
    + '      "origem": "novo|persiste",\n'
    + '      "problema": "<O QUE está errado. 1-2 frases.>",\n'
    + '      "evidencia": "<cite o arquivo + trecho do diff (linhas + ou -). Se inferência, comece com \\"Inferência:\\".>",\n'
    + '      "solucao": "<COMO resolver. 2-4 passos. Numera 1) 2) 3).>",\n'
    + '      "prompt": "<texto pronto pra colar no Cursor/Claude.>",\n'
    + '      "toolSugerida": "registrar_risco|registrar_decisao|registrar_oportunidade",\n'
    + '      "toolParams": { ...parametros corretos, com sistemaId="' + sistemaId + '"... }\n'
    + '    }\n'
    + '  ]\n'
    + '}\n'
    + '</AUDIT>\n\n'
    + 'REGRAS DURAS (qualidade > quantidade):\n'
    + '- "findings" deve conter: TODOS os achados anteriores que AINDA PERSISTEM (origem="persiste") + os NOVOS achados introduzidos pelo diff (origem="novo"). NÃO inclua achados que o diff resolveu — liste o título deles em "resolvidos".\n'
    + '- Um achado anterior só é "resolvido" se o DIFF claramente o corrige. Na dúvida, mantenha como "persiste".\n'
    + '- ⚠ ANTI-DUPLICIDADE (crítico): se um achado está em "resolvidos", você NÃO pode criar um achado NOVO cuja CAUSA-RAIZ seja a mesma do resolvido (mesmo com redação diferente). Exemplo proibido: resolver "URL de produção não registrada" e criar novo "URL de produção não registrada na Forja" → ambos têm a mesma causa-raiz "ausência de URL registrada" → escolha UM dos dois lados (mantém em "persiste" com nota OU deixa só em "resolvidos"). Cada problema lógico aparece em EXATAMENTE 1 lugar.\n'
    + '- Antes de marcar um achado como NOVO, verifique se ele cobre uma DIMENSÃO genuinamente diferente da que estava nos resolvidos. Se for variação textual, descarta.\n'
    + '- ⚠ NOVO finding só vale se tiver IMPACTO mensurável (segurança, dinheiro, tempo, manutenibilidade). Se o diff introduziu mudança de estilo/nomenclatura sem risco real, NÃO crie achado.\n'
    + '- Severidades têm critério OBJETIVO: ALTA=segurança/perda/blocker; MEDIA=dívida técnica que limita evolução, deps com CVE, ausência de testes em código crítico; BAIXA=DX/qualidade que economiza tempo no longo prazo (use COM PARCIMÔNIA).\n'
    + '- Máximo 8 findings. Não force mínimo — aceito 0 novos findings se o diff só resolveu coisas.\n'
    + '- Todo achado de CÓDIGO deve citar o ARQUIVO e o trecho literal do diff. Ex: "src/api.ts → + const API_KEY = \'sk-...\'".\n'
    + '- O JSON dentro de <AUDIT> precisa ser VÁLIDO. Aspas escapadas, sem comentários, sem trailing commas.\n'
    + '- toolParams perfeito pro tipo: registrar_risco {sistemaId, area, descricao, gravidade}; registrar_decisao {sistemaId, titulo, decisao, justificativa}; registrar_oportunidade {titulo, valorEstimado, proximoPasso}.\n\n'
    + 'IDs reais: sistemaId="' + sistemaId + '". Não invente outros.\n\n'
    + '--- ACHADOS ANTERIORES (auditados no commit ' + diff.baseCommit + ') ---\n' + prevList + '\n\n'
    + (modo === 'completa' ? '--- CONTEXTO DE GOVERNANÇA (metadados, custos, riscos, decisões) ---\n' + _contextoSistemaProfundo(sistemaId) + '\n\n' : '')
    + '--- DIFF DE CÓDIGO (' + diff.baseCommit + ' → ' + diff.headCommit + ') ---\n' + diff.contexto
  );

  const messages: LlmMessage[] = [
    { role: 'system', content: 'Você é um auditor técnico/produto sênior. Seguir o formato exigido é mais importante do que ser eloquente.' },
    { role: 'user', content: promptUser },
  ];

  const props = PropertiesService.getScriptProperties();
  const modeloAuditoria = props.getProperty('LLM_MODEL_AUDITORIA') || '';
  const modeloEfetivo = modeloAuditoria || props.getProperty('LLM_MODEL') || 'desconhecido';

  const inicio = Date.now();
  const resposta = forjaCallLLM(messages, 5500, modeloAuditoria, 'auditoria');
  const duracaoMs = Date.now() - inicio;
  const parsed = _parseAuditPayload(resposta);

  // Auto-fecha os itens de backlog cujos achados o diff resolveu. Faz ANTES de
  // calcular a saúde, pra que riscos mitigados/decisões "feito" já reflitam no score.
  let fechadosAuto: BacklogFechadoAuto[] = [];
  if (parsed.payload && parsed.payload.resolvidos && parsed.payload.resolvidos.length > 0) {
    fechadosAuto = _fecharBacklogResolvidos(prevPayload, prevRegistros, parsed.payload.resolvidos);
  }

  // Passa o payload novo direto pra calcularSaudeReal — assim o score já reflete
  // os achados RECÉM-RECONCILIADOS (e não os antigos do banco, que ainda não
  // foram substituídos pela nova auditoria persistida abaixo).
  const saudeAtual = calcularSaudeReal(sistemaId, parsed.payload || null);
  const saudeScore = (saudeAtual.ok && saudeAtual.data) ? Number((saudeAtual.data as { score: number }).score) : 0;

  const resultadoFinal: AuditResultPayloadServer = {
    id: '',
    texto: parsed.texto || resposta,
    payload: parsed.payload,
    fontes,
    saudeAtual: saudeAtual.ok ? saudeAtual.data : null,
    modeloUsado: modeloEfetivo,
    duracaoMs,
    criadoEm: new Date().toISOString(),
    registros: {},
    fechadosAuto,
  };

  try {
    if (parsed.payload) {
      const novaLinha = dbCreate('Auditorias', {
        sistemaId,
        criadoEm: resultadoFinal.criadoEm,
        modeloUsado: modeloEfetivo,
        duracaoMs,
        scoreNoMomento: saudeScore,
        numFindings: parsed.payload.findings.length,
        payloadJson: JSON.stringify(parsed.payload),
        fontesJson: JSON.stringify(fontes),
        registrosJson: '{}',
      }) as Record<string, unknown>;
      resultadoFinal.id = String(novaLinha.id || '');
    }
  } catch { /* persistência é best-effort */ }

  return { ok: true, data: resultadoFinal };
}

function acaoIAAuditarSistema(sistemaId: string, modo?: string, forcar?: boolean): ServerResult {
  try {
    const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId);
    if (!sistema) return { ok: false, error: 'Sistema não encontrado' };

    const modoSolicitado: 'governanca' | 'codigo' | 'completa' =
      (modo === 'governanca' || modo === 'codigo') ? modo : 'completa';

    // Caminho incremental (GitHub, sem forçar). Uma única ida ao GitHub pega o HEAD:
    //  - HEAD == commit auditado  → curto-circuito: devolve a auditoria salva (sem LLM).
    //  - HEAD != commit auditado e há achados anteriores → auditoria INCREMENTAL:
    //    reconcilia os achados antigos contra o diff (resolvido/persiste) + acha novos.
    // `forcar` pula tudo isso e roda a auditoria completa do repo.
    const repoUrlSist = String(sistema.repoUrl || '').trim();
    if (!forcar && modoSolicitado !== 'governanca' && repoUrlSist) {
      const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
      const full = _ghFullName(repoUrlSist);
      if (token && /^[^/]+\/[^/]+$/.test(full)) {
        const { auditoria: ultAud, commit: lastCommit } = _ultimaAuditoriaCommit(sistemaId);
        if (lastCommit) {
          const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };
          const head = _ghHeadCommitCurto(full, headers);
          if (head && head === lastCommit) {
            const ult = getUltimaAuditoria(sistemaId);
            if (ult.ok && ult.data) {
              return { ok: true, data: Object.assign({}, ult.data, { semMudanca: true }) };
            }
          } else if (head && ultAud) {
            // Repo mudou: tenta auditoria incremental sobre o diff.
            let prevPayload: AuditPayload | null = null;
            try { prevPayload = JSON.parse(String(ultAud.payloadJson || 'null')) as AuditPayload; } catch { prevPayload = null; }
            let prevRegistros: Record<string, RegistroFinding> = {};
            try { prevRegistros = JSON.parse(String(ultAud.registrosJson || '{}')) || {}; } catch { prevRegistros = {}; }
            if (prevPayload && Array.isArray(prevPayload.findings) && prevPayload.findings.length > 0) {
              // Lê o diff PAGINADO. Se cabe em 1 batch (caso comum) → caminho rápido (1 chamada).
              // Se precisa de N batches → caminho chunked (N chamadas + 1 síntese), resolve o
              // DIFF TRUNCADO histórico que silenciava arquivos sem o user saber.
              const pag = _lerDiffGitHubPaginado(repoUrlSist, lastCommit);
              if (!pag.erro && pag.batches.length > 0) {
                if (pag.batches.length === 1 && pag.arquivosIgnorados.length === 0) {
                  // Cabe em 1 batch → fluxo single (mais rápido, 1 chamada).
                  const diffSingle: DiffContexto = {
                    contexto: pag.batches[0].contexto,
                    arquivos: pag.batches[0].arquivos.length,
                    bytes: pag.batches[0].bytes,
                    baseCommit: pag.baseCommit,
                    headCommit: pag.headCommit,
                    truncado: false,
                    lista: pag.batches[0].arquivos.map((u) => u.filename),
                  };
                  return _executarAuditoriaIncremental(sistemaId, sistema, modoSolicitado, diffSingle, prevPayload, prevRegistros);
                }
                // Múltiplos batches → caminho chunked.
                return _executarAuditoriaIncrementalChunked(sistemaId, sistema, modoSolicitado, pag, prevPayload, prevRegistros);
              }
              // Sem diff utilizável (erro/0 arquivos relevantes) → cai pra completa.
            }
          }
        }
      }
    }

    const fontes = _coletarFontesAuditoria(sistemaId);
    fontes.modo = modoSolicitado;

    // Leitura de código (GitHub/GAS) quando o modo pede. Se falhar, degradamos
    // pra governança em vez de devolver um relatório vazio.
    const codigo = modoSolicitado !== 'governanca' ? _lerCodigoSistema(sistema) : null;
    const temCodigo = !!(codigo && codigo.arquivos > 0 && codigo.contexto);
    const usaGov = modoSolicitado !== 'codigo' || !temCodigo;
    if (codigo) {
      fontes.fonteCodigo = codigo.fonte;
      fontes.arquivosLidos = codigo.arquivos;
      fontes.bytesCodigo = codigo.bytes;
      fontes.commitSha = codigo.commitSha;
      fontes.codigoTruncado = codigo.truncado;
      if (codigo.erro) fontes.codigoErro = codigo.erro;
    } else if (modoSolicitado !== 'governanca' && !String(sistema.repoUrl || '').trim() && !String(sistema.scriptId || '').trim()) {
      fontes.codigoErro = 'Sistema sem repositório (repoUrl) nem scriptId pra auditar código.';
    }

    // Sistema "faminto de dados": sem código legível, sem repo e sem nenhum registro
    // de governança. Auditar com IA aqui só geraria achados genéricos — devolvemos um
    // checklist de setup determinístico (sem gastar LLM).
    const totalRegistros = fontes.custos + fontes.decisoes + fontes.riscos + fontes.alertas + fontes.timeline;
    if (!temCodigo && !fontes.temRepo && totalRegistros === 0) {
      return _auditoriaOnboarding(sistemaId, sistema, fontes, (codigo && codigo.erro) || fontes.codigoErro || '');
    }

    const blocosCtx: string[] = [];
    if (usaGov) blocosCtx.push('--- CONTEXTO DE GOVERNANÇA (metadados, custos, riscos, decisões) ---\n' + _contextoSistemaProfundo(sistemaId));
    if (temCodigo) blocosCtx.push('--- CONTEXTO DE CÓDIGO (repositório real) ---\n' + (codigo as CodigoContexto).contexto);
    const contexto = blocosCtx.join('\n\n');

    const areasPermitidas = temCodigo
      ? 'governanca|arquitetura|seguranca|dependencias|testes|operacional|financeiro|produto|ux|codigo|performance'
      : 'governanca|arquitetura|seguranca|operacional|financeiro|produto|ux';

    const promptUser = (
      `Auditoria estruturada do sistema "${sistema.nome}" (id=${sistemaId}).\n\n`
      + 'Você é um diretor técnico/produto experiente. Sua análise vai ser renderizada como cards individuais, então precisa ser CONCRETA e ACIONÁVEL.\n\n'
      + 'Responda ESTRITAMENTE neste formato Markdown + bloco JSON ao final:\n\n'
      + '## Estado geral\n'
      + '(2-3 frases sobre o "momento" desse sistema. Sem fluff.)\n\n'
      + '## O que empolga\n'
      + '(opcional, 0-3 bullets curtos. Pode omitir se não houver nada concreto.)\n\n'
      + '## Próximos passos estratégicos\n'
      + '(1 parágrafo curto sobre o que priorizar AGORA. Aponta o achado #N mais importante.)\n\n'
      + '<AUDIT>\n'
      + '{\n'
      + '  "estadoGeral": "<repita o conteúdo de Estado geral>",\n'
      + '  "oQueEmpolga": ["bullet 1", "bullet 2"],\n'
      + '  "proximosPassos": "<repita o conteúdo de Próximos passos>",\n'
      + '  "findings": [\n'
      + '    {\n'
      + '      "titulo": "<curto, máx 70 chars, descritivo>",\n'
      + '      "severidade": "alta|media|baixa",\n'
      + '      "area": "' + areasPermitidas + '",\n'
      + '      "problema": "<O QUE está errado. 1-2 frases. Sem repetir o título.>",\n'
      + '      "evidencia": "<RASTREABILIDADE: cite literalmente o dado do contexto que sustenta o problema. Ex: \\"0 decisões registradas\\", \\"stack vazia\\", \\"sem urlProd nem dominioCustomizado\\". Se você ESTIVER INFERINDO sem dado direto, comece com \\"Inferência:\\".>",\n'
      + '      "solucao": "<COMO resolver. 2-4 passos concretos. Numera com 1) 2) 3).>",\n'
      + '      "prompt": "<Texto pronto pra colar no Cursor ou Claude. Inicia com \\"Você é...\\" ou \\"Sua tarefa é...\\". Pode ter 100-400 palavras. Sem cercas markdown internas.>",\n'
      + '      "toolSugerida": "registrar_risco|registrar_decisao|registrar_oportunidade",\n'
      + '      "toolParams": { ...parametros corretos da tool, com sistemaId="' + sistemaId + '"... }\n'
      + '    }\n'
      + '  ]\n'
      + '}\n'
      + '</AUDIT>\n\n'
      + 'REGRAS DURAS (qualidade > quantidade):\n'
      + '- SEM MÍNIMO. Aceito 0 findings se o sistema realmente não tiver problemas reais. Aceito até ' + (temCodigo ? '8' : '6') + ' findings no máximo.\n'
      + '- ⚠ ANTES DE LISTAR um finding, pergunte a si mesmo: "Este achado tem IMPACTO mensurável (segurança, dinheiro, tempo, manutenibilidade) OU é nitpicking estético/preferência de estilo?" Se for nitpicking, NÃO LISTE.\n'
      + '- ⚠ Cada finding DEVE ter um IMPACTO concreto explícito no campo "problema". Não aceito "não está documentado" sozinho — exija "não está documentado, e isso faz X (custo/risco/atraso/dívida) acontecer".\n'
      + '- Severidades têm critério OBJETIVO:\n'
      + '  • ALTA: vulnerabilidade de segurança, perda de dados, sistema indisponível, vazamento de PII, custo descontrolado, blocker pra negócio.\n'
      + '  • MEDIA: dívida técnica que limita evolução, ausência de testes em código crítico, falta de monitoramento em prod, dependência desatualizada com CVE conhecida.\n'
      + '  • BAIXA: melhorias de DX/qualidade de código que economizam tempo no longo prazo. Use COM PARCIMÔNIA — sistema saudável não precisa ter achados baixos.\n'
      + '- NUNCA repita um problema que já está em DECISÕES PRÉVIAS, RISCOS ABERTOS ou ALERTAS RECENTES.\n'
      + '- Cada finding TEM que ter evidência rastreável ao contexto, ou começar com "Inferência:" e explicar de onde tirou.\n'
      + (temCodigo ? '- Quando o achado vier do CÓDIGO, a evidência DEVE citar o ARQUIVO e o trecho literal. Ex: "src/config.ts → const API_KEY = \'sk-...\'". Priorize achados de código reais (segredos, deps desatualizadas, falta de testes/CI, arquitetura, código morto) sobre achados de metadados.\n' : '')
      + '- O JSON dentro de <AUDIT> precisa ser VÁLIDO. Aspas escapadas, sem comentários, sem trailing commas.\n'
      + '- toolParams precisa estar PERFEITO pro tipo de tool. Ex: registrar_risco quer {sistemaId, area, descricao, gravidade}; registrar_decisao quer {sistemaId, titulo, decisao, justificativa}; registrar_oportunidade quer {titulo, valorEstimado, proximoPasso}.\n\n'
      + 'IDs reais: sistemaId="' + sistemaId + '". Não invente outros.\n\n'
      + '--- CONTEXTO COMPLETO DO SISTEMA ---\n' + contexto
    );

    const messages: LlmMessage[] = [
      { role: 'system', content: 'Você é um auditor técnico/produto sênior. Seguir o formato exigido é mais importante do que ser eloquente.' },
      { role: 'user', content: promptUser },
    ];

    const props = PropertiesService.getScriptProperties();
    const modeloAuditoria = props.getProperty('LLM_MODEL_AUDITORIA') || '';
    const modeloEfetivo = modeloAuditoria || props.getProperty('LLM_MODEL') || 'desconhecido';

    const inicio = Date.now();
    const resposta = forjaCallLLM(messages, 5500, modeloAuditoria, 'auditoria');
    const duracaoMs = Date.now() - inicio;
    const parsed = _parseAuditPayload(resposta);

    // Reconciliação determinística pós-IA: cruza títulos novos contra os da
    // última auditoria pra reconstruir "saíram / entraram / persistem" mesmo
    // quando a IA não passa por reconciliação explícita (caminho completo).
    if (parsed.payload) {
      parsed.payload = _reconciliarComAnterior(parsed.payload, sistemaId);
    }

    // Auto-fecha backlog dos achados que o reconciliador deterministou como
    // resolvidos. Antes só o incremental fazia isso — agora o completo também,
    // pra fechar o ciclo de "registrei decisão → próxima auditoria fecha o achado".
    let fechadosAuto: BacklogFechadoAuto[] = [];
    if (parsed.payload && parsed.payload.resolvidos && parsed.payload.resolvidos.length > 0) {
      const auditoriasPrev = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
        .filter((a) => String(a.sistemaId || '') === sistemaId)
        .sort((a, b) => String(b.criadoEm).localeCompare(String(a.criadoEm)));
      if (auditoriasPrev.length > 0) {
        try {
          const prevPayloadParaFechar = JSON.parse(String(auditoriasPrev[0].payloadJson || 'null')) as AuditPayload | null;
          const prevRegistrosParaFechar = JSON.parse(String(auditoriasPrev[0].registrosJson || '{}')) as Record<string, RegistroFinding>;
          if (prevPayloadParaFechar) {
            fechadosAuto = _fecharBacklogResolvidos(prevPayloadParaFechar, prevRegistrosParaFechar, parsed.payload.resolvidos);
          }
        } catch { /* ignore */ }
      }
    }

    // Score reflete os achados recém-encontrados — não os antigos no banco.
    const saudeAtual = calcularSaudeReal(sistemaId, parsed.payload || null);
    const saudeScore = (saudeAtual.ok && saudeAtual.data) ? Number((saudeAtual.data as { score: number }).score) : 0;

    const resultadoFinal: AuditResultPayloadServer = {
      id: '',
      texto: parsed.texto || resposta,
      payload: parsed.payload,
      fontes,
      saudeAtual: saudeAtual.ok ? saudeAtual.data : null,
      modeloUsado: modeloEfetivo,
      duracaoMs,
      criadoEm: new Date().toISOString(),
      registros: {},
      fechadosAuto,
    };

    // Persiste só se o payload parseou (pra não guardar lixo)
    try {
      if (parsed.payload) {
        const novaLinha = dbCreate('Auditorias', {
          sistemaId,
          criadoEm: resultadoFinal.criadoEm,
          modeloUsado: modeloEfetivo,
          duracaoMs,
          scoreNoMomento: saudeScore,
          numFindings: parsed.payload.findings.length,
          payloadJson: JSON.stringify(parsed.payload),
          fontesJson: JSON.stringify(fontes),
          registrosJson: '{}',
        }) as Record<string, unknown>;
        resultadoFinal.id = String(novaLinha.id || '');
      }
    } catch { /* persistência é best-effort */ }

    return { ok: true, data: resultadoFinal };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao auditar' };
  }
}

// Retorna a auditoria mais recente de um sistema (ou null se nunca foi auditado).
function getUltimaAuditoria(sistemaId: string): ServerResult {
  try {
    const todas = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
      .filter((a) => String(a.sistemaId || '') === sistemaId)
      .sort((a, b) => String(b.criadoEm || '').localeCompare(String(a.criadoEm || '')));
    if (todas.length === 0) return { ok: true, data: null };
    const ult = todas[0];
    let payload: AuditPayload | null = null;
    let fontes: AuditFontes | null = null;
    let registros: Record<string, RegistroFinding> = {};
    try { payload = JSON.parse(String(ult.payloadJson || 'null')); } catch { payload = null; }
    try { fontes = JSON.parse(String(ult.fontesJson || 'null')); } catch { fontes = null; }
    try { registros = JSON.parse(String(ult.registrosJson || '{}')) || {}; } catch { registros = {}; }
    const saude = calcularSaudeReal(sistemaId);
    return {
      ok: true,
      data: {
        id: ult.id,
        sistemaId,
        criadoEm: String(ult.criadoEm || ''),
        modeloUsado: String(ult.modeloUsado || ''),
        duracaoMs: Number(ult.duracaoMs || 0),
        scoreNoMomento: Number(ult.scoreNoMomento || 0),
        numFindings: Number(ult.numFindings || 0),
        texto: '',
        payload,
        fontes,
        saudeAtual: saude.ok ? saude.data : null,
        totalAuditorias: todas.length,
        registros,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar auditoria' };
  }
}

// Linha do tempo das auditorias de um sistema: cada rodada com score, nº de
// achados, quantos o diff resolveu, modelo e commit. Alimenta a aba Histórico
// (evolução do score ao longo do tempo). Mais recente primeiro.
function getHistoricoAuditorias(sistemaId: string): ServerResult {
  try {
    const alvo = String(sistemaId || '').trim();
    const todas = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
      .filter((a) => String(a.sistemaId || '').trim() === alvo)
      .sort((a, b) => String(b.criadoEm || '').localeCompare(String(a.criadoEm || '')));
    const itens = todas.map((a) => {
      let resolvidos = 0;
      let incremental = false;
      let commitSha = '';
      try {
        const p = JSON.parse(String(a.payloadJson || 'null')) as AuditPayload | null;
        resolvidos = p && Array.isArray(p.resolvidos) ? p.resolvidos.length : 0;
      } catch { /* ignora payload corrompido */ }
      try {
        const f = JSON.parse(String(a.fontesJson || 'null')) as AuditFontes | null;
        incremental = !!(f && f.incremental);
        commitSha = f && f.commitSha ? String(f.commitSha) : '';
      } catch { /* ignora fontes corrompidas */ }
      return {
        id: String(a.id || ''),
        criadoEm: String(a.criadoEm || ''),
        modeloUsado: String(a.modeloUsado || ''),
        duracaoMs: Number(a.duracaoMs || 0),
        scoreNoMomento: Number(a.scoreNoMomento || 0),
        numFindings: Number(a.numFindings || 0),
        resolvidos,
        incremental,
        commitSha,
      };
    });
    return { ok: true, data: itens };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar histórico' };
  }
}

// Marca um finding específico como "já registrado" — atualiza o JSON do registrosJson
// na linha da Auditorias. Permite que ao reabrir o drawer, o FindingCard mostre
// "Já registrado" ao invés do botão de ação, evitando duplicações.
function marcarFindingRegistrado(payload: {
  auditoriaId: string;
  findingId: string;
  tipo: 'risco' | 'decisao' | 'oportunidade' | string;
  idCriado: string;
}): ServerResult {
  try {
    if (!payload || !payload.auditoriaId || !payload.findingId) {
      throw new Error('auditoriaId e findingId são obrigatórios');
    }
    const linha = dbGetById('Auditorias', payload.auditoriaId);
    if (!linha) throw new Error('Auditoria não encontrada');

    let registros: Record<string, RegistroFinding> = {};
    try { registros = JSON.parse(String(linha.registrosJson || '{}')) || {}; } catch { registros = {}; }
    registros[payload.findingId] = {
      tipo: String(payload.tipo || ''),
      idCriado: String(payload.idCriado || ''),
      registradoEm: new Date().toISOString(),
    };
    dbUpdate('Auditorias', payload.auditoriaId, { registrosJson: JSON.stringify(registros) });
    return { ok: true, data: { findingId: payload.findingId, registros } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Apaga TODO o histórico de auditorias de um sistema. Pensado pra testar do zero
// (ex.: validar mudanças no fluxo de auditoria sem o curto-circuito/incremental
// reaproveitando rodadas antigas).
function limparAuditoriasSistema(sistemaId: string): ServerResult {
  try {
    const alvo = String(sistemaId || '').trim();
    if (!alvo) return { ok: false, error: 'sistemaId é obrigatório' };
    const ids = (dbGetAll('Auditorias') as Array<Record<string, unknown>>)
      .filter((a) => String(a.sistemaId || '').trim() === alvo)
      .map((a) => String(a.id || ''))
      .filter((id) => id);
    const removidas = ids.length > 0 ? dbDeleteMany('Auditorias', ids) : 0;
    return { ok: true, data: { removidas } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao limpar auditorias' };
  }
}

// Versão "rica" — devolve TODOS os itens do backlog de UM sistema usando
// exatamente o mesmo critério do sumário (filtro tolerante por trim).
// Substitui getDecisoesBySistema no painel do Kanban pra garantir que
// quando o badge mostra N, o painel também mostra N — uma fonte única.
function getBacklogItensSistema(sistemaIdAlvo: string): ServerResult {
  try {
    const alvo = String(sistemaIdAlvo || '').trim();
    if (!alvo) return { ok: true, data: { itens: [], total: 0 } };
    const todas = dbGetAll('Decisoes') as Array<Record<string, unknown>>;
    const itens = todas.filter((d) => String(d.sistemaId || '').trim() === alvo);
    // Mapeia pra forma esperada pelo frontend, garantindo strings.
    const itensNormalizados = itens.map((d) => ({
      id: String(d.id || ''),
      sistemaId: String(d.sistemaId || '').trim(),
      data: String(d.data || ''),
      titulo: String(d.titulo || ''),
      decisao: String(d.decisao || ''),
      justificativa: String(d.justificativa || ''),
      status: String(d.status || 'backlog').toLowerCase().trim(),
      prioridade: String(d.prioridade || 'media').toLowerCase().trim(),
      tags: String(d.tags || ''),
      estimativa: String(d.estimativa || ''),
    }));
    return { ok: true, data: { itens: itensNormalizados, total: itensNormalizados.length, sistemaIdConsultado: alvo, totalNaPlanilha: todas.length } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Sumário leve do backlog por sistema (Bancada → card mostra "3 a fazer · 1 fazendo").
// Conta itens nas colunas ativas (backlog/ativa/fazendo) e marca alta como prio.
function getBacklogSumario(): ServerResult {
  try {
    const todas = dbGetAll('Decisoes') as Array<Record<string, unknown>>;
    const porSistema: Record<string, { aFazer: number; fazendo: number; alta: number; total: number }> = {};
    for (const d of todas) {
      const sid = String(d.sistemaId || '').trim();
      if (!sid) continue;
      const status = String(d.status || '').toLowerCase();
      const prio = String(d.prioridade || 'media').toLowerCase();
      if (!porSistema[sid]) porSistema[sid] = { aFazer: 0, fazendo: 0, alta: 0, total: 0 };
      if (status === 'backlog' || status === 'ativa' || status === '') {
        porSistema[sid].aFazer++;
        porSistema[sid].total++;
        if (prio === 'alta') porSistema[sid].alta++;
      } else if (status === 'fazendo') {
        porSistema[sid].fazendo++;
        porSistema[sid].total++;
        if (prio === 'alta') porSistema[sid].alta++;
      }
    }
    return { ok: true, data: porSistema };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Sumário leve pra batch (Bancada): { sistemaId -> { criadoEm, numFindings } }
function getAuditoriasSumario(): ServerResult {
  try {
    const todas = dbGetAll('Auditorias') as Array<Record<string, unknown>>;
    const porSistema: Record<string, { criadoEm: string; numFindings: number; modeloUsado: string }> = {};
    for (const a of todas) {
      const sid = String(a.sistemaId || '');
      if (!sid) continue;
      const criadoEm = String(a.criadoEm || '');
      if (!porSistema[sid] || criadoEm > porSistema[sid].criadoEm) {
        porSistema[sid] = {
          criadoEm,
          numFindings: Number(a.numFindings || 0),
          modeloUsado: String(a.modeloUsado || ''),
        };
      }
    }
    return { ok: true, data: porSistema };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

function getModeloAuditoria(): ServerResult {
  try {
    const props = PropertiesService.getScriptProperties();
    const scriptId = ScriptApp.getScriptId();
    return {
      ok: true,
      data: {
        modeloAuditoria: props.getProperty('LLM_MODEL_AUDITORIA') || '',
        modeloChat: props.getProperty('LLM_MODEL') || '',
        chaveProperty: 'LLM_MODEL_AUDITORIA',
        chavePropertyChat: 'LLM_MODEL',
        // Página de Project Settings (onde fica a UI de Script Properties).
        settingsUrl: `https://script.google.com/home/projects/${scriptId}/settings`,
        editorUrl: `https://script.google.com/home/projects/${scriptId}/edit`,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Tenta GET /models no proxy/endpoint configurado e retorna lista normalizada.
// Funciona com qualquer provider OpenAI-compatible (proxies, LiteLLM, OpenRouter)
// e com Anthropic nativo (que também expõe /v1/models desde 2024).
function listModelosDisponiveis(): ServerResult {
  try {
    const cfg = getLlmConfig();
    if (!cfg.baseUrl) throw new Error('Configure a Base URL do proxy em Configurações de IA.');
    if (!cfg.apiKey) throw new Error('Configure a chave da API em Configurações de IA.');

    const urls = llmUrlCandidates(cfg.baseUrl, '/models');
    const headers: Record<string, string> = cfg.provider === 'anthropic'
      ? { 'x-api-key': cfg.apiKey, 'anthropic-version': '2023-06-01' }
      : { Authorization: `Bearer ${cfg.apiKey}` };

    let resposta: { code: number; body: string; url: string } = { code: 0, body: '', url: urls[0] || '' };
    for (const url of urls) {
      const res = UrlFetchApp.fetch(url, {
        method: 'get',
        muteHttpExceptions: true,
        headers,
      });
      const code = res.getResponseCode();
      resposta = { code, body: res.getContentText(), url };
      if (code !== 404) break;
    }

    if (resposta.code < 200 || resposta.code >= 300) {
      throw new Error(`${resposta.code} em ${resposta.url} — ${resposta.body.slice(0, 200)}`);
    }

    const json = JSON.parse(resposta.body);
    // Formatos esperados:
    //  - OpenAI / proxies: { data: [{ id, ... }] }
    //  - Anthropic: { data: [{ id, display_name?, ... }] }
    //  - alguns retornam array direto
    let raw: Array<Record<string, unknown>> = [];
    if (Array.isArray(json)) raw = json;
    else if (Array.isArray(json.data)) raw = json.data as Array<Record<string, unknown>>;
    else if (Array.isArray(json.models)) raw = json.models as Array<Record<string, unknown>>;
    else throw new Error('Formato de resposta não reconhecido (esperava .data[] ou .models[])');

    interface ModeloDisponivel {
      id: string;
      label: string;
      familia: 'anthropic' | 'openai' | 'google' | 'meta' | 'mistral' | 'outros';
      categoria: 'rápido' | 'balanço' | 'qualidade' | 'embedding' | 'outros';
    }

    const familiaFromId = (id: string): ModeloDisponivel['familia'] => {
      const s = id.toLowerCase();
      if (s.indexOf('claude') >= 0) return 'anthropic';
      if (s.indexOf('gpt') >= 0 || s.indexOf('o1') === 0 || s.indexOf('o3') === 0 || s.indexOf('o4') === 0) return 'openai';
      if (s.indexOf('gemini') >= 0 || s.indexOf('palm') >= 0) return 'google';
      if (s.indexOf('llama') >= 0) return 'meta';
      if (s.indexOf('mistral') >= 0 || s.indexOf('mixtral') >= 0) return 'mistral';
      return 'outros';
    };

    const categoriaFromId = (id: string): ModeloDisponivel['categoria'] => {
      const s = id.toLowerCase();
      if (s.indexOf('embed') >= 0) return 'embedding';
      if (s.indexOf('haiku') >= 0 || s.indexOf('mini') >= 0 || s.indexOf('nano') >= 0 || s.indexOf('flash') >= 0) return 'rápido';
      if (s.indexOf('opus') >= 0 || s.indexOf('ultra') >= 0) return 'qualidade';
      if (s.indexOf('sonnet') >= 0 || s.indexOf('gpt-4o') >= 0 || s.indexOf('gpt-4-turbo') >= 0 || s.indexOf('pro') >= 0) return 'balanço';
      return 'outros';
    };

    const modelos: ModeloDisponivel[] = raw
      .map((m): ModeloDisponivel | null => {
        const id = String(m.id || m.name || '');
        if (!id) return null;
        return {
          id,
          label: String(m.display_name || m.id || id),
          familia: familiaFromId(id),
          categoria: categoriaFromId(id),
        };
      })
      .filter((x): x is ModeloDisponivel => x !== null)
      .sort((a, b) => a.id.localeCompare(b.id));

    return {
      ok: true,
      data: {
        total: modelos.length,
        endpoint: resposta.url,
        modelos,
        consultadoEm: new Date().toISOString(),
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar modelos' };
  }
}

function setModeloAuditoria(modelo: string): ServerResult {
  try {
    const props = PropertiesService.getScriptProperties();
    if (!modelo || !modelo.trim()) props.deleteProperty('LLM_MODEL_AUDITORIA');
    else props.setProperty('LLM_MODEL_AUDITORIA', modelo.trim());
    return { ok: true, data: { modeloAuditoria: modelo.trim() || '(usando o mesmo modelo do chat)' } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// ─── Roteamento de IA por serviço (painel Configurações → IA) ────────────────
// Lista cada serviço de IA com o modelo efetivo, se tem override, endpoint e
// (pro proxy) o farol de status compartilhado.
function listarServicosIA(): ServerResult {
  try {
    const cfg = getLlmConfig();
    const props = PropertiesService.getScriptProperties();
    let geminiModelo = '';
    try { geminiModelo = _geminiModelo(); } catch { geminiModelo = props.getProperty('GEMINI_MODEL') || ''; }

    // Farol do proxy (compartilhado entre todos os serviços proxy).
    const ultimo = _lerStatusLLM();
    let saudeProxy: 'verde' | 'vermelho' | 'desconhecido' = 'desconhecido';
    if (ultimo) {
      const min = (Date.now() - ultimo.ts) / 60000;
      if (min < 30) saudeProxy = ultimo.ok ? 'verde' : 'vermelho';
    }

    const servicos = SERVICOS_IA.map((s) => {
      if (s.stack === 'gemini') {
        const meta = _classificarModelo(geminiModelo);
        return {
          id: s.id, label: s.label, descricao: s.descricao, stack: s.stack,
          complexidade: s.complexidade, roteavel: false,
          modeloEfetivo: geminiModelo, overrideAtivo: false,
          rotulo: meta.rotulo, tier: meta.tier,
          endpoint: 'generativelanguage.googleapis.com',
        };
      }
      const ov = (props.getProperty(s.propKey) || '').trim();
      const modeloEfetivo = ov || cfg.modelo;
      const meta = _classificarModelo(modeloEfetivo);
      // Farol individual: status da última chamada DESTE serviço (< 30min).
      const stUso = _lerStatusUso(s.id);
      let saude: 'verde' | 'vermelho' | 'desconhecido' = 'desconhecido';
      let ultimaChamada: { ts: number; ok: boolean; latenciaMs?: number; erro?: string } | null = null;
      if (stUso) {
        const min = (Date.now() - stUso.ts) / 60000;
        if (min < 30) saude = stUso.ok ? 'verde' : 'vermelho';
        ultimaChamada = { ts: stUso.ts, ok: stUso.ok, latenciaMs: stUso.latenciaMs, erro: stUso.erro };
      }
      return {
        id: s.id, label: s.label, descricao: s.descricao, stack: s.stack,
        complexidade: s.complexidade, roteavel: s.roteavel,
        modeloEfetivo, overrideAtivo: !!ov,
        rotulo: meta.rotulo, tier: meta.tier,
        endpoint: cfg.baseUrl, saude, ultimaChamada,
      };
    });

    const metaGlobal = _classificarModelo(cfg.modelo);
    return {
      ok: true,
      data: {
        global: {
          configurado: !!cfg.modelo, modelo: cfg.modelo, provider: cfg.provider,
          baseUrl: cfg.baseUrl, rotulo: metaGlobal.rotulo, tier: metaGlobal.tier,
          saude: saudeProxy,
        },
        gemini: { configurado: !!props.getProperty('GEMINI_API_KEY'), modelo: geminiModelo },
        servicos,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar serviços de IA' };
  }
}

// Define (ou limpa, se vazio) o modelo de um serviço proxy roteável.
function setModeloServico(uso: string, modelo: string): ServerResult {
  try {
    const svc = SERVICOS_IA.find((s) => s.id === uso && s.stack === 'proxy' && s.roteavel);
    if (!svc) return { ok: false, error: 'Serviço não roteável: ' + uso };
    const props = PropertiesService.getScriptProperties();
    const m = String(modelo || '').trim();
    if (!m) props.deleteProperty(svc.propKey);
    else props.setProperty(svc.propKey, m);
    return { ok: true, data: { id: uso, modelo: m, usandoGlobal: !m } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar modelo do serviço' };
  }
}

// Pede pra própria LLM recomendar, dentre os modelos DISPONÍVEIS no provedor,
// o mais barato/eficiente pra cada serviço (pela complexidade). Estima custo
// pelo nome do modelo — não mantém tabela de preços.
function sugerirRoteamentoIA(): ServerResult {
  try {
    const lr = listModelosDisponiveis();
    if (!lr.ok || !lr.data) {
      return { ok: false, error: 'Não consegui listar os modelos do seu provedor (GET /models falhou). Teste a conexão em Configurações → IA e tente de novo.' };
    }
    const modelosIds = (lr.data as { modelos: Array<{ id: string }> }).modelos.map((m) => m.id);
    if (modelosIds.length === 0) return { ok: false, error: 'Seu provedor não retornou modelos em /models.' };

    const servicosProxy = SERVICOS_IA.filter((s) => s.stack === 'proxy' && s.roteavel);
    const catalogoTxt = servicosProxy
      .map((s) => `- ${s.id} | ${s.label} | complexidade=${s.complexidade} | ${s.descricao}`)
      .join('\n');
    const modelosTxt = modelosIds.join(', ');

    const sys = 'Você é um arquiteto de custos de LLM. Recebe a lista de MODELOS DISPONÍVEIS e uma lista de SERVIÇOS com sua complexidade. '
      + 'Para CADA serviço, escolha o modelo MAIS BARATO/eficiente da lista que ainda entregue qualidade suficiente pra complexidade '
      + '(simples = um modelo rápido/barato resolve; média = intermediário; pesada = precisa de um modelo capaz). '
      + 'Estime custo/eficiência pelo NOME do modelo: haiku/mini/flash/nano/lite = baratos e rápidos; sonnet/gpt-4o/pro = intermediários; opus/ultra/gpt-4-turbo/reasoning = caros. '
      + 'Use SOMENTE ids EXATOS da lista de modelos disponíveis. '
      + 'Responda APENAS um JSON array válido, sem texto fora dele: '
      + '[{"id":"<id do serviço>","modeloRecomendado":"<id>","alternativaMaisBarata":"<id ou string vazia>","motivo":"<1 frase curta>"}]';
    const user = 'MODELOS DISPONÍVEIS:\n' + modelosTxt + '\n\nSERVIÇOS:\n' + catalogoTxt;

    const txt = forjaCallLLM([{ role: 'system', content: sys }, { role: 'user', content: user }], 1500);
    const ini = txt.indexOf('[');
    const fim = txt.lastIndexOf(']');
    if (ini < 0 || fim <= ini) throw new Error('A IA não retornou JSON. Tente de novo.');
    const arr = JSON.parse(txt.slice(ini, fim + 1)) as Array<{ id: string; modeloRecomendado: string; alternativaMaisBarata?: string; motivo?: string }>;

    const idsValidos = servicosProxy.map((s) => s.id);
    const sugestoes = (Array.isArray(arr) ? arr : [])
      .filter((x) => x && idsValidos.indexOf(String(x.id)) >= 0)
      .map((x) => ({
        id: String(x.id),
        modeloRecomendado: String(x.modeloRecomendado || ''),
        alternativaMaisBarata: String(x.alternativaMaisBarata || ''),
        motivo: String(x.motivo || ''),
        disponivel: modelosIds.indexOf(String(x.modeloRecomendado || '')) >= 0,
      }));

    return { ok: true, data: { sugestoes, modelosConsiderados: modelosIds.length, geradoEm: new Date().toISOString() } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao sugerir roteamento' };
  }
}

// ─── Driver (Atelier) — navegador do Google Drive + registro de nuvens ───────
// Lista pastas/arquivos do Drive da conta logada (read-only via Advanced Drive
// Service v3 + escopo drive.readonly). Multi-cloud (OneDrive / outras contas
// Google) é por conector OAuth — driveConnectors* guarda só METADADOS da conta
// (provedor, email, rótulo, status). NUNCA senha; tokens OAuth, quando houver,
// ficam no PropertiesService server-side.

function _driveFilesList(opts: Record<string, unknown>): { files?: unknown[]; nextPageToken?: string } {
  return (Drive as unknown as { Files: { list: (o: Record<string, unknown>) => { files?: unknown[]; nextPageToken?: string } } }).Files.list(opts);
}

function driveListar(folderId?: string, busca?: string, pageToken?: string): ServerResult {
  try {
    const parent = (folderId && folderId !== 'root') ? folderId : 'root';
    let q = `'${parent}' in parents and trashed = false`;
    if (busca && busca.trim()) {
      const termo = busca.trim().replace(/\\/g, '\\\\').replace(/'/g, "\\'");
      q += ` and name contains '${termo}'`;
    }
    const resp = _driveFilesList({
      q,
      fields: 'nextPageToken, files(id,name,mimeType,modifiedTime,size,webViewLink)',
      pageSize: 200,
      orderBy: 'folder,name',
      supportsAllDrives: true,
      includeItemsFromAllDrives: true,
      pageToken: pageToken || undefined,
    });
    const arquivos = ((resp.files || []) as Array<Record<string, unknown>>).map((f) => {
      const mime = String(f.mimeType || '');
      return {
        id: String(f.id || ''),
        nome: String(f.name || '(sem nome)'),
        mimeType: mime,
        isFolder: mime === 'application/vnd.google-apps.folder',
        modificado: String(f.modifiedTime || ''),
        tamanho: f.size ? Number(f.size) : 0,
        link: String(f.webViewLink || ''),
      };
    });
    return { ok: true, data: { arquivos, nextPageToken: String(resp.nextPageToken || '') } };
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : String(e);
    if (/permission|authoriz|scope|403|401/i.test(msg)) {
      return { ok: false, error: 'AUTH_NEEDED::' + `https://script.google.com/home/projects/${ScriptApp.getScriptId()}/edit` };
    }
    return { ok: false, error: 'Erro ao listar o Drive: ' + msg };
  }
}

function driveInfoConta(): ServerResult {
  try {
    return { ok: true, data: { email: Session.getActiveUser().getEmail() || '' } };
  } catch {
    return { ok: true, data: { email: '' } };
  }
}

function driveConnectorsList(): ServerResult {
  try {
    const linhas = (dbGetAll('DriveConnectors') as Array<Record<string, unknown>>)
      // O conector do YouTube (Estudos) usa a mesma tabela, mas não é uma "nuvem
      // de arquivos" — fica fora do painel Driver pra não confundir.
      .filter((l) => String(l.provedor || '') !== 'google-youtube')
      .map((l) => ({
        id: String(l.id || ''),
        provedor: String(l.provedor || ''),
        email: String(l.email || ''),
        rotulo: String(l.rotulo || ''),
        status: String(l.status || 'registrada'),
        pastaRaizId: String(l.pastaRaizId || ''),
        notas: String(l.notas || ''),
        criadoEm: String(l.criadoEm || ''),
      }));
    return { ok: true, data: linhas };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar contas' };
  }
}

function driveConnectorSave(payload: {
  id?: string; provedor: string; email?: string; rotulo?: string; pastaRaizId?: string; notas?: string;
}): ServerResult {
  try {
    const provedor = String(payload.provedor || '').trim();
    if (!provedor) throw new Error('Escolha o provedor (Google Drive, OneDrive…).');
    const agora = new Date().toISOString();
    const email = String(payload.email || '').trim();
    // Default do rótulo = parte do e-mail antes do @ (ex.: "lazaroweb"). Evita
    // vários "Pessoal" iguais quando há várias contas.
    let rotulo = String(payload.rotulo || '').trim();
    if (!rotulo && email.indexOf('@') > 0) rotulo = email.split('@')[0];
    const base = {
      provedor,
      email,
      rotulo,
      pastaRaizId: String(payload.pastaRaizId || '').trim(),
      notas: String(payload.notas || '').trim(),
      atualizadoEm: agora,
    };
    if (payload.id) {
      dbUpdate('DriveConnectors', payload.id, base);
      return { ok: true, data: { id: payload.id } };
    }
    const novo = dbCreate('DriveConnectors', { ...base, status: 'registrada', criadoEm: agora });
    return { ok: true, data: { id: String(novo.id || '') } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar conta' };
  }
}

function driveConnectorDelete(id: string): ServerResult {
  try {
    // Limpa o token OAuth associado (se houver) antes de remover o registro.
    try {
      const conn = _findConnector(id);
      if (conn && _OAUTH_PROVIDERS[String(conn.provedor || '')]) {
        _oauthService(id, String(conn.provedor || '')).reset();
      }
    } catch { /* sem token, segue */ }
    dbDelete('DriveConnectors', id);
    return { ok: true };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao remover conta' };
  }
}

// ─── Contas (Atelier → Contas) — inventário central de contas/serviços ────────
// Guarda só metadados (plano, cobrança, custo, renovação). A senha/API key vive
// no Cofre (E2E) — aqui só referenciamos via segredoLabel + flag temSegredo.

function _parseLogins(l: Record<string, unknown>): Array<{ email: string; rotulo: string }> {
  let logins: Array<{ email: string; rotulo: string }> = [];
  try {
    const raw = l.logins;
    if (raw) {
      const arr = JSON.parse(String(raw));
      if (Array.isArray(arr)) {
        logins = arr
          .map((x) => ({ email: String((x && x.email) || ''), rotulo: String((x && x.rotulo) || '') }))
          .filter((x) => x.email || x.rotulo);
      }
    }
  } catch { /* json inválido — cai no fallback */ }
  // Back-compat: linhas antigas sem `logins` mas com `email` único.
  if (logins.length === 0 && String(l.email || '').trim()) {
    logins = [{ email: String(l.email).trim(), rotulo: String(l.rotulo || '').trim() }];
  }
  return logins;
}

function _normalizarConta(l: Record<string, unknown>): Record<string, unknown> {
  const logins = _parseLogins(l);
  return {
    id: String(l.id || ''),
    categoria: String(l.categoria || 'outro'),
    servico: String(l.servico || ''),
    rotulo: String(l.rotulo || ''),
    email: logins[0] ? logins[0].email : String(l.email || ''),
    logins,
    url: String(l.url || ''),
    plano: String(l.plano || ''),
    tipoCobranca: String(l.tipoCobranca || ''),
    custo: Number(l.custo || 0) || 0,
    moeda: String(l.moeda || 'BRL'),
    formaPagamento: String(l.formaPagamento || ''),
    proximaCobranca: String(l.proximaCobranca || ''),
    status: String(l.status || 'ativa'),
    temSegredo: String(l.temSegredo || ''),
    segredoLabel: String(l.segredoLabel || ''),
    tags: String(l.tags || ''),
    notas: String(l.notas || ''),
    recEmail: String(l.recEmail || ''),
    recTelefone: String(l.recTelefone || ''),
    recNotas: String(l.recNotas || ''),
    criadoEm: String(l.criadoEm || ''),
    atualizadoEm: String(l.atualizadoEm || ''),
  };
}

function contasList(): ServerResult {
  try {
    const linhas = (dbGetAll('Contas') as Array<Record<string, unknown>>).map(_normalizarConta);
    return { ok: true, data: linhas };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar contas' };
  }
}

function contasSave(payload: {
  id?: string; categoria?: string; servico?: string; rotulo?: string; email?: string; url?: string;
  logins?: Array<{ email?: string; rotulo?: string }>;
  plano?: string; tipoCobranca?: string; custo?: number | string; moeda?: string; formaPagamento?: string;
  proximaCobranca?: string; status?: string; temSegredo?: string; segredoLabel?: string; tags?: string; notas?: string;
  recEmail?: string; recTelefone?: string; recNotas?: string;
  cartaoId?: string;
}): ServerResult {
  try {
    const servico = String(payload.servico || '').trim();
    if (!servico) throw new Error('Informe o nome do serviço/conta (ex.: ChatGPT, Gmail).');
    const agora = new Date().toISOString();
    const custoNum = typeof payload.custo === 'number' ? payload.custo : parseFloat(String(payload.custo || '0').replace(',', '.'));
    // Normaliza a lista de logins (várias contas/e-mails no mesmo serviço).
    let logins = Array.isArray(payload.logins)
      ? payload.logins.map((x) => ({ email: String((x && x.email) || '').trim(), rotulo: String((x && x.rotulo) || '').trim() })).filter((x) => x.email || x.rotulo)
      : [];
    if (logins.length === 0 && String(payload.email || '').trim()) {
      logins = [{ email: String(payload.email).trim(), rotulo: String(payload.rotulo || '').trim() }];
    }
    const base = {
      categoria: String(payload.categoria || 'outro').trim(),
      servico,
      rotulo: String(payload.rotulo || '').trim(),
      email: logins[0] ? logins[0].email : String(payload.email || '').trim(),
      logins: JSON.stringify(logins),
      url: String(payload.url || '').trim(),
      plano: String(payload.plano || '').trim(),
      tipoCobranca: String(payload.tipoCobranca || '').trim(),
      custo: Number.isFinite(custoNum) ? custoNum : 0,
      moeda: String(payload.moeda || 'BRL').trim(),
      formaPagamento: String(payload.formaPagamento || '').trim(),
      proximaCobranca: String(payload.proximaCobranca || '').trim(),
      status: String(payload.status || 'ativa').trim(),
      temSegredo: payload.temSegredo ? 'sim' : '',
      segredoLabel: String(payload.segredoLabel || '').trim(),
      tags: String(payload.tags || '').trim(),
      notas: String(payload.notas || '').trim(),
      recEmail: String(payload.recEmail || '').trim(),
      recTelefone: String(payload.recTelefone || '').trim(),
      recNotas: String(payload.recNotas || '').trim(),
      cartaoId: String(payload.cartaoId || '').trim(),
      atualizadoEm: agora,
    };
    if (payload.id) {
      dbUpdate('Contas', payload.id, base);
      return { ok: true, data: { id: payload.id } };
    }
    const novo = dbCreate('Contas', { ...base, criadoEm: agora });
    return { ok: true, data: { id: String(novo.id || '') } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar conta' };
  }
}

function contasDelete(id: string): ServerResult {
  try {
    dbDelete('Contas', id);
    return { ok: true };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao remover conta' };
  }
}

// ─── Dívida técnica (v1.147.0) ────────────────────────────────────────────────
// Scan automático do repositório GitHub procurando 4 padrões em comentários:
//   `// TODO:`, `// FIXME:`, `// HACK:` (texto livre)
//   `// DEBT(area,sev): descrição` (estruturado — vem da "skill" colocada no repo)
// Cada match vira um item de DebitoTecnico ancorado em arquivo:linha.
//
// Sincronização: ao chamar `sincronizarDebitos`, faz scan do HEAD atual e:
// 1. Adiciona itens NOVOS (hash inédito)
// 2. Marca como `pago` itens ATIVOS que sumiram do código (limpeza automática)
// 3. Preserva itens já PROMOVIDOS (eles têm vida própria no backlog)
//
// Cache duplo:
// - Por commit SHA: se HEAD não mudou desde último scan → retorna instant
//   (a UI mostra "sincronizado · sem mudanças")
// - Por blob SHA: reusa o cache de blobs já existente da auditoria (`fcode:`)
//
// `_codeArquivoRelevante` (já existe) cuida do filtro de arquivos.

interface DebitoMatchRaw {
  tipo: DebitoTipoServer;
  arquivo: string;
  linha: number;
  descricao: string;
  area?: string;
  severidade?: string;
}

type DebitoTipoServer = 'debt' | 'todo' | 'fixme' | 'hack';
type DebitoStatusServer = 'ativo' | 'pago' | 'promovido';

const _DEBT_AREAS_VALIDAS = ['governanca', 'arquitetura', 'seguranca', 'dependencias', 'testes', 'operacional', 'performance', 'ux', 'codigo'];
const _DEBT_SEV_VALIDAS = ['alta', 'media', 'baixa'];

// v1.148.12 — Heurística "está dentro de string literal".
// Conta aspas (' " `) não-escapadas até a posição do match. Se a "aspa
// corrente" não é null naquele ponto, o marcador está dentro de uma string
// (típico de mensagem de UI que exemplifica marcadores: "marque com // TODO:").
// Não é parser completo de JS/TS, mas pega 99% dos casos reais.
function _estaDentroDeString(linha: string, posMarcador: number): boolean {
  let aspaAtual: string | null = null;
  for (let i = 0; i < posMarcador; i++) {
    const c = linha.charAt(i);
    if (aspaAtual === null) {
      if (c === "'" || c === '"' || c === '`') aspaAtual = c;
    } else if (c === aspaAtual && linha.charAt(i - 1) !== '\\') {
      aspaAtual = null;
    }
  }
  return aspaAtual !== null;
}

// v1.148.12 — Heurística "menção meta sobre marcadores".
// Se a linha tem 2 ou mais marcadores DIFERENTES, quase certo é doc/exemplo
// explicando o protocolo (ex: "marque com // TODO:, // FIXME: ou // DEBT(...)").
// Débito real só menciona 1 tipo por linha. Skip pra evitar ruído.
function _temMultiplosMarcadores(linha: string): boolean {
  const matches = linha.match(/\b(TODO|FIXME|HACK|DEBT)\b/gi);
  if (!matches || matches.length < 2) return false;
  const tipos = new Set<string>();
  for (const m of matches) tipos.add(m.toUpperCase());
  return tipos.size >= 2;
}

// Parseia uma linha de código procurando por TODO/FIXME/HACK/DEBT.
// Aceita prefixos: `//`, `#`, `--`, `<!--`, `/*` (basta o marcador). Case-insensitive.
// Block comments `/* DEBT(...) */` são importantes em código processado por bundlers
// que removem `//` (esbuild com `target: 'es2020'` é o nosso caso — DEBT em // some
// no Server.js que vai pro Apps Script). Use `/* */` quando precisar sobreviver ao build.
//
// v1.148.8 — fix de falso positivo crítico: regex agora usa `\b` (word boundary)
// pra evitar match em palavras como "TODOs" (português pra "todos"), "FIXMEd",
// "HACKy". Bug detectado em produção: "// TODOs os nodes na 11.x" estava
// matchando como TODO e gerando débito "s os nodes na 11.x" (com 's' sobrando).
//
// v1.148.12 — 2 novas defesas: skip se marcador dentro de string literal
// (mensagem de UI que exemplifica marcadores) e skip se linha tem múltiplos
// marcadores diferentes (doc/exemplo explicando o protocolo).
function _parseLinhaDebito(linha: string, arquivo: string, numLinha: number): DebitoMatchRaw | null {
  // Defesa #1: linha cita múltiplos marcadores → quase certo é doc/exemplo
  if (_temMultiplosMarcadores(linha)) return null;

  const debtRe = /(?:\/\/|\/\*|#|--|<!--)\s*\bDEBT\b\s*\(\s*([a-z]+)\s*,\s*(alta|media|baixa)\s*\)\s*:?\s*(.+?)(?:\*\/|-->)?\s*$/i;
  const debtMatch = linha.match(debtRe);
  if (debtMatch) {
    // Defesa #2: marcador dentro de string literal → skip
    if (_estaDentroDeString(linha, debtMatch.index || 0)) return null;
    const area = String(debtMatch[1] || '').toLowerCase();
    const sev = String(debtMatch[2] || 'media').toLowerCase();
    let desc = String(debtMatch[3] || '').trim();
    desc = desc.replace(/\*\/\s*$/, '').trim();
    return {
      tipo: 'debt',
      arquivo,
      linha: numLinha,
      descricao: desc.slice(0, 280),
      area: _DEBT_AREAS_VALIDAS.indexOf(area) >= 0 ? area : 'codigo',
      severidade: _DEBT_SEV_VALIDAS.indexOf(sev) >= 0 ? sev : 'media',
    };
  }
  const livreRe = /(?:\/\/|\/\*|#|--|<!--)\s*\b(TODO|FIXME|HACK)\b\s*[:\-]?\s*(.+?)(?:\*\/|-->)?\s*$/i;
  const livreMatch = linha.match(livreRe);
  if (livreMatch) {
    if (_estaDentroDeString(linha, livreMatch.index || 0)) return null;
    const tipo = String(livreMatch[1] || '').toLowerCase() as 'todo' | 'fixme' | 'hack';
    let desc = String(livreMatch[2] || '').trim();
    desc = desc.replace(/\*\/\s*$/, '').trim();
    if (desc.length < 3) return null; // ignora marcadores sem descrição real
    return { tipo, arquivo, linha: numLinha, descricao: desc.slice(0, 280) };
  }
  return null;
}

// v1.148.8 — Filtra arquivos que FALAM SOBRE débito como exemplo/doc, evitando
// que o scanner colete "// FIXME: ..." como débito real quando na verdade é
// documentação (CHANGELOG.md, SKILL.md, AGENTS.md, .mdc do Cursor, README de
// skills). Bug detectado em produção: "// FIXME ou // DEBT(area,sev): pra
// acompanhar aqui" aparecia como débito mas era texto da skill forja-debt-tracking.
function _arquivoFalaSobreDebt(path: string): boolean {
  const p = String(path || '').toLowerCase();
  if (p.endsWith('.mdc')) return true; // Cursor rules sempre falam sobre padrão
  if (p.endsWith('changelog.md')) return true;
  if (/(^|\/)skill\.md$/.test(p)) return true;
  if (/(^|\/)agents\.md$/.test(p)) return true;
  if (/agents-debt-tracking/.test(p)) return true;
  if (/\.cursor\/rules\//.test(p)) return true;
  if (/\/skills\/[^/]+\/(readme|reference)/.test(p)) return true;
  if (/\/docs\/[^/]*debt/.test(p)) return true;
  return false;
}

// Hash determinístico curto pra dedup entre syncs.
// Usa tipo+arquivo+descricao (sem linha) pra resistir a deslocamento por edição.
function _hashDebito(tipo: string, arquivo: string, descricao: string): string {
  const raw = `${tipo}|${arquivo}|${descricao.toLowerCase().trim().slice(0, 200)}`;
  // Hash leve (não-cripto) — suficiente pra dedup de strings curtas.
  let h = 0;
  for (let i = 0; i < raw.length; i++) { h = ((h << 5) - h) + raw.charCodeAt(i); h |= 0; }
  return Math.abs(h).toString(36).slice(0, 10);
}

// Pega só HEAD commit (1 chamada barata). Usado pra checar se mudou desde
// último scan ANTES de fazer o scan completo (otimização do "sempre fresco").
function _ghHeadShaSeguro(repoUrl: string): string {
  const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
  if (!token) return '';
  const full = _ghFullName(repoUrl);
  if (!/^[^/]+\/[^/]+$/.test(full)) return '';
  const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };
  return _ghHeadCommitCurto(full, headers);
}

// Hash leve do conteúdo concatenado de um projeto GAS (substitui o commit SHA
// no fluxo de cache). Se nada mudou no projeto, hash igual → sem re-scan.
// Usa só nomes + tamanhos (não o source todo) pra ser barato.
function _hashConteudoGAS(arquivos: Array<{ name: string; source?: string }>): string {
  const raw = arquivos.map((f) => `${f.name}:${(f.source || '').length}`).join('|');
  let h = 0;
  for (let i = 0; i < raw.length; i++) { h = ((h << 5) - h) + raw.charCodeAt(i); h |= 0; }
  return 'gas-' + Math.abs(h).toString(36).slice(0, 7);
}

// Scan completo: lê tree do repo, baixa blobs (cache por SHA), parseia.
// Retorna lista de matches com SHA do HEAD scaneado.
function _scanRepoTodos(repoUrl: string): { sha: string; matches: DebitoMatchRaw[]; erro?: string } {
  const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
  if (!token) return { sha: '', matches: [], erro: 'GitHub não conectado (sem token).' };
  const full = _ghFullName(repoUrl);
  if (!/^[^/]+\/[^/]+$/.test(full)) return { sha: '', matches: [], erro: 'repoUrl inválida.' };
  const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };
  try {
    const branchRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}`, { headers, muteHttpExceptions: true });
    if (branchRes.getResponseCode() !== 200) return { sha: '', matches: [], erro: `Erro ao ler o repo (${branchRes.getResponseCode()}).` };
    const branch = String((JSON.parse(branchRes.getContentText()) as { default_branch?: string }).default_branch || 'main');

    let headSha = '';
    try {
      const commitRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/commits/${encodeURIComponent(branch)}`, { headers, muteHttpExceptions: true });
      if (commitRes.getResponseCode() === 200) headSha = String((JSON.parse(commitRes.getContentText()) as { sha?: string }).sha || '').slice(0, 7);
    } catch { /* segue com tree */ }

    const treeRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}/git/trees/${encodeURIComponent(branch)}?recursive=1`, { headers, muteHttpExceptions: true });
    if (treeRes.getResponseCode() !== 200) return { sha: headSha, matches: [], erro: `Erro ao ler a árvore (${treeRes.getResponseCode()}).` };
    const treeJson = JSON.parse(treeRes.getContentText()) as { sha?: string; tree?: Array<{ path: string; type: string; size?: number; sha: string }> };
    if (!headSha) headSha = String(treeJson.sha || '').slice(0, 7);

    const blobs = (treeJson.tree || []).filter((n) => n.type === 'blob');
    // Mesmo filtro da auditoria (skipa node_modules, dist, etc).
    const refs = blobs.filter((b) => _codeArquivoRelevante(b.path, b.size || 0));
    // Cap defensivo: max 200 arquivos por scan (TODOs cabem em qualquer canto;
    // mais que isso vira sopa e estoura quota).
    const selecionados = refs.slice(0, 200);

    // Cache de blobs (reusa o "fcode:" da auditoria — mesmo conteúdo, mesmo SHA).
    const cache = CacheService.getScriptCache();
    const cacheKeys = selecionados.map((f) => 'fcode:' + f.sha);
    let cacheados: Record<string, string | null> = {};
    try { cacheados = cache.getAll(cacheKeys) as Record<string, string | null>; } catch { cacheados = {}; }

    const conteudos: Record<string, string> = {};
    const aBuscar = selecionados.filter((f) => {
      const hit = cacheados['fcode:' + f.sha];
      if (typeof hit === 'string') { conteudos[String(f.sha)] = hit; return false; }
      return true;
    });

    if (aBuscar.length > 0) {
      const requests = aBuscar.map((f) => ({ url: `https://api.github.com/repos/${full}/git/blobs/${f.sha}`, headers, muteHttpExceptions: true }));
      for (let i = 0; i < requests.length; i += 50) {
        const slice = requests.slice(i, i + 50);
        const sliceArqs = aBuscar.slice(i, i + 50);
        const res = UrlFetchApp.fetchAll(slice);
        const novosCache: Record<string, string> = {};
        for (let j = 0; j < res.length; j++) {
          const r = res[j];
          if (r.getResponseCode() !== 200) continue;
          try {
            const blob = JSON.parse(r.getContentText()) as { content?: string; encoding?: string };
            if (blob.encoding !== 'base64' || !blob.content) continue;
            const decoded = Utilities.newBlob(Utilities.base64Decode(blob.content)).getDataAsString();
            conteudos[String(sliceArqs[j].sha)] = decoded;
            novosCache['fcode:' + sliceArqs[j].sha] = decoded;
          } catch { /* arquivo binário/erro de parse — ignora */ }
        }
        try { cache.putAll(novosCache, 21600); } catch { /* cache cheio: ok */ } // 6h TTL
      }
    }

    // Parseia conteúdos linha-a-linha.
    // v1.148.8 — pula arquivos que falam SOBRE débito como doc/exemplo
    // (CHANGELOG, SKILL.md, AGENTS.md, .mdc).
    const matches: DebitoMatchRaw[] = [];
    for (const f of selecionados) {
      if (_arquivoFalaSobreDebt(f.path)) continue;
      const conteudo = conteudos[String(f.sha)];
      if (!conteudo) continue;
      const linhas = conteudo.split('\n');
      for (let i = 0; i < linhas.length; i++) {
        const m = _parseLinhaDebito(linhas[i], f.path, i + 1);
        if (m) matches.push(m);
      }
    }

    return { sha: headSha, matches };
  } catch (e: unknown) {
    return { sha: '', matches: [], erro: e instanceof Error ? e.message : 'Erro ao escanear repo' };
  }
}

// Scan de projeto Google Apps Script via Apps Script API.
// Mesmo formato de retorno de `_scanRepoTodos` (sha + matches + erro) — assim
// o `sincronizarDebitos` consegue tratar GitHub e GAS uniformemente.
// `sha` aqui é um hash determinístico do conteúdo (não tem commit no GAS).
function _scanGASTodos(scriptId: string): { sha: string; matches: DebitoMatchRaw[]; erro?: string } {
  const sid = String(scriptId || '').trim();
  if (!sid) return { sha: '', matches: [], erro: 'Sistema sem scriptId.' };
  try {
    const token = ScriptApp.getOAuthToken();
    const res = UrlFetchApp.fetch(`https://script.googleapis.com/v1/projects/${encodeURIComponent(sid)}/content`, {
      headers: { Authorization: 'Bearer ' + token },
      muteHttpExceptions: true,
    });
    const code = res.getResponseCode();
    if (code === 403) return { sha: '', matches: [], erro: 'Apps Script API desativada. Ative em script.google.com/home/usersettings.' };
    if (code !== 200) return { sha: '', matches: [], erro: `Apps Script API respondeu ${code}.` };
    const json = JSON.parse(res.getContentText()) as { files?: Array<{ name: string; type: string; source?: string }> };
    const arquivos = json.files || [];
    if (arquivos.length === 0) return { sha: '', matches: [], erro: 'Projeto GAS sem arquivos legíveis.' };

    const sha = _hashConteudoGAS(arquivos);
    const matches: DebitoMatchRaw[] = [];
    for (const f of arquivos) {
      const source = String(f.source || '');
      if (!source) continue;
      // Reusa convenção de path com extensão (igual auditoria).
      const ext = f.type === 'HTML' ? 'html' : f.type === 'JSON' ? 'json' : 'gs';
      const path = `${f.name}.${ext}`;
      if (_arquivoFalaSobreDebt(path)) continue;
      const linhas = source.split('\n');
      for (let i = 0; i < linhas.length; i++) {
        const m = _parseLinhaDebito(linhas[i], path, i + 1);
        if (m) matches.push(m);
      }
    }
    return { sha, matches };
  } catch (e: unknown) {
    return { sha: '', matches: [], erro: e instanceof Error ? e.message : 'Erro ao ler projeto GAS' };
  }
}

// Escolhe a melhor fonte pra escanear: GitHub (se repoUrl) > GAS (se scriptId).
// Mesma lógica que `_lerCodigoSistema` usa pra auditoria — garante consistência.
function _scanCodigoSistemaParaDebitos(sistema: Record<string, unknown>): { sha: string; matches: DebitoMatchRaw[]; fonte: 'github' | 'gas'; erro?: string } {
  const repoUrl = String(sistema.repoUrl || '').trim();
  if (repoUrl) {
    const r = _scanRepoTodos(repoUrl);
    return { ...r, fonte: 'github' };
  }
  const scriptId = String(sistema.scriptId || '').trim();
  if (scriptId) {
    const r = _scanGASTodos(scriptId);
    return { ...r, fonte: 'gas' };
  }
  return { sha: '', matches: [], fonte: 'github', erro: 'Sistema sem repoUrl nem scriptId — sem código pra escanear.' };
}

// Checagem barata "mudou desde último scan?" — só faz sentido pra GitHub (HEAD
// SHA cheap). Pra GAS não tem equivalente sem baixar o content completo, então
// sempre devolve falso (vai re-escanear sempre, mas Apps Script API é rápida).
function _mudouDesdeUltimoScan(sistema: Record<string, unknown>, ultimoScanSha: string): { mudou: boolean; novaShaSePararAqui: string } {
  if (!ultimoScanSha) return { mudou: true, novaShaSePararAqui: '' };
  const repoUrl = String(sistema.repoUrl || '').trim();
  if (repoUrl) {
    const head = _ghHeadShaSeguro(repoUrl);
    if (head && head.slice(0, 7) === ultimoScanSha) return { mudou: false, novaShaSePararAqui: ultimoScanSha };
    return { mudou: true, novaShaSePararAqui: '' };
  }
  // GAS: sem HEAD barato — sempre re-escaneia (Apps Script API é rápida).
  /*! DEBT(performance,baixa): Apps Script API não tem HEAD/ETag — toda abertura da aba Dívida em sistema GAS baixa o content completo. Investigar If-None-Match ou cachear versionNumber do último deploy pra evitar o roundtrip quando nada mudou. */
  return { mudou: true, novaShaSePararAqui: '' };
}

// Sincroniza dívidas do sistema com o estado atual do código.
// 1. Checa se HEAD mudou desde último scan — se igual, retorna cache (semMudanca).
// 2. Roda scan da fonte certa (GitHub OU GAS).
// 3. Diff: novos vs existentes (hash); marca como pago os ativos que sumiram.
// 4. Preserva status='promovido' (não desfaz ligação com backlog).
function sincronizarDebitos(sistemaId: string, forcar?: boolean): ServerResult {
  try {
    const sistema = (dbGetAll('Sistemas') as Array<Record<string, unknown>>).find((s) => s.id === sistemaId);
    if (!sistema) return { ok: false, error: 'Sistema não encontrado' };
    const temRepo = !!String(sistema.repoUrl || '').trim();
    const temScript = !!String(sistema.scriptId || '').trim();
    if (!temRepo && !temScript) {
      return { ok: false, error: 'Sistema sem repoUrl nem scriptId — sem código pra escanear.' };
    }

    const debitosAtuais = (dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>).filter((d) => String(d.sistemaId || '') === sistemaId);
    const ultimoScanSha = debitosAtuais.length > 0
      ? String(debitosAtuais[0].ultimoScanSha || '').slice(0, 7)
      : '';

    // Otimização: HEAD check barato antes do scan pesado (só faz efeito no GitHub;
    // GAS sempre re-escaneia porque API já é rápida e não tem HEAD equivalente).
    if (!forcar) {
      const check = _mudouDesdeUltimoScan(sistema, ultimoScanSha);
      if (!check.mudou) {
        return {
          ok: true,
          data: {
            scanSha: check.novaShaSePararAqui,
            itensAtuais: debitosAtuais.map(_debitoToView),
            novos: 0,
            pagosAuto: 0,
            inalterados: debitosAtuais.filter((d) => d.status === 'ativo').length,
            semMudanca: true,
          },
        };
      }
    }

    const scan = _scanCodigoSistemaParaDebitos(sistema);
    if (scan.erro) return { ok: false, error: scan.erro };
    const novoSha = scan.sha.slice(0, 7);

    // Index dos atuais por hash, tirando os já promovidos (eles têm vida própria).
    const ativosByHash: Record<string, Record<string, unknown>> = {};
    const promovidos: Record<string, Record<string, unknown>> = {};
    for (const d of debitosAtuais) {
      const h = String(d.hash || '');
      if (d.status === 'promovido') promovidos[h] = d;
      else if (d.status === 'ativo') ativosByHash[h] = d;
    }

    // Index dos matches do scan por hash.
    const matchByHash: Record<string, DebitoMatchRaw> = {};
    for (const m of scan.matches) {
      const h = _hashDebito(m.tipo, m.arquivo, m.descricao);
      if (!matchByHash[h]) matchByHash[h] = m; // primeira ocorrência ganha (caso raro de hash colidir)
    }

    const agora = new Date().toISOString();
    let novos = 0, pagosAuto = 0, inalterados = 0;

    // 1. Adiciona novos (hash que não existe nem como ativo nem como promovido).
    for (const h in matchByHash) {
      if (ativosByHash[h] || promovidos[h]) continue;
      const m = matchByHash[h];
      dbCreate('DebitoTecnico', {
        sistemaId,
        tipo: m.tipo,
        area: m.area || '',
        severidade: m.severidade || '',
        descricao: m.descricao,
        arquivo: m.arquivo,
        linha: m.linha,
        hash: h,
        status: 'ativo',
        backlogId: '',
        criadoEm: agora,
        atualizadoEm: agora,
        pagoEm: '',
        promovidoEm: '',
        ultimoScanSha: novoSha,
      });
      novos++;
    }

    // 2. Atualiza ativos que continuam existindo (preserva criação, atualiza linha + sha).
    for (const h in ativosByHash) {
      const d = ativosByHash[h];
      const m = matchByHash[h];
      if (m) {
        // Sumiu? não — só atualiza linha (pode ter movido) + sha.
        dbUpdate('DebitoTecnico', String(d.id), {
          linha: m.linha,
          arquivo: m.arquivo,
          atualizadoEm: agora,
          ultimoScanSha: novoSha,
        });
        inalterados++;
      } else {
        // Sumiu do código → auto-pago.
        dbUpdate('DebitoTecnico', String(d.id), {
          status: 'pago',
          atualizadoEm: agora,
          pagoEm: agora,
          ultimoScanSha: novoSha,
        });
        pagosAuto++;
      }
    }

    // Atualiza ultimoScanSha dos promovidos também (referência de "último que viu").
    for (const h in promovidos) {
      dbUpdate('DebitoTecnico', String(promovidos[h].id), { ultimoScanSha: novoSha });
    }

    // Releitura dos atuais pra devolver no payload.
    const finais = (dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>).filter((d) => String(d.sistemaId || '') === sistemaId);

    return {
      ok: true,
      data: {
        scanSha: novoSha,
        itensAtuais: finais.map(_debitoToView),
        novos,
        pagosAuto,
        inalterados,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao sincronizar dívidas' };
  }
}

// Lista dívidas atuais (sem sincronizar). Usado pelo render inicial da aba.
function getDebitosTecnicos(sistemaId: string): ServerResult {
  try {
    const itens = (dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>)
      .filter((d) => String(d.sistemaId || '') === sistemaId)
      .map(_debitoToView);
    return { ok: true, data: itens };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar dívidas' };
  }
}

// v1.148.11 — Gera prompt formatado em markdown pronto pra colar em agente de IA
// (Cursor, Claude Code, Codex, Continue, GitHub Copilot, Windsurf etc).
// Inclui: contexto do sistema, ancoragem arquivo:linha, descrição, tarefas
// numeradas, critério de aceite e promessa do ciclo ("commit fecha sozinho").
// Reusado pelo corpo do card no backlog E pelo botão "Copiar prompt" do drawer.
function _gerarPromptIA(d: Record<string, unknown>, sistema: Record<string, unknown>): string {
  const tipoLabel: Record<string, string> = { debt: 'Dívida técnica', todo: 'TODO', fixme: 'FIXME', hack: 'HACK' };
  const tipo = String(d.tipo || 'todo');
  const tipoStr = tipoLabel[tipo] || 'Dívida técnica';
  const marcadorComentario = tipo === 'debt'
    ? `DEBT(${d.area || 'codigo'},${d.severidade || 'media'})`
    : tipoStr.toUpperCase();
  const arquivo = String(d.arquivo || '');
  const linha = Number(d.linha || 0);
  const desc = String(d.descricao || '(sem descrição)');
  const nomeSist = String(sistema.nome || sistema.codinome || 'projeto');
  const repoUrl = String(sistema.repoUrl || '').replace(/\.git$/, '').replace(/\/+$/, '');
  const permalink = repoUrl ? `${repoUrl}/blob/HEAD/${arquivo}#L${linha}` : '';
  const hash = String(d.hash || '');
  const meta = [
    d.area ? `**Área:** ${d.area}` : '',
    d.severidade ? `**Severidade:** ${d.severidade}` : '',
  ].filter(Boolean).join(' · ');

  return `# Resolva este ${tipoStr.toLowerCase()}

**Projeto:** ${nomeSist}
**Arquivo:** \`${arquivo}:${linha}\`
${meta ? meta + '\n' : ''}${permalink ? `**Permalink:** ${permalink}\n` : ''}
## O que está marcado no código

\`\`\`
// ${marcadorComentario}: ${desc}
\`\`\`

## Tarefas

1. Abra o arquivo \`${arquivo}\` e leia o contexto ao redor da linha ${linha}.
2. Entenda o que esse ${tipoStr.toLowerCase()} está pedindo — analise a função/componente em que está inserido.
3. Implemente a solução adequada (refator, fix, completar a feature etc).
4. **Apague o comentário marcador** (\`// ${marcadorComentario}:\`) da linha ${linha} — ele é o sinalizador do débito.
5. Commit + push no branch default.

## Critério de aceite

- ✅ O comentário marcador foi removido do código.
- ✅ A implementação cobre o que a descrição pede.
- ✅ Não introduziu regressão (rode os testes se houver).

## Como o débito fecha sozinho

A **Forja** (sistema de gestão deste projeto) escaneia o repositório periodicamente. Quando este comentário sumir do código E o commit estiver no branch default, o débito de hash \`${hash}\` vai automaticamente pra status \`pago\`. **Você não precisa fazer nada extra na Forja.**

---
_Gerado automaticamente pela Forja a partir do scan de dívida técnica._`;
}

// Promove débito para o Backlog (cria card e linka). Mantém débito como
// 'promovido' pra não recriar no próximo sync. Quando o user concluir o card
// no backlog, débito não volta pra 'ativo' automaticamente — ele tem que apagar
// do código (ou marcar como 'pago' manualmente).
function promoverDebitoParaBacklog(debitoId: string): ServerResult {
  try {
    const todos = dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>;
    const d = todos.find((x) => String(x.id) === debitoId);
    if (!d) return { ok: false, error: 'Débito não encontrado' };
    if (d.status === 'promovido' && d.backlogId) return { ok: false, error: 'Já promovido pra backlog.' };

    const sistemaId = String(d.sistemaId || '');
    const sistemas = dbGetAll('Sistemas') as Array<Record<string, unknown>>;
    const sist = sistemas.find((s) => String(s.id) === sistemaId) || { nome: 'projeto' };
    const tipoLabel: Record<string, string> = { debt: 'Dívida', todo: 'TODO', fixme: 'FIXME', hack: 'HACK' };
    const titulo = `[${tipoLabel[String(d.tipo)] || 'Dívida'}] ${String(d.descricao).slice(0, 80)}`;
    // v1.148.11 — corpo agora é um PROMPT pronto pra colar em agente de IA.
    // Antes era só descrição. Agora é acionável: cola no Cursor/Claude e a IA
    // já tem tudo que precisa (arquivo, linha, marcador, critério de aceite,
    // promessa do ciclo "commit fecha sozinho").
    const corpo = _gerarPromptIA(d, sist);

    // Cria card no backlog (Decisoes é a tabela do kanban — coluna `status`
    // controla a coluna no board: aFazer | fazendo | feito).
    const novoCard = dbCreate('Decisoes', {
      sistemaId,
      titulo,
      decisao: corpo,
      justificativa: `Promovido do scan de dívida técnica (hash ${d.hash}). Corpo é um prompt pronto pra IA — cole no Cursor/Claude Code/etc.`,
      status: 'aFazer',
      gravidade: d.severidade || 'media',
      area: d.area || 'codigo',
      criadoEm: new Date().toISOString(),
    }) as Record<string, unknown>;

    const agora = new Date().toISOString();
    dbUpdate('DebitoTecnico', debitoId, {
      status: 'promovido',
      backlogId: String(novoCard.id || ''),
      promovidoEm: agora,
      atualizadoEm: agora,
    });

    return { ok: true, data: { backlogId: String(novoCard.id || '') } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao promover dívida' };
  }
}

// v1.148.11 — Retorna o prompt formatado pra IA SEM promover (útil pro botão
// "Copiar prompt pra IA" do drawer, que permite trabalhar o débito sem precisar
// criar card no backlog).
function getPromptIADebito(debitoId: string): ServerResult {
  try {
    const todos = dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>;
    const d = todos.find((x) => String(x.id) === debitoId);
    if (!d) return { ok: false, error: 'Débito não encontrado' };
    const sistemas = dbGetAll('Sistemas') as Array<Record<string, unknown>>;
    const sist = sistemas.find((s) => String(s.id) === String(d.sistemaId || '')) || { nome: 'projeto' };
    return { ok: true, data: { prompt: _gerarPromptIA(d, sist) } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Marca débito como pago manualmente (escape hatch: user removeu do código fora
// do branch default ou refatorou de outro jeito que o scan não detectou).
function marcarDebitoComoPago(debitoId: string): ServerResult {
  try {
    const agora = new Date().toISOString();
    dbUpdate('DebitoTecnico', debitoId, { status: 'pago', pagoEm: agora, atualizadoEm: agora });
    return { ok: true, data: { ok: true } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// v1.148.9 — Apaga definitivamente um débito do banco.
// Use quando o débito é claramente falso positivo (bug do parser, exemplo em doc)
// ou quando você quer limpar lixo histórico sem manter rastro.
// Segurança: bloqueia apagar 'promovido' com backlogId vivo (pra não orfanizar card).
function apagarDebito(debitoId: string): ServerResult {
  try {
    const todos = dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>;
    const d = todos.find((x) => String(x.id) === debitoId);
    if (!d) return { ok: false, error: 'Débito não encontrado.' };
    if (d.status === 'promovido' && d.backlogId) {
      return {
        ok: false,
        error: 'Débito promovido pra backlog — apague o card do backlog primeiro (ou marque como pago).',
      };
    }
    const ok = dbDelete('DebitoTecnico', debitoId);
    if (!ok) return { ok: false, error: 'Falha ao apagar.' };
    return { ok: true, data: { ok: true } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// v1.148.9 — Limpeza em massa: apaga todos os débitos 'pago' que nunca foram
// promovidos pra backlog (típico de falso positivo limpo automaticamente pelo
// scan). Preserva pagos que tinham sido promovidos antes (rastro de trabalho real).
// Retorna quantos foram apagados.
function apagarDebitosPagosSemPromocao(sistemaId: string): ServerResult {
  try {
    const todos = dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>;
    const alvos = todos
      .filter((d) => String(d.sistemaId || '') === sistemaId)
      .filter((d) => String(d.status || '') === 'pago')
      .filter((d) => !d.promovidoEm && !d.backlogId) // nunca passou por promoção
      .map((d) => String(d.id));
    if (alvos.length === 0) return { ok: true, data: { apagados: 0 } };
    const n = dbDeleteMany('DebitoTecnico', alvos);
    return { ok: true, data: { apagados: n } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// v1.148.8 — Busca contexto completo de um débito: ~10 linhas no entorno do
// match + descrição não-truncada + URL pra abrir no editor (GitHub ou Apps Script).
// Usado pelo drawer de detalhes da UI ("ver mais" no card de débito).
function getDebitoContexto(debitoId: string): ServerResult {
  try {
    const debitos = dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>;
    const d = debitos.find((x) => String(x.id) === debitoId);
    if (!d) return { ok: false, error: 'Débito não encontrado.' };
    const sistemaId = String(d.sistemaId || '');
    const arquivo = String(d.arquivo || '');
    const linhaNum = Number(d.linha || 0);
    if (!arquivo || linhaNum <= 0) return { ok: false, error: 'Débito sem ancoragem de arquivo/linha.' };

    const sistemas = dbGetAll('Sistemas') as Array<Record<string, unknown>>;
    const sist = sistemas.find((s) => String(s.id) === sistemaId);
    if (!sist) return { ok: false, error: 'Sistema não encontrado.' };

    const repoUrl = String(sist.repoUrl || '').trim();
    const scriptId = String(sist.scriptId || '').trim();

    let fonte: 'github' | 'gas' = 'github';
    let conteudo = '';
    let urlArquivo = '';
    let urlLinha = '';
    let branchDetectada = 'main';

    if (repoUrl) {
      fonte = 'github';
      const token = PropertiesService.getScriptProperties().getProperty('GITHUB_TOKEN');
      if (!token) return { ok: false, error: 'GitHub não conectado (sem token).' };
      const full = _ghFullName(repoUrl);
      if (!/^[^/]+\/[^/]+$/.test(full)) return { ok: false, error: 'repoUrl inválida.' };
      const headers = { Authorization: 'Bearer ' + token, Accept: 'application/vnd.github+json', 'User-Agent': 'FORJA' };
      try {
        const bRes = UrlFetchApp.fetch(`https://api.github.com/repos/${full}`, { headers, muteHttpExceptions: true });
        if (bRes.getResponseCode() === 200) {
          branchDetectada = String((JSON.parse(bRes.getContentText()) as { default_branch?: string }).default_branch || 'main');
        }
      } catch { /* fallback main */ }

      // GET /contents/:path?ref=:branch retorna { content: base64, encoding, sha }
      const pathEnc = arquivo.split('/').map((p) => encodeURIComponent(p)).join('/');
      const cUrl = `https://api.github.com/repos/${full}/contents/${pathEnc}?ref=${encodeURIComponent(branchDetectada)}`;
      const cRes = UrlFetchApp.fetch(cUrl, { headers, muteHttpExceptions: true });
      if (cRes.getResponseCode() !== 200) {
        return { ok: false, error: `Arquivo não encontrado no repo (${cRes.getResponseCode()}). Pode ter sido removido depois do último scan — rode sincronizar.` };
      }
      const blob = JSON.parse(cRes.getContentText()) as { content?: string; encoding?: string };
      if (blob.encoding === 'base64' && blob.content) {
        conteudo = Utilities.newBlob(Utilities.base64Decode(blob.content)).getDataAsString();
      }
      urlArquivo = `https://github.com/${full}/blob/${branchDetectada}/${arquivo}`;
      urlLinha = `${urlArquivo}#L${linhaNum}`;
    } else if (scriptId) {
      fonte = 'gas';
      const token = ScriptApp.getOAuthToken();
      const r = UrlFetchApp.fetch(`https://script.googleapis.com/v1/projects/${encodeURIComponent(scriptId)}/content`, {
        headers: { Authorization: 'Bearer ' + token },
        muteHttpExceptions: true,
      });
      if (r.getResponseCode() !== 200) {
        return { ok: false, error: `Apps Script API respondeu ${r.getResponseCode()}.` };
      }
      const json = JSON.parse(r.getContentText()) as { files?: Array<{ name: string; type: string; source?: string }> };
      const nomeBase = arquivo.replace(/\.(gs|html|json)$/i, '');
      const f = (json.files || []).find((x) => x.name === nomeBase);
      if (!f) return { ok: false, error: 'Arquivo não encontrado no projeto GAS — pode ter sido renomeado.' };
      conteudo = String(f.source || '');
      urlArquivo = `https://script.google.com/d/${scriptId}/edit`;
      urlLinha = urlArquivo; // GAS não tem deep link de linha
    } else {
      return { ok: false, error: 'Sistema sem código auditável.' };
    }

    if (!conteudo) return { ok: false, error: 'Conteúdo do arquivo vazio ou ilegível.' };

    const linhas = conteudo.split('\n');
    const idx = Math.max(0, Math.min(linhas.length - 1, linhaNum - 1));
    const ANTES = 6; const DEPOIS = 6;
    const inicio = Math.max(0, idx - ANTES);
    const fim = Math.min(linhas.length, idx + DEPOIS + 1);
    const contextoLinhas = linhas.slice(inicio, fim);
    const linhaDestaqueIdx = idx - inicio;

    return {
      ok: true,
      data: {
        fonte,
        arquivo,
        linha: linhaNum,
        urlArquivo,
        urlLinha,
        contextoInicio: inicio + 1, // 1-indexed pra exibição
        contextoLinhas,
        linhaDestaqueIdx,
        linhaCompleta: String(linhas[idx] || ''),
        totalLinhas: linhas.length,
        branch: fonte === 'github' ? branchDetectada : '',
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao buscar contexto' };
  }
}

// Resumo compacto pro widget no resumo do sistema. Lê só os ativos.
function getDebitosResumo(sistemaId: string): ServerResult {
  try {
    const itens = (dbGetAll('DebitoTecnico') as Array<Record<string, unknown>>)
      .filter((d) => String(d.sistemaId || '') === sistemaId && d.status === 'ativo');
    let debts = 0, todos = 0, fixmes = 0, hacks = 0;
    let alta = 0, media = 0, baixa = 0;
    for (const d of itens) {
      const tipo = String(d.tipo);
      if (tipo === 'debt') debts++;
      else if (tipo === 'todo') todos++;
      else if (tipo === 'fixme') fixmes++;
      else if (tipo === 'hack') hacks++;
      const sev = String(d.severidade || '');
      if (sev === 'alta') alta++;
      else if (sev === 'media') media++;
      else if (sev === 'baixa') baixa++;
    }
    const ultimoScanSha = itens.length > 0 ? String(itens[0].ultimoScanSha || '') : '';
    return { ok: true, data: { total: itens.length, debts, todos, fixmes, hacks, alta, media, baixa, ultimoScanSha } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

function _debitoToView(d: Record<string, unknown>): Record<string, unknown> {
  return {
    id: String(d.id || ''),
    sistemaId: String(d.sistemaId || ''),
    tipo: String(d.tipo || 'todo'),
    area: d.area ? String(d.area) : undefined,
    severidade: d.severidade ? String(d.severidade) : undefined,
    descricao: String(d.descricao || ''),
    arquivo: String(d.arquivo || ''),
    linha: Number(d.linha || 0),
    hash: String(d.hash || ''),
    status: (String(d.status || 'ativo') as DebitoStatusServer),
    backlogId: d.backlogId ? String(d.backlogId) : undefined,
    criadoEm: String(d.criadoEm || ''),
    atualizadoEm: String(d.atualizadoEm || ''),
    pagoEm: d.pagoEm ? String(d.pagoEm) : undefined,
    promovidoEm: d.promovidoEm ? String(d.promovidoEm) : undefined,
    ultimoScanSha: String(d.ultimoScanSha || ''),
  };
}

// ─── Servidores (v1.146.0) ────────────────────────────────────────────────────
// CRUD pra inst\u00e2ncias que o user roda — proxies LLM (LiteLLM, Ollama), workers,
// automa\u00e7\u00f5es, m\u00edstria, DBs locais. paths e dependencias s\u00e3o JSON em string.
// Decis\u00e3o: nada de senha aqui — sempre via Cofre (cofreLabel referencia o item).

interface PathItem { label?: string; valor?: string }

function servidoresList(): ServerResult {
  try {
    const todos = (dbGetAll('Servidores') as Array<Record<string, unknown>>).map((s) => {
      // Normaliza paths: aceita string JSON, array ou vazio.
      let paths: PathItem[] = [];
      const rawPaths = s.paths;
      if (Array.isArray(rawPaths)) {
        paths = rawPaths as PathItem[];
      } else if (rawPaths && typeof rawPaths === 'string' && rawPaths.trim()) {
        try {
          const parsed = JSON.parse(rawPaths);
          if (Array.isArray(parsed)) paths = parsed;
        } catch { /* ignora valores inv\u00e1lidos */ }
      }
      return {
        ...s,
        paths,
        porta: s.porta ? String(s.porta) : '',
        custoMensal: Number(s.custoMensal || 0) || 0,
      };
    });
    return { ok: true, data: todos };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar servidores' };
  }
}

function servidoresSave(payload: {
  id?: string; nome?: string; tipo?: string; descricao?: string; status?: string;
  host?: string; porta?: string | number; url?: string;
  ambiente?: string; tecnologia?: string; sistemaId?: string;
  comandoStart?: string; paths?: PathItem[] | string;
  dependencias?: string; recursos?: string;
  custoMensal?: number | string; moeda?: string;
  docsUrl?: string; cofreLabel?: string;
  tags?: string; notas?: string;
}): ServerResult {
  try {
    const nome = String(payload.nome || '').trim();
    if (!nome) throw new Error('Informe o nome do servidor (ex.: LiteLLM Proxy).');
    const agora = new Date().toISOString();
    const custoNum = typeof payload.custoMensal === 'number'
      ? payload.custoMensal
      : parseFloat(String(payload.custoMensal || '0').replace(',', '.'));

    // paths chega como array do front; gravamos como JSON pra caber numa c\u00e9lula.
    const pathsArr: PathItem[] = Array.isArray(payload.paths)
      ? payload.paths.filter((p) => p && (p.label || p.valor))
        .map((p) => ({ label: String(p.label || '').trim(), valor: String(p.valor || '').trim() }))
      : [];

    const base = {
      nome,
      tipo: String(payload.tipo || '').trim(),
      descricao: String(payload.descricao || '').trim(),
      status: String(payload.status || 'rodando').trim(),
      host: String(payload.host || '').trim(),
      porta: String(payload.porta || '').trim(),
      url: String(payload.url || '').trim(),
      ambiente: String(payload.ambiente || 'local').trim(),
      tecnologia: String(payload.tecnologia || '').trim(),
      sistemaId: String(payload.sistemaId || '').trim(),
      comandoStart: String(payload.comandoStart || '').trim(),
      paths: JSON.stringify(pathsArr),
      dependencias: String(payload.dependencias || '').trim(),
      recursos: String(payload.recursos || '').trim(),
      custoMensal: Number.isFinite(custoNum) ? custoNum : 0,
      moeda: String(payload.moeda || 'BRL').trim(),
      docsUrl: String(payload.docsUrl || '').trim(),
      cofreLabel: String(payload.cofreLabel || '').trim(),
      tags: String(payload.tags || '').trim(),
      notas: String(payload.notas || '').trim(),
      atualizadoEm: agora,
    };
    if (payload.id) {
      dbUpdate('Servidores', payload.id, base);
      return { ok: true, data: { id: payload.id } };
    }
    const novo = dbCreate('Servidores', { ...base, criadoEm: agora });
    return { ok: true, data: { id: String(novo.id || '') } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar servidor' };
  }
}

function servidoresDelete(id: string): ServerResult {
  try {
    dbDelete('Servidores', id);
    return { ok: true };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao remover servidor' };
  }
}

