// ─── Driver — OAuth multi-cloud (Google extra / OneDrive via Microsoft Graph) ─
// Fluxo de authorization code com a lib apps-script-oauth2 (userSymbol OAuth2).
// Credenciais do app OAuth (client id/secret) ficam no ScriptProperties por
// PROVEDOR (um app cobre N contas). O token de cada CONTA fica no UserProperties
// sob o nome "oauth_<connectorId>". A redirect URI é a /usercallback do script.

interface OAuth2Service {
  setAuthorizationBaseUrl(url: string): OAuth2Service;
  setTokenUrl(url: string): OAuth2Service;
  setClientId(id: string): OAuth2Service;
  setClientSecret(secret: string): OAuth2Service;
  setScope(scope: string): OAuth2Service;
  setCallbackFunction(name: string): OAuth2Service;
  setPropertyStore(store: GoogleAppsScript.Properties.Properties): OAuth2Service;
  setCache(cache: GoogleAppsScript.Cache.Cache): OAuth2Service;
  setParam(name: string, value: string): OAuth2Service;
  getAuthorizationUrl(optState?: Record<string, string>): string;
  handleCallback(request: { parameter: Record<string, string> }): boolean;
  hasAccess(): boolean;
  getAccessToken(): string;
  reset(): void;
}
declare const OAuth2: {
  createService(name: string): OAuth2Service;
  getRedirectUri(optScriptId?: string): string;
};

interface OAuthProviderCfg {
  authUrl: string;
  tokenUrl: string;
  scope: string;
  extraAuthParams: Record<string, string>;
  callback: string;
}

const _OAUTH_PROVIDERS: Record<string, OAuthProviderCfg> = {
  'google-drive': {
    authUrl: 'https://accounts.google.com/o/oauth2/v2/auth',
    tokenUrl: 'https://oauth2.googleapis.com/token',
    scope: 'https://www.googleapis.com/auth/drive.readonly',
    extraAuthParams: { access_type: 'offline', prompt: 'consent' },
    callback: 'authCallbackGoogle',
  },
  // Estudos → YouTube. OAuth próprio (Client ID/Secret do usuário, com a YouTube
  // Data API v3 habilitada). Usar o token do conector via REST evita adicionar o
  // scope sensível youtube.readonly ao manifesto do app — que, em contas Workspace
  // de apps não verificados, derruba a autorização (tela branca).
  'google-youtube': {
    authUrl: 'https://accounts.google.com/o/oauth2/v2/auth',
    tokenUrl: 'https://oauth2.googleapis.com/token',
    scope: 'https://www.googleapis.com/auth/youtube.readonly',
    extraAuthParams: { access_type: 'offline', prompt: 'consent' },
    callback: 'authCallbackGoogle',
  },
  onedrive: {
    authUrl: 'https://login.microsoftonline.com/common/oauth2/v2.0/authorize',
    tokenUrl: 'https://login.microsoftonline.com/common/oauth2/v2.0/token',
    scope: 'offline_access Files.Read User.Read',
    extraAuthParams: { prompt: 'consent' },
    callback: 'authCallbackMicrosoft',
  },
};

function _findConnector(id: string): Record<string, unknown> | null {
  const linhas = dbGetAll('DriveConnectors') as Array<Record<string, unknown>>;
  return linhas.find((l) => String(l.id || '') === id) || null;
}

function _oauthService(connectorId: string, provedor: string): OAuth2Service {
  const cfg = _OAUTH_PROVIDERS[provedor];
  if (!cfg) throw new Error('Provedor sem OAuth suportado: ' + provedor);
  const props = PropertiesService.getScriptProperties();
  const clientId = props.getProperty('oauth_' + provedor + '_client_id');
  const clientSecret = props.getProperty('oauth_' + provedor + '_client_secret');
  if (!clientId || !clientSecret) {
    throw new Error('Configure as credenciais OAuth deste provedor antes de conectar.');
  }
  let svc = OAuth2.createService('oauth_' + connectorId)
    .setAuthorizationBaseUrl(cfg.authUrl)
    .setTokenUrl(cfg.tokenUrl)
    .setClientId(clientId)
    .setClientSecret(clientSecret)
    .setScope(cfg.scope)
    .setCallbackFunction(cfg.callback)
    .setPropertyStore(PropertiesService.getUserProperties())
    .setCache(CacheService.getUserCache());
  const extra = cfg.extraAuthParams;
  Object.keys(extra).forEach((k) => { svc = svc.setParam(k, extra[k]); });
  return svc;
}

function _oauthHtml(titulo: string, msg: string): string {
  return '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">'
    + '<style>body{font-family:-apple-system,BlinkMacSystemFont,system-ui,sans-serif;background:#0f1115;color:#e7e2d8;'
    + 'display:flex;align-items:center;justify-content:center;height:100vh;margin:0}div{text-align:center;max-width:440px;padding:32px}'
    + 'h2{font-weight:600;margin:0 0 10px;font-size:20px}p{color:#9aa0a6;margin:0;line-height:1.5}</style></head>'
    + '<body><div><h2>' + titulo + '</h2><p>' + msg + '</p></div></body></html>';
}

function driveOAuthRedirectUri(): ServerResult {
  try {
    let uri = '';
    try { uri = OAuth2.getRedirectUri(); } catch { uri = ''; }
    if (!uri) uri = 'https://script.google.com/macros/d/' + ScriptApp.getScriptId() + '/usercallback';
    return { ok: true, data: { redirectUri: uri } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

function driveOAuthGetCredenciaisStatus(): ServerResult {
  try {
    const props = PropertiesService.getScriptProperties();
    const status: Record<string, boolean> = {};
    Object.keys(_OAUTH_PROVIDERS).forEach((p) => {
      status[p] = !!(props.getProperty('oauth_' + p + '_client_id') && props.getProperty('oauth_' + p + '_client_secret'));
    });
    let redirectUri = '';
    try { redirectUri = OAuth2.getRedirectUri(); } catch { redirectUri = 'https://script.google.com/macros/d/' + ScriptApp.getScriptId() + '/usercallback'; }
    return { ok: true, data: { status, redirectUri } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

function driveOAuthSetCredenciais(payload: { provedor: string; clientId: string; clientSecret: string }): ServerResult {
  try {
    const provedor = String(payload.provedor || '').trim();
    if (!_OAUTH_PROVIDERS[provedor]) throw new Error('Provedor sem OAuth suportado: ' + provedor);
    const clientId = String(payload.clientId || '').trim();
    const clientSecret = String(payload.clientSecret || '').trim();
    if (!clientId || !clientSecret) throw new Error('Informe Client ID e Client Secret.');
    const props = PropertiesService.getScriptProperties();
    props.setProperty('oauth_' + provedor + '_client_id', clientId);
    props.setProperty('oauth_' + provedor + '_client_secret', clientSecret);
    return { ok: true };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar credenciais' };
  }
}

function driveOAuthAuthorizeUrl(connectorId: string): ServerResult {
  try {
    const conn = _findConnector(connectorId);
    if (!conn) throw new Error('Conta não encontrada.');
    const provedor = String(conn.provedor || '');
    const svc = _oauthService(connectorId, provedor);
    if (svc.hasAccess()) {
      dbUpdate('DriveConnectors', connectorId, { status: 'conectada', atualizadoEm: new Date().toISOString() });
      return { ok: true, data: { authorized: true } };
    }
    const url = svc.getAuthorizationUrl({ connector: connectorId });
    return { ok: true, data: { authorized: false, url } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao iniciar autorização' };
  }
}

function _oauthHandleCallback(request: { parameter: Record<string, string> }): GoogleAppsScript.HTML.HtmlOutput {
  const connectorId = String((request && request.parameter && request.parameter.connector) || '');
  const conn = connectorId ? _findConnector(connectorId) : null;
  const provedor = conn ? String(conn.provedor || '') : '';
  try {
    if (!conn) throw new Error('Conta não encontrada para este retorno de OAuth.');
    const svc = _oauthService(connectorId, provedor);
    const ok = svc.handleCallback(request);
    if (ok) {
      dbUpdate('DriveConnectors', connectorId, { status: 'conectada', atualizadoEm: new Date().toISOString() });
      return HtmlService.createHtmlOutput(_oauthHtml('✅ Conta conectada!', 'Pode fechar esta aba e voltar ao Forja.'));
    }
    return HtmlService.createHtmlOutput(_oauthHtml('Acesso negado', 'A autorização foi cancelada. Pode fechar esta aba.'));
  } catch (e: unknown) {
    return HtmlService.createHtmlOutput(_oauthHtml('Erro ao conectar', e instanceof Error ? e.message : String(e)));
  }
}

function authCallbackGoogle(request: { parameter: Record<string, string> }): GoogleAppsScript.HTML.HtmlOutput {
  return _oauthHandleCallback(request);
}

function authCallbackMicrosoft(request: { parameter: Record<string, string> }): GoogleAppsScript.HTML.HtmlOutput {
  return _oauthHandleCallback(request);
}

function driveOAuthStatus(connectorId: string): ServerResult {
  try {
    const conn = _findConnector(connectorId);
    if (!conn) throw new Error('Conta não encontrada.');
    const provedor = String(conn.provedor || '');
    if (!_OAUTH_PROVIDERS[provedor]) return { ok: true, data: { conectada: false, suportado: false } };
    const svc = _oauthService(connectorId, provedor);
    const conectada = svc.hasAccess();
    dbUpdate('DriveConnectors', connectorId, { status: conectada ? 'conectada' : 'registrada', atualizadoEm: new Date().toISOString() });
    return { ok: true, data: { conectada, suportado: true } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao verificar conexão' };
  }
}

function driveOAuthDesconectar(connectorId: string): ServerResult {
  try {
    const conn = _findConnector(connectorId);
    if (conn && _OAUTH_PROVIDERS[String(conn.provedor || '')]) {
      _oauthService(connectorId, String(conn.provedor || '')).reset();
      dbUpdate('DriveConnectors', connectorId, { status: 'registrada', atualizadoEm: new Date().toISOString() });
    }
    return { ok: true };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao desconectar' };
  }
}

// Lista arquivos de uma conta REMOTA conectada (Google extra ou OneDrive).
function driveListarRemoto(connectorId: string, folderId?: string, busca?: string): ServerResult {
  try {
    const conn = _findConnector(connectorId);
    if (!conn) throw new Error('Conta não encontrada.');
    const provedor = String(conn.provedor || '');
    if (!_OAUTH_PROVIDERS[provedor]) throw new Error('Provedor sem OAuth suportado.');
    const svc = _oauthService(connectorId, provedor);
    if (!svc.hasAccess()) return { ok: false, error: 'NOT_CONNECTED' };
    const token = svc.getAccessToken();
    const headers = { Authorization: 'Bearer ' + token };

    if (provedor === 'onedrive') {
      const base = 'https://graph.microsoft.com/v1.0/me/drive';
      let url: string;
      if (busca && busca.trim()) {
        url = base + "/root/search(q='" + encodeURIComponent(busca.trim()) + "')?$top=200";
      } else if (folderId && folderId !== 'root') {
        url = base + '/items/' + encodeURIComponent(folderId) + '/children?$top=200';
      } else {
        url = base + '/root/children?$top=200';
      }
      const resp = UrlFetchApp.fetch(url, { headers, muteHttpExceptions: true });
      if (resp.getResponseCode() >= 400) throw new Error('Microsoft Graph ' + resp.getResponseCode() + ': ' + resp.getContentText().slice(0, 200));
      const data = JSON.parse(resp.getContentText()) as { value?: Array<Record<string, unknown>> };
      const arquivos = (data.value || []).map((it) => {
        const folder = it.folder as Record<string, unknown> | undefined;
        const file = it.file as Record<string, unknown> | undefined;
        return {
          id: String(it.id || ''),
          nome: String(it.name || '(sem nome)'),
          mimeType: folder ? 'application/vnd.google-apps.folder' : String((file && file.mimeType) || ''),
          isFolder: !!folder,
          modificado: String(it.lastModifiedDateTime || ''),
          tamanho: Number(it.size || 0),
          link: String(it.webUrl || ''),
        };
      });
      return { ok: true, data: { arquivos } };
    }

    // google-drive (outra conta)
    const parent = (folderId && folderId !== 'root') ? folderId : 'root';
    let q = "'" + parent + "' in parents and trashed = false";
    if (busca && busca.trim()) q += " and name contains '" + busca.trim().replace(/\\/g, '\\\\').replace(/'/g, "\\'") + "'";
    const fields = 'files(id,name,mimeType,modifiedTime,size,webViewLink)';
    const url = 'https://www.googleapis.com/drive/v3/files?q=' + encodeURIComponent(q)
      + '&pageSize=200&orderBy=' + encodeURIComponent('folder,name')
      + '&fields=' + encodeURIComponent(fields);
    const resp = UrlFetchApp.fetch(url, { headers, muteHttpExceptions: true });
    if (resp.getResponseCode() >= 400) throw new Error('Google Drive ' + resp.getResponseCode() + ': ' + resp.getContentText().slice(0, 200));
    const data = JSON.parse(resp.getContentText()) as { files?: Array<Record<string, unknown>> };
    const arquivos = (data.files || []).map((f) => {
      const mime = String(f.mimeType || '');
      return {
        id: String(f.id || ''),
        nome: String(f.name || '(sem nome)'),
        mimeType: mime,
        isFolder: mime === 'application/vnd.google-apps.folder',
        modificado: String(f.modifiedTime || ''),
        tamanho: f.size ? Number(f.size) : 0,
        link: String(f.webViewLink || ''),
      };
    });
    return { ok: true, data: { arquivos } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar a conta remota' };
  }
}

// ─── Skills Hub ──────────────────────────────────────────────────────────────
// Skills são prompts/instruções/playbooks que o usuário coleciona pra usar com
// LLMs (formato SKILL.md / agent-skill). Guardamos como linhas na sheet "Skills"
// pra evitar escopos extras de Drive. O conteúdo é texto Markdown completo.

// Bloco estruturado: cada seção H2 do conteúdo vira um par título → texto.
// Preservamos ordem e o título exato pra exibir bonito no Drawer.
interface SecaoEstruturada {
  titulo: string;
  // chave canônica pra reconhecer seções "famosas" (quando_usar, identidade,
  // pre_execucao, principios, regras, boas_praticas, framework, checklist,
  // metadados). 'outra' quando não reconhece.
  chave: string;
  conteudo: string;
}

interface SkillParsed {
  nome: string;
  descricao: string;
  categoria: string;
  tags: string[];
  // Headings de nível 2 (compat — só os títulos pra preview).
  secoes: string[];
  // v1.149.0 — novos campos extraídos do formato "Pack PT-BR".
  slug: string;            // do frontmatter ou do bloco METADADOS
  idExterno: string;       // ex.: "#0237"
  ultimaAtualizacao: string; // YYYY-MM-DD
  usos: number;            // valor inicial declarado (raramente vem)
  relacionadas: string[];  // lista de slugs/ids relacionados
  // Texto curto da seção "QUANDO USAR" pra preview no card.
  quandoUsar: string;
  // Texto curto da seção "IDENTIDADE E PAPEL" pra preview.
  identidadePapel: string;
  // Todas as seções extraídas com seu conteúdo (renderizadas no Drawer).
  blocos: SecaoEstruturada[];
  // v1.150.0 — campos específicos do formato AGENT.
  tipo: string;             // ex.: "agente-autonomo"
  diretrizFinal: string;    // 1 frase resumo (vira preview do card)
  dominios: string[];       // áreas de conhecimento (### dentro do bloco DOMÍNIOS)
}

// v1.149.0 — Normaliza um título H2 pra chave canônica.
// Reconhece tanto o formato PT-BR do novo pack quanto variações em inglês.
// v1.150.0 — Adicionadas chaves específicas de Agent: protocolo_inicializacao,
// dominios, workflow, protocolo_comunicacao, integracoes, diretriz_final.
// v1.150.1 — Adicionadas chaves do formato vibeship-spawner: capacidades,
// requisitos, arestas_perigosas, habilidades_relacionadas. Padrões → boas_praticas.
// Limpa emoji/símbolo do início do título antes do regex (### ⚠️ X → x).
function _chaveSecao(tituloRaw: string): string {
  const t = tituloRaw
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // tira acentos
    // v1.150.1 — Remove emojis/símbolos do início (⚠️, 🚨, ❌, ✅, etc.).
    // Range cobre os blocos Unicode comuns de emoji/símbolo + as variantes
    // de seleção (FE0F/200D). Mantém pontuação ASCII básica.
    .replace(/[\u{1F300}-\u{1F9FF}\u{2600}-\u{27BF}\u{FE0F}\u{200D}]/gu, '')
    .trim();
  if (/^metadados|^metadata$/.test(t)) return 'metadados';
  if (/quando\s+usar|when\s+to\s+use/.test(t)) return 'quando_usar';
  // "IDENTIDADE E EXPERTISE" (agent) e "IDENTIDADE E PAPEL" (skill) caem aqui.
  if (/identidade|identity|persona|papel|role|expertise/.test(t)) return 'identidade';
  // v1.150.0 — Protocolo de inicialização (passo-a-passo de quando o agent é invocado).
  if (/protocolo\s+de\s+inicializ|protocol(?:o)?\s+de\s+ativacao|inicializacao|initialization|invoked|startup/.test(t)) return 'protocolo_inicializacao';
  // v1.150.0 — Domínios de conhecimento (áreas + sub-skills do agent).
  if (/dominios?\s+de\s+conhec|knowledge\s+domains?|areas\s+de\s+expertise|expertise\s+areas/.test(t)) return 'dominios';
  // v1.150.1 — Capacidades (vibeship-spawner): lista de tags/skills nucleares.
  if (/^capacidades?$|^capabilities$|^skills$|^habilidades$/.test(t)) return 'capacidades';
  // v1.150.1 — Requisitos (vibeship-spawner): pré-requisitos / dependências.
  if (/^requisitos$|^requirements$|^prerequisit|^pre.?requis|^dependencias$|^dependencies$|^depende\s+de/.test(t)) return 'requisitos';
  if (/pre.?execucao|context|coleta\s+de\s+contexto|prerequisit/.test(t)) return 'pre_execucao';
  if (/principios|principles/.test(t)) return 'principios';
  if (/regras|rules|estilo|style/.test(t)) return 'regras';
  // v1.150.1 — "Padrões" mapeia pra boas_praticas (sinônimos contextuais).
  if (/boas\s+praticas|best\s+practices|good\s+practices|^padroes$|^patterns$/.test(t)) return 'boas_praticas';
  if (/framework\s+de\s+entrega|delivery\s+framework|output\s+format|entrega|formato\s+da\s+resposta/.test(t)) return 'framework';
  // v1.150.0 — Workflow de execução (fases) — agent específico.
  if (/workflow\s+de\s+execucao|execution\s+workflow|fluxo\s+de\s+execucao|workflow|execution\s+flow/.test(t)) return 'workflow';
  // Checklist genérico. Vem DEPOIS de workflow pra não pegar "workflow de qualidade".
  if (/checklist|qualidade|quality\s+check/.test(t)) return 'checklist';
  // v1.150.0 — Protocolo de comunicação (JSON entre agents).
  if (/protocolo\s+de\s+comunicacao|communication\s+protocol|agent\s+protocol/.test(t)) return 'protocolo_comunicacao';
  // v1.150.1 — Arestas perigosas / armadilhas / gotchas / pitfalls (geralmente
  // vem com tabela Problema/Severidade/Solução).
  if (/arestas?\s+perigosas|armadilhas?|gotchas|pitfalls|edge\s+cases?|riscos/.test(t)) return 'arestas_perigosas';
  // v1.150.1 — Habilidades relacionadas (geralmente lista slugs em backticks).
  if (/habilidades\s+relacionadas|skills?\s+relacionadas?|related\s+(?:skills|capabilities)|see\s+also|works?\s+well\s+with/.test(t)) return 'habilidades_relacionadas';
  // v1.150.0 — Integrações com outros agents (mais específico que habilidades_relacionadas).
  if (/integracao\s+com\s+outros\s+agen|colabora|colaboracao|integration|interacts?\s+with/.test(t)) return 'integracoes';
  // v1.150.0 — Diretriz final (1 frase resumo, vira preview do card).
  if (/diretriz\s+final|princip(?:io|al)\s+(?:de\s+ouro|guideline)|final\s+directive|golden\s+rule/.test(t)) return 'diretriz_final';
  if (/exemplos?|examples?/.test(t)) return 'exemplos';
  if (/anti.?padr|antipattern|nao\s+faca|do\s+not/.test(t)) return 'antipadroes';
  return 'outra';
}

// v1.149.0 — Parse o sub-bloco "## METADADOS" do formato PT-BR.
// Captura linhas tipo "- id: #0237", "- slug: nome", "- usos: 12",
// "- ultima_atualizacao: 2025-11-30", "- skills_relacionadas: [a, b, c]".
// v1.150.0 — Captura também "- tipo: agente-autonomo" (específico de Agent).
function _parseMetadadosBloco(texto: string): {
  idExterno?: string;
  slug?: string;
  categoria?: string;
  usos?: number;
  ultimaAtualizacao?: string;
  relacionadas?: string[];
  tipo?: string;
} {
  const out: ReturnType<typeof _parseMetadadosBloco> = {};
  if (!texto) return out;
  const linhas = texto.split('\n');
  for (const lnRaw of linhas) {
    // Aceita "- chave: valor", "* chave: valor" ou "chave: valor".
    const ln = lnRaw.replace(/^[\s\-\*]+/, '');
    const kv = ln.match(/^([\w\-]+)\s*:\s*(.+)$/);
    if (!kv) continue;
    const k = kv[1].toLowerCase().trim();
    let v = kv[2].trim().replace(/^['"]|['"]$/g, '');
    // remove "[" e "]" se vier array inline
    const arrInline = v.match(/^\[(.*)\]$/);
    if (k === 'id' || k === 'id_externo' || k === 'codigo') {
      out.idExterno = v;
    } else if (k === 'slug') {
      out.slug = v.replace(/^#/, '').trim();
    } else if (k === 'categoria' || k === 'category') {
      out.categoria = v;
    } else if (k === 'tipo' || k === 'type' || k === 'agent_type' || k === 'kind') {
      out.tipo = v;
    } else if (k === 'usos' || k === 'uses' || k === 'uso') {
      const n = Number(v.replace(/\D+/g, ''));
      if (!isNaN(n)) out.usos = n;
    } else if (k === 'ultima_atualizacao' || k === 'updated' || k === 'updated_at' || k === 'data') {
      out.ultimaAtualizacao = v;
    } else if (
      k === 'skills_relacionadas' || k === 'relacionadas' || k === 'related' || k === 'see_also'
      || k === 'integracoes' || k === 'integrations' || k === 'colabora_com' || k === 'collaborates_with'
    ) {
      if (arrInline) v = arrInline[1];
      out.relacionadas = v.split(/[,;]/).map((x) => x.trim().replace(/^[\-\*]\s*/, '')).filter(Boolean);
    }
  }
  return out;
}

// v1.150.0 — Extrai as ÁREAS de expertise do bloco "## DOMÍNIOS DE CONHECIMENTO".
// Cada área aparece como sub-heading `### Nome`. Retorna lista de nomes pra
// usar como tags/dominios estruturados (busca, agrupamento).
function _extrairDominios(texto: string): string[] {
  if (!texto) return [];
  const matches = texto.match(/^###\s+(.+)$/gm) || [];
  return matches
    .map((h) => h.replace(/^###\s+/, '').trim())
    .filter(Boolean)
    .slice(0, 24);
}

// v1.150.0 — Extrai os slugs/nomes do bloco "## INTEGRAÇÃO COM OUTROS AGENTES".
// Cada linha vem como: "- Colabora com [agente-x] em [tarefa]".
// Captura o que estiver dentro de [colchetes] OU `backticks` OU palavra
// kebab-case isolada (fallback). Limita a 16 pra não estourar a célula.
function _extrairIntegracoes(texto: string): string[] {
  if (!texto) return [];
  const out: string[] = [];
  // 1) Match em [colchetes]
  const matchesBracket = texto.match(/\[([a-z0-9\-_]+)\]/g) || [];
  for (const m of matchesBracket) out.push(m.slice(1, -1));
  // 2) Match em `backticks`
  const matchesBack = texto.match(/`([a-z0-9\-_]+)`/g) || [];
  for (const m of matchesBack) out.push(m.slice(1, -1));
  // Dedup, mantém ordem de aparição.
  const seen = new Set<string>();
  const dedup: string[] = [];
  for (const x of out) { if (!seen.has(x)) { seen.add(x); dedup.push(x); } }
  return dedup.slice(0, 16);
}

// v1.150.0 — Extrai a DIRETRIZ FINAL — vira o preview principal do card do agent.
// Tira aspas, markdown e mantém só a primeira "frase" (até o primeiro ponto-final
// + espaço/EOL). Se vazio, retorna a 1ª linha não-vazia do bloco.
function _extrairDiretrizFinal(texto: string): string {
  if (!texto) return '';
  const limpo = texto
    .replace(/^[#>\s]+/gm, '') // remove marcadores de markdown no início de linha
    .replace(/\*\*?/g, '')      // remove ** e *
    .trim();
  if (!limpo) return '';
  // Pega a 1ª frase completa, máximo 280 chars.
  const matchFrase = limpo.match(/^[^\n]+?[.!?](?:\s|$)/);
  if (matchFrase) return matchFrase[0].trim().slice(0, 280);
  // Fallback: 1ª linha.
  return limpo.split('\n')[0].trim().slice(0, 280);
}

// v1.149.0 — Slugify simples (acento, espaço, símbolos → kebab-case).
function _slugify(s: string): string {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s\-_]/g, '')
    .trim()
    .replace(/[\s_]+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 64);
}

// Parse frontmatter YAML simples + extração de blocos estruturados.
// Suporta TRÊS formatos:
// 1) Claude/Cursor SKILL.md (frontmatter YAML + headings em inglês)
// 2) "Pack PT-BR" (sem frontmatter, com ## METADADOS, ## QUANDO USAR ESTA SKILL,
//    ## IDENTIDADE E PAPEL, etc.)
// 3) .md "comum" (extrai H1 + primeiro parágrafo)
function _parseSkillMd(conteudo: string): SkillParsed {
  const out: SkillParsed = {
    nome: '', descricao: '', categoria: '', tags: [], secoes: [],
    slug: '', idExterno: '', ultimaAtualizacao: '', usos: 0,
    relacionadas: [], quandoUsar: '', identidadePapel: '', blocos: [],
    tipo: '', diretrizFinal: '', dominios: [],
  };
  if (!conteudo) return out;

  const texto = conteudo.replace(/\r\n/g, '\n');

  // 1) Frontmatter YAML (--- ... ---) — se existir.
  const m = texto.match(/^---\n([\s\S]*?)\n---\n?/);
  let corpo = texto;
  if (m) {
    corpo = texto.slice(m[0].length);
    const fm = m[1];
    const linhas = fm.split('\n');
    for (const ln of linhas) {
      const kv = ln.match(/^(\w+)\s*:\s*(.*)$/);
      if (!kv) continue;
      const k = kv[1].toLowerCase().trim();
      let v = kv[2].trim();
      v = v.replace(/^['"]|['"]$/g, '');
      if (k === 'name' || k === 'nome' || k === 'title' || k === 'titulo') out.nome = v;
      else if (k === 'description' || k === 'descricao' || k === 'desc') out.descricao = v;
      else if (k === 'category' || k === 'categoria') out.categoria = v;
      else if (k === 'slug') out.slug = v;
      else if (k === 'id' || k === 'id_externo') out.idExterno = v;
      else if (k === 'source' || k === 'fonte' || k === 'origem') {
        // v1.150.1 — frontmatter `source: vibeship-spawner-skills (Apache 2.0)`
        // pode ser usado pra agrupar packs. Por ora vai pra tags como sinal.
        if (v && !out.tags.includes(v)) out.tags.push(v.split('(')[0].trim());
      }
      else if (k === 'tags') {
        v = v.replace(/^\[|\]$/g, '');
        out.tags = v.split(',').map((x) => x.trim()).filter(Boolean);
      }
    }
  }

  // v1.150.1 — Heurística nome/slug: se o frontmatter `name` veio como
  // kebab-case (sem espaço, ex.: "agent-evaluation") E existe um H1 PT-BR,
  // promove o H1 a `nome` legível e o `name` vira `slug`. Isso evita cards
  // feios tipo "agent-evaluation" quando o autor já escreveu "Avaliação de
  // Agentes" como título principal.
  const h1Match = corpo.match(/^#\s+(.+)$/m);
  const h1Texto = h1Match ? h1Match[1].trim() : '';
  if (out.nome && /^[a-z0-9][a-z0-9\-_]*$/.test(out.nome) && h1Texto && h1Texto.toLowerCase() !== out.nome) {
    if (!out.slug) out.slug = out.nome;
    out.nome = h1Texto;
  } else if (!out.nome && h1Texto) {
    out.nome = h1Texto;
  }
  if (!out.descricao) {
    const aposH1 = corpo.replace(/^#\s+.+$/m, '').trim();
    const par = aposH1.match(/^([^\n#][^\n]+(?:\n[^\n#][^\n]+)*)/);
    if (par) out.descricao = par[1].trim().slice(0, 240);
  } else {
    // v1.150.1 — Frontmatter pode trazer descrição enorme (ex.: vibeship usa
    // o description como "system prompt do trigger"). Pra preview do card e
    // do drawer, cortar a 240 chars na 1ª frase mantendo legibilidade.
    if (out.descricao.length > 240) {
      const recorte = out.descricao.slice(0, 240);
      const ultimaPontuacao = Math.max(recorte.lastIndexOf('. '), recorte.lastIndexOf('! '), recorte.lastIndexOf('? '));
      out.descricao = ultimaPontuacao > 80
        ? recorte.slice(0, ultimaPontuacao + 1).trim()
        : recorte.trim() + '…';
    }
  }

  // 3) Extrai TODAS as seções H2 com conteúdo. Vai do "## X" até o próximo "## Y"
  // ou EOF. Preserva ordem e título original.
  const blocos: SecaoEstruturada[] = [];
  const regexH2 = /^##\s+(.+)$/gm;
  let mh: RegExpExecArray | null;
  const matches: Array<{ titulo: string; inicio: number; fimHeader: number }> = [];
  while ((mh = regexH2.exec(corpo)) !== null) {
    matches.push({ titulo: mh[1].trim(), inicio: mh.index, fimHeader: mh.index + mh[0].length });
  }
  for (let i = 0; i < matches.length; i++) {
    const cur = matches[i];
    const prox = matches[i + 1];
    const corpoSecao = corpo.slice(cur.fimHeader, prox ? prox.inicio : undefined).trim();
    blocos.push({ titulo: cur.titulo, chave: _chaveSecao(cur.titulo), conteudo: corpoSecao });
  }
  out.blocos = blocos;
  out.secoes = blocos.map((b) => b.titulo).slice(0, 24);

  // 4) Bloco METADADOS (formato Pack PT-BR) — pode complementar/sobrescrever o
  // frontmatter se houver.
  const blocoMeta = blocos.find((b) => b.chave === 'metadados');
  if (blocoMeta) {
    const meta = _parseMetadadosBloco(blocoMeta.conteudo);
    if (meta.idExterno && !out.idExterno) out.idExterno = meta.idExterno;
    if (meta.slug && !out.slug) out.slug = meta.slug;
    if (meta.categoria && !out.categoria) out.categoria = meta.categoria;
    if (meta.tipo) out.tipo = meta.tipo;
    if (meta.usos !== undefined) out.usos = meta.usos;
    if (meta.ultimaAtualizacao) out.ultimaAtualizacao = meta.ultimaAtualizacao;
    if (meta.relacionadas) out.relacionadas = meta.relacionadas;
  }

  // 5) Preview de "QUANDO USAR" e "IDENTIDADE" (campos rápidos pra card).
  const blocoQuando = blocos.find((b) => b.chave === 'quando_usar');
  if (blocoQuando) out.quandoUsar = blocoQuando.conteudo.slice(0, 400);
  const blocoIden = blocos.find((b) => b.chave === 'identidade');
  if (blocoIden) out.identidadePapel = blocoIden.conteudo.slice(0, 400);

  // v1.150.0 — Campos específicos de Agent.
  // 5.1) Diretriz final → preview do card (mais resumido que QUANDO USAR).
  const blocoDiretriz = blocos.find((b) => b.chave === 'diretriz_final');
  if (blocoDiretriz) out.diretrizFinal = _extrairDiretrizFinal(blocoDiretriz.conteudo);
  // 5.2) Domínios de conhecimento → tags estruturadas (áreas dos ###).
  const blocoDominios = blocos.find((b) => b.chave === 'dominios');
  if (blocoDominios) out.dominios = _extrairDominios(blocoDominios.conteudo);
  // 5.3) Integrações com outros agents → reusa `relacionadas` se ainda vazio,
  // ou complementa se o METADADOS não trouxe a lista. Dedup.
  const blocoIntegracoes = blocos.find((b) => b.chave === 'integracoes');
  if (blocoIntegracoes) {
    const integracoes = _extrairIntegracoes(blocoIntegracoes.conteudo);
    if (integracoes.length > 0) {
      const set = new Set([...out.relacionadas, ...integracoes]);
      out.relacionadas = Array.from(set);
    }
  }
  // v1.150.1 — Habilidades relacionadas (vibeship-spawner format): tem o mesmo
  // shape de slugs em `backticks` ou [colchetes] — reusa o extrator e mergeia.
  const blocoHabRel = blocos.find((b) => b.chave === 'habilidades_relacionadas');
  if (blocoHabRel) {
    const habs = _extrairIntegracoes(blocoHabRel.conteudo);
    if (habs.length > 0) {
      const set = new Set([...out.relacionadas, ...habs]);
      out.relacionadas = Array.from(set);
    }
  }

  // 6) Se ainda não tem descricao, deriva de DIRETRIZ FINAL → QUANDO USAR (1ª frase)
  // — útil pro pack PT-BR que não tem frontmatter nem H1.
  if (!out.descricao) {
    if (out.diretrizFinal) out.descricao = out.diretrizFinal.slice(0, 240);
    else if (out.quandoUsar) {
      const primeiraFrase = out.quandoUsar.split(/[.!?\n]/).map((x) => x.trim()).filter(Boolean)[0];
      if (primeiraFrase) out.descricao = primeiraFrase.slice(0, 240);
    }
  }

  // 7) Slug: se não vier explícito, deriva do nome.
  if (!out.slug && out.nome) out.slug = _slugify(out.nome);

  return out;
}

// Cria/atualiza uma skill a partir do conteúdo Markdown + nome de origem.
// Se id for fornecido, atualiza; senão cria nova.
function skillsSave(payload: {
  id?: string;
  conteudo: string;
  fonte?: string; // nome do arquivo original, ex.: "review-bugbot.md"
  nomeOverride?: string;
  descricaoOverride?: string;
  categoriaOverride?: string;
  tagsOverride?: string;
}): ServerResult {
  try {
    if (!payload.conteudo || !payload.conteudo.trim()) {
      throw new Error('Conteúdo vazio — cole o markdown da skill ou faça upload de um arquivo.');
    }
    const parsed = _parseSkillMd(payload.conteudo);
    const nome = (payload.nomeOverride || parsed.nome || payload.fonte?.replace(/\.md$/i, '') || 'Skill sem nome').trim();
    const descricao = (payload.descricaoOverride || parsed.descricao || '').trim();
    const categoria = (payload.categoriaOverride || parsed.categoria || '').trim();
    const tags = (payload.tagsOverride !== undefined ? payload.tagsOverride : parsed.tags.join(', ')).trim();
    const agora = new Date().toISOString();
    const tamanho = payload.conteudo.length;

    // v1.149.0 — extra: persiste campos ricos extraídos do parser (formato Pack PT-BR).
    const extra = {
      slug: parsed.slug || _slugify(nome),
      idExterno: parsed.idExterno || '',
      relacionadas: (parsed.relacionadas || []).join(','),
      quandoUsar: parsed.quandoUsar || '',
      identidadePapel: parsed.identidadePapel || '',
      // Armazena a lista de blocos como JSON (até 6KB cabe tranquilo na célula).
      secoesJson: JSON.stringify(parsed.blocos || []),
    };

    if (payload.id) {
      const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
      const existe = linhas.find((l) => String(l.id || '') === payload.id);
      if (!existe) throw new Error('Skill não encontrada pra atualizar.');
      // Se o conteúdo mudou, invalida a tradução em cache (ficou obsoleta).
      const conteudoMudou = String(existe.conteudo || '') !== payload.conteudo;
      dbUpdate('Skills', payload.id, {
        nome, descricao, categoria, tags,
        conteudo: payload.conteudo,
        fonte: payload.fonte || String(existe.fonte || ''),
        tamanhoBytes: tamanho,
        atualizadoEm: agora,
        ...extra,
        ...(conteudoMudou ? { traducaoPt: '', descricaoPt: '', tipoIA: '', adaptacoes: '' } : {}),
      });
      return { ok: true, data: { id: payload.id, nome, descricao, categoria, tags, ...extra } };
    }

    const novo = dbCreate('Skills', {
      nome,
      descricao,
      categoria,
      tags,
      conteudo: payload.conteudo,
      fonte: payload.fonte || '',
      tamanhoBytes: tamanho,
      criadoEm: agora,
      atualizadoEm: agora,
      ...extra,
      // Usos arranca do que vier no parser (0 na maioria dos casos).
      usos: parsed.usos || 0,
    });
    return { ok: true, data: { id: String(novo.id || ''), nome, descricao, categoria, tags, ...extra } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar skill' };
  }
}

// v1.149.0 — Incrementa contador de "usos" da skill. Chamado pelo front quando
// o user copia, baixa ou exporta a skill (sinal forte de uso). Idempotente
// no sentido de que não falha se a skill sumir.
function skillsRegistrarUso(id: string): ServerResult {
  try {
    const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
    const s = linhas.find((l) => String(l.id || '') === id);
    if (!s) return { ok: true, data: { usos: 0 } }; // silencioso
    const atual = Number(s.usos || 0);
    const novo = atual + 1;
    dbUpdate('Skills', id, { usos: novo, atualizadoEm: new Date().toISOString() });
    return { ok: true, data: { usos: novo } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// v1.151.0 — Import em lote. Aceita N skills numa só chamada e usa dbBatchCreate
// (1 write pra todo o lote) em vez de N appendRow().
// Payload:
//   itens: array de { markdown, slug?, categoria?, tags?, fonte?, idExterno? }
//   opcoes:
//     - categoriaDefault: aplica a TODOS os itens (override). Caso típico:
//       user baixou 129 skills duma mesma categoria.
//     - fonteDefault: agrupa visualmente as skills (vira "fonte" da pasta).
//     - modo: 'criar' (skip se slug existe) ou 'upsert' (atualiza se existe).
//       Default 'upsert' — mais útil pra re-imports.
// Resposta: { total, criados, atualizados, pulados, erros: [{slug, msg}] }.
//
// LIMITE: 200 itens por chamada. Pra 1036 skills, o frontend faz 6 chamadas.
// Isso evita timeout do GAS (~6 min) e mantém a UI responsiva (mostra
// progresso de batch em batch).
function skillsBulkSave(payload: {
  itens: Array<{
    markdown: string;
    slug?: string;
    categoria?: string;
    tags?: string;
    fonte?: string;
    idExterno?: string;
  }>;
  opcoes?: {
    categoriaDefault?: string;
    fonteDefault?: string;
    segmento?: string;
    modo?: 'criar' | 'upsert';
  };
}): ServerResult {
  return _bulkSaveGenerico('Skills', payload);
}

function agentsBulkSave(payload: {
  itens: Array<{
    markdown: string;
    slug?: string;
    categoria?: string;
    tags?: string;
    fonte?: string;
    idExterno?: string;
    modelo?: string;
    ferramentas?: string;
  }>;
  opcoes?: {
    categoriaDefault?: string;
    fonteDefault?: string;
    segmento?: string;
    modo?: 'criar' | 'upsert';
  };
}): ServerResult {
  return _bulkSaveGenerico('Agents', payload);
}

// v1.151.3 — Heurística de "completude" do conteúdo. Usada pra (a) barrar
// itens incompletos na importação e (b) decidir qual versão manter quando há
// duplicata. Pontua tamanho do markdown + nome + descrição + nº de seções +
// quando_usar. Não precisa ser exata: serve só pra comparar versões e cortar lixo.
function _scoreCompletudeParsed(parsed: {
  nome?: string; descricao?: string; quandoUsar?: string; blocos?: unknown[];
}, md: string): number {
  let score = Math.min(md.length, 4000) / 100; // até 40 pts por tamanho
  if (parsed.nome && parsed.nome.trim() && parsed.nome.toLowerCase() !== 'sem nome') score += 10;
  if (parsed.descricao && parsed.descricao.trim().length > 20) score += 10;
  score += Math.min((parsed.blocos || []).length, 8) * 5; // estrutura (seções)
  if (parsed.quandoUsar && parsed.quandoUsar.trim()) score += 5;
  return score;
}

// Score equivalente pra uma linha JÁ salva no banco (pra comparar com a importada).
function _scoreCompletudeLinha(row: Record<string, unknown>): number {
  const md = String(row.conteudo || '');
  let blocos = 0;
  try { const arr = JSON.parse(String(row.secoesJson || '[]')); if (Array.isArray(arr)) blocos = arr.length; } catch { /* ignora */ }
  let score = Math.min(md.length, 4000) / 100;
  if (String(row.nome || '').trim() && String(row.nome).toLowerCase() !== 'sem nome') score += 10;
  if (String(row.descricao || '').trim().length > 20) score += 10;
  score += Math.min(blocos, 8) * 5;
  if (String(row.quandoUsar || '').trim()) score += 5;
  return score;
}

// "Completinho" = tem nome de verdade, markdown com tamanho mínimo e corpo
// (não só frontmatter). Barra entradas truncadas/redirecionadas/placeholder.
function _pareceCompletoConteudo(parsed: { nome?: string }, md: string): boolean {
  const corpo = md.replace(/^\s*---[\s\S]*?\n---\s*/, '').trim(); // remove frontmatter YAML
  const temNome = !!(parsed.nome && parsed.nome.trim() && parsed.nome.toLowerCase() !== 'sem nome');
  return md.length >= 120 && temNome && corpo.length >= 40;
}

// v1.151.0 — Implementação compartilhada do bulk save (Skills e Agents).
// Skills = sem campos modelo/ferramentas/metaJson/tipo/diretrizFinal/dominios
// (ficam vazios pras Skills, sem impacto). Agents = campos extra preenchidos
// pelo parser quando vierem no markdown.
function _bulkSaveGenerico(
  tabela: 'Skills' | 'Agents',
  payload: {
    itens: Array<{
      markdown: string;
      slug?: string;
      categoria?: string;
      tags?: string;
      fonte?: string;
      idExterno?: string;
      modelo?: string;
      ferramentas?: string;
    }>;
    opcoes?: {
      categoriaDefault?: string;
      fonteDefault?: string;
      segmento?: string;
      modo?: 'criar' | 'upsert';
    };
  },
): ServerResult {
  try {
    if (!payload || !Array.isArray(payload.itens) || payload.itens.length === 0) {
      return { ok: false, error: 'Lote vazio.' };
    }
    if (payload.itens.length > 200) {
      return { ok: false, error: `Lote acima de 200 itens (${payload.itens.length}). Fatiar em vários chunks.` };
    }
    const op = payload.opcoes || {};
    const modo = op.modo || 'upsert';
    const agora = new Date().toISOString();

    // v1.156.0 — Segmento de destino: quando informado, TODO item do lote vai pra
    // pasta/seção desse segmento (fonte = "<segKey>/<slug>"), e garantimos o
    // registro de metadados da fonte. Assim packs de domínio (contabilidade,
    // fiscal...) caem numa seção própria nos hubs — de onde se monta o kit.
    const segKey = op.segmento ? _slugFonte(op.segmento) : '';
    if (segKey) _garantirFonteMeta(segKey, String(op.segmento || '').trim());

    // Pré-busca: slugs já existentes (caso modo upsert/criar precise checar).
    const existentes = dbGetAll(tabela) as Array<Record<string, unknown>>;
    const porSlug = new Map<string, Record<string, unknown>>();
    for (const e of existentes) {
      const sl = String(e.slug || '').trim();
      if (sl) porSlug.set(sl, e);
    }

    const paraCriar: Array<Record<string, unknown>> = [];
    const paraAtualizar: Array<{ id: string; data: Record<string, unknown> }> = [];
    let pulados = 0;
    const erros: Array<{ slug: string; msg: string }> = [];
    // v1.151.3 — itens descartados de propósito (incompletos, duplicados no
    // lote, ou downgrade evitado). Não são "erros" — são a trava de segurança
    // funcionando. Reportados separadamente pra transparência.
    const ignorados: Array<{ slug: string; msg: string }> = [];

    // ── 1ª passada: parse + trava de qualidade + dedup DENTRO do lote ──────────
    // Mantém apenas a versão MAIS COMPLETA de cada slug dentro deste lote, então
    // se o mesmo slug vier em 2 arquivos (ex.: o quebrado + o regerado), só o
    // melhor sobrevive — nunca os dois.
    const candidatos = new Map<string, { row: Record<string, unknown>; md: string; score: number; slug: string; usos: number }>();
    let semSlugSeq = 0;
    for (const item of payload.itens) {
      try {
        const md = (item.markdown || '').trim();
        if (!md) { ignorados.push({ slug: item.slug || '(sem slug)', msg: 'Markdown vazio.' }); continue; }
        const parsed = _parseSkillMd(md);

        // Trava de qualidade: só passa o que estiver "completinho".
        if (!_pareceCompletoConteudo(parsed, md)) {
          ignorados.push({ slug: item.slug || parsed.slug || '(incompleto)', msg: 'Conteúdo incompleto — não importado.' });
          continue;
        }

        const slugFinal = (item.slug || parsed.slug || _slugify(parsed.nome) || '').trim();
        const nome = (parsed.nome || item.slug || 'Sem nome').trim();
        // v1.151.1 — Prioridade da categoria invertida: o que o ARQUIVO já traz
        // ganha do default do modal. O `categoriaDefault` agora é só FALLBACK
        // pra itens sem categoria. Faz sentido porque a outra AI já vem com
        // `category` correto nos JSONs por categoria.
        const categoria = (item.categoria || parsed.categoria || op.categoriaDefault || '').trim();
        // Com segmento: força a fonte pra "<segKey>/<slug>" (agrupa na seção).
        // Sem segmento: comportamento legado (item.fonte ou fonteDefault).
        const fonte = segKey
          ? `${segKey}/${slugFinal || _slugify(nome) || 'item'}`
          : (item.fonte || op.fonteDefault || '').trim();
        const tags = (item.tags || parsed.tags.join(', ')).trim();
        const descricao = parsed.descricao;

        const baseRow: Record<string, unknown> = {
          nome, descricao, categoria, tags,
          conteudo: md,
          fonte,
          tamanhoBytes: md.length,
          atualizadoEm: agora,
          slug: slugFinal,
          idExterno: item.idExterno || parsed.idExterno || '',
          relacionadas: (parsed.relacionadas || []).join(','),
          quandoUsar: parsed.quandoUsar || '',
          identidadePapel: parsed.identidadePapel || '',
          secoesJson: JSON.stringify(parsed.blocos || []),
        };

        // Campos específicos de Agent (vazios pra Skills, sem dano).
        if (tabela === 'Agents') {
          baseRow.modelo = item.modelo || '';
          baseRow.ferramentas = item.ferramentas || '';
          baseRow.tipo = parsed.tipo || '';
          baseRow.diretrizFinal = parsed.diretrizFinal || '';
          baseRow.dominios = (parsed.dominios || []).join(',');
        }

        const score = _scoreCompletudeParsed(parsed, md);
        const usos = parsed.usos || 0;
        // Chave de dedup: slug quando existe; senão, cada item é único.
        const chave = slugFinal || `__noslug_${++semSlugSeq}`;
        const anterior = candidatos.get(chave);
        if (anterior) {
          // Duplicado no MESMO lote → mantém o mais completo, descarta o outro.
          if (score > anterior.score) candidatos.set(chave, { row: baseRow, md, score, slug: slugFinal, usos });
          pulados++;
          ignorados.push({ slug: slugFinal, msg: 'Duplicado no lote — mantida a versão mais completa.' });
        } else {
          candidatos.set(chave, { row: baseRow, md, score, slug: slugFinal, usos });
        }
      } catch (e: unknown) {
        erros.push({ slug: item.slug || '(parse falhou)', msg: e instanceof Error ? e.message : 'Erro' });
      }
    }

    // ── 2ª passada: criar vs atualizar contra o que JÁ existe no banco ─────────
    for (const cand of candidatos.values()) {
      const { row, md, score, slug, usos } = cand;
      const existente = slug ? porSlug.get(slug) : undefined;
      if (existente) {
        if (modo === 'criar') {
          pulados++;
          ignorados.push({ slug, msg: 'Slug já existe (modo "pular existentes").' });
          continue;
        }
        // upsert com proteção anti-downgrade: não troca uma versão completa
        // por uma claramente mais pobre (ex.: re-import de arquivo truncado).
        const scoreExistente = _scoreCompletudeLinha(existente);
        if (scoreExistente > 0 && score < scoreExistente * 0.6) {
          pulados++;
          ignorados.push({ slug, msg: 'Mantida a versão salva (mais completa que a importada).' });
          continue;
        }
        const conteudoMudou = String(existente.conteudo || '') !== md;
        paraAtualizar.push({
          id: String(existente.id || ''),
          data: {
            ...row,
            ...(conteudoMudou ? { traducaoPt: '', descricaoPt: '', tipoIA: '', adaptacoes: '' } : {}),
          },
        });
      } else {
        paraCriar.push({ ...row, criadoEm: agora, usos });
      }
    }

    // Atualizações (uma a uma — não tem batch do GAS pra setValues de linhas
    // não-contíguas. Mas em geral upsert é minoria; o ganho real está no batch
    // de inserção de novos).
    let atualizados = 0;
    for (const upd of paraAtualizar) {
      try { dbUpdate(tabela, upd.id, upd.data); atualizados++; }
      catch (e: unknown) { erros.push({ slug: String(upd.data.slug || ''), msg: e instanceof Error ? e.message : 'Erro update' }); }
    }

    // Criações em batch (a economia real).
    let criados = 0;
    if (paraCriar.length > 0) {
      try {
        const novos = dbBatchCreate(tabela, paraCriar);
        criados = novos.length;
      } catch (e: unknown) {
        // Fallback: tenta um por um pra ao menos salvar o que der.
        for (const c of paraCriar) {
          try { dbCreate(tabela, c); criados++; }
          catch (e2: unknown) { erros.push({ slug: String(c.slug || ''), msg: e2 instanceof Error ? e2.message : 'Erro create' }); }
        }
      }
    }

    return {
      ok: true,
      data: {
        total: payload.itens.length,
        criados,
        atualizados,
        pulados,
        erros,
        ignorados,
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro no bulk save' };
  }
}

// Traduz a descrição + o conteúdo de uma skill via LLM para pt-BR, preservando
// formatação Markdown, código, comandos e o frontmatter YAML. O resultado é
// PERSISTIDO em `traducaoPt` (cache) pra não re-gastar tokens nas próximas vezes.
// Se já houver cache válido e `forcar` for falso, devolve o cache sem chamar a LLM.
function skillsTraduzir(id: string, idioma?: string, forcar?: boolean): ServerResult {
  try {
    const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
    const s = linhas.find((l) => String(l.id || '') === id);
    if (!s) throw new Error('Skill não encontrada.');
    const alvo = (idioma && idioma.trim()) || 'português do Brasil';

    // Cache hit: devolve sem chamar a LLM.
    if (!forcar) {
      const cache = _parseTraducaoPt(s.traducaoPt);
      if (cache) return { ok: true, data: { ...cache, doCache: true } };
    }

    const conteudo = String(s.conteudo || '');
    const descricao = String(s.descricao || '');
    if (!conteudo.trim() && !descricao.trim()) {
      return { ok: true, data: { conteudo, descricao, idioma: alvo } };
    }
    const sys = 'Você é um tradutor técnico. Traduza o texto a seguir para ' + alvo + '. '
      + 'Mantenha EXATAMENTE a estrutura Markdown (títulos, listas, tabelas), o frontmatter YAML '
      + '(traduza apenas o VALOR de "description"; NÃO altere a chave "name" nem seu valor), e NÃO '
      + 'traduza conteúdo dentro de crases `assim`, blocos de código, comandos de terminal, nomes de '
      + 'arquivos, caminhos ou URLs. Responda somente com o texto traduzido, sem comentários.';
    const conteudoTraduzido = conteudo.trim()
      ? forjaCallLLM([{ role: 'system', content: sys }, { role: 'user', content: conteudo }], 4000, undefined, 'traducao')
      : conteudo;
    let descricaoTraduzida = descricao;
    if (descricao.trim()) {
      descricaoTraduzida = forjaCallLLM([
        { role: 'system', content: 'Traduza para ' + alvo + ' em uma única frase, sem aspas, mantendo termos técnicos:' },
        { role: 'user', content: descricao },
      ], 400, undefined, 'traducao');
    }
    const resultado = {
      conteudo: String(conteudoTraduzido || '').trim(),
      descricao: String(descricaoTraduzida || '').trim(),
      idioma: alvo,
      em: new Date().toISOString(),
    };
    // Persiste o cache (best-effort — se falhar, ainda devolve a tradução).
    try { dbUpdate('Skills', id, { traducaoPt: JSON.stringify(resultado) }); } catch { /* segue baile */ }
    return { ok: true, data: { ...resultado, doCache: false } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao traduzir skill' };
  }
}

// Parse defensivo do cache de tradução; devolve null se vazio/inválido.
function _parseTraducaoPt(raw: unknown): { conteudo: string; descricao: string; idioma: string; em: string } | null {
  const txt = String(raw || '').trim();
  if (!txt) return null;
  try {
    const o = JSON.parse(txt) as Record<string, unknown>;
    if (!o || (!o.conteudo && !o.descricao)) return null;
    return {
      conteudo: String(o.conteudo || ''),
      descricao: String(o.descricao || ''),
      idioma: String(o.idioma || 'português do Brasil'),
      em: String(o.em || ''),
    };
  } catch { return null; }
}

// Traduz para pt-BR APENAS as descrições (uma frase curta) de todas as skills
// que ainda não têm `descricaoPt`. Barato e idempotente: cacheia por skill e só
// retraduz com `forcar`. Não toca em `traducaoPt` (tradução completa do drawer).
function skillsTraduzirDescricoes(forcar?: boolean): ServerResult {
  try {
    const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
    const pendentes = linhas.filter((s) => {
      const desc = String(s.descricao || '').trim();
      const jaPt = String(s.descricaoPt || '').trim();
      return desc && (forcar || !jaPt);
    });
    if (pendentes.length === 0) {
      return { ok: true, data: { traduzidas: 0, total: linhas.length } };
    }
    let n = 0; let erros = 0;
    for (const s of pendentes) {
      const desc = String(s.descricao || '').trim();
      try {
        const pt = forjaCallLLM([
          { role: 'system', content: 'Traduza para português do Brasil em uma única frase, sem aspas, mantendo termos técnicos. Responda somente com a tradução:' },
          { role: 'user', content: desc },
        ], 400, undefined, 'traducao');
        const ptTxt = String(pt || '').trim();
        if (ptTxt) { dbUpdate('Skills', String(s.id || ''), { descricaoPt: ptTxt }); n++; }
      } catch { erros++; /* pula esta, segue as outras */ }
    }
    return { ok: true, data: { traduzidas: n, total: linhas.length, erros } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao traduzir descrições' };
  }
}

// Vocabulário fixo de temas de alto nível. Manter curto e estável pra que os
// agrupamentos não explodam em dezenas de rótulos. A IA escolhe UM desta lista.
const SKILL_TEMAS = [
  'Design', 'Frontend', 'Backend', 'Dados', 'Infra/DevOps', 'Testes',
  'Segurança', 'IA/Prompts', 'Automação', 'Documentação', 'Revisão de código',
  'Produtividade', 'Outro',
];

// Classifica por IA cada skill num tema de alto nível (SKILL_TEMAS) a partir do
// nome + descrição, persistindo em `tipoIA`. Faz UMA chamada à LLM com todas as
// pendentes (JSON in/out) pra economizar tokens. Idempotente: só reclassifica
// quem não tem `tipoIA`, salvo `forcar`.
function skillsClassificar(forcar?: boolean): ServerResult {
  try {
    const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
    const pendentes = linhas.filter((s) => {
      const temTexto = String(s.nome || '').trim() || String(s.descricao || '').trim();
      return temTexto && (forcar || !String(s.tipoIA || '').trim());
    });
    if (pendentes.length === 0) {
      return { ok: true, data: { classificadas: 0, total: linhas.length } };
    }
    const itens = pendentes.map((s, i) => ({
      i,
      id: String(s.id || ''),
      nome: String(s.nome || ''),
      desc: String(s.descricaoPt || s.descricao || '').slice(0, 400),
    }));
    const sys = 'Você classifica skills de desenvolvimento de software em UM tema de alto nível. '
      + 'Use EXATAMENTE um destes valores: ' + SKILL_TEMAS.join(', ') + '. '
      + 'Se nada se encaixar, use "Outro". Responda SOMENTE com um array JSON, sem texto extra, '
      + 'no formato [{"i":0,"tema":"Design"}, ...] cobrindo todos os itens recebidos.';
    const userMsg = JSON.stringify(itens.map((x) => ({ i: x.i, nome: x.nome, descricao: x.desc })));
    const resp = forjaCallLLM(
      [{ role: 'system', content: sys }, { role: 'user', content: userMsg }],
      1500, undefined, 'traducao',
    );
    const mapa = _parseClassificacao(resp);
    let n = 0;
    for (const it of itens) {
      const tema = _temaValido(mapa[it.i]);
      if (tema) { try { dbUpdate('Skills', it.id, { tipoIA: tema }); n++; } catch { /* segue */ } }
    }
    return { ok: true, data: { classificadas: n, total: linhas.length } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao classificar skills' };
  }
}

// Normaliza um tema retornado pela IA pro valor canônico de SKILL_TEMAS (case/
// acento-insensível). Devolve '' se não casar com nada.
function _temaValido(raw: unknown): string {
  const txt = String(raw || '').trim().toLowerCase();
  if (!txt) return '';
  const norm = (s: string) => s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const alvo = norm(txt);
  for (const tema of SKILL_TEMAS) if (norm(tema) === alvo) return tema;
  return '';
}

// Parse defensivo da resposta da IA → { [i]: tema }. Tenta JSON direto; se vier
// cercado por texto/markdown, extrai o primeiro array JSON.
function _parseClassificacao(resp: string): Record<number, string> {
  const out: Record<number, string> = {};
  let txt = String(resp || '').trim();
  const ini = txt.indexOf('[');
  const fim = txt.lastIndexOf(']');
  if (ini >= 0 && fim > ini) txt = txt.slice(ini, fim + 1);
  try {
    const arr = JSON.parse(txt) as Array<Record<string, unknown>>;
    if (Array.isArray(arr)) {
      for (const o of arr) {
        const i = Number(o.i);
        if (!Number.isNaN(i)) out[i] = String(o.tema || o.tipo || '');
      }
    }
  } catch { /* sem classificação utilizável */ }
  return out;
}

// ─── Avaliação de qualidade (estrelas 0-5) pela Lume (v1.152.0) ─────────────
// Nota GLOBAL de qualidade, gravada na skill/agent. Processa UM chunk por
// chamada (pra não estourar timeout do GAS) e devolve `restantes` pro frontend
// repetir até zerar, com barra de progresso. Escopo: ids | fonte | categoria,
// e por padrão só "pendentes" (sem estrelas) — re-rodar não re-gasta tokens.
const CHUNK_AVALIACAO = 40;

interface OpcoesAvaliar {
  ids?: string[];
  fonte?: string;       // chave da pasta (prefixo de `fonte`)
  categoria?: string;   // casa contra tipoIA || categoria
  escopo?: 'pendentes' | 'todas';
  forcar?: boolean;     // re-avalia mesmo quem já tem estrelas
}

function _selecionarParaAvaliar(
  linhas: Array<Record<string, unknown>>,
  op: OpcoesAvaliar,
): Array<Record<string, unknown>> {
  let alvo = linhas;
  if (op.ids && op.ids.length > 0) {
    const set = new Set(op.ids.map((x) => String(x)));
    return linhas.filter((l) => set.has(String(l.id || '')));
  }
  if (op.fonte) {
    alvo = alvo.filter((l) => _chaveDaFonte(String(l.fonte || '')) === op.fonte);
  }
  if (op.categoria) {
    const norm = (s: string) => s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
    const alvoCat = norm(op.categoria);
    alvo = alvo.filter((l) => norm(String(l.tipoIA || l.categoria || '')) === alvoCat);
  }
  const querTodas = op.escopo === 'todas' || op.forcar;
  if (!querTodas) alvo = alvo.filter((l) => !(Number(l.estrelas || 0) > 0));
  // Só itens com texto avaliável.
  alvo = alvo.filter((l) => String(l.nome || '').trim() || String(l.descricao || '').trim());
  return alvo;
}

// Parse defensivo da resposta de avaliação → { [i]: {estrelas, motivo} }.
function _parseAvaliacao(resp: string): Record<number, { estrelas: number; motivo: string }> {
  const out: Record<number, { estrelas: number; motivo: string }> = {};
  let txt = String(resp || '').trim();
  const ini = txt.indexOf('[');
  const fim = txt.lastIndexOf(']');
  if (ini >= 0 && fim > ini) txt = txt.slice(ini, fim + 1);
  try {
    const arr = JSON.parse(txt) as Array<Record<string, unknown>>;
    if (Array.isArray(arr)) {
      for (const o of arr) {
        const i = Number(o.i);
        if (Number.isNaN(i)) continue;
        let n = Math.round(Number(o.estrelas ?? o.nota ?? o.stars ?? 0));
        if (Number.isNaN(n)) n = 0;
        n = Math.max(0, Math.min(5, n));
        out[i] = { estrelas: n, motivo: String(o.motivo || o.razao || o.reason || '').slice(0, 160) };
      }
    }
  } catch { /* sem avaliação utilizável */ }
  return out;
}

function _avaliarGenerico(tabela: 'Skills' | 'Agents', op: OpcoesAvaliar): ServerResult {
  try {
    const linhas = dbGetAll(tabela) as Array<Record<string, unknown>>;
    const candidatos = _selecionarParaAvaliar(linhas, op || {});
    const total = candidatos.length;
    if (total === 0) return { ok: true, data: { avaliadas: 0, restantes: 0, total: 0 } };

    const chunk = candidatos.slice(0, CHUNK_AVALIACAO);
    const itens = chunk.map((s, i) => ({
      i,
      id: String(s.id || ''),
      nome: String(s.nome || ''),
      desc: String(s.descricaoPt || s.descricao || s.diretrizFinal || '').slice(0, 320),
      tipo: String(s.tipoIA || s.categoria || ''),
    }));
    const oque = tabela === 'Agents' ? 'agents de IA' : 'skills de desenvolvimento';
    const sys = `Você avalia a QUALIDADE de ${oque}. Para cada item dê uma nota inteira de 0 a 5 `
      + 'considerando: clareza, completude, utilidade prática e maturidade. '
      + '5 = excelente/pronto pra produção; 3 = ok mas genérico; 0-1 = vago/incompleto. '
      + 'Responda SOMENTE com um array JSON, sem texto extra, no formato '
      + '[{"i":0,"estrelas":4,"motivo":"frase curta"}] cobrindo TODOS os itens. '
      + 'O motivo deve ter no máximo 12 palavras, em português.';
    const userMsg = JSON.stringify(itens.map((x) => ({ i: x.i, nome: x.nome, tipo: x.tipo, descricao: x.desc })));
    const resp = forjaCallLLM(
      [{ role: 'system', content: sys }, { role: 'user', content: userMsg }],
      1800, undefined, 'avaliacao',
    );
    const mapa = _parseAvaliacao(resp);
    const agora = new Date().toISOString();
    let n = 0;
    for (const it of itens) {
      const aval = mapa[it.i];
      if (!aval) continue;
      try {
        dbUpdate(tabela, it.id, { estrelas: aval.estrelas, estrelasMotivo: aval.motivo, avaliadaEm: agora });
        n++;
      } catch { /* segue */ }
    }
    return { ok: true, data: { avaliadas: n, restantes: Math.max(0, total - chunk.length), total } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao avaliar' };
  }
}

function skillsAvaliar(opcoes?: OpcoesAvaliar): ServerResult {
  return _avaliarGenerico('Skills', opcoes || {});
}

function agentsAvaliar(opcoes?: OpcoesAvaliar): ServerResult {
  return _avaliarGenerico('Agents', opcoes || {});
}

// Override manual da nota (0-5). Marca motivo como ajuste manual.
function _definirEstrelasGenerico(tabela: 'Skills' | 'Agents', id: string, estrelas: number): ServerResult {
  try {
    let n = Math.round(Number(estrelas || 0));
    if (Number.isNaN(n)) n = 0;
    n = Math.max(0, Math.min(5, n));
    const agora = new Date().toISOString();
    dbUpdate(tabela, id, { estrelas: n, estrelasMotivo: 'Ajuste manual', avaliadaEm: agora });
    return { ok: true, data: { id, estrelas: n } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao definir estrelas' };
  }
}

function skillsDefinirEstrelas(id: string, estrelas: number): ServerResult {
  return _definirEstrelasGenerico('Skills', id, estrelas);
}

function agentsDefinirEstrelas(id: string, estrelas: number): ServerResult {
  return _definirEstrelasGenerico('Agents', id, estrelas);
}

