function kitMontarDominio(nome: string, objetivo: string, alvoSkills?: number, alvoAgents?: number): ServerResult {
  try {
    const nomeLimpo = String(nome || '').trim().slice(0, 80);
    const objLimpo = String(objetivo || '').trim().slice(0, 1200);
    if (!nomeLimpo) throw new Error('Dê um nome ao domínio/projeto da coleção.');
    if (objLimpo.length < 8) throw new Error('Descreva um pouco melhor o domínio/projeto pra Lume curar bem.');
    const slug = _slugFonte(nomeLimpo) || `col-${Date.now()}`;
    return _montarKitCore({
      templateId: `dominio:${slug}`,
      nome: nomeLimpo,
      descricao: objLimpo.slice(0, 200),
      objetivo: `Coleção por domínio de negócio "${nomeLimpo}". ${objLimpo} `
        + 'Selecione as skills e agents da base mais úteis pra construir um produto desse domínio, '
        + 'combinando fundação técnica com o que for específico da vertical. '
        + 'Inclua também a melhor skill de design/UI (premium, com identidade própria, anti "cara de IA").',
      alvoSkills: Math.max(4, Math.min(40, Number(alvoSkills) || 16)),
      alvoAgents: Math.max(2, Math.min(20, Number(alvoAgents) || 6)),
    });
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao montar coleção' };
  }
}

// Lista os segmentos (chaves de fonte) existentes na base, com contagem de
// skills e agents. Um "segmento" é a pasta/seção pra onde um pack importado vai
// (ex.: "contabilidade", "fiscal"). Usado nos hubs e pra montar kit do segmento.
function segmentosList(): ServerResult {
  try {
    const fontes = dbGetAll('SkillFontes') as Array<Record<string, unknown>>;
    const meta: Record<string, Record<string, unknown>> = {};
    for (const f of fontes) meta[String(f.chave || '')] = f;
    const contar = (tabela: 'Skills' | 'Agents'): Record<string, number> => {
      const m: Record<string, number> = {};
      for (const l of dbGetAll(tabela) as Array<Record<string, unknown>>) {
        if (!String(l.nome || '').trim()) continue;
        const k = _chaveDaFonte(String(l.fonte || ''));
        m[k] = (m[k] || 0) + 1;
      }
      return m;
    };
    const cs = contar('Skills');
    const ca = contar('Agents');
    const chaves = new Set<string>([...Object.keys(cs), ...Object.keys(ca)]);
    const data = Array.from(chaves).map((k) => ({
      chave: k,
      nome: String(meta[k]?.nome || (k === 'avulsas' ? 'Avulsas / Importadas' : k)),
      cor: String(meta[k]?.cor || ''),
      skills: cs[k] || 0,
      agents: ca[k] || 0,
      total: (cs[k] || 0) + (ca[k] || 0),
    })).filter((s) => s.total > 0).sort((a, b) => b.total - a.total);
    return { ok: true, data };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar segmentos' };
  }
}

// Monta o "kit dos sonhos" de UM segmento específico — escopa o pool só aos
// itens daquele segmento (skills + agents). Chamado a partir dos hubs.
function kitMontarSegmento(segKey: string, nome?: string): ServerResult {
  try {
    const key = _slugFonte(String(segKey || ''));
    if (!key) throw new Error('Segmento inválido.');
    const nomeSeg = String(nome || '').trim() || key;
    return _montarKitCore({
      templateId: `segmento:${key}`,
      nome: `Segmento — ${nomeSeg}`,
      descricao: `Kit dos sonhos do segmento "${nomeSeg}" (apenas skills + agents desse segmento).`,
      objetivo: `Monte o kit dos sonhos usando SOMENTE as skills e agents do segmento "${nomeSeg}". `
        + 'Selecione os melhores, mais completos e mais bem avaliados que, juntos, formam um conjunto '
        + 'coeso e de alto nível pra desenvolver nessa área/vertical. Se houver uma boa skill de design/UI, '
        + 'inclua (interface premium, com identidade própria, anti "cara de IA"). Evite redundância.',
      alvoSkills: 24, alvoAgents: 10,
      fonteEscopo: key,
    });
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao montar kit do segmento' };
  }
}

function kitsList(): ServerResult {
  try {
    const kits = (dbGetAll('Kits') as Array<Record<string, unknown>>).map((k) => {
      const skillIds = String(k.skillIds || '').split(',').map((x) => x.trim()).filter(Boolean);
      const agentIds = String(k.agentIds || '').split(',').map((x) => x.trim()).filter(Boolean);
      return {
        id: String(k.id || ''),
        templateId: String(k.templateId || ''),
        nome: String(k.nome || ''),
        descricao: String(k.descricao || ''),
        skills: skillIds.length,
        agents: agentIds.length,
        justificativa: String(k.justificativa || ''),
        montadoPorLume: String(k.montadoPorLume || '') === 'true',
        criadoEm: String(k.criadoEm || ''),
        atualizadoEm: String(k.atualizadoEm || ''),
      };
    });
    return { ok: true, data: kits };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao listar kits' };
  }
}

function kitsGetContent(id: string): ServerResult {
  try {
    const kits = dbGetAll('Kits') as Array<Record<string, unknown>>;
    const k = kits.find((x) => String(x.id || '') === id);
    if (!k) throw new Error('Kit não encontrado.');
    const skillIds = String(k.skillIds || '').split(',').map((x) => x.trim()).filter(Boolean);
    const agentIds = String(k.agentIds || '').split(',').map((x) => x.trim()).filter(Boolean);

    const skillsTodas = dbGetAll('Skills') as Array<Record<string, unknown>>;
    const agentsTodos = dbGetAll('Agents') as Array<Record<string, unknown>>;
    const porIdSkill = new Map(skillsTodas.map((s) => [String(s.id || ''), s]));
    const porIdAgent = new Map(agentsTodos.map((a) => [String(a.id || ''), a]));

    const resumo = (l: Record<string, unknown> | undefined, id2: string) => l ? {
      id: String(l.id || ''),
      nome: String(l.nome || ''),
      descricao: String(l.descricaoPt || l.descricao || l.diretrizFinal || ''),
      tema: String(l.tipoIA || l.categoria || ''),
      estrelas: Number(l.estrelas || 0),
      fonte: String(l.fonte || ''),
    } : { id: id2, nome: '(removido)', descricao: '', tema: '', estrelas: 0, fonte: '' };

    return {
      ok: true,
      data: {
        id: String(k.id || ''),
        templateId: String(k.templateId || ''),
        nome: String(k.nome || ''),
        descricao: String(k.descricao || ''),
        justificativa: String(k.justificativa || ''),
        montadoPorLume: String(k.montadoPorLume || '') === 'true',
        atualizadoEm: String(k.atualizadoEm || ''),
        skills: skillIds.map((sid) => resumo(porIdSkill.get(sid), sid)),
        agents: agentIds.map((aid) => resumo(porIdAgent.get(aid), aid)),
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao abrir kit' };
  }
}

function kitSalvar(payload: {
  id?: string; templateId?: string; nome: string; descricao?: string;
  skillIds?: string[]; agentIds?: string[];
}): ServerResult {
  try {
    const nome = String(payload.nome || '').trim();
    if (!nome) throw new Error('Dê um nome pro kit.');
    const agora = new Date().toISOString();
    const dados = {
      templateId: String(payload.templateId || ''),
      nome,
      descricao: String(payload.descricao || ''),
      skillIds: (payload.skillIds || []).join(','),
      agentIds: (payload.agentIds || []).join(','),
      montadoPorLume: 'false',
      atualizadoEm: agora,
    };
    if (payload.id) {
      dbUpdate('Kits', payload.id, dados);
      return { ok: true, data: { id: payload.id } };
    }
    const novo = dbCreate('Kits', { ...dados, justificativa: '', criadoEm: agora });
    return { ok: true, data: { id: String(novo.id || '') } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao salvar kit' };
  }
}

function kitRemover(id: string): ServerResult {
  try {
    dbDelete('Kits', id);
    return { ok: true, data: { id } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao remover kit' };
  }
}

// Devolve nome+conteúdo das skills E agents de um kit, pra montar o .zip misto.
function kitExportar(id: string): ServerResult {
  try {
    const kits = dbGetAll('Kits') as Array<Record<string, unknown>>;
    const k = kits.find((x) => String(x.id || '') === id);
    if (!k) throw new Error('Kit não encontrado.');
    const skillIds = String(k.skillIds || '').split(',').map((x) => x.trim()).filter(Boolean);
    const agentIds = String(k.agentIds || '').split(',').map((x) => x.trim()).filter(Boolean);

    const mapear = (tabela: 'Skills' | 'Agents', ids: string[]) => {
      const linhas = dbGetAll(tabela) as Array<Record<string, unknown>>;
      const porId = new Map(linhas.map((l) => [String(l.id || ''), l]));
      return ids.map((x) => porId.get(x)).filter((l): l is Record<string, unknown> => !!l).map((l) => ({
        id: String(l.id || ''),
        nome: String(l.nome || ''),
        descricao: String(l.descricaoPt || l.descricao || ''),
        conteudo: String(l.conteudo || ''),
        fonte: String(l.fonte || ''),
      }));
    };

    return {
      ok: true,
      data: {
        nome: String(k.nome || 'Kit'),
        skills: mapear('Skills', skillIds),
        agents: mapear('Agents', agentIds),
      },
    };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro ao exportar kit' };
  }
}

// Lista todas as skills com metadados (sem o conteúdo completo, pra ser leve).
function skillsList(): ServerResult {
  try {
    const todas = (dbGetAll('Skills') as Array<Record<string, unknown>>)
      .map((s) => ({
        id: String(s.id || ''),
        nome: String(s.nome || ''),
        descricao: String(s.descricao || ''),
        descricaoPt: String(s.descricaoPt || ''),
        tipoIA: String(s.tipoIA || ''),
        categoria: String(s.categoria || ''),
        tags: String(s.tags || '').split(',').map((x) => x.trim()).filter(Boolean),
        fonte: String(s.fonte || ''),
        tamanhoBytes: Number(s.tamanhoBytes || 0),
        criadoEm: String(s.criadoEm || ''),
        atualizadoEm: String(s.atualizadoEm || ''),
        // v1.148.13 — favorita (boolean) + favoritadaEm (timestamp pra ordenação estável).
        favorita: String(s.favorita || '') === 'true' || s.favorita === true,
        favoritadaEm: String(s.favoritadaEm || ''),
        // v1.149.0 — campos ricos (Pack PT-BR).
        slug: String(s.slug || ''),
        idExterno: String(s.idExterno || ''),
        usos: Number(s.usos || 0),
        relacionadas: String(s.relacionadas || '').split(',').map((x) => x.trim()).filter(Boolean),
        quandoUsar: String(s.quandoUsar || ''),
        // v1.152.0 — nota global de qualidade (0-5) dada pela Lume (ou manual).
        estrelas: Number(s.estrelas || 0),
        estrelasMotivo: String(s.estrelasMotivo || ''),
        avaliadaEm: String(s.avaliadaEm || ''),
      }))
      // Ordena favoritas primeiro (mais recente favoritada no topo), depois resto por atualizadoEm.
      .sort((a, b) => {
        if (a.favorita !== b.favorita) return a.favorita ? -1 : 1;
        if (a.favorita) return b.favoritadaEm.localeCompare(a.favoritadaEm);
        return b.atualizadoEm.localeCompare(a.atualizadoEm);
      });
    return { ok: true, data: todas };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// v1.148.13 — Toggle favorita de uma skill. Idempotente.
// Resposta ao user: "pensei em ter um campo na skill que eu possa favoritar com
// uma estrela as mais tops". Ordenação faz favoritas subirem pro topo da lista.
function skillsToggleFavorita(id: string): ServerResult {
  try {
    const linhas = dbGetAll('Skills') as Array<Record<string, unknown>>;
    const s = linhas.find((l) => String(l.id || '') === id);
    if (!s) return { ok: false, error: 'Skill não encontrada.' };
    const eraFavorita = String(s.favorita || '') === 'true' || s.favorita === true;
    const agora = new Date().toISOString();
    dbUpdate('Skills', id, {
      favorita: eraFavorita ? '' : 'true',
      favoritadaEm: eraFavorita ? '' : agora,
      atualizadoEm: agora,
    });
    return { ok: true, data: { favorita: !eraFavorita, favoritadaEm: eraFavorita ? '' : agora } };
  } catch (e: unknown) {
    return { ok: false, error: e instanceof Error ? e.message : 'Erro' };
  }
}

// Carrega o conteúdo completo de uma skill (chamado quando o user abre o drawer).
